var CARDS=[// SALAM
// id 1, 2, 3 dihapus di v25 — digantikan oleh kartu text4l yang lebih lengkap: id 677, 679, 678
{id:4,category:"salam",source:"text1l",jp:"朝礼",romaji:"chorei",id_text:"Apel pagi",desc:"Pertemuan wajib setiap pagi sebelum kerja dimulai. Ada 2 jenis: apel pagi umum dan apel per jenis pekerjaan."},{id:5,category:"salam",source:"text1l",jp:"危険予知活動（KY活動）",romaji:"kiken yochi katsudou (KY katsudou)",id_text:"Kegiatan Prediksi Bahaya (KY)",desc:"Kegiatan mengidentifikasi potensi bahaya sebelum bekerja. Dilaksanakan saat apel pagi per jenis pekerjaan."},{id:6,category:"salam",source:"text1l",jp:"ラジオ体操",romaji:"rajio taiso",id_text:"Senam radio",desc:"Senam pemanasan yang dilakukan saat apel pagi. Bertujuan membangunkan tubuh dan mencegah cedera."},{id:7,category:"salam",source:"text1l",jp:"指差し呼称",romaji:"yubisashi koshou",id_text:"Tunjuk dan panggil",desc:"Metode konfirmasi keselamatan dengan menunjuk dan menyebut dengan keras. Meningkatkan kesadaran keselamatan."},{id:8,category:"salam",source:"text1l",jp:"ヒヤリハット",romaji:"hiyari hatto",id_text:"Hampir kecelakaan (near miss)",desc:"Insiden yang nyaris menjadi kecelakaan. Wajib dilaporkan untuk mencegah kecelakaan sebenarnya di masa depan."},// id 142, 143, 144 dihapus di v25 — digantikan oleh kartu text4l yang lebih lengkap: id 680, 681, 682
// HUKUM
{id:9,category:"hukum",source:"text2",jp:"労働基準法",romaji:"roudou kijunhou",id_text:"UU Standar Ketenagakerjaan",desc:"Menetapkan syarat kerja minimum: jam kerja max 8 jam/hari & 40 jam/minggu, upah, cuti, dll."},{id:10,category:"hukum",source:"text2",jp:"労働安全衛生法",romaji:"roudou anzen eisei hou",id_text:"UU Keselamatan dan Kesehatan Kerja",desc:"Bertujuan memastikan keselamatan & kesehatan pekerja di tempat kerja. Mengatur pendidikan keselamatan, APD, dll."},{id:11,category:"hukum",source:"text2",jp:"最低賃金法",romaji:"saitei chingin hou",id_text:"UU Upah Minimum",desc:"Upah minimum ditetapkan per prefektur karena perbedaan harga dan standar upah tiap daerah."},{id:12,category:"hukum",source:"text2",jp:"建設業法",romaji:"kensetsu gyou hou",id_text:"UU Industri Konstruksi",desc:"Mengatur izin usaha konstruksi, kontrak pekerjaan, insinyur penanggung jawab, dan perlindungan pemesan."},{id:13,category:"hukum",source:"text2",jp:"建築基準法",romaji:"kenchiku kijun hou",id_text:"UU Standar Bangunan",desc:"Aturan minimum untuk membangun/menggunakan bangunan. Terdiri dari peraturan individu dan peraturan kelompok."},{id:14,category:"hukum",source:"text2",jp:"消防法",romaji:"shoubou hou",id_text:"UU Pemadam Kebakaran",desc:"Mengatur alat pemadam, hidran, sprinkler, peralatan evakuasi, dan alarm kebakaran di gedung."},{id:15,category:"hukum",source:"text2",jp:"水道法",romaji:"suidou hou",id_text:"UU Air Bersih",desc:"Mengatur usaha pasokan air. Insinyur yang ditetapkan UU ini harus ditempatkan di setiap pekerjaan."},{id:16,category:"hukum",source:"text2",jp:"電気事業法",romaji:"denki jigyou hou",id_text:"UU Usaha Kelistrikan",desc:"Mengatur standar konstruksi, pemeliharaan, dan pengoperasian fasilitas ketenagalistrikan."},{id:17,category:"hukum",source:"text2",jp:"電気通信事業法",romaji:"denki tsuushin jigyou hou",id_text:"UU Usaha Telekomunikasi",desc:"Mengatur pemasangan jaringan & peralatan telekomunikasi. Wajib dilaksanakan oleh insinyur berkualifikasi."},{id:18,category:"hukum",source:"text2",jp:"36協定",romaji:"saburoku kyoutei",id_text:"Perjanjian 36 (perjanjian lembur)",desc:"Perjanjian antara pemberi kerja dan tenaga kerja berdasarkan Pasal 36 UU Standar Ketenagakerjaan yang membolehkan lembur."},{id:19,category:"hukum",source:"text2",jp:"労災保険",romaji:"rousai hoken",id_text:"Asuransi kecelakaan kerja",desc:"Memberikan manfaat jika pekerja terluka/sakit/meninggal karena kecelakaan kerja. Premi ditanggung sepenuhnya oleh pemberi kerja."},{id:20,category:"hukum",source:"text2",jp:"マニフェスト",romaji:"manifesuto",id_text:"Manifest (lembar kontrol limbah konstruksi)",desc:"Dokumen yang wajib dibuat kontraktor utama untuk memastikan pembuangan limbah industri dilakukan dengan benar."},{id:116,category:"hukum",source:"text2",jp:"建設リサイクル法",romaji:"kensetsu risaikuru hou",id_text:"UU Daur Ulang Konstruksi",desc:"Nama resmi: 建設工事に係る資材の再資源化等に関する法律. Wajibkan pemilahan (分別) dan daur ulang (再資源化) material limbah konstruksi. Di lokasi kerja: sampah HARUS disimpan sesuai klasifikasi yang ditentukan. Hubungan dengan 廃棄物処理法: 廃棄物処理法 = siapa boleh angkut; 建設リサイクル法 = bagaimana dipisah & didaur ulang. (Sumber: text2 §2.5)"},{id:117,category:"hukum",source:"text2",jp:"雇用保険法",romaji:"koyou hoken hou",id_text:"UU Asuransi Ketenagakerjaan",desc:"Memberikan tunjangan pengangguran bila pekerja kehilangan pekerjaan. Premi ditanggung BERSAMA pemberi kerja dan pekerja. Berbeda dari 労災保険. (Sumber: text1l §2.1.5)"},{id:118,category:"hukum",source:"text2",jp:"ガス事業法",romaji:"gasu jigyou hou",id_text:"UU Usaha Gas",desc:"Mengatur usaha gas KOTA (都市ガス). Berbeda dari LPガス. (Sumber: tt_sample2 Q7, text1l §2.1.2)"},{id:121,category:"hukum",source:"text2",jp:"下水道法",romaji:"gesuidou hou",id_text:"UU Saluran Air Limbah",desc:"Mengatur sistem saluran pembuangan air limbah kota. Instalasi dari gedung harus terhubung ke sistem ini."},{id:125,category:"hukum",source:"text2",jp:"廃棄物処理法",romaji:"haikibumono shori hou",id_text:"UU Pengelolaan Limbah",desc:"Mengatur pengelolaan limbah industri. マニフェスト wajib dibuat kontraktor utama."},{id:132,category:"hukum",source:"text2",jp:"労災かくし",romaji:"rousai kakushi",id_text:"Penyembunyian kecelakaan kerja — KEJAHATAN",desc:"Jika terjadi kecelakaan kerja, wajib lapor ke Kantor Inspeksi. Menyembunyikan = KEJAHATAN (melanggar UU K3). (Sumber: text2 §2.1.4)"},{id:133,category:"hukum",source:"text2",jp:"電気工事業法",romaji:"denki kouji gyou hou",id_text:"UU Usaha Pekerjaan Listrik (≠ UU Usaha Kelistrikan!)",desc:"Mengatur kontraktor yang melakukan pekerjaan listrik. BERBEDA dari 電気事業法 yang mengatur perusahaan penyedia listrik. (Sumber: text2 §2.13)"},{id:134,category:"hukum",source:"text2",jp:"建設業法の29業種",romaji:"kensetsu gyou hou no nijuukyuu gyoushu",id_text:"29 jenis usaha yang perlu izin konstruksi",desc:"Termasuk: Listrik, Pipa, Pemadam Kebakaran, Insulasi Termal, Telekomunikasi, Pembongkaran, dll. Total 29 jenis. (Sumber: text2 §2.2)"},{id:135,category:"hukum",source:"text2",jp:"アスベスト（石綿）",romaji:"asubesuto (ishiwata)",id_text:"Asbes — DILARANG",desc:"Dilarang karena menyebabkan kanker paru. Jika membongkar bangunan lama yang mengandung asbes, wajib lapor ke gubernur prefektur 14 hari sebelumnya. (Sumber: text2 §2.6)"},{id:136,category:"hukum",source:"text2",jp:"大気汚染防止法",romaji:"taiki osen boushi hou",id_text:"UU Pencegahan Polusi Udara",desc:"Di konstruksi: jika membongkar gedung yang mengandung asbes, wajib lapor ke gubernur prefektur 14 hari sebelum mulai. (Sumber: text2 §2.6)"},// JENIS KERJA
{id:21,category:"jenis_kerja",source:"text3",jp:"ライフライン工事",romaji:"raifu rain kouji",id_text:"Pekerjaan lifeline",desc:"Meliputi pekerjaan listrik, gas kota, suplai air & drainase, dan telekomunikasi."},{id:22,category:"jenis_kerja",source:"text3",jp:"設備工事",romaji:"setsubi kouji",id_text:"Pekerjaan peralatan (設備)",desc:"Meliputi peralatan AC, peralatan kebersihan suplai air & drainase, pekerjaan menjaga suhu, dan peralatan pemadam kebakaran."},{id:23,category:"jenis_kerja",source:"text3",jp:"電気工事",romaji:"denki kouji",id_text:"Pekerjaan listrik",desc:"Listrik dari pembangkit → gardu → tiang/bawah tanah → gedung. 'Sengatan listrik' adalah kecelakaan khas pekerjaan ini."},{id:24,category:"jenis_kerja",source:"text3",jp:"都市ガス工事",romaji:"toshi gasu kouji",id_text:"Pekerjaan gas kota",desc:"LNG → tangki penyimpanan → pipa bawah tanah → penampung gas → distribusi ke pabrik/rumah."},{id:25,category:"jenis_kerja",source:"text3",jp:"給排水工事",romaji:"kyuu haisui kouji",id_text:"Pekerjaan suplai air dan drainase",desc:"Suplai: air sungai → pemurnian → reservoir → pipa. Drainase: limbah gedung → pipa → instalasi pengolahan."},{id:26,category:"jenis_kerja",source:"text3",jp:"通信工事",romaji:"tsuushin kouji",id_text:"Pekerjaan telekomunikasi",desc:"Pembangunan jaringan informasi: telepon, internet. Menggunakan kabel logam atau kabel serat optik."},{id:27,category:"jenis_kerja",source:"text3",jp:"空調設備工事",romaji:"kuuchou setsubi kouji",id_text:"Pekerjaan AC & pendingin udara",desc:"Pembuatan peralatan yang menyesuaikan suhu, kelembapan, dan memurnikan udara di dalam ruangan."},{id:28,category:"jenis_kerja",source:"text3",jp:"消防設備工事",romaji:"shoubou setsubi kouji",id_text:"Pekerjaan peralatan pemadam kebakaran",desc:"Melindungi orang & bangunan dari kebakaran. Meliputi alarm, sprinkler, dan pompa pemadam."},{id:29,category:"jenis_kerja",source:"text3",jp:"保温保冷工事",romaji:"hoon horei kouji",id_text:"Pekerjaan isolasi termal panas & dingin",desc:"Memasang bahan isolasi termal pada saluran & pipa. 保温 (panas): mengurangi kehilangan panas & mencegah luka bakar dari pipa panas. 保冷 (dingin): mencegah kondensasi & kehilangan suhu dingin."},{id:30,category:"jenis_kerja",source:"text3",jp:"給排水衛生設備工事",romaji:"kyuu haisui eisei setsubi kouji",id_text:"Pekerjaan sanitasi suplai air & drainase",desc:"Memasang peralatan untuk menjaga kebersihan lingkungan tempat tinggal menggunakan air dan air panas."},{id:115,category:"jenis_kerja",source:"st_sample2_l",jp:"加湿器 vs 除湿器",romaji:"kashitsuki vs joshitsuki",id_text:"Pelembap udara vs Penyerap kelembapan",desc:"加湿器 = MENAMBAH kelembapan ke udara kering. 除湿器 = MENGURANGI kelembapan. 冷却コイル = koil pendingin. (Sumber: st_sample2_l Q4)"},{id:124,category:"jenis_kerja",source:"st_sample2_l",jp:"築炉工事（耐火物）",romaji:"chikuro kouji (taikabumotsu)",id_text:"Pekerjaan konstruksi tungku — bahan tahan api",desc:"Melapisi bagian dalam tungku/kiln yang suhu tinggi dengan BAHAN TAHAN API (耐火物). Perekat bata = 耐熱断熱煉瓦用モルタル. BUKAN 保温材/断熱材 biasa. (Sumber: st_sample_l Q11, st_sample2_l Q13)"},{id:126,category:"jenis_kerja",source:"st_sample2_l",jp:"丸ダクト → 差し込み継手工法",romaji:"maru dakuto → sashikomi tsugite kouhou",id_text:"Saluran udara bulat → sambungan selip/insert",desc:"丸ダクト (round duct): pakai 差し込み継手工法 (insert joint). 角ダクト (square duct): pakai 共板フランジ工法 (flange). (Sumber: st_sample2_l Q9)"},{id:129,category:"jenis_kerja",source:"text6l",jp:"受注一品生産",romaji:"juchuu ippin seisan",id_text:"Produksi pesanan satu-per-satu",desc:"Karakteristik khas konstruksi: setiap proyek dibuat sesuai permintaan klien dari awal, berbeda dari produksi pabrik. (Sumber: text6l §6.1.1)"},{id:137,category:"jenis_kerja",source:"text3",jp:"コンバージョン",romaji:"konbaajon",id_text:"Konversi bangunan",desc:"Memanfaatkan struktur bangunan yang sudah ada untuk diubah ke fungsi baru. Contoh: kantor → apartemen. (Sumber: text3 §3.1.2)"},{id:138,category:"jenis_kerja",source:"text3",jp:"あと施工アンカー",romaji:"ato sekou ankaa",id_text:"Angkur pasca-cor",desc:"Angkur yang dipasang pada beton yang sudah mengeras. Ada 2 jenis: 金属系 (metal) dan 接着系 (adhesive/resin). (Sumber: text3 §3.1.2)"},{id:139,category:"jenis_kerja",source:"text3",jp:"軽量鉄骨（LGS） vs 重量鉄骨",romaji:"keiryou tekkotsu vs juryou tekkotsu",id_text:"Baja ringan (LGS <6mm) vs baja berat (≥6mm)",desc:"Baja ringan (軽量鉄骨/LGS): tebal <6mm — untuk rangka dinding/plafon. Baja berat (重量鉄骨): ≥6mm — struktur utama gedung. (Sumber: text3 §3.2.10)"},{id:140,category:"jenis_kerja",source:"text3",jp:"鉄骨構造の種類（ブレース・ラーメン・トラス）",romaji:"buresu / raamen / torasu",id_text:"Struktur baja: brace / ramen / truss",desc:"①ブレース: diagonal brace. ②ラーメン: rigid joint kolom-balok → tahan gempa. ③トラス: susunan segitiga → atap/jembatan. (Sumber: text3 §3.2.10)"},{id:141,category:"jenis_kerja",source:"text3",jp:"建て逃げ方式 vs 水平積み上げ方式",romaji:"tate nige vs suihei tsumage",id_text:"Pemasangan baja: mobile crane vs tower crane",desc:"①建て逃げ: mobile crane, dari belakang ke depan. ②水平積み上げ: tower crane, lantai per lantai → gedung pencakar langit. (Sumber: text3 §3.2.10)"},{id:148,category:"jenis_kerja",source:"text4",jp:"転圧（てんあつ）",romaji:"ten'atsu",id_text:"Pemadatan dengan roller",desc:"Proses memadatkan tanah/aspal menggunakan roller. Digunakan dalam pekerjaan perkerasan jalan (舗装工事). (Sumber: text4 §4.2.3)"},{id:149,category:"jenis_kerja",source:"text3",jp:"路床・路盤・表層（舗装工事の層構造）",romaji:"roshou / roban / hyousou",id_text:"Lapisan jalan: subgrade / base / surface",desc:"Dari bawah: ①路床 (subgrade, digali ±1m) ②路盤 (batu pecah, dipadatkan roller) ③表層 (aspal atas, tahan air). (Sumber: text3 §3.2.6, text4 §4.2.3)"},{id:152,category:"jenis_kerja",source:"text4",jp:"遣り方（やりかた）・水貫・水盛り",romaji:"yarikata / mizunuki / mizumori",id_text:"Setting out bangunan — tiang & papan referensi",desc:"遣り方: rangka sementara tiang kayu + papan horizontal (水貫) untuk menentukan posisi & ketinggian bangunan. Di sipil disebut '丁張り'. (Sumber: text4 §4.2.2)"},{id:153,category:"jenis_kerja",source:"st_sample_l",jp:"施工管理 — 所定の品質",romaji:"sekou kanri — shotei no hinshitsu",id_text:"Manajemen konstruksi — kualitas yang ditentukan",desc:"施工管理とは、施工計画に基づいて、施工者が、所定の【品質】の工事目的物を完成させるために必要な管理のことである。Kata kunci: 品質 (kualitas), bukan 環境 (lingkungan). (Sumber: st_sample_l Q7)"},// LISTRIK
{id:31,category:"listrik",source:"text5l",jp:"検電器",romaji:"kendenki",id_text:"Detektor tegangan",desc:"Alat untuk memeriksa apakah ada muatan listrik atau tidak. Ada untuk tegangan rendah dan tegangan tinggi."},{id:32,category:"listrik",source:"text5l",jp:"検相器",romaji:"kensou ki",id_text:"Detektor fase",desc:"Perangkat untuk memeriksa arah rotasi (urutan fase) pada sistem 3-fase."},{id:33,category:"listrik",source:"text5l",jp:"テスター / 万用計",romaji:"tesutaa / banyou kei",id_text:"Tester / Multimeter",desc:"Perangkat untuk memeriksa keadaan rangkaian listrik, voltase, dan resistansi."},{id:34,category:"listrik",source:"text5l",jp:"クランプメーター",romaji:"kuranpu meetaa",id_text:"Clamp meter",desc:"Alat ukur yang dapat mengukur arus listrik hanya dengan menjepit kabel listrik di bagian sensornya."},{id:35,category:"listrik",source:"text5l",jp:"電線管",romaji:"densenkan",id_text:"Conduit (pelindung kabel)",desc:"Pipa dari logam atau resin sintetis yang menampung kabel listrik di dalamnya. Ada pipa E, C, G, PF, CD, dll."},{id:36,category:"listrik",source:"text5l",jp:"フレキシブル管",romaji:"furekishiburu kan",id_text:"Conduit fleksibel",desc:"Conduit yang dapat ditekuk dengan bebas. Ada jenis logam dan resin sintetis (Pipa PF & CD)."},{id:37,category:"listrik",source:"text5l",jp:"プルボックス",romaji:"puru bokkusu",id_text:"Pull box",desc:"Kotak untuk menghubungkan dan mencabangkan kabel. Ada jenis logam dan resin."},{id:38,category:"listrik",source:"text5l",jp:"ケーブルラック",romaji:"keepuru rakku",id_text:"Rak kabel",desc:"Rak berbentuk tangga untuk mengelola berbagai jenis kabel sekaligus. Kait kabel digunakan jika jumlah kabel sedikit."},{id:39,category:"listrik",source:"text5l",jp:"VVFケーブル",romaji:"VVF keepuru",id_text:"Kabel VVF",desc:"Vinyl insulated Vinyl sheathed Flat-type cable. Kawat listrik berisolasi vinil berbentuk datar."},{id:40,category:"listrik",source:"text5l",jp:"圧着端子",romaji:"acchaku tanshi",id_text:"Terminal crimping",desc:"Terminal untuk menghubungkan kabel listrik ke peralatan. Dikencangkan dengan memberikan tekanan (crimping)."},{id:41,category:"listrik",source:"st_sample_l",jp:"ブレーカー（NFB）",romaji:"bureekaa (NFB)",id_text:"Pemutus arus listrik (breaker)",desc:"Otomatis menghentikan pasokan listrik saat arus berlebih mengalir di sirkuit. NFB = No-Fuse Breaker. (Sumber: st_sample_l Q1)"},{id:42,category:"listrik",source:"text5l",jp:"接地棒",romaji:"secchibou",id_text:"Batang pentanahan (grounding rod)",desc:"Batang yang didorong ke dalam tanah untuk pentanahan. Umumnya berlapis baja."},{id:43,category:"listrik",source:"text5l",jp:"ハンドホール",romaji:"hando hooru",id_text:"Handhole",desc:"Block manhole yang digunakan untuk kabel listrik dan komunikasi di bawah tanah."},{id:44,category:"listrik",source:"text5l",jp:"配電盤",romaji:"haiden ban",id_text:"Panel distribusi listrik",desc:"Perangkat untuk mencabangkan catu daya dan memasok listrik ke setiap perangkat. Ada papan mandiri dan papan dinding."},{id:103,category:"listrik",source:"st_sample_l",jp:"短絡（たんらく）",romaji:"tanraku",id_text:"Hubungan arus pendek (short circuit)",desc:"2 kabel atau lebih bersentuhan TANPA melalui beban. Berbeda dari 漏電 (arus bocor) dan 感電 (sengatan listrik). Bisa menyebabkan kebakaran. (Sumber: st_sample_l Q9)"},{id:104,category:"listrik",source:"st_sample_l",jp:"電工ナイフ",romaji:"denkou naifu",id_text:"Pisau listrik (electrician's knife)",desc:"Pisau untuk mengupas isolasi kabel. Bilah melengkung, ujung TUMPUL (mencegah merusak konduktor). Sering diuji lewat FOTO. (Sumber: st_sample_l Q2)"},// TELEKOMUNIKASI
{id:45,category:"telekomunikasi",source:"st_sample2_l",jp:"光ファイバー",romaji:"hikari faibaa",id_text:"Serat optik",desc:"Serat tipis & ringan, kapasitas transmisi besar, rugi-rugi kecil (損失が小さい), non-induktif. Kelemahan: rentan goresan & tekukan. (Sumber: st_sample2_l Q1)"},{id:46,category:"telekomunikasi",source:"text5l",jp:"光ファイバーケーブル",romaji:"hikari faibaa keepuru",id_text:"Kabel serat optik",desc:"Serat optik dibundel menjadi kabel. Berbagai jenis: 20 inti, 100 inti, 400 inti, dll."},{id:47,category:"telekomunikasi",source:"text5l",jp:"同軸ケーブル",romaji:"dojiku keepuru",id_text:"Kabel koaksial",desc:"Kabel dengan konduktor di tengah, dilindungi isolator & konduktor luar. Digunakan untuk kabel antena TV."},{id:48,category:"telekomunikasi",source:"text5l",jp:"UTPケーブル",romaji:"UTP keepuru",id_text:"Kabel UTP twisted pair",desc:"Kabel 2 konduktor yang dipilin berpasangan. Lebih murah & lembut dari koaksial. Digunakan untuk telepon atau jaringan."},{id:49,category:"telekomunikasi",source:"st_sample2_l",jp:"融着接続機",romaji:"yuuchaku setsuzoku ki",id_text:"Alat penyambung fusi serat optik",desc:"Mesin yang MELELEHKAN dan menyambungkan ujung 2 kabel serat optik. (Sumber: st_sample2_l Q3)"},{id:50,category:"telekomunikasi",source:"text5l",jp:"光コネクタ",romaji:"hikari konekuta",id_text:"Konektor optik",desc:"Bagian untuk menyambungkan kabel serat optik. Dapat dimasukkan & dilepas dengan tangan. Jenis: SC, FC, LC, MU."},{id:51,category:"telekomunikasi",source:"st_sample2_l",jp:"OTDR",romaji:"OTDR (optical time domain reflectometer)",id_text:"Alat uji pulsa optik",desc:"Mengukur panjang jalur serat optik dan mendeteksi titik abnormal (rugi-rugi sambungan, pantulan). (Sumber: st_sample2_l Q2)"},{id:52,category:"telekomunikasi",source:"text5l",jp:"ルーター",romaji:"ruutaa",id_text:"Router",desc:"Perangkat yang menghubungkan beberapa jaringan berbeda. Dapat memisahkan beberapa jaringan."},{id:53,category:"telekomunikasi",source:"text5l",jp:"スイッチングハブ",romaji:"suitchingu habu",id_text:"Switching hub",desc:"Perangkat relai jaringan yang memeriksa alamat dan mengirimkan data hanya ke perangkat yang diperlukan."},{id:109,category:"telekomunikasi",source:"st_sample2_l",jp:"融着接続 vs コネクタ接続 vs メカニカルスプライス",romaji:"yuuchaku / konekuta / mekanikaru supuraisusu",id_text:"3 metode penyambungan serat optik",desc:"①融着接続: MELELEHKAN ujung serat → permanen, rugi terkecil. ②コネクタ接続: konektor, bisa lepas-pasang. ③メカニカルスプライス: mekanis, lebih cepat dari fusion. (Sumber: st_sample2_l Q3)"},{id:113,category:"telekomunikasi",source:"st_sample2_l",jp:"管路（かんろ）",romaji:"kanro",id_text:"Sistem jalur kabel bawah tanah",desc:"Menghubungkan manhole, handhole, とう道 (terowongan), dan 引上柱 (tiang pengangkat). Kedalaman di jalan raya >0.8m. (Sumber: st_sample2_l Q11-Q12)"},{id:123,category:"telekomunikasi",source:"text5l",jp:"ファイバーカッター（光ファイバー用）",romaji:"faiibaa kattaa",id_text:"Pemotong serat optik (presisi)",desc:"Memotong serat optik secara presisi, tegak lurus sempurna agar fusion bersih. Berbeda dari ファイバーカッター untuk kain/plastik."},{id:154,category:"telekomunikasi",source:"st_sample2_l",jp:"手掘り・穴掘建柱車・探針棒（埋設物確認）",romaji:"tebori / anahori kenchuusha / tanshinbou",id_text:"Hand-digging + pole-erecting vehicle + probe rod — konfirmasi benda terpendam",desc:"Sebelum menggali lubang untuk mendirikan tiang listrik → gunakan 手掘り (gali manual) DAN 探針棒 (batang probe) untuk konfirmasi benda terpendam (埋設物). 穴掘建柱車 = kendaraan khusus penggali & pendiri tiang. (Sumber: st_sample2_l Q10)"},{id:157,category:"telekomunikasi",source:"text5l",jp:"光パワーメーター",romaji:"hikari pawaa meetaa",id_text:"Pengukur daya optik (optical power meter)",desc:"Mengukur kekuatan sinyal cahaya (daya) pada kabel serat optik. Berbeda dari OTDR yang mengukur panjang jalur & titik abnormal."},{id:159,category:"telekomunikasi",source:"text5l",jp:"共同溝（きょうどうこう）",romaji:"kyoudoukou",id_text:"Terowongan utilitas bersama (common utility duct)",desc:"Saluran bawah tanah besar yang menampung BERBAGAI jenis kabel/pipa utilitas sekaligus (listrik, komunikasi, dll). Berbeda dari 管路 (kanro) yang menghubungkan manhole satu ke lainnya."},// PIPA
{id:54,category:"pipa",source:"text5l",jp:"炭素鋼鋼管（SGP）",romaji:"tanso kou koukan (SGP)",id_text:"Pipa baja karbon (SGP)",desc:"Pipa baja untuk uap, air, minyak, gas, dan udara. Ada tabung putih (berlapis) dan tabung hitam (tanpa lapisan). Sambungan ulir untuk 15A–100A."},{id:55,category:"pipa",source:"text5l",jp:"硬質塩化ビニル管（VP/VU）",romaji:"koushitsu enka biniru kan (VP/VU)",id_text:"Pipa PVC keras (VP/VU)",desc:"VP = tebal, VU = tipis. Abu-abu. Ringan & halus. Kelemahan: rentan benturan & panas."},{id:56,category:"pipa",source:"text5l",jp:"耐衝撃性塩ビ管（HIVP）",romaji:"taishougekkisei en bi kan (HIVP)",id_text:"Pipa HIVP (PVC tahan benturan)",desc:"Pipa PVC berwarna biru tua yang tahan benturan eksternal. Digunakan di tempat benturan besar dan daerah dingin."},{id:57,category:"pipa",source:"text5l",jp:"ダクタイル鋳鉄管",romaji:"dakutairu chuutetsu kan",id_text:"Pipa besi cor ulet",desc:"Grafit berbentuk bola (球状黒鉛) → kekuatan & ketangguhan lebih tinggi dari besi cor biasa. Relatif berat. Aliran utama sejak 1955."},{id:58,category:"pipa",source:"text5l",jp:"銅管",romaji:"doukan",id_text:"Pipa tembaga",desc:"Pipa tanpa sambungan dari tembaga. Digunakan untuk pipa refrigeran AC unit indoor-outdoor."},{id:59,category:"pipa",source:"text5l",jp:"シールテープ",romaji:"shiiru teepu",id_text:"Sealant tape",desc:"Pita untuk mencegah kebocoran pada sambungan ulir pipa. Digulung searah jarum jam, menyisakan 1 ulir, ~6-7 gulungan."},{id:60,category:"pipa",source:"st_sample_l",jp:"パイプカッター",romaji:"paipu kattaa",id_text:"Pemotong pipa",desc:"Alat untuk memotong pipa baja, kuningan, tembaga. Roda pemotong menjepit dan memotong melingkar. Sering diuji lewat FOTO. (Sumber: st_sample_l Q3)"},{id:61,category:"pipa",source:"text5l",jp:"パイプレンチ（ピレン）",romaji:"paipu renchi (piren)",id_text:"Kunci pipa (piren)",desc:"Alat untuk mencengkeram pipa bulat dan memutarnya. Digunakan menyambung pipa dan sambungan."},{id:62,category:"pipa",source:"text5l",jp:"ねじ切り機",romaji:"nejikiri ki",id_text:"Mesin ulir pipa (threading machine)",desc:"Mesin untuk membuat ulir pada pipa baja. JANGAN pakai sarung tangan saat threading!"},{id:63,category:"pipa",source:"text5l",jp:"フランジ",romaji:"furanji",id_text:"Flensa",desc:"Perangkat berbentuk cincin yang dipasang di ujung pipa untuk menyambung pipa satu sama lain."},{id:64,category:"pipa",source:"text5l",jp:"スリーブ",romaji:"suriibu",id_text:"Selongsong (sleeve)",desc:"Tabung silinder dipasang pada dinding/lantai/balok untuk melewatkan pipa. Dibenamkan sebelum cor beton."},{id:65,category:"pipa",source:"text5l",jp:"エルボ",romaji:"erubo",id_text:"Siku (elbow)",desc:"Sambungan yang mengubah arah aliran pipa (biasanya 45° atau 90°)."},{id:66,category:"pipa",source:"text5l",jp:"チーズ（チー）",romaji:"chiizu (chii)",id_text:"Tee",desc:"Sambungan pipa yang bercabang menjadi tiga. Digunakan untuk membuat cabang aliran."},{id:110,category:"pipa",source:"st_sample2_l",jp:"ポリエチレン管（EF接合）",romaji:"pori echiren kan (EF setsugou)",id_text:"Pipa polietilen — sambungan EF (Electro Fusion)",desc:"Digunakan untuk pipa suplai air bersih dan pipa gas. Sambungan khas: EF接合 (Electro Fusion = fusi listrik). Berbeda dari SGP yang pakai ねじ接合. (Sumber: st_sample2_l Q8)"},{id:114,category:"pipa",source:"st_sample_l",jp:"SGP ねじ接合 → 15A～100A",romaji:"SGP neji setsugou → 15A kara 100A",id_text:"Pipa SGP — sambungan ulir untuk 15A～100A",desc:"Metode penyambungan utama SGP = ねじ接合 (sambungan ulir), digunakan untuk ukuran 15A～100A. Di atas 100A → sambungan flensa/las. (Sumber: st_sample_l Q8)"},{id:156,category:"pipa",source:"text5l",jp:"パイプ万力（ぱいぷまんりき）",romaji:"paipu manriki",id_text:"Ragum pipa (pipe vise)",desc:"Alat penjepit/penahan pipa agar tidak bergerak saat dikerjakan (disambung, dipotong, dibuat ulir). Berbeda dari パイプレンチ yang untuk memutar/menyambung pipa."},// ISOLASI
{id:67,category:"isolasi",source:"text5l",jp:"グラスウール断熱材",romaji:"gurasu uuru dannetsu zai",id_text:"Bahan isolasi wol kaca",desc:"KACA dilebur → serat tipis. Fleksibel, tahan panas, tidak mudah terbakar. Tersedia bentuk tabung, sabuk, & pelat."},{id:68,category:"isolasi",source:"text5l",jp:"ロックウール断熱材",romaji:"rokku uuru dannetsu zai",id_text:"Bahan isolasi wol batu",desc:"Basalt/andesit dilebur → serat. Ketahanan api LEBIH BAIK dari wol kaca. Juga digunakan sebagai pengisi tahan api."},{id:69,category:"isolasi",source:"text5l",jp:"発泡スチロール断熱材 / ポリスチレンフォーム",romaji:"happou suchiroru dannetsu zai",id_text:"Bahan isolasi busa polistiren",desc:"Tidak bisa digunakan pada suhu ≥70°C. Banyak digunakan pada pipa suplai air dan drainase."},{id:70,category:"isolasi",source:"text5l",jp:"冷媒管（被覆銅管）",romaji:"reibaikan (hifuku doukan)",id_text:"Pipa refrigeran (pipa tembaga berlapis)",desc:"Pipa yang membawa refrigeran antara unit indoor & outdoor AC. Ditutupi bahan isolasi termal tahan api."},{id:111,category:"isolasi",source:"st_sample2_l",jp:"グラスウール vs ロックウール — perbedaan kunci",romaji:"gurasu uuru vs rokku uuru",id_text:"Wol kaca (dari kaca) vs wol batu (dari basalt)",desc:"グラスウール: dari KACA dilebur jadi serat. ロックウール: dari BASALT/batu vulkanik, tahan api lebih baik. Ujian tanya: 'kaca dilelehkan jadi serat' → グラスウール. (Sumber: st_sample2_l Q5)"},{id:112,category:"isolasi",source:"st_sample2_l",jp:"ラッキングカバー",romaji:"rakkingu kabaa",id_text:"Penutup luar isolasi pipa (lagging cover)",desc:"Penutup finishing pada isolasi pipa yang TEREKSPOS DI LUAR RUANGAN (屋外露出). Melapisi 保温筒 dari cuaca. Untuk dalam ruangan tidak wajib. (Sumber: st_sample2_l Q7)"},{id:158,category:"isolasi",source:"text5l",jp:"けい酸カルシウム保温材",romaji:"keisan karushiumu hoon zai",id_text:"Bahan isolasi kalsium silikat",desc:"Bahan isolasi termal berbasis kalsium silikat. Digunakan untuk pipa/peralatan suhu tinggi. Bukan untuk pipa air biasa. Muncul sebagai opsi pengecoh di soal グラスウール vs ロックウール."},// PEMADAM
{id:71,category:"pemadam",source:"text5l",jp:"消火器",romaji:"shoukaiki",id_text:"Alat pemadam api (APAR)",desc:"Perangkat portabel untuk memadamkan api pada tahap awal kebakaran."},{id:72,category:"pemadam",source:"text5l",jp:"スプリンクラー設備",romaji:"supurinkuraa setsubi",id_text:"Peralatan sprinkler",desc:"Alat yang dipasang pada pipa pemadam dan memercikkan air otomatis dari plafon jika terjadi kebakaran."},{id:74,category:"pemadam",source:"st_sample_l",jp:"屋外消火栓設備",romaji:"okugai shoukaisen setsubi",id_text:"Hidran kebakaran LUAR ruangan",desc:"Dipasang di LUAR gedung. Untuk pemadaman awal & mencegah api menyebar ke bangunan berdekatan (jangkauan lantai 1-2). Sering diuji lewat FOTO. (Sumber: st_sample_l Q4)"},{id:75,category:"pemadam",source:"text5l",jp:"自動火災報知設備",romaji:"jidou kasai houchi setsubi",id_text:"Peralatan alarm kebakaran otomatis",desc:"Menerima sinyal dari detektor, memberi tahu gedung, dan melapor ke pemadam kebakaran."},{id:76,category:"pemadam",source:"text5l",jp:"粉末消火設備",romaji:"funmatsu shouka setsubi",id_text:"Peralatan pemadam api bubuk",desc:"Menggunakan bahan pemadam bubuk. Cocok untuk kebakaran minyak dan kebakaran peralatan listrik berenergi."},{id:105,category:"pemadam",source:"st_sample_l",jp:"屋外消火栓 vs 屋内消火栓 — perbedaan kunci",romaji:"okugai vs okunai shoukaisen",id_text:"Hidran LUAR vs DALAM — perbedaan kunci",desc:"屋外: di luar gedung, mencegah menyebar, lantai 1-2. 屋内: di dalam gedung, dioperasikan penghuni, No.1/No.1易/No.2. Ujian tampilkan FOTO → bedakan keduanya. (Sumber: st_sample_l Q4)"},// KESELAMATAN
{id:77,category:"keselamatan",source:"text2",jp:"安全第一",romaji:"anzen daiichi",id_text:"Keselamatan Utama (Safety First)",desc:"Prinsip dasar di lokasi konstruksi Jepang. Papan tanda 'Safety First' dipasang di setiap lokasi konstruksi."},{id:78,category:"keselamatan",source:"text2",jp:"フルハーネス型墜落制止用器具",romaji:"furu haanesugata tsuiraku seishi you kiguu",id_text:"Peralatan penahan jatuh jenis full harness",desc:"Wajib digunakan saat bekerja di ketinggian. Full harness lebih aman dari harness dada saja."},{id:79,category:"keselamatan",source:"text2",jp:"熱中症",romaji:"netchuushou",id_text:"Sengatan panas (heatstroke)",desc:"Pencegahan: tempat berteduh, air, permen garam (garam natrium), tanggap darurat di musim panas."},{id:80,category:"keselamatan",source:"text2",jp:"墜落・転落",romaji:"tsuiraku / tenraku",id_text:"Jatuh dari ketinggian / Terjatuh bergulir",desc:"Penyebab kematian TERBANYAK di konstruksi. Tahun 2021: 110 kasus dari total 288 kasus kematian."},{id:81,category:"keselamatan",source:"st_sample_l",jp:"感電",romaji:"kanden",id_text:"Sengatan listrik",desc:"Listrik mengalir melalui tubuh manusia → kejutan kuat. Kecelakaan khas pekerjaan listrik. (Sumber: st_sample_l Q13)"},{id:82,category:"keselamatan",source:"text6l",jp:"QCDSE",romaji:"kyuu shii dii esu ii",id_text:"5 Manajemen QCDSE",desc:"Q=Kualitas, C=Biaya (Cost), D=Jadwal/Waktu (Delivery), S=Keselamatan (Safety), E=Lingkungan (Environment)."},{id:83,category:"keselamatan",source:"text2",jp:"リスクアセスメント",romaji:"risuku asesumento",id_text:"Penilaian risiko",desc:"Metode untuk menemukan dan mengeliminasi potensi bahaya di tempat kerja sebelum terjadi kecelakaan."},{id:84,category:"keselamatan",source:"text6l",jp:"5M",romaji:"go emu",id_text:"5M (metode pelaksanaan)",desc:"Men (Manusia), Materials (Material), Methods (Metode), Machinery (Mesin), Money (Uang)."},{id:85,category:"keselamatan",source:"text7l",jp:"アンカーポイント",romaji:"ankaa pointo",id_text:"Titik angkur (anchor point)",desc:"Titik pengait pada struktur untuk mengaitkan peralatan penahan jatuh saat bekerja di ketinggian."},{id:107,category:"keselamatan",source:"st_sample_l",jp:"酸素欠乏（さんそけつぼう）",romaji:"sanso ketsubou",id_text:"Kekurangan oksigen — bahaya di MANHOLE",desc:"Bahaya di ruang tertutup → MANHOLE. Perlu cek kadar oksigen sebelum masuk. Kerja di atas tiang/atap gedung TIDAK termasuk risiko ini. (Sumber: st_sample_l Q14)"},{id:108,category:"keselamatan",source:"st_sample_l",jp:"土留め（どどめ）≥ 1.5m",romaji:"dodome",id_text:"Penahan tanah — WAJIB jika galian ≥ 1.5m",desc:"Mencegah longsor tanah (土砂崩れ) pada pekerjaan galian. WAJIB jika kedalaman ≥1.5m. Berbeda dari 換気 (ventilasi) dan 排水 (drainase). (Sumber: st_sample_l Q15)"},{id:119,category:"keselamatan",source:"st_sample2_l",jp:"新規入場者教育 vs 新入者安全衛生教育",romaji:"shinki nyuujousha kyouiku vs shinnyuusha anzen eisei kyouiku",id_text:"Pendidikan keselamatan: pendatang baru lokasi vs perekrutan baru perusahaan",desc:"①新規入場者教育 = untuk PENDATANG BARU ke LOKASI KERJA. ②新入者安全衛生教育 = untuk PEKERJA BARU yang baru DIREKRUT perusahaan. Keduanya wajib. (Sumber: st_sample2_l Q14)"},{id:127,category:"keselamatan",source:"st_sample_l",jp:"三大災害（さんだいさいがい）",romaji:"sandai saigai",id_text:"Tiga bencana besar konstruksi",desc:"①墜落・転落 (TERBANYAK) ②建設機械・クレーン災害 ③崩壊・倒壊. Menyumbang 40–70% kematian. (Sumber: st_sample_l Q12)"},{id:130,category:"keselamatan",source:"text6l",jp:"始業前点検（しぎょうまえてんけん）",romaji:"shigyou mae tenken",id_text:"Pemeriksaan sebelum mulai kerja",desc:"WAJIB sebelum bekerja: ①Mesin ②Alat/perkakas ③Prosedur kerja. Banyak kecelakaan terjadi saat menangani alat/mesin. (Sumber: text6l §6.1.4)"},{id:131,category:"keselamatan",source:"text7l",jp:"バックホウ（油圧ショベル）の安全",romaji:"bakkuhou no anzen",id_text:"Keselamatan backhoe / excavator",desc:"Bahaya: ①激突 — tertabrak bucket ②はさまれ — terjepit bucket. Saat naik/turun ke truk: risiko terbalik. Wajib ada 誘導員 (pemandu). (Sumber: text7l §7.1.2)"},{id:150,category:"keselamatan",source:"text4",jp:"素掘り（すぼり）",romaji:"subori",id_text:"Penggalian tanpa penahan (open cut)",desc:"Penggalian TANPA 土留め, diperbolehkan HANYA jika tanah benar-benar stabil. Berbeda dari galian ≥1.5m yang WAJIB pakai 土留め. (Sumber: text4 §4.2.3)"},{id:151,category:"keselamatan",source:"text3",jp:"ドライワーク（ウェルポイント工法）",romaji:"dorai waaku (weru pointo kouhou)",id_text:"Pekerjaan kering — metode wellpoint (max 10m)",desc:"Pipa pompa ditancapkan ke tanah, air dipompa keluar dengan pompa vakum. Kedalaman max ≈10m. Lebih dalam → ディープウェル. (Sumber: text3 §3.2.5)"},{id:155,category:"keselamatan",source:"st_sample2_l",jp:"疲労防止 — 適切な睡眠と食事",romaji:"hirou boushi — tekisetsu na suimin to shokuji",id_text:"Pencegahan kelelahan — tidur & makan yang cukup",desc:"疲労がたまると事故につながるので、【適切な睡眠と食事をとること】を心がける。Kelelahan menyebabkan kecelakaan → perhatikan tidur & makan yang cukup. (Sumber: st_sample2_l Q15)"},// KARIER
{id:86,category:"karier",source:"text1l",jp:"建設キャリアアップシステム（CCUS）",romaji:"kensetsu kyaria appu shisutemu",id_text:"Sistem Kenaikan Karier Konstruksi",desc:"4 level (putih→biru→perak→emas). Level 2 butuh ≥645 hari kerja tercatat."},{id:89,category:"karier",source:"text1l",jp:"元請（ゼネコン）",romaji:"motouri (zenekon)",id_text:"Kontraktor umum (general contractor)",desc:"Perusahaan pengatur seluruh pekerjaan konstruksi. Bertanggung jawab atas semua sub-kontraktor."},{id:90,category:"karier",source:"text1l",jp:"下請（専門工事業者）",romaji:"shitauke (senmon kouji gyousha)",id_text:"Kontraktor khusus / sub-kontraktor",desc:"Ahli dalam jenis pekerjaan tertentu. Bekerja sesuai instruksi mandor di bawah kontraktor umum."},{id:92,category:"karier",source:"text2",jp:"残業",romaji:"zangyou",id_text:"Kerja lembur",desc:"Batas max: 45 jam/bulan & 360 jam/tahun (berlaku April 2024 untuk konstruksi). Upah tambahan min. 25%."},{id:93,category:"karier",source:"text2",jp:"有給休暇",romaji:"yuukyuu kyuuka",id_text:"Cuti berbayar tahunan",desc:"Diberikan setelah bekerja 6 bulan dengan kehadiran ≥80%. Awal: 10 hari, bertambah tiap tahun, max 20 hari."},{id:101,category:"karier",source:"tt_sample",jp:"5S（整理・整頓・清掃・清潔・しつけ）",romaji:"go esu",id_text:"5S: Pilah / Tata / Bersih / Higienis / Disiplin",desc:"Seiri=Pilah, Seiton=Tata, Seisou=Bersih, Seiketsu=Higienis, Shitsuke=DISIPLIN (item ke-5, sering ditanyakan). (Sumber: tt_sample Q28)"},{id:102,category:"karier",source:"tt_sample",jp:"パワー・ハラスメント（パワハラ）",romaji:"pawaa harasumento",id_text:"Pelecehan kekuasaan (Power Harassment)",desc:"Memanfaatkan keunggulan posisi untuk memberi tekanan melebihi batas wajar. Berbeda dari セクハラ. (Sumber: tt_sample Q3)"},{id:120,category:"karier",source:"tt_sample2",jp:"資格の種類：電気工事士・工事担任者・消防設備士",romaji:"shikaku no shurui",id_text:"Kualifikasi: listrik / telekomunikasi / pemadam",desc:"①電気工事士 = LISTRIK. ②工事担任者 = TELEKOMUNIKASI. ③消防設備士 = PEMADAM KEBAKARAN. (Sumber: tt_sample Q17, tt_sample2 Q8)"},{id:122,category:"karier",source:"text2",jp:"セクシャル・ハラスメント（セクハラ）",romaji:"sekusharu harasumento",id_text:"Pelecehan seksual (Sexual Harassment)",desc:"Tindakan atau ucapan seksual yang tidak diinginkan di tempat kerja. Berbeda dari パワハラ. Keduanya dilarang."},// ALAT UMUM
{id:94,category:"alat_umum",source:"st_sample_l",jp:"水準器（レベル）",romaji:"suijunki (reberu)",id_text:"Waterpas / Level (instrumen survei)",desc:"Alat survei dengan teleskop untuk mengukur ketinggian/elevasi. Dipasang di atas tripod. Sering diuji lewat FOTO. (Sumber: st_sample_l Q6)"},{id:95,category:"alat_umum",source:"text5l",jp:"トランシット",romaji:"toranshitto",id_text:"Theodolit / Transit",desc:"Perangkat pengukur sudut vertikal & horizontal. Saat ini sering menggunakan versi digital."},{id:96,category:"alat_umum",source:"text5l",jp:"トータルステーション",romaji:"tootaru suteeshon",id_text:"Total station",desc:"Menggabungkan alat ukur gelombang cahaya dan transit elektronik. Mengukur jarak & sudut sekaligus."},{id:97,category:"alat_umum",source:"text5l",jp:"墨出し（すみだし）",romaji:"sumi dashi",id_text:"Penandaan tinta / marking",desc:"Penandaan posisi dan ketinggian struktur di lokasi konstruksi. Pekerjaan terpenting yang butuh akurasi tinggi."},{id:98,category:"alat_umum",source:"text5l",jp:"コンベックス",romaji:"konbekkusu",id_text:"Meteran pita (convex rule)",desc:"Meteran dari logam tipis. Nama resminya 'aturan konveks'. Kadang disebut 'konbe'."},{id:99,category:"alat_umum",source:"text5l",jp:"振り子・下げ振り",romaji:"furiko / sage furi",id_text:"Bandul lot (plumb bob)",desc:"Pemberat berujung kerucut untuk memeriksa tegak lurusnya tiang. Prinsip: benang dari atas, cek jarak ke permukaan."},{id:100,category:"alat_umum",source:"text5l",jp:"サンダー",romaji:"sandaa",id_text:"Sander (alat poles)",desc:"Alat listrik untuk memoles permukaan datar dengan kertas ampelas. Jenis: getar, sabuk, dan putar."},{id:106,category:"alat_umum",source:"st_sample_l",jp:"墨つぼ（すみつぼ）",romaji:"sumi tsubo",id_text:"Wadah tinta / chalk line reel",desc:"Membuat garis lurus panjang dengan menarik benang bercelup tinta. Berbeda dari: 墨さし (kuas pendek), チョーク, レーザー墨出し器. Sering diuji lewat FOTO. (Sumber: st_sample_l Q5)"},{id:145,category:"alat_umum",source:"text4",jp:"墨出し用語：陸墨・逃げ墨・地墨",romaji:"rokuzumi / nigesumi / jizumi",id_text:"Tinta horizontal / tinta geser / tinta lantai",desc:"①陸墨: garis referensi HORIZONTAL (ketinggian). ②逃げ墨: garis yang dipindah dari posisi asli karena terhalang. ③地墨: garis ditandai langsung di LANTAI. (Sumber: text4 §4.2.1)"},{id:146,category:"alat_umum",source:"text4",jp:"ベンチマーク（BM）・GL・FL",romaji:"BM / GL / FL",id_text:"BM (benchmark) · GL (ground level) · FL (floor level)",desc:"BM: titik referensi ketinggian di lokasi. GL: ketinggian permukaan tanah. FL: ketinggian lantai jadi (1FL, 2FL, ...). (Sumber: text4 §4.2.2)"},{id:147,category:"alat_umum",source:"text4",jp:"通り芯（とおりしん）・壁芯・柱芯",romaji:"toori shin / kabe shin / hashira shin",id_text:"Garis sumbu tengah — dinding dan kolom",desc:"通り芯: center line. 壁芯: center line dinding. 柱芯: center line kolom. Acuan penandaan posisi di lokasi. (Sumber: text4 §4.2.1)"},{id:342,category:"alat_umum",source:"st_sample2_l",jp:"台車（だいしゃ）",romaji:"daisha",id_text:"Kereta dorong datar (platform cart/台車)",desc:"Alat angkut berupa platform datar berkaki roda. Digunakan untuk mengangkut material/peralatan berat di lokasi konstruksi. Berbeda dari: 一輪車 (gerobak satu roda), そり (sledge), ころ (roller). Sering diuji lewat FOTO. (Sumber: st_sample2_l Q6)"},{id:160,category:"alat_umum",source:"text5l",jp:"一輪車（いちりんしゃ）",romaji:"ichirinsha",id_text:"Gerobak sorong satu roda (wheelbarrow)",desc:"Alat angkut dengan satu roda di depan dan dua gagang di belakang. Digunakan untuk mengangkut tanah, pasir, campuran beton di lokasi konstruksi. Berbeda dari 台車 (platform datar 4 roda)."},// ── KARTU BARU v10 — dari text2.pdf (gap audit) ──────────────────────────
// 🔴 PRIORITAS TINGGI (id 161–168)
{id:161,category:"hukum",source:"text2",jp:"割増賃金率（時間外・休日・深夜）",romaji:"warimashi chingin ritsu",id_text:"Tarif upah tambahan: lembur biasa +25% / libur +35% / malam +25%",desc:"3 angka wajib hafal: 通常残業 (lembur biasa) ≥25%, 休日出勤 (kerja hari libur) ≥35%, 深夜残業 (lembur malam, 22:00–05:00) ≥25%. Batas lembur: 45 jam/bulan, 360 jam/tahun (berlaku April 2024). (Sumber: text2 §2.1.1)"},{id:162,category:"hukum",source:"text2",jp:"通勤災害 vs 業務災害",romaji:"tsuukin saigai vs gyoumu saigai",id_text:"Kecelakaan perjalanan kerja vs kecelakaan di tempat kerja",desc:"通勤災害: kecelakaan saat perjalanan rumah↔tempat kerja lewat rute WAJAR. Jika pakai rute tak wajar (misal terdaftar naik bus tapi ternyata naik sepeda) → TIDAK tercakup. 業務災害: kecelakaan yang disebabkan pekerjaan itu sendiri. Keduanya tercakup 労災保険. (Sumber: text2 §2.1.4)"},{id:163,category:"karier",source:"text2",jp:"技能検定 / 技能士（ぎのうけんてい / ぎのうし）",romaji:"ginou kentei / ginoushi",id_text:"Uji keterampilan nasional / Teknisi berlisensi negara",desc:"Lulus 技能検定 → dapat 合格証書, resmi menyebut diri 技能士. Ada 5 tingkat: 特級, 1級, 2級, 3級, 基礎級 + 単一等級. Untuk bidang konstruksi: 32 jenis uji tersedia. Diatur 職業能力開発促進法. (Sumber: text2 §2.1.7)"},{id:164,category:"hukum",source:"text2",jp:"特定技能外国人の雇用保険（失業給付）",romaji:"tokutei ginou gaikokujin no koyou hoken",id_text:"SSW asing BISA dapat tunjangan pengangguran seperti WN Jepang",desc:"Jika SSW kehilangan pekerjaan: ①TIDAK wajib langsung pulang ②BISA dapat 雇用保険 基本手当 seperti WN Jepang ③Boleh tinggal selama aktif cari kerja dalam masa berlaku visa. HATI-HATI: jika >3 bulan tidak aktif cari kerja tanpa alasan → status visa bisa dicabut. (Sumber: text2 §2.1.5)"},{id:165,category:"hukum",source:"text2",jp:"雇用保険の支給要件（12ヶ月以上）",romaji:"koyou hoken no shikyuu youken",id_text:"Syarat tunjangan pengangguran: ≥12 bulan asuransi dalam 2 tahun terakhir",desc:"2 syarat wajib: ①離職し就職できない状態 (menganggur, mau & mampu bekerja). ②離職前2年間に被保険者期間が通算12ヶ月以上. Besarnya 基本手当: 45〜80% dari upah harian 6 bulan terakhir, dibayar selama 90〜360 hari. (Sumber: text2 §2.1.5)"},{id:166,category:"hukum",source:"text2",jp:"ストレスチェック（50人以上の事業場）",romaji:"sutoresu chekku",id_text:"Pemeriksaan stres — WAJIB untuk perusahaan ≥50 orang, 1x/tahun",desc:"Perusahaan ≥50 karyawan WAJIB lakukan ストレスチェック (pemeriksaan beban psikologis) setiap tahun oleh dokter/perawat. Bertujuan mencegah gangguan mental akibat kerja. Diatur 労働安全衛生法. Angka kunci: 50人以上. (Sumber: text2 §2.1.2)"},{id:167,category:"hukum",source:"text2",jp:"ドローン（無人航空機）登録義務 ≥ 100g",romaji:"doroon touroku gimu",id_text:"Drone ≥100g WAJIB didaftarkan sebagai pesawat tak berawak (航空法)",desc:"Drone berat ≥100g wajib didaftarkan. Dilarang di mana pun: terbang saat mabuk, terbang malam, terbang di luar jangkauan visual (目視外). Di konstruksi: drone sering digunakan untuk 測量 (survei). Angka kunci: 100g. (Sumber: text2 §2.16)"},{id:168,category:"hukum",source:"text2",jp:"航空障害灯（こうくうしょうがいとう）≥ 60m",romaji:"koukuu shougai tou",id_text:"Lampu peringatan penerbangan — WAJIB pada objek ≥60m dari permukaan tanah",desc:"Bangunan, crane, atau struktur setinggi ≥60m dari permukaan tanah/air WAJIB memasang 航空障害灯 (aviation obstacle light). Termasuk crane konstruksi sementara. Angka kunci: 60m. (Sumber: text2 §2.16)"},// 🟡 PRIORITAS SEDANG (id 169–173)
{id:169,category:"hukum",source:"text2",jp:"賃金支払いの5原則",romaji:"chingin shiharai no go gensoku",id_text:"5 prinsip pembayaran upah (Labor Standards Act)",desc:"①通貨で (tunai/mata uang resmi) ②直接 (langsung ke pekerja, bukan perantara) ③全額 (penuh, tidak boleh dipotong sembarangan) ④毎月1回以上 (min. 1x per bulan) ⑤一定の期日 (tanggal tetap). Semua 5 harus terpenuhi. (Sumber: text2 §2.1.1)"},{id:170,category:"hukum",source:"text2",jp:"休憩時間の規定（6時間・8時間）",romaji:"kyuukei jikan no kitei",id_text:"Aturan istirahat: kerja >6jam → 45 mnt; kerja >8jam → 1 jam",desc:"Kerja >6 jam: wajib istirahat 45 menit. Kerja >8 jam: wajib istirahat 1 jam. Diberikan DI TENGAH jam kerja (bukan awal/akhir), dan SERENTAK untuk semua pekerja (一斉に). (Sumber: text2 §2.1.1)"},{id:171,category:"hukum",source:"text2",jp:"解雇予告（かいこよこく）— 30日前",romaji:"kaiko yokoku — sanjuunichi mae",id_text:"PHK wajib diumumkan 30 hari sebelumnya",desc:"Pemberi kerja yang ingin memecat pekerja WAJIB memberi tahu 30 hari sebelumnya. Jika tidak, harus bayar upah 30 hari. Pengecualian: pekerja yang sedang SAKIT/CEDERA KARENA KERJA tidak boleh dipecat selama masa pengobatan + 30 hari setelahnya. (Sumber: text2 §2.1.1)"},{id:172,category:"hukum",source:"text2",jp:"騒音規制法・低騒音型建設機械の選択",romaji:"souon kisei hou / tei souon gata kensetsu kikai",id_text:"UU Regulasi Kebisingan — wajib pilih mesin konstruksi rendah kebisingan",desc:"Untuk mematuhi 騒音規制法: ①pilih metode kerja rendah kebisingan ②pilih mesin 低騒音型 (low-noise) ③atur jadwal & zona sumber bising ④pasang fasilitas peredam suara. Berlaku juga untuk 振動防止法 (getaran). (Sumber: text2 §2.7)"},{id:173,category:"hukum",source:"text2",jp:"電波法 — 免許が必要なトランシーバー",romaji:"denpa hou — menkyou ga hitsuyou na toranshiibaa",id_text:"UU Gelombang Radio — transceiver tertentu BUTUH izin (免許)",desc:"Penggunaan transceiver tergantung output & frekuensi — beberapa perlu 免許. Tanpa izin = ILEGAL. Transceiver impor yang belum disetujui Jepang juga ILEGAL meski legal di negara asal. Di lokasi kerja besar: wajib patuhi 電波法. (Sumber: text2 §2.15)"},// ── KARTU BARU v11 — text2.pdf LENGKAP (tutup semua gap) ─────────────────
{id:174,category:"hukum",source:"text2",jp:"労災保険の4給付（療養・休業・遺族・介護）",romaji:"rousai hoken no yon kyuufu",id_text:"4 jenis tunjangan 労災: pengobatan / istirahat / ahli waris / perawatan",desc:"①療養給付: biaya pengobatan di RS ditanggung PENUH. ②休業給付: ganti rugi upah saat tidak bisa bekerja karena sakit/cedera. ③遺族給付: uang pensiun atau uang sekaligus + biaya pemakaman kepada keluarga jika meninggal. ④介護給付: jika setelah 1 tahun 6 bulan masih cacat dan butuh perawatan. (Sumber: text2 §2.1.4)"},{id:175,category:"hukum",source:"text2",jp:"労災保険の特別加入制度（一人親方・中小企業主）",romaji:"rousai hoken tokubetsu kanyuu seido",id_text:"Skema masuk khusus 労災 untuk kontraktor mandiri & pemilik UKM",desc:"労災保険 normalnya hanya untuk karyawan. Tapi 一人親方 (kontraktor mandiri tanpa karyawan), pemilik UKM konstruksi, dan anggota keluarganya boleh masuk secara sukarela lewat 特別加入制度. (Sumber: text2 §2.1.4)"},{id:176,category:"hukum",source:"text2",jp:"建設労働者雇用改善法（第10次計画）",romaji:"kensetsu roudousha koyou kaizen hou",id_text:"UU Peningkatan Ketenagakerjaan Konstruksi — Rencana ke-10 (2021–2025)",desc:"Rencana ke-10 (2021–2025) menargetkan: ①rekrut & kembangkan pekerja muda ②CCUS (建設キャリアアップシステム) ③batas lembur April 2024 ④フルハーネス型 wajib untuk ketinggian ⑤penerimaan tenaga asing termasuk 特定技能. (Sumber: text2 §2.1.6)"},{id:177,category:"hukum",source:"text2",jp:"駐車場法（ちゅうしゃじょうほう）",romaji:"chuushajou hou",id_text:"UU Perparkiran — wajib lapor sebelum mulai konstruksi parkir",desc:"Mengatur pembangunan fasilitas parkir di perkotaan demi kelancaran lalu lintas. Jika ingin membangun/memodifikasi fasilitas parkir → wajib lapor ke pemerintah daerah (自治体) SEBELUM pekerjaan dimulai. (Sumber: text2 §2.17)"},{id:178,category:"hukum",source:"text2",jp:"水質汚濁防止法 — 高アルカリ排水の中和処理",romaji:"suishitsu odaku boushi hou — koua arukari haisui no chuuwa shori",id_text:"UU Pencemaran Air — air sisa beton (pH tinggi) WAJIB dinetralkan dulu",desc:"Air yang melewati beton → 高アルカリ排水 (air pH sangat tinggi). Tidak boleh langsung dibuang ke saluran/sungai. Wajib dilakukan 中和処理 (netralisasi) menggunakan gas CO₂ atau bahan kimia sebelum dibuang. (Sumber: text2 §2.8)"},{id:179,category:"hukum",source:"text2",jp:"賠償予定の禁止（ばいしょうよていのきんし）",romaji:"baishou yotei no kinshi",id_text:"Dilarang menetapkan denda/ganti rugi di muka dalam kontrak kerja",desc:"Pemberi kerja DILARANG menetapkan denda pemutusan kontrak atau jumlah ganti rugi di muka dalam perjanjian kerja. Contoh ilegal: 'jika kamu berhenti sebelum 1 tahun, bayar denda ¥500,000'. Diatur 労働基準法. (Sumber: text2 §2.1.1)"},{id:180,category:"hukum",source:"text2",jp:"機会均等の原則 / 強制労働の禁止",romaji:"kikai kintou no gensoku / kyousei roudou no kinshi",id_text:"Non-diskriminasi nasionalitas/agama/status + dilarang kerja paksa",desc:"①機会均等: pemberi kerja DILARANG membeda-bedakan upah/kondisi kerja berdasarkan 国籍 (kebangsaan), 信条 (kepercayaan), 社会的身分 (status sosial). ②強制労働の禁止: dilarang memaksa bekerja dengan kekerasan, ancaman, atau perampasan kebebasan. (Sumber: text2 §2.1.1)"},{id:181,category:"hukum",source:"text2",jp:"解雇制限 — 傷病療養中は解雇禁止",romaji:"kaiko seigen — shoubyou ryouyouchuu wa kaiko kinshi",id_text:"Dilarang memecat pekerja yang sedang sakit/cedera karena kerja + 30 hari setelah sembuh",desc:"Pekerja yang cedera/sakit KARENA PEKERJAAN dan sedang dalam masa pengobatan (休業中) TIDAK BOLEH dipecat. Larangan ini berlaku selama masa pengobatan + 30 hari setelah kembali bekerja. Berbeda dari 解雇予告 (kartu #171) yang mengatur prosedur PHK biasa. (Sumber: text2 §2.1.1)"},{id:182,category:"hukum",source:"text2",jp:"労働条件の明示 — 6項目",romaji:"roudou jouken no meiji — roku koumon",id_text:"6 hal wajib diberitahu pemberi kerja saat rekrut",desc:"①期間 (durasi kontrak) ②更新基準 (kriteria perpanjangan jika ada batas waktu) ③就業場所・業務内容 (lokasi & jenis kerja) ④労働時間・残業・休憩・休日・休暇 (jam, lembur, istirahat, libur, cuti) ⑤賃金の決定・支払・締日・昇給 (upah, cara bayar, tanggal potong, kenaikan) ⑥退職・解雇 (resign & PHK). (Sumber: text2 §2.1.1)"},{id:183,category:"hukum",source:"text2",jp:"地域別最低賃金（ちいきべつさいていちんぎん）",romaji:"chiiki betsu saitei chingin",id_text:"Upah minimum berbeda per prefektur (都道府県単位)",desc:"Upah minimum ditetapkan per 都道府県 (prefektur) karena perbedaan biaya hidup & standar upah tiap daerah. Berlaku untuk SEMUA pekerja di area tersebut, tanpa membedakan jenis kontrak atau profesi. Diumumkan di 官報 dan situs dinas tenaga kerja prefektur. (Sumber: text2 §2.1.3)"},{id:184,category:"karier",source:"text2",jp:"認定訓練（にんていくんれん）",romaji:"nintei kunren",id_text:"Pelatihan vokasi yang diakui gubernur prefektur",desc:"Pelatihan yang memenuhi standar UU dan dilaksanakan oleh pihak swasta (民間事業主等), kemudian diakui resmi oleh 都道府県知事. Berbeda dari 職業訓練 yang diselenggarakan pemerintah langsung. Diatur 職業能力開発促進法. (Sumber: text2 §2.1.7)"},// ── KARTU BARU v12 — text2.pdf FINAL (3 gap terakhir) ────────────────────
{id:185,category:"hukum",source:"text2",jp:"法定休日 — 毎週少なくとも1回",romaji:"houtei kyuujitsu — maishuu sukunakutomo ikkai",id_text:"Hari libur wajib: minimal 1 hari per minggu",desc:"Pemberi kerja WAJIB memberikan setidaknya 1 hari libur per minggu kepada setiap pekerja. Ini adalah 法定休日 (hari libur yang ditetapkan UU). Jika bekerja di hari ini → 休日出勤 → upah +35%. Diatur 労働基準法. (Sumber: text2 §2.1.1)"},{id:186,category:"hukum",source:"text2",jp:"有給休暇の買い取り禁止",romaji:"yuukyuu kyuuka no kaitori kinshi",id_text:"Dilarang membeli/mengkonversi cuti berbayar menjadi uang",desc:"Jika pekerja tidak menggunakan 有給休暇, pemberi kerja TIDAK BOLEH membeli/menebusnya dengan uang (買い取り). Ini melanggar 労働基準法. Cuti berbayar harus digunakan sebagai waktu istirahat, bukan sebagai bonus uang. (Sumber: text2 §2.1.1)"},{id:187,category:"hukum",source:"text2",jp:"健康診断 — 定期（年1回）と雇い入れ時",romaji:"kenkou shindan — teiki nen ikkai to yatoiire ji",id_text:"Pemeriksaan kesehatan: wajib setahun sekali + saat rekrut baru",desc:"Perusahaan WAJIB menyelenggarakan: ①定期健康診断 (pemeriksaan rutin) 1x per tahun untuk semua karyawan, ②雇い入れ時の健康診断 saat merekrut pekerja baru. Diatur 労働安全衛生法. Angka kunci: 年1回. (Sumber: text2 §2.1.2)"},// ── KARTU BARU v13 — text3.pdf (Agent A) ──────────────────────────────────
{id:188,category:"jenis_kerja",source:"text3",jp:"治水（ちすい）vs 利水（りすい）",romaji:"chisui vs risui",id_text:"Pengendalian banjir vs Pemanfaatan air",desc:"Dua tujuan utama bendungan (ダム). Chisui = menampung air saat hujan lebat agar sungai tidak meluap. Risui = menyediakan air stabil untuk pertanian, industri, dan PLTA. (Sumber: text3 §3.1.1)"},{id:189,category:"jenis_kerja",source:"text3",jp:"NATM（ナトム）工法",romaji:"NATM natomu kouhou",id_text:"Metode terowongan gunung / New Austrian Tunnelling Method",desc:"Metode penggalian terowongan gunung dengan cara: mengebor/meledakkan batuan, lalu menyemprotkan beton (吹付けコンクリート), memasang penopang baja (鋼製支保工), dan rock bolt untuk menopang dinding terowongan. (Sumber: text3 §3.1.1)"},{id:190,category:"jenis_kerja",source:"text3",jp:"シールドトンネル・セグメント",romaji:"shiirudo tonneru segumento",id_text:"Terowongan shield / segmen beton/baja",desc:"Shield machine menggali dari shaft vertikal (立坑), lalu panel beton atau besi bernama segmen dipasang di belakang mesin untuk membentuk dinding terowongan. Cocok untuk tanah lunak dan lokasi dengan bangunan di atasnya. (Sumber: text3 §3.1.1)"},{id:191,category:"jenis_kerja",source:"text3",jp:"推進トンネル（すいしんトンネル）",romaji:"suishin tonneru",id_text:"Terowongan jack-push / pipe jacking",desc:"Pipa prefabrikasi (コンクリート管・ダクタイル管・鋼管) didorong masuk ke tanah oleh jack dari shaft peluncur. Digunakan untuk infrastruktur perkotaan seperti saluran air, gas, listrik, dan komunikasi. (Sumber: text3 §3.1.1)"},{id:192,category:"jenis_kerja",source:"text3",jp:"橋梁工事の下部工 vs 上部工（きょうりょうこうじ）",romaji:"kyouryou kouji kabukou vs joubukou",id_text:"Pekerjaan jembatan: struktur bawah vs struktur atas",desc:"下部工 = pekerjaan pondasi yang menopang jembatan. 上部工 = pekerjaan badan jembatan yang dilalui kendaraan dan pejalan kaki. Metode ereksi: bent, cable erection, launching, traveller crane, floating crane. (Sumber: text3 §3.1.1)"},{id:193,category:"jenis_kerja",source:"text3",jp:"海洋土木工事（かいようどぼく）",romaji:"kaiyou doboku kouji",id_text:"Pekerjaan sipil laut / offshore civil work",desc:"Pembangunan pelabuhan, bandara, terowongan bawah laut, jembatan laut, dan turbin angin di laut. Menggunakan kapal kerja (作業船) untuk mengeruk atau mengangkat material, serta penyelam (潜水士). (Sumber: text3 §3.1.1)"},{id:194,category:"jenis_kerja",source:"text3",jp:"浚渫工事（しゅんせつ）",romaji:"shunsetsu kouji",id_text:"Pengerukan dasar laut/sungai",desc:"Mengangkat lumpur dan pasir dari dasar laut atau sungai menggunakan kapal keruk (浚渫船) agar kapal dapat berlayar dengan aman di jalur pelayaran dan sandar di pelabuhan. (Sumber: text3 §3.2.3)"},{id:195,category:"jenis_kerja",source:"text3",jp:"ケーソン（防波堤工事）",romaji:"keeson",id_text:"Caisson / kotak beton untuk pemecah gelombang",desc:"Kotak beton besar yang diletakkan di atas hamparan batu di dasar laut, lalu diisi pasir/kerikil untuk menstabilkan. Digunakan dalam pembuatan pemecah gelombang (防波堤). (Sumber: text3 §3.2.3)"},{id:196,category:"jenis_kerja",source:"text3",jp:"建築物の構造種類（RC・S・SRC・木造・CB造）",romaji:"kenchikubutsu no kouzou shurui",id_text:"Jenis struktur bangunan: RC, S, SRC, kayu, blok beton",desc:"RC造=tulangan+beton, S造=kolom/balok baja, SRC造=kombinasi baja+tulangan+beton (paling kuat), 木造=kayu (rumah biasa), CB造=blok beton dengan tulangan dan mortar. (Sumber: text3 §3.1.2)"},{id:197,category:"jenis_kerja",source:"text3",jp:"ボーリング調査・支持層（しじそう）",romaji:"booringu chousa shijisou",id_text:"Penyelidikan tanah / lapisan pendukung pondasi",desc:"Sebelum membangun gedung, dilakukan pengeboran tanah (ボーリング調査) untuk menemukan lapisan tanah keras (支持層) tempat ujung tiang pondasi (杭) harus mencapai. Juga mengecek rintangan bawah tanah dan situs arkeologi. (Sumber: text3 §3.1.2)"},{id:198,category:"jenis_kerja",source:"text3",jp:"山留め工事（やまどめ）・支保工（しほこう）",romaji:"yamadome kouji shihokou",id_text:"Pekerjaan penahan tanah / shoring",desc:"Dinding sementara dibuat di dalam tanah untuk mencegah longsor saat penggalian. Dinding ini diperkuat dengan strutting (支保工). Catatan angka: 土留め wajib dipasang jika galian ≥1.5m (規則 LAB安全衛生規則); pada galian ≥2m diperlukan pengawasan ketat tambahan (山留め工事 sesuai regulasi keselamatan). Keduanya benar untuk konteks berbeda. (Sumber: text3 §3.1.2)"},{id:199,category:"jenis_kerja",source:"text3",jp:"杭工事 — 場所打ち杭 vs 既成杭（くいこうじ）",romaji:"kui kouji basho uchi kui vs kisei kui",id_text:"Pekerjaan tiang: cast-in-place vs precast",desc:"場所打ち杭 = lubang digali di lapangan, diisi rangka tulangan lalu dicor beton di tempat. 既成杭 = tiang dibuat di pabrik (beton/baja/kayu) lalu dipancang atau ditanam di lapangan. Jika bising, metode tanam lebih diutamakan. (Sumber: text3 §3.1.2 & §3.2.8)"},{id:200,category:"jenis_kerja",source:"text3",jp:"耐震・制振・免振（たいしん・せいしん・めんしん）",romaji:"taishin seishin menshin",id_text:"Tahan gempa / kontrol getaran / isolasi gempa",desc:"耐震 = kolom/balok dibuat kokoh untuk menahan guncangan. 制振 = damper dipasang di bangunan untuk menyerap energi getaran. 免振 = isolator + damper di fondasi agar energi gempa tidak tersalur ke bangunan. (Sumber: text3 §3.1.2)"},{id:201,category:"jenis_kerja",source:"text3",jp:"根切り（ねぎり）",romaji:"negiri",id_text:"Galian pondasi bangunan",desc:"Penggalian tanah di lokasi pondasi bangunan agar struktur bawah tanah bisa dibangun. Berbeda dari galian umum — 根切り spesifik untuk menanam fondasi gedung. (Sumber: text3 §3.2.1)"},{id:202,category:"keselamatan",source:"text3",jp:"発破（はっぱ）",romaji:"happa",id_text:"Peledakan / blasting",desc:"Peledakan batu menggunakan bahan peledak (火薬類) dalam pekerjaan tambang, terowongan, atau galian batu. Untuk mengerjakan peledakan, wajib memiliki lisensi 発破技士. (Sumber: text3 §3.2.1 & §3.3.2)"},{id:203,category:"jenis_kerja",source:"text3",jp:"盛り土（もりど）vs 切り土（きりど）",romaji:"morido vs kirido",id_text:"Penimbunan vs penggalian untuk meratakan lahan",desc:"盛り土 = tanah ditimbun pada lahan miring atau tidak rata agar menjadi datar. 切り土 = tanah dipotong/digali agar permukaan menjadi rata. Keduanya adalah bagian dari pekerjaan tanah (土工作業). (Sumber: text3 §3.2.1)"},{id:204,category:"jenis_kerja",source:"text3",jp:"埋め戻し作業（うめもどし）",romaji:"umemodoshi sagyou",id_text:"Pekerjaan pengurugan kembali",desc:"Setelah pekerjaan bawah tanah atau fondasi selesai, ruang kosong di sekitar struktur ditimbun kembali dengan tanah. Ini adalah tahap akhir dari pekerjaan galian. (Sumber: text3 §3.2.1)"},{id:205,category:"jenis_kerja",source:"text3",jp:"さく井工事の4種類（水源・観測・温泉・地熱）",romaji:"sakusei kouji 4 shurui",id_text:"4 jenis pekerjaan pengeboran sumur",desc:"4 jenis: ①水源井 = borlog sumur air tanah (alat: ボーリングマシン; perlu survei kualitas air + dampak ke sekitar). ②観測井 = sumur pemantau 地盤沈下 (penurunan tanah). ③温泉井 = bor 500〜1000m untuk air panas; risiko gas alam keluar → perlu beberapa izin. ④地熱井 = bor ±2000m untuk geothermal (地熱発電); risiko air panas, uap, zat berbahaya → butuh keahlian tinggi. (Sumber: text3 §3.2.4, text3l §3.2.4)"},{id:206,category:"jenis_kerja",source:"text3",jp:"ディープウェル（深井戸排水）",romaji:"diipu ueru",id_text:"Deep well dewatering / drainase sumur dalam",desc:"Metode pemompaan air tanah untuk galian di kedalaman >10m. Berbeda dari wellpoint (id:151) yang hanya efektif hingga ~10m. Untuk air tanah sangat dalam, ディープウェル adalah solusinya. (Sumber: text3 §3.2.5)"},{id:207,category:"jenis_kerja",source:"text3",jp:"とび工事の種類（足場・鉄骨・橋梁・重量・送電・町場）",romaji:"tobi kouji no shurui",id_text:"Jenis pekerjaan tobi / rigger-scaffolder",desc:"足場とび=memasang perancah, 鉄骨とび=merakit rangka baja gedung tinggi, 橋梁とび=jembatan/menara, 重量とび=memindahkan mesin ratusan ton, 送電とbi=kabel listrik tegangan tinggi di menara, 町場とび=perancah rumah/apartemen. (Sumber: text3 §3.2.9)"},{id:208,category:"jenis_kerja",source:"text3",jp:"鉄筋継手工事の4種類（てっきんつぎて）",romaji:"tekkin tsugite kouji 4 shurui",id_text:"4 metode penyambungan tulangan baja",desc:"①ガス圧接 = dipanaskan + ditekan (paling umum). ②溶接継手 = arc welding untuk diameter besar. ③機械式継手 = penyambung berulir (coupler). ④重ね接手 = ditumpuk lalu disatukan dengan beton (untuk tulangan tipis). (Sumber: text3 §3.2.12)"},{id:209,category:"jenis_kerja",source:"text3",jp:"溶接の3分類（融接・圧接・ろう接）",romaji:"yousetsu 3 bunrui: yuusetsu assetsu rousetsu",id_text:"3 kategori pengelasan: fusion / pressure / brazing",desc:"融接 = material dilelehkan (arc, gas, laser) — paling umum, cepat, tapi kualitas tergantung skill. 圧接 = dipanaskan + ditekan tanpa sampai cair (= 固相接合), contoh: ガス圧接 tulangan. ろう接 = logam penghubung bersuhu leleh rendah dipakai sebagai 'lem'. (Sumber: text3 §3.2.13)"},{id:210,category:"jenis_kerja",source:"text3",jp:"型枠工事・支保工（かたわく・しほこう）",romaji:"katawaku kouji shihokou",id_text:"Pekerjaan bekisting dan penopangnya",desc:"Cetakan kayu (型枠) dibuat melingkupi tulangan, lalu beton dicor ke dalamnya. Tekanan dari dalam sangat besar, sehingga bekisting diperkuat dengan pipa baja dari luar (支保工). Setelah beton mengeras dan kuat, bekisting dibongkar dan dipakai ulang di lantai atas. (Sumber: text3 §3.2.14)"},{id:211,category:"jenis_kerja",source:"text3",jp:"レディミクスドコンクリート（生コン）・コンクリート圧送",romaji:"redimikusudo konkuriito namakon assou",id_text:"Ready-mix concrete dan pemompaan beton",desc:"Beton yang sudah dikontrol kualitasnya di pabrik disebut レディミクスドコンクリート (生コン), dikirim via truk molen (トラックアジテータ), lalu dipompa ke bekisting menggunakan コンクリートポンプ車. (Sumber: text3 §3.2.15)"},{id:212,category:"alat_umum",source:"text3",jp:"バイブレータ（コンクリート締固め）",romaji:"baibureeta konkuriito shimekatame",id_text:"Vibrator untuk pemadatan beton",desc:"Alat getar yang dimasukkan ke dalam beton segar untuk menghilangkan gelembung udara (気泡) dan memastikan beton mengisi sudut-sudut bekisting. Proses ini disebut 締固め dan penting untuk mencegah penurunan kekuatan beton. (Sumber: text3 §3.2.15)"},{id:213,category:"jenis_kerja",source:"text3",jp:"左官工事（さかん）— 壁土・漆喰・モルタル",romaji:"sakan kouji kabetsuchi shikkui morutaru",id_text:"Pekerjaan plesteran tradisional Jepang",desc:"Menggunakan alat 'kote' (roskam) untuk mengoleskan material seperti 壁土 (tanah liat), 漆喰 (plester kapur — tradisional Jepang), dan モルタル ke dinding atau lantai. Berbeda dari painting (塗装工事) — alatnya berbeda. (Sumber: text3 §3.2.18)"},{id:214,category:"jenis_kerja",source:"text3",jp:"防水工事の5種類（ウレタン・FRP・シート・アスファルト・シーリング）",romaji:"bousui kouji 5 shurui",id_text:"5 jenis pekerjaan waterproofing",desc:"①ウレタン = cairan dioles, cocok untuk bentuk rumit (ベランダ・屋上・雨漏り補修). ②FRP = bentangkan serat kaca + resin polyester, kuat dan cepat kering. ③シート = tempel lembaran karet/plastik dengan lem, efisien untuk area luas. ④アスファルト = tempel lembaran aspal ke dasar (oleskan プライマー dulu). ⑤シーリング = isi celah sambungan antar material dengan sealant (oleskan プライマー dulu, lalu injeksi). (Sumber: text3 §3.2.28, text3l §3.2.28)"},{id:216,category:"jenis_kerja",source:"text3",jp:"宮大工（みやだいく）",romaji:"miyadaiku",id_text:"Tukang kayu kuil/shrine / master carpenter tradisional",desc:"Spesialis membangun dan merenovasi kuil (お寺) dan shrine (神社). Membutuhkan pengetahuan mendalam tentang jenis kayu dan teknik sambungan kayu tradisional agar bangunan dapat bertahan ratusan tahun dari angin dan hujan. (Sumber: text3 §3.2.19)"},{id:217,category:"jenis_kerja",source:"text3",jp:"雨仕舞（あまじまい）",romaji:"amajimai",id_text:"Penanganan air hujan / rain detailing",desc:"Pengetahuan dan teknik konstruksi untuk mencegah air hujan masuk ke dalam bangunan melalui atap dan sambungan material. Merupakan kompetensi wajib dalam pekerjaan atap (屋根工事) dan panel baja (建築板金工事). (Sumber: text3 §3.2.20 & §3.2.21)"},{id:218,category:"jenis_kerja",source:"text3",jp:"外線工事 vs 内線工事（がいせん・ないせん）",romaji:"gaisen kouji vs naisen kouji",id_text:"Instalasi listrik luar gedung vs dalam gedung",desc:"外線工事 = menghubungkan tiang listrik/kabel bawah tanah ke gedung (架空配線 atau 地中配線). 内線工事 = seluruh pekerjaan listrik di dalam gedung: grounding, panel, daya, pencahayaan, stop kontak, AC. Untuk gedung besar, butuh lisensi 電気工事士一種. (Sumber: text3 §3.2.30)"},{id:219,category:"keselamatan",source:"text3",jp:"玉掛け（たまがけ）— 1t以上は技能講習",romaji:"tamagake 1t ijou wa ginou koushuu",id_text:"Rigging (pengikatan beban crane) — ≥1t wajib teknik",desc:"玉掛け = mengikat atau menggantungkan beban ke kait crane. Beban ≥1t wajib memiliki sertifikat 技能講習修了者. Beban <1t cukup 特別教育修了者. Kesalahan rigging bisa menyebabkan beban jatuh dan kecelakaan fatal. (Sumber: text3 §3.3.2)"},{id:220,category:"hukum",source:"text3",jp:"資格の3種類：国家免許・技能講習・特別教育",romaji:"shikaku 3 shurui: kokka menkyo ginou koushuu tokubetsu kyouiku",id_text:"3 jenis kualifikasi keselamatan kerja di konstruksi Jepang",desc:"①国家免許 = lisensi negara (misal: クレーン運転士, 発破技士, 潜水士). ②技能講習修了証 = lulus pelatihan keahlian terdaftar. ③特別教育 = pelatihan khusus internal/eksternal wajib sebelum mengerjakan tugas berbahaya. (Sumber: text3 §3.3.1)"},{id:221,category:"hukum",source:"text3",jp:"発破技士免許（はっぱぎし）",romaji:"happa gishi menkyo",id_text:"Lisensi juru peledak / blaster license",desc:"Untuk melakukan peledakan (発破) di lapangan konstruksi atau tambang batu, wajib memiliki lisensi negara 発破技士. Lingkup tugasnya: pengeboran lubang, pemasangan bahan peledak, penyambungan kawat, penyalaan, serta pengecekan dan penanganan gagal ledak (不発). (Sumber: text3 §3.3.2)"},{id:222,category:"jenis_kerja",source:"text3",jp:"解体工事（かいたい）— アスベスト対策",romaji:"kaitai kouji asbesuto taisaku",id_text:"Pekerjaan pembongkaran bangunan + penanganan asbes",desc:"Membongkar bangunan tua mencakup struktur atas dan bawah tanah. Sebelum mulai, wajib survei asbes (石綿); jika ditemukan, dibongkar dengan prosedur khusus agar tidak terhirup. Limbah bongkaran (解体ガラ) dipilah: beton, besi, dan material berbahaya dibuang terpisah. (Sumber: text3 §3.2.38)"},{id:223,category:"jenis_kerja",source:"text3",jp:"塗装工事の3方法（はけ・ローラー・エアスプレー）",romaji:"tosou kouji 3 houhou: hake rooraa easupuree",id_text:"3 metode pengecatan: kuas / roller / semprotan udara",desc:"①はけ塗り = kuas, sesuai bentuk apapun, hasil paling rapi. ②ローラー塗り = roller busa, efisien untuk bidang luas (dinding luar) tapi hasil kurang rapi. ③エアスプレー塗装 = cat dikabutkan dengan kompresor, dipakai untuk permukaan luas atau bidang sulit. (Sumber: text3 §3.2.16)"},{id:224,category:"jenis_kerja",source:"text3",jp:"造園工事の5種類（植栽・屋上緑化・広場・公園設備・緑地育成）",romaji:"zooen kouji 5 shurui",id_text:"5 jenis pekerjaan taman/lansekap",desc:"造園 = lanskap dengan pohon, tanaman, batu — butuh ilmu konstruksi + ilmu tanaman + selera estetika. ①植栽工事 = menanam pohon di area sekitar gedung (外構). ②屋上緑化 = menghijaukan atap/dinding gedung. ③広場工事 = taman berumput/lapangan olahraga. ④公園設備 = bedengan bunga, gazebo, air mancur (噴水), jalur pejalan kaki. ⑤緑地育成 = perbaikan tanah + pasang penyangga pohon (支柱) untuk rawat pertumbuhan. (Sumber: text3 §3.2.17, text3l §3.2.17)"},{id:225,category:"jenis_kerja",source:"text3",jp:"軽天工事（けいてん）・LGS・ボード貼り・クロス貼り",romaji:"keiten kouji LGS boodo hari kurosu hari",id_text:"Pekerjaan rangka plafon ringan + papan gypsum + wallpaper",desc:"LGS (Light Gauge Steel / スタッド) dipakai untuk rangka dinding dan plafon → disebut 軽天工事. Di atasnya ditempel papan gypsum (ボード貼り), sambungan dirapikan dengan dempul (パテ), lalu dilapisi wallpaper (クロス貼り). (Sumber: text3 §3.2.23)"},{id:226,category:"jenis_kerja",source:"text3",jp:"カバー工法（サッシ改修）",romaji:"kabaa kouhou sashi kaishuu",id_text:"Metode cover — renovasi kusen tanpa bongkar rangka lama",desc:"Saat merenovasi kusen (枠) jendela di apartemen, mengganti rangka lama membutuhkan kerja tukang kayu, plester, dan cat → mahal dan lama. カバー工法 = pasang rangka baru DI ATAS rangka lama tanpa membongkar, lalu pasang sash baru. Hemat waktu dan biaya. (Sumber: text3 §3.2.26)"},{id:227,category:"keselamatan",source:"text3",jp:"タイル張り工事 — 落下リスクと他職種連携",romaji:"tairu hari kouji rakka risuku ta-shokushu renkei",id_text:"Pemasangan ubin — risiko jatuh + koordinasi lintas profesi",desc:"Ubin yang jatuh dari gedung tinggi berpotensi fatal (命に関わる). Wajib punya skill teknis agar ubin tidak lepas, bukan sekadar rapi. Juga wajib koordinasi dengan pekerjaan pipa (配管) dan listrik (電気): jika saluran pipa tidak diperhitungkan sebelum ubin dipasang, pekerjaan pipa jadi terhambat. (Sumber: text3 §3.2.22)"},{id:228,category:"jenis_kerja",source:"text3",jp:"石工事 — 大理石・御影石・擬石",romaji:"ishi kouji dairiishi mikageishi giishi",id_text:"Pekerjaan batu: marmer, granit, batu artifisial",desc:"Memasang batu alam (大理石=marmer, 御影石=granit) atau buatan (擬石=batu tiruan, コンクリートブロック) pada bangunan. Tidak mempengaruhi struktur, tapi memberi kesan mewah. Batu yang retak/pecah saat proses = tidak bisa dipakai, jadi tidak boleh ada kesalahan. (Sumber: text3 §3.2.29)"},{id:229,category:"jenis_kerja",source:"text3",jp:"開削トンネル（かいさくトンネル）",romaji:"kaisaku tonneru",id_text:"Cut-and-cover tunnel / terowongan gali-tutup",desc:"Tanah digali dari permukaan dengan dinding penahan (土留め支保工), lalu terowongan dibangun di dalam galian tersebut. Setelah selesai, bagian di luar terowongan ditimbun kembali. Berbeda dari shield tunnel yang menggali horizontal dari dalam. (Sumber: text3 §3.1.1)"},{id:230,category:"jenis_kerja",source:"text3",jp:"法面工事（のりめん）— モルタル吹付け・植生工法",romaji:"norimenkouji morutaru fukitsuke shokusei kouhou",id_text:"Perkuatan lereng: semprotan mortar & revegetasi",desc:"Lereng galian/timbunan (法面) rentan longsor. ①モルタル吹付け = mortar disemprotkan ke lereng untuk stabilisasi. ②植生工法 = mat berisi benih+pupuk+media tumbuh ditempel ke lereng agar tanaman tumbuh dan menahan tanah. (Sumber: text3 §3.2.1)"},{id:231,category:"jenis_kerja",source:"text3",jp:"河川・海岸の構造物（防波堤・防潮堤・護岸・堤防・水路）",romaji:"kasen kaigan kouzoubutsu: bouhatei bouchoutei gogan teibou suiro",id_text:"Struktur sungai & pantai: pemecah gelombang/pasang, turap, tanggul, saluran",desc:"防波堤=memecah gelombang di pelabuhan. 防潮堤=menahan pasang tinggi dan tsunami. 護岸=turap tepi sungai/pantai agar tidak longsor. 堤防=tanggul banjir tepi sungai. 水路=saluran irigasi/drainase. Semua bagian dari 河川・海岸工事. (Sumber: text3 §3.1.1)"},{id:232,category:"jenis_kerja",source:"text3",jp:"鉄道工事（てつどう）— 多職種集約工事",romaji:"tetsudou kouji ta-shokushu shuuyaku kouji",id_text:"Pekerjaan rel kereta — gabungan hampir semua keahlian konstruksi",desc:"Pekerjaan kereta bukan sekadar sipil. Mencakup hampir SEMUA jenis pekerjaan konstruksi: 土木工事 + 電気設備工事 + 建築工事 + berbagai pekerjaan spesialis. Ini yang membuat kereta menjadi proyek paling kompleks dalam dunia konstruksi. (Sumber: text3 §3.1.1)"},{id:233,category:"jenis_kerja",source:"text3",jp:"上下水道工事 — 浄水場・下水処理場",romaji:"jouge suidou kouji jousui jou gesui shori jou",id_text:"Instalasi air bersih & air kotor: water treatment & sewage plant",desc:"上水道: air sungai → 浄水場 (water treatment plant) → reservoir → jaringan pipa ke rumah. 下水道: air kotor dari gedung → 下水処理場 (sewage treatment plant) → air bersih → sungai/laut. Termasuk pekerjaan lahan (敷地造成) dan instalasi pipa. (Sumber: text3 §3.1.1)"},{id:234,category:"jenis_kerja",source:"text3",jp:"災害復旧工事（さいがいふっきゅう）",romaji:"saigai fukkyuu kouji",id_text:"Pekerjaan pemulihan bencana",desc:"Setiap tahun Jepang mengalami kerusakan infrastruktur akibat topan, hujan lebat, dan gempa. 災害復旧工事 = memperbaiki fasilitas sipil yang rusak (sungai, pantai, penahan longsor, jalan, pelabuhan, air bersih/kotor) dengan cepat. (Sumber: text3 §3.1.1)"},{id:235,category:"hukum",source:"text3",jp:"クレーン・移動式クレーン資格の閾値（5t・1t境界）",romaji:"kureen idoushiki kureen shikaku shikii 5t 1t",id_text:"Ambang batas lisensi crane: 5t dan 1t",desc:"クレーン/デリック: ≥5t→免許 (クレーン運転士). 移動式クレーン: ≥5t→免許, 1-5t→技能講習または免許, <1t→特別教育. 玉掛け: ≥1t→技能講習, <1t→特別教育. Angka kunci: 5t と 1t. (Sumber: text3 §3.3.2)"},{id:236,category:"hukum",source:"text3",jp:"高所作業車の資格境界 — 10m",romaji:"kousho sagyousha shikaku kyoukai 10m",id_text:"Kendaraan kerja ketinggian: ≥10m → teknik, <10m → pendidikan khusus",desc:"作業床の高さ ≥10m → 技能講習修了者が必要. 作業床の高さ <10m → 特別教育修了者で可. Angka kunci: 10m が境界. Keduanya mengecualikan운転 di jalan raya (道路上の走行運転を除く). (Sumber: text3 §3.3.2)"},{id:237,category:"hukum",source:"text3",jp:"車両系建設機械の資格境界 — 3t",romaji:"sharyoukei kensetsu kikai shikaku kyoukai 3t",id_text:"Alat berat konstruksi: ≥3t → teknik, <3t → pendidikan khusus",desc:"Mesin seperti buldoser, power shovel, backhoe, concrete pump: 機体重量 ≥3t → 技能講習修了者. 機体重量 <3t → 特別教育修了者. Angka kunci: 3t が境界. Berlaku untuk mesin整地・運搬・積込み・掘削用 dan mesin 解体用. (Sumber: text3 §3.3.2)"},{id:238,category:"hukum",source:"text3",jp:"ガス溶接作業主任者（免許）vs アーク溶接作業者（特別教育）",romaji:"gasu yousetsu sagyou shuninsha menkyo vs aaku yousetsu sagyousha tokubetsu kyouiku",id_text:"Pengawas las gas = lisensi / Pekerja las listrik = pendidikan khusus",desc:"ガス溶接作業主任者: membutuhkan 免許 (lisensi negara) — bertugas mengawasi pengelasan gas asetilen/oksigen. ガス溶接作業者: 技能講習修了者. アーク溶接作業者: cukup 特別教育修了者. Hierarki: 主任者>作業者. (Sumber: text3 §3.3.2)"},{id:239,category:"jenis_kerja",source:"text3",jp:"冷凍空気調和機器工事の代表機器",romaji:"reitou kuuki chouwa kiki kouji daihyou kiki",id_text:"Mesin utama dalam pekerjaan AC/refrigerasi",desc:"Termasuk: エアコン (rumah+komersial), 冷凍庫, パッケージ型/セパレート型空調, 業務用冷凍冷蔵庫, ショーケース, 輸送用冷凍ユニット. Pekerja perlu skill配管 (銅管加工) karena pekerjaan ini mencakup juga instalasi refrigerant piping. (Sumber: text3 §3.2.33)"},{id:240,category:"jenis_kerja",source:"text3",jp:"消防設備の3分類（消火・警報・避難）",romaji:"shoubou setsubi 3 bunrui: shouka keihou hinan",id_text:"3 kategori peralatan pemadam kebakaran wajib UU",desc:"①消火設備 = alat padamkan api (sprinkler, hidran, pompa). ②警報設備 = detektor asap/panas, alarm darurat, sistem siaran. ③避難設備 = perosotan dan tangga evakuasi. Ketiganya wajib dipasang dan dirawat berdasarkan 消防法. (Sumber: text3 §3.2.37)"},{id:241,category:"jenis_kerja",source:"text3",jp:"各種炉の種類（築炉工事詳細）",romaji:"kakushu ro no shurui chikuro kouji shousai",id_text:"Jenis-jenis tungku dalam pekerjaan築炉",desc:"焼却炉=incinerator sampah/limbah industri. キューポラ=lebur besi dengan kokas. 焼鈍炉=pemerataan sifat logam. 脱臭炉=hilangkan bau gas buang (oksidasi). アルミ溶解炉=lebur alumunium. バイオマスボイラー=bakar kayu sisa pabrik→air panas/listrik. 電気炉=lebur logam dengan induksi elektromagnetik. (Sumber: text3 §3.2.36)"},{id:242,category:"alat_umum",source:"text3",jp:"機械土工事の代表機械（ブルドーザ・油圧ショベル・ホイールローダ）",romaji:"kikai dokou kouji daihyou kikai: burudoozaa yuatsu shoberu hoiiruroodaa",id_text:"Alat berat utama pekerjaan tanah: buldoser, excavator, wheel loader",desc:"ブルドーザ = mendorong tanah (押土) dan memadatkan lereng. 油圧ショベル (backhoe) = menggali + memuat ke dump truck, bisa ganti bucket untuk 法面整形. ホイールローダ = memuat material ke dump truck. クラムシェル = menggali bawah air. (Sumber: text3 §3.2.7)"},{id:243,category:"jenis_kerja",source:"text3",jp:"埋立工事 vs 岸壁工事（うめたて・がんぺき）",romaji:"umetate kouji vs ganpeki kouji",id_text:"Reklamasi laut vs Konstruksi dermaga kapal",desc:"埋立工事 = tanah hasil pengerukan (浚渫) diangkut kapal/mesin ke laut, ditimbun untuk membuat lahan baru (contoh: bandara, kawasan industri). 岸壁工事 = membuat tempat sandar kapal menggunakan sheet pile baja (鋼矢板) sebagai dinding penahan, dan tiang (杭) sebagai penopang struktur. (Sumber: text3 §3.2.3)"},{id:244,category:"hukum",source:"text3",jp:"建築基準法の耐震基準 — 震度5強・震度6強〜7",romaji:"kenchiku kijunhou taishin kijun: shindo 5kyou / 6kyou-7",id_text:"Standar tahan gempa UU Bangunan: intensitas 5 kuat & 6 kuat~7",desc:"建築基準法 mewajibkan: ①震度5強程度 → 機能保持（bangunan tetap berfungsi normal）. ②震度6強〜7程度の大規模地震 → 倒壊しない（tidak runtuh, boleh rusak ringan）. Angka kunci: 5強 と 6強〜7. (Sumber: text3 §3.1.2)"},{id:245,category:"jenis_kerja",source:"text3",jp:"舗装の4層 — 路床・路盤・基層・表層（アスファルトフィニッシャー）",romaji:"housou 4sou: roshou roban kisou hyousou asufuruto finisshaa",id_text:"4 lapisan jalan: subgrade / base / binder / wearing course",desc:"①路床=lapisan dasar terbawah, digali ±1m, diberi pasir. ②路盤=batu pecah, dipadatkan roller. ③基層=aspal pertama, dihampar アスファルトフィニッシャー lalu dipadatkan roller. ④表層=aspal atas, tahan air, anti-selip. CATATAN: id:149 hanya menyebut 3 lapis — 基層 adalah lapis ke-3 yang sering terlewat. (Sumber: text3 §3.2.6)"},{id:246,category:"jenis_kerja",source:"text3",jp:"杭の材料3種 — 木杭・鋼杭・コンクリート杭",romaji:"kui no zairyou 3 shurui: ki-kui kou-kui konkuriito-kui",id_text:"3 material tiang pondasi: kayu / baja / beton",desc:"木杭 = tiang kayu (tertua, untuk tanah lunak). 鋼杭 = tiang baja (kuat, dapat dipancang dalam). コンクリート杭 = paling umum saat ini, bisa場所打ち (dicor di tempat) atau 既成 (pabrik). Pemilihan tergantung kondisi tanah, kedalaman支持層, dan kebisingan yang diizinkan. (Sumber: text3 §3.2.8)"},{id:247,category:"jenis_kerja",source:"text3",jp:"コンクリート圧送工事の3役チームワーク",romaji:"konkuriito assou kouji 3yaku chiimuwaaku",id_text:"3 peran tim pengecoran beton: operator pompa / ujung selang / pemadatan",desc:"①操作オペレータ = mengoperasikan pompa beton. ②筒先作業員 = mengarahkan ujung selang ke bekisting. ③土工作業員 = mengoperasikan バイブレータ untuk締固め. Ketiga peran harus sinkron karena 生コン mulai mengeras — tidak boleh ada penundaan. (Sumber: text3 §3.2.15)"},{id:248,category:"jenis_kerja",source:"text3",jp:"左官仕上げ — 研ぎ出し vs 洗い出し",romaji:"sakan shiage: togidashi vs araidashi",id_text:"Finishing plester khusus: poles batu vs cuci permukaan",desc:"研ぎ出し = permukaan batu/material diamplas/dipoles hingga rata dan mengkilap. 洗い出し = 種石 (batu hias kecil) dicampur semen+kapur, ditempelkan ke permukaan, lalu permukaan dicuci sikat agar batu-batu kecil terlihat menonjol keluar. Keduanya membutuhkan teknik tinggi. (Sumber: text3 §3.2.18)"},{id:249,category:"jenis_kerja",source:"text3",jp:"在来軸組工法（ざいらいじくぐみ）— 木造住宅の代表工法",romaji:"zairaijikugumi kouhou — mokuzou juutaku",id_text:"Metode rangka kayu tradisional Jepang — teknik bangunan kayu dominan",desc:"Metode konstruksi kayu paling umum di Jepang: kolom (柱) dan balok (梁) kayu dirakit sebagai rangka struktural. 工務店 (kontraktor kecil lokal) biasanya menangani semua tahap: desain, pengolahan kayu, konstruksi, dan manajemen. (Sumber: text3 §3.2.19)"},{id:250,category:"jenis_kerja",source:"text3",jp:"ダクトの3種類 — 排煙・空調・排気",romaji:"dakuto 3 shurui: haien kuuchou haiki",id_text:"3 jenis saluran udara: asap kebakaran / AC / pembuangan",desc:"排煙ダクト = saat kebakaran, membuang asap keluar gedung. 空調ダクト = mendistribusikan udara dingin/panas/segar ke tiap ruangan. 排気ダクト = membuang panas dan bau dari ruang mesin, toilet, dll. Semua dibuat dari lembaran logam dalam 建築板金工事. (Sumber: text3 §3.2.21)"},{id:251,category:"jenis_kerja",source:"text3",jp:"建具の材料種類 + シャッター・自動ドア",romaji:"tategu no zairyou shurui + shattaa jidou doa",id_text:"Material kusen/pintu/jendela + shutter & pintu otomatis",desc:"建具 = semua yang dipasang di bukaan (pintu, jendela, fusuma, shoji + rangkanya). Material: 木製・アルミ製・樹脂製・鋼製・ステンレス製. Pekerjaan 建具工事 juga mencakup シャッター取付工事 dan 自動ドア取付工事. (Sumber: text3 §3.2.25)"},{id:252,category:"hukum",source:"text3",jp:"電気工事士 — 一種 vs 二種（大型施設 → 一種が必要）",romaji:"denki koujishi isshu vs nishu: oogata shisetsu → isshu",id_text:"Lisensi teknisi listrik: kelas 1 vs kelas 2",desc:"二種電気工事士 = cukup untuk rumah tinggal dan fasilitas kecil (600V以下). 一種電気工事士 = wajib untuk gedung besar, pabrik, atau fasilitas tegangan tinggi. Kerja keras listrik tegangan tinggi tanpa lisensi = pelanggaran hukum dan risiko kebakaran/jiwa. (Sumber: text3 §3.2.30)"},{id:253,category:"hukum",source:"text3",jp:"工事担任者・電気通信主任技術者（電気通信工事の資格）",romaji:"kouji tanninsha denki tsuushin shunin gijutsusha",id_text:"Lisensi wajib pekerjaan telekomunikasi: penanggung jawab & direktur teknis",desc:"電気通信工事 terkait langsung dengan infrastruktur jaringan — kesalahan bisa sebabkan gangguan jaringan masif. Oleh karena itu: ①工事担任者 dan ②電気通信主任技術者 adalah lisensi wajib untuk jenis pekerjaan tertentu. Bukan sekadar 特別教育. (Sumber: text3 §3.2.31)"},{id:254,category:"hukum",source:"text3",jp:"ゴンドラ操作 → 特別教育（高層ビルの外壁作業）",romaji:"gondora sousa → tokubetsu kyouiku: kousou biru gaiheki sagyou",id_text:"Gondola kerja gedung tinggi → wajib pendidikan khusus",desc:"ゴンドラ = platform gantung yang dipakai untuk pekerjaan dinding luar gedung tinggi (外壁改修, pembersihan kaca). Untuk mengoperasikannya wajib 特別教育修了者. Berbeda dari 高所作業車 yang berjalan di darat. (Sumber: text3 §3.3.2)"},{id:255,category:"hukum",source:"text3",jp:"酸素欠乏危険作業主任者 → 技能講習（マンホール・地下道）",romaji:"sanso ketsubou kiken sagyou shuninsha: ginou koushuu — manhooru chikadou",id_text:"Pengawas kerja kekurangan oksigen → wajib pelatihan teknik",desc:"マンホール・下水道・トンネル内 = risiko 酸素欠乏症 (keracunan O₂ rendah) dan 硫化水素中毒. 作業主任者 (pengawas lapangan) wajib 技能講習修了者. Pekerja biasa yang masuk area ini wajib 特別教育修了者. Lihat juga id:107. (Sumber: text3 §3.3.2)"},{id:256,category:"hukum",source:"text3",jp:"石綿（アスベスト）取り扱い作業者 → 特別教育",romaji:"ishiwata asubesuto toriatsukai sagyousha → tokubetsu kyouiku",id_text:"Pekerja penanganan asbes saat bongkar bangunan → pendidikan khusus wajib",desc:"Bangunan lama yang mengandung 石綿 (asbes) harus dibongkar dengan sangat hati-hati. Pekerja yang menangani pembongkaran/penanganan石綿 wajib 特別教育修了者 (石綿則第27条). Berbeda dari 石綿作業主任者 yang perlu 技能講習. Lihat juga id:135. (Sumber: text3 §3.3.2)"},{id:257,category:"hukum",source:"text3",jp:"有機溶剤作業主任者 → 技能講習（室内タンク等）",romaji:"yuuki youzai sagyou shuninsha → ginou koushuu: shitsunai tanku",id_text:"Pengawas kerja pelarut organik → wajib pelatihan teknik",desc:"Bekerja dengan 有機溶剤 (pelarut organik) di ruang dalam, tangki, atau ruangan sempit dapat menyebabkan keracunan. Pengawas (作業主任者) wajib 技能講習修了者. Berlaku saat kadar pelarut organik dalam campuran >5%. (Sumber: text3 §3.3.2)"},{id:258,category:"jenis_kerja",source:"text3",jp:"温泉井 vs 地熱井 — 深さと危険性（500〜1000m / 約2000m）",romaji:"onsensei vs chinetsusei: fukasa to kikensei 500-1000m / 2000m",id_text:"Sumur air panas vs sumur panas bumi: kedalaman & bahaya",desc:"温泉井 = 500〜1000m, bahaya: gas alam bisa keluar saat pengeboran → perlu beberapa izin. 地熱井 = ±2000m (paling dalam), bahaya: 熱水・蒸気・有害物質 → butuh teknologi dan keahlian tertinggi di antara semua jenis さく井工事. (Sumber: text3 §3.2.4)"},{id:259,category:"jenis_kerja",source:"text3",jp:"吹付けウレタン — 施工前検査（450mm板）と施工中確認（4〜5m間隔）",romaji:"fukitsuke uretan: sekou mae kensa 450mm ita · sekou chuu kakunin 4-5m kankaku",id_text:"Cek kualitas uretan semprot: uji coba 450mm sebelum + ukur ketebalan tiap 4-5m",desc:"施工前 = semprotkan ke papan uji 450mm × 450mm untuk mengecek kepadatan busa (発泡の密度). 施工中 = tiap 4〜5m interval, gunakan 厚測定機 untuk memastikan ketebalan uretan sesuai spec. Permukaan beton harus bersih dari debu dan minyak sebelum aplikasi. (Sumber: text3 §3.2.27)"},{id:260,category:"jenis_kerja",source:"text3",jp:"コンクリートブロック造（CB造）— 鉄筋+モルタル補強",romaji:"konkuriito burokku zou (CB-zou): tekkin + morutaru hokyou",id_text:"Konstruksi blok beton: tulangan di rongga + perkuatan mortar",desc:"コンクリートブロック造 = blok beton (berlubang di tengah) disusun bertingkat. Lubang/rongga (空洞部分) diisi tulangan baja, lalu dicor/diisi mortar untuk memperkuat. Lebih kokoh dari tumpukan bata biasa. Digunakan untuk pagar, tembok penahan, dan bangunan kecil. (Sumber: text3 §3.1.2)"},// ── KARTU BARU v13 — text4.pdf (Agent B) ──────────────────────────────────
{id:261,category:"alat_umum",source:"text4",jp:"立て墨（たてずみ）・仕上げ墨（しあげずみ）",romaji:"tate zumi / shiage zumi",id_text:"Garis referensi vertikal / Garis dimensi finishing",desc:"立て墨 = garis vertikal yang ditampilkan pada permukaan dinding/kolom. 仕上げ墨 = garis referensi yang menunjukkan dimensi finishing dari sumbu atau permukaan struktural. Keduanya digunakan untuk menentukan posisi finishing interior. (Sumber: text4 §4.2.1)"},{id:262,category:"alat_umum",source:"text4",jp:"親墨（おやずみ）",romaji:"oya zumi",id_text:"Garis induk / garis referensi utama",desc:"Garis referensi utama seperti 通り芯 (sumbu kolom/dinding) dan 陸墨 (horizontal) yang menjadi DASAR untuk pekerjaan墨出し di tahap berikutnya. Disebut 'induk' karena semua garis lain diturunkan dari sini. (Sumber: text4 §4.2.1)"},{id:263,category:"alat_umum",source:"text4",jp:"矩を振る（かねをふる）・墨付け（すみつけ）",romaji:"kane wo furu / sumitsuke",id_text:"Membuat sudut siku-siku / Menandai kayu untuk pemotongan",desc:"矩を振る = pekerjaan membuat garis sudut 90° pada墨出し. 墨付け = menandai bagian kayu struktural dengan tanda untuk pemrosesan. Keduanya adalah tahap dasar sebelum pemasangan elemen konstruksi. (Sumber: text4 §4.2.1)"},{id:264,category:"alat_umum",source:"text4",jp:"基準墨（きじゅんずみ）",romaji:"kijun zumi",id_text:"Garis referensi dasar bangunan",desc:"Garis lurus horizontal/vertikal yang menjadi standar utama saat mendirikan bangunan. Dari garis ini, 通り芯 (sumbu kolom/dinding) diturunkan. Dibuat menggunakan墨つぼ tradisional atau laser墨出し器. (Sumber: text4 §4.2.1)"},{id:265,category:"alat_umum",source:"text4",jp:"地縄張り（じなわばり）・水糸（みずいと）",romaji:"jinawabari / mizuito",id_text:"Penandaan posisi bangunan di tanah / Benang horizontal referensi",desc:"地縄張り = menandai posisi pondasi di permukaan tanah menggunakan tali/pita. 水糸 = benang yang direntangkan horizontal antara papan 水貫, menjadi referensi sumbu bangunan saat 遣り方. (Sumber: text4 §4.2.2)"},{id:266,category:"alat_umum",source:"text4",jp:"FH・SL・CH（高さ記号）",romaji:"FH / SL / CH",id_text:"FH = tinggi tanah rencana / SL = tinggi permukaan slab / CH = tinggi plafon",desc:"FH (Formation Height) = tinggi tanah yang direncanakan. SL (Slab Level) = tinggi finishing permukaan slab beton. CH (Ceiling Height) = jarak dari FL ke finishing plafon. Melengkapi simbol GL/FL/BM yang sudah ada di id:146. (Sumber: text4 §4.2.2)"},{id:267,category:"jenis_kerja",source:"text4",jp:"盛り土（もりど）・段切り（だんきり）",romaji:"morido / dangiri",id_text:"Timbunan tanah / Pemotongan tangga pada lereng",desc:"盛り土 = menimbun tanah untuk meratakan lahan yang tidak rata atau miring. 段切り = memotong lahan miring secara bertingkat seperti tangga sebelum menimbun, agar timbunan tidak longsor. (Sumber: text4 §4.2.3)"},{id:268,category:"jenis_kerja",source:"text4",jp:"根切り（ねきり）・余堀り（よぼり）・鋤取り（すきとり）・床付け（とこづけ）",romaji:"nekiri / yobori / sukitori / tokoduke",id_text:"Galian pondasi / Galian lebih / Perataan permukaan / Finishing dasar galian",desc:"根切り = menggali lubang (掘削) hingga kedalaman pondasi menggunakan alat berat. 余堀り = galian tambahan untuk ruang kerja. 鋤取り = meratakan tanah ke ketinggian yang ditentukan. 床付け = finishing dasar galian secara presisi sebelum pekerjaan pondasi dimulai. (Sumber: text4 §4.2.3)"},{id:269,category:"jenis_kerja",source:"text4",jp:"埋め戻し（うめもどし）・突き固め（つきかため）・水締め（みずしめ）",romaji:"umemodoshi / tsukigatame / mizushime",id_text:"Urugan balik / Pemadatan manual / Pemadatan dengan air",desc:"埋め戻し = mengisi kembali tanah di sekitar/dalam bangunan setelah pekerjaan bawah tanah selesai. 突き固め = memadatkan tanah urugan menggunakan alat seperti ramma/plate. 水締め = menuangkan air sambil memadatkan untuk mencegah penurunan tanah di kemudian hari. (Sumber: text4 §4.2.3)"},{id:270,category:"jenis_kerja",source:"text4",jp:"擁壁（ようへき）・矢板（やいた）・鋼矢板（こうやいた）",romaji:"youheki / yaita / kou yaita",id_text:"Dinding penahan tanah / Papan turap / Turap baja",desc:"擁壁 = struktur berbentuk dinding untuk menahan tanah (jenis 土留め yang berbentuk dinding). 矢板 = papan penahan tanah. 鋼矢板 = turap baja dengan ujung berbentuk alur agar bisa saling mengunci satu sama lain. (Sumber: text4 §4.2.3)"},{id:271,category:"jenis_kerja",source:"text4",jp:"法面（のりめん）・地山（じやま）・山がくる・山留め（やまどめ）",romaji:"norimen / jiyama / yama ga kuru / yamadome",id_text:"Lereng galian / Tanah alami / Lereng longsor / Penahan lereng",desc:"法面 = permukaan miring pada galian konstruksi. 地山 = tanah dalam kondisi alami (belum diganggu). 山がくる = lereng/turap longsor — BAHAYA kecelakaan! 山留め = menahan tanah agar tidak runtuh menggunakan turap. Jika lahan cukup: オープンカット法; jika sempit: 山留め壁付き工法. (Sumber: text4 §4.2.3)"},{id:272,category:"alat_umum",source:"text4",jp:"釜場（かまば）・水替え（みずかえ）・万棒（まんぼう）",romaji:"kamaba / mizukae / manbou",id_text:"Lubang pompa penguras / Pemompaan air galian / Penghitungan masuk-keluar",desc:"水替え = memompa air yang mengumpul di dasar galian menggunakan pompa. 釜場 = lubang kecil di dasar galian tempat pompa dipasang. 万棒 = menghitung jumlah truk, orang, atau bahan (kayu/tiang) yang masuk ke lokasi. (Sumber: text4 §4.2.3)"},{id:273,category:"jenis_kerja",source:"text4",jp:"地業（じぎょう）・ベタ基礎・フーチング・杭基礎（くいきそ）",romaji:"jigyou / beta kiso / fuuchingu / kui kiso",id_text:"Pekerjaan bawah pondasi / Pondasi pelat penuh / Pondasi setempat / Pondasi tiang",desc:"地業 = bagian di bawah slab pondasi (pasir/kerikil/捨てコン/tiang). 直接基礎 dibagi: ベタ基礎 (seluruh dasar bangunan dicor beton, tanah keras) dan フーチング (hanya di titik beban, bentuk T terbalik). 杭基礎 = tanah lunak → tiang박힌ke tanah keras untuk menyalurkan beban. (Sumber: text4 §4.2.4)"},{id:274,category:"jenis_kerja",source:"text4",jp:"スラブ（構造スラブ・基礎スラブ・フラットスラブ）",romaji:"surabu",id_text:"Slab (pelat lantai/pondasi/tanpa balok)",desc:"スラブ = pelat datar pada bangunan (lantai, pondasi, dll). 構造スラブ = slab yang menopang bangunan. 基礎スラブ = slab di bagian pondasi. フラットスラブ = slab tanpa balok (梁なし). (Sumber: text4 §4.2.4)"},{id:275,category:"jenis_kerja",source:"text4",jp:"基礎免振（きそめんしん）",romaji:"kiso menshin",id_text:"Isolasi seismik pada pondasi",desc:"Sistem yang menyerap gaya horizontal akibat gempa sehingga getaran yang diteruskan ke bangunan berkurang. Dipasang di antara tanah dan bagian pondasi. Wajib untuk gedung bertingkat di Jepang yang rawan gempa. (Sumber: text4 §4.2.4)"},{id:276,category:"keselamatan",source:"text4",jp:"足場（あしば）の種類：枠組み・単管・くさび緊結式",romaji:"ashiba no shurui: wakugumi / tankan / kusabi kinketsu shiki",id_text:"Jenis-jenis perancah: rangka / pipa tunggal / pasak kunci",desc:"枠組み足場 = perancah rangka prefabrikasi, paling umum. 単管足場 = perancah dari pipa tunggal, fleksibel. くさび緊結式足場 = perancah yang dikunci dengan pasak/wedge, kuat dan cepat dipasang. Pemilihan jenis tergantung jenis dan skala pekerjaan. (Sumber: text4 §4.2.5)"},{id:277,category:"keselamatan",source:"text4",jp:"作業床（さぎょうゆか）・仮囲い（かりがこい）",romaji:"sagyouyuka / karigakoi",id_text:"Lantai kerja (perancah) / Pagar sementara lokasi",desc:"作業床 = lantai perancah yang dibuat dari papan (布板) tempat pekerja berdiri dan bekerja. 仮囲い = pagar sementara yang membatasi lokasi konstruksi dari jalan/lahan tetangga — untuk mencegah bahaya, pencurian, dan akses orang tidak berkepentingan. (Sumber: text4 §4.2.5)"},{id:278,category:"jenis_kerja",source:"text4",jp:"配筋（はいきん）・間隔（かんかく）・あき",romaji:"haikin / kankaku / aki",id_text:"Pemasangan besi tulangan / Jarak antar tulangan (dari pusat ke pusat) / Jarak bersih antar tulangan",desc:"配筋 = mengatur dan merakit besi tulangan sebelum dicor. 間隔 = jarak dari pusat tulangan ke pusat tulangan berikutnya. あき = jarak BERSIH antar tulangan (ruang kosong). Dua istilah ini berbeda dan penting untuk memenuhi standar kekuatan struktur. (Sumber: text4 §4.2.6)"},{id:279,category:"jenis_kerja",source:"text4",jp:"かぶり厚さ",romaji:"kaburi atsusa",id_text:"Selimut beton (jarak tulangan ke permukaan beton)",desc:"Jarak antara permukaan LUAR besi tulangan ke permukaan beton yang menutupinya. Harus cukup tebal untuk melindungi tulangan dari korosi dan api. Termasuk hal yang selalu dicek dalam inspeksi kualitas. (Sumber: text4 §4.2.6)"},{id:280,category:"jenis_kerja",source:"text4",jp:"捨てコンクリート（すてコン）",romaji:"sute konkuriito (sute kon)",id_text:"Beton lantai kerja (beton lean/blinding)",desc:"Beton tipis 5–10 cm yang dicor rata di atas 地業 sebelum pemasangan tulangan dan bekisting. Fungsi: membuat referensi ketinggian墨出し yang akurat dan menyediakan permukaan rata sebagai dasar bekisting/tulangan. Disingkat 捨てコン. (Sumber: text4 §4.2.6)"},{id:281,category:"alat_umum",source:"text4",jp:"結束（けっそく）・ハッカー",romaji:"kessoku / hakkaa",id_text:"Pengikatan tulangan / Alat pengikat kawat besi",desc:"結束 = mengikat persilangan tulangan menggunakan kawat khusus (結束線). ハッカー = alat berbentuk kait untuk memutar kawat pengikat tulangan dengan cepat. Ada cara ikat たすき掛け (silang penuh) dan 片だすき (silang satu sisi). (Sumber: text4 §4.2.6)"},{id:282,category:"jenis_kerja",source:"text4",jp:"打ち重ね（うちかさね）vs 打ち継ぎ（うちつぎ）・コールドジョイント",romaji:"uchi kasane vs uchitsugi / koorudo jointo",id_text:"Pengecoran di atas beton belum keras vs sudah keras / Sambungan cacat",desc:"打ち重ね = pengecoran di atas beton yang BELUM mengeras. Harus dalam 150 menit (suhu <25°C) atau 120 menit (≥25°C). Jika terlambat → コールドジョイント (cacat sambungan, struktur lemah). 打ち継ぎ = pengecoran di atas beton yang SUDAH mengeras, dilakukan di lokasi yang sudah dikaji secara struktur/kedap air. (Sumber: text4 §4.2.6)"},{id:283,category:"keselamatan",source:"text4",jp:"パンク（型枠崩壊）",romaji:"panku (kata waku houkai)",id_text:"Pecahnya bekisting akibat tekanan beton",desc:"Saat pengecoran atau selama beton mengeras, bekisting bisa pecah/jebol sehingga beton mengalir keluar — disebut パンク. Terjadi jika 支保工 (penopang bekisting) tidak cukup kuat. Berbahaya dan menyebabkan pemborosan material besar. (Sumber: text4 §4.2.6)"},{id:284,category:"jenis_kerja",source:"text4",jp:"納まり（おさまり）・取合い（とりあい）",romaji:"osamari / toriai",id_text:"Kerapian/keserasian pemasangan / Pertemuan dua elemen berbeda",desc:"納まり = keserasian tata letak elemen. '納まりが悪い' = elemen tidak rapi/tidak cocok. 取合い = bagian pertemuan dua atau lebih elemen yang berbeda (contoh: 天井と壁の取合い = sambungan plafon-dinding). '納まりが悪い' dan '取合いが悪い' sering digunakan dengan arti sama. (Sumber: text4 §4.2.7)"},{id:285,category:"jenis_kerja",source:"text4",jp:"面一（つらいち）・不陸（ふろく）・目違い（めちがい）",romaji:"tsura ichi / furoku / mechigai",id_text:"Permukaan rata sejajar / Permukaan tidak rata / Tepi yang tidak sejajar",desc:"面一 = dua permukaan elemen berada dalam satu bidang rata (flat). 不陸 (ふりく juga OK) = permukaan bergelombang/tidak rata. 目違い = sambungan papan/tile/board yang permukaannya tidak berada dalam satu bidang, atau nat-nya bergeser. (Sumber: text4 §4.2.7)"},{id:286,category:"jenis_kerja",source:"text4",jp:"駄目（だめ）・手直し（てなおし）・手戻り（てもどり）・段取り（だんどり）",romaji:"dame / tenaoshi / temodori / dandori",id_text:"Pekerjaan tersisa di akhir / Koreksi sebagian / Pengerjaan ulang / Perencanaan urutan kerja",desc:"駄目 = pekerjaan yang terlewat/belum selesai saat hampir finishing. 駄目直し = menyelesaikannya. 手直し = koreksi sebagian yang tidak sesuai gambar/mutu buruk. 手戻り = mengulang pekerjaan yang sudah selesai (buang waktu). 段取り = merencanakan urutan kerja sebelumnya agar手戻りtidak terjadi. (Sumber: text4 §4.2.7)"},{id:287,category:"jenis_kerja",source:"text4",jp:"建端（たっぱ）・上端（うわば）・下端（したば）",romaji:"tappa / uwaba / shitaba",id_text:"Tinggi elemen / Ujung atas elemen / Ujung bawah elemen",desc:"建端（立端）= tinggi/ketinggian elemen bangunan. 上端 = tepi/permukaan ATAS suatu elemen atau material. 下端 = tepi/permukaan BAWAH suatu elemen atau material. Ketiga istilah ini sering digunakan saat memberi instruksi pemasangan di lapangan. (Sumber: text4 §4.2.7)"},{id:288,category:"alat_umum",source:"text4",jp:"一間（いっけん）・一尺（いっしゃく）・一寸（いっすん）・一坪（ひとつぼ）",romaji:"ikken / isshaku / issun / hitotsubo",id_text:"Satuan panjang/luas tradisional Jepang (1 ken≈1.8m, 1 shaku≈30.3cm, 1 sun≈3.03cm, 1 tsubo≈3.3m²)",desc:"Satuan lama yang masih dipakai di konstruksi Jepang: 1間≈1.818m, 1尺≈30.3cm, 1寸=1/10尺≈3.03cm. 1坪 = 1間×1間 ≈ 3.3m² (satuan luas). Sering muncul dalam gambar bangunan tradisional dan pembicaraan di lapangan. (Sumber: text4 §4.2.8)"},{id:289,category:"alat_umum",source:"text4",jp:"ピッチ（割り付けの間隔）",romaji:"picchi",id_text:"Jarak pemasangan / Pitch (antar elemen yang berulang)",desc:"Jarak antara elemen-elemen yang dipasang berulang, misalnya jarak antar tulangan, jarak antar baut, atau jarak tile. Berbeda dari 間隔 (center-to-center) — ピッチ dipakai lebih umum untuk layout berulang. Contoh: 'ピッチ200mm'. (Sumber: text4 §4.2.8)"},{id:290,category:"jenis_kerja",source:"text4",jp:"RC造・S造・SRC造・木造",romaji:"RC zou / S zou / SRC zou / moku zou",id_text:"Struktur beton bertulang / Struktur baja / Beton bertulang+baja / Struktur kayu",desc:"RC造 (Reinforced Concrete) = tulangan+beton. S造 (Steel) = kolom/balok baja. SRC造 = kombinasi S+RC: tulangan mengelilingi baja kemudian dicor. 木造 = kolom/balok kayu. Di SSW konstruksi, memahami perbedaan jenis struktur ini penting untuk identifikasi pekerjaan. (Sumber: text4 §4.2.9)"},{id:291,category:"listrik",source:"text4",jp:"絶縁（ぜつえん）・漏電（ろうでん）・接地（せっち）・アース",romaji:"zetsuen / rouden / secchi / aasu",id_text:"Isolasi listrik / Kebocoran arus / Pembumian (grounding)",desc:"絶縁 = mencegah arus listrik mengalir ke bagian yang seharusnya tidak dialiri. 漏電 = arus mengalir ke bagian yang tidak seharusnya — berbahaya dan bisa menyebabkan kebakaran/感電. 接地(アース) = menghubungkan peralatan listrik ke tanah secara elektrik untuk mencegah感電 dan melindungi peralatan komunikasi. (Sumber: text4 §4.2.10)"},{id:292,category:"listrik",source:"text4",jp:"架空配線（かくうはいせん）vs 埋設（まいせつ）配線",romaji:"kakuu haisen vs maisetsu haisen",id_text:"Pemasangan kabel lewat tiang listrik vs penguburan kabel di dalam tanah",desc:"架空配線 = menggunakan tiang listrik (電柱) untuk menyalurkan kabel ke dalam gedung dari luar. 埋設 = kabel ditanam di dalam tanah, ada 3 cara: 管路式 (dalam pipa), 直接埋設式 (kabel khusus langsung tanam), dan とう道 (terowongan/共同溝). (Sumber: text4 §4.2.10)"},{id:293,category:"listrik",source:"text4",jp:"隠ぺい配管（いんぺいはいかん）vs 露出配管（ろしゅつはいかん）",romaji:"inpei haikan vs roshutsu haikan",id_text:"Instalasi pipa tersembunyi (dalam dinding/plafon) vs terlihat",desc:"隠ぺい配管 = pipa/kabel dilewatkan di dalam dinding, plafon, atau lantai sehingga tidak terlihat dari luar. 露出配管 = pipa/kabel tampak terlihat di permukaan. Pemilihan metode tergantung estetika dan kemudahan perawatan. (Sumber: text4 §4.2.10)"},{id:294,category:"listrik",source:"text4",jp:"低圧・高圧・特別高圧（電圧の区分）",romaji:"teiatsu / kouatsu / tokubetsu kouatsu",id_text:"Tegangan rendah / Tegangan tinggi / Tegangan ekstra tinggi",desc:"低圧 = DC ≤750V, AC ≤600V. 高圧 = DC 750V–7000V, AC 600V–7000V. 特別高圧 = keduanya >7000V. Klasifikasi ini diatur dalam standar teknis peralatan listrik Jepang dan menentukan syarat kualifikasi pekerja listrik. (Sumber: text4 §4.2.10)"},{id:295,category:"listrik",source:"text4",jp:"直流（DC）vs 交流（AC）",romaji:"chokuryuu (DC) vs kouryuu (AC)",id_text:"Arus searah vs Arus bolak-balik",desc:"直流 (DC = Direct Current) = arus yang besarnya dan arahnya TIDAK berubah terhadap waktu. 交流 (AC = Alternating Current) = arus yang besar dan arahnya berubah secara periodik. Listrik rumah tangga Jepang adalah AC 100V, 50Hz (Timur) atau 60Hz (Barat). (Sumber: text4 §4.2.10)"},{id:296,category:"listrik",source:"text4",jp:"MDF（Main Distribution Frame）",romaji:"emudiiefu",id_text:"Panel distribusi utama telekomunikasi gedung",desc:"Papan distribusi yang mengelola dan menghubungkan saluran komunikasi dari luar gedung ke dalam. Semua jalur telepon/internet dari luar masuk ke MDF dulu sebelum didistribusikan ke tiap ruangan. (Sumber: text4 §4.2.10)"},{id:297,category:"listrik",source:"text4",jp:"Φ（ファイ / パイ）",romaji:"fai (dibaca 'pai' di konstruksi)",id_text:"Simbol diameter — DIBACA 'PAI' di lapangan konstruksi",desc:"Φ adalah simbol matematika untuk diameter, seharusnya dibaca 'ファイ (fai)'. NAMUN di industri konstruksi Jepang, simbol ini dibaca 'パイ (pai)'. Contoh: 'Φ50のパイプ' = pipa berdiameter 50mm. Penting agar tidak bingung di lapangan. (Sumber: text4 §4.2.10)"},{id:298,category:"listrik",source:"text4",jp:"通電（つうでん）・あたる・かしめる・飛ぶ/落ちる（ブレーカー）",romaji:"tsuuden / ataru / kashimeru / tobu/ochiru",id_text:"Ada arus listrik / Mengecek dengan alat ukur / Crimping kabel / Breaker trip",desc:"通電 = arus listrik mengalir/aktif. あたる = memeriksa sesuatu dengan alat (contoh: 検電器やテスターで調べる). かしめる = menjepit/crimping ujung kabel ke terminal menggunakan 圧着ペンチ. 飛ぶ/落ちる = breaker bekerja memutus rangkaian (circuit breaker trip). (Sumber: text4 §4.2.10)"},{id:299,category:"jenis_kerja",source:"text4",jp:"空調（くうちょう）・換気（かんき）・排煙（はいえん）",romaji:"kuuchou / kanki / haien",id_text:"AC/pendingin udara (suhu+kelembapan) / Ventilasi / Pembuangan asap kebakaran",desc:"空調 = 空気調和設備 (singkatan). Mengatur suhu, kelembapan, dan kualitas udara ruangan. 換気 = mengganti udara kotor ruangan dengan udara segar. 排煙 = mengeluarkan asap SAAT KEBAKARAN dari dalam ruangan ke luar — sistem keselamatan wajib di gedung tertentu. (Sumber: text4 §4.2.11)"},{id:300,category:"pipa",source:"text4",jp:"汚水（おすい）・雑排水（ざつはいすい）",romaji:"osui / zatsuhaisui",id_text:"Air limbah toilet / Air limbah non-toilet (dapur, kamar mandi, wastafel)",desc:"汚水 = air buangan dari WC/toilet (大便器・小便器). 雑排水 = air buangan dari kamar mandi (風呂), wastafel (洗面所), dan dapur (台所). Keduanya disalurkan secara terpisah dalam sistem drainase gedung sebelum diolah. (Sumber: text4 §4.2.11)"},{id:301,category:"pipa",source:"text4",jp:"漏洩試験（ろうえいしけん）：水圧試験・満水試験",romaji:"rouei shiken: suiatsu shiken / mansui shiken",id_text:"Uji kebocoran: uji tekanan air / uji penuh air",desc:"漏洩試験 = pengujian setelah pemasangan pipa selesai untuk memastikan tidak ada kebocoran (漏水). 水圧試験 = pipa suplai/panas diisi air lalu diberi tekanan. 満水試験 = pipa drainase diisi penuh air dan diperiksa apakah ada kebocoran. (Sumber: text4 §4.2.11)"},{id:302,category:"pipa",source:"text4",jp:"ライニング（コーティング）・逆流（ぎゃくりゅう）・勾配（こうばい）",romaji:"rainingu / gyakukan / koubai",id_text:"Pelapisan dalam pipa / Aliran balik / Kemiringan pipa untuk mengalirkan air",desc:"ライニング = melapisi permukaan dalam pipa/duct dengan lapisan tipis pelindung (= コーティング; bedanya: ライニング lebih tebal dari コーティング). 逆流 = cairan/gas mengalir berlawanan arah yang benar. 勾配 = kemiringan yang dipasang pada pipa drainase agar air mengalir ke arah yang ditentukan. (Sumber: text4 §4.2.11)"},{id:303,category:"karier",source:"text4",jp:"ほうれんそう（報告・連絡・相談）",romaji:"houren sou (houkoku / renraku / soudan)",id_text:"Laporan / Komunikasi / Konsultasi — 3 pilar komunikasi kerja Jepang",desc:"ほうれんそう = akronim dari 報告 (melaporkan hasil/kemajuan ke atasan), 連絡 (menyampaikan informasi pekerjaan atau jadwal), 相談 (berkonsultasi saat ada masalah atau ketidaktahuan). Di konstruksi, selalu sampaikan dengan singkat, jelas, dan kesimpulan di depan. (Sumber: text4 §4.3.4)"},{id:304,category:"karier",source:"text4",jp:"作業員詰め所（さぎょういんつめしょ）のルール",romaji:"sagyouin tsumesho no ruuru",id_text:"Aturan di ruang pekerja (ruang ganti/istirahat lokasi)",desc:"作業員詰め所 adalah ruang ganti, makan, dan istirahat di lokasi konstruksi. Aturan wajib: ①merokok hanya di tempat yang ditentukan, ②tidak buang sampah sembarangan (ポイ捨て禁止), ③helm & 安全帯 disimpan di tempat yang ditetapkan, ④barang pribadi di loker, ⑤cuci tangan & kumur saat masuk/keluar, ⑥rajin periksa 掲示板. (Sumber: text4 §4.3.2)"},{id:305,category:"jenis_kerja",source:"text4",jp:"見付け（みつけ）・見え掛かり（みえがかり）・見え隠れ（みえかくれ）",romaji:"mitsuke / miegakari / miekakure",id_text:"Permukaan tampak penuh / Tampak sebagian / Tampak hanya jika bergerak",desc:"見付け = permukaan elemen yang SEPENUHNYA terlihat dari depan. 見え掛かり = bagian yang terlihat dari celah atau sudut miring (tidak seluruhnya). 見え隠れ = bagian yang hanya terlihat saat sesuatu digeser/diangkat — kebalikan dari 見え掛かり. Penting saat menentukan mutu finishing material. (Sumber: text4 §4.2.7)"},{id:306,category:"jenis_kerja",source:"text4",jp:"反り（そり）vs 起り（むくり）・陸（ろく）",romaji:"sori vs mukuri / roku",id_text:"Melengkung cekung / Melengkung cembung / Horizontal/datar",desc:"反り = garis/permukaan yang melengkung CEKUNG (konkaf, seperti mangkuk). 起り = garis/permukaan yang melengkung CEMBUNG (konveks, seperti kubah). 陸 (りく も可) = kondisi horizontal sempurna. Contoh: 陸屋根 = atap datar. Ketiga istilah dipakai saat QC permukaan. (Sumber: text4 §4.2.7)"},{id:307,category:"jenis_kerja",source:"text4",jp:"転び（ころび）・逃げ（にげ）",romaji:"korobi / nige",id_text:"Kolom/dinding yang miring dari vertikal / Toleransi dimensi yang disengaja",desc:"転び = kondisi kolom/dinding yang seharusnya tegak lurus namun miring. 拝む (おがむ) = bangunan yang miring secara umum. 逃げ = toleransi atau kelonggaran dimensi yang SENGAJA diambil sebelumnya untuk mengakomodasi kesalahan pengukuran atau pemasangan material. (Sumber: text4 §4.2.7)"},{id:308,category:"jenis_kerja",source:"text4",jp:"見切る（みきる）・見切り材（みきりざい）・馴染み（なじみ）",romaji:"mikiru / mikirizable / najimi",id_text:"Menyelesaikan sambungan dua pekerjaan / Material penutup sambungan / Tingkat kerapatan sambungan",desc:"見切る = menyelesaikan sambungan/batas antara dua pekerjaan finishing secara rapi. 見切り材 = material yang dipakai untuk menutup sambungan tersebut (contoh: list antara lantai dan dinding). 馴染み = tingkat kerapatan dua elemen yang disambung. '馴染みが良い' = rapat sempurna, '馴染みが悪い' = ada celah/tidak rapat. (Sumber: text4 §4.2.7)"},{id:309,category:"jenis_kerja",source:"text4",jp:"ベタ・ふかし（ふかす）",romaji:"beta / fukashi (fukasu)",id_text:"Penuh tanpa celah / Penebalan finishing melebihi desain awal",desc:"ベタ = kondisi menutupi SELURUH permukaan tanpa celah. Contoh: ベタ基礎 (pondasi penuh), ベタ塗り (cat seluruh permukaan). ふかし = bagian finishing yang dibuat lebih tebal/maju dari desain awal, atau tindakan memajukan permukaan finishing ke depan. Kata kerja: ふかす. (Sumber: text4 §4.2.7)"},{id:310,category:"jenis_kerja",source:"text4",jp:"通り（とおり）を見る",romaji:"toori wo miru",id_text:"Mengecek kelurusan elemen",desc:"'通り' = kondisi lurus/linear suatu elemen. '通りが悪い' = bengkok atau tidak lurus. '通りを見る' = tindakan memeriksa apakah elemen sudah lurus, biasanya dengan mata atau alat bantu. Dipakai saat QC pemasangan besi, dinding, dan kolom. (Sumber: text4 §4.2.7)"},{id:311,category:"jenis_kerja",source:"text4",jp:"拾い出し（ひろいだし）",romaji:"hiroi dashi",id_text:"Perhitungan volume/kuantitas material dari gambar (take-off)",desc:"Proses membaca gambar kerja dan spesifikasi untuk menghitung jumlah material yang dibutuhkan serta berapa tenaga kerja (労務) yang diperlukan. Mirip dengan quantity take-off di Indonesia. Penting agar pengadaan material tidak kekurangan atau berlebih. (Sumber: text4 §4.2.6)"},{id:312,category:"jenis_kerja",source:"text4",jp:"場所打ち（ばしょうち）・打つ／打設する（だせつ）",romaji:"bashouuchi / utsu / dasetsu suru",id_text:"Pengecoran langsung di lokasi (bukan precast) / Memasukkan/menuang beton",desc:"場所打ち (現場打ち) = beton yang dicor langsung di lokasi proyek, bukan menggunakan produk prefabrikasi pabrik. Contoh: 場所打ちコンクリート杭. 打つ/打設する = istilah konstruksi untuk 'menuang/memasukkan beton ke dalam bekisting' (bukan makna 'memukul'). (Sumber: text4 §4.2.3, §4.2.6)"},{id:313,category:"jenis_kerja",source:"text4",jp:"ノロ・アンコ",romaji:"noro / anko",id_text:"Adukan semen encer / Isi penyumbat sementara dalam bekisting",desc:"ノロ = campuran semen+air yang sangat encer. Juga merujuk pada bocoran beton dari celah bekisting. アンコ = material pengisi yang dipasang di dalam bekisting untuk membentuk cekungan/alur kompleks pada beton. Dilepas setelah beton mengeras. (Sumber: text4 §4.2.6)"},{id:314,category:"jenis_kerja",source:"text4",jp:"転用（てんよう）・釘仕舞（くぎじまい）",romaji:"tenyou / kugijimai",id_text:"Pemakaian ulang bekisting di lantai berbeda / Pencabutan paku dari bekisting bekas",desc:"転用 = menggunakan kembali material bekisting yang sama di lokasi atau lantai berbeda dalam proyek yang sama. Menghemat biaya. 釘仕舞 = mencabut semua paku dari material bekisting yang sudah dilepas agar bisa digunakan ulang. Dari makna ini juga berarti 'beres-beres sisa bekisting'. (Sumber: text4 §4.2.6)"},{id:315,category:"jenis_kerja",source:"text4",jp:"配合（はいごう）・練り混ぜ（ねりまぜ）・タンピング",romaji:"haigou / nerimaze / tanpingu",id_text:"Rasio campuran beton / Pengadukan material beton / Pemadatan slab dari atas",desc:"配合 = perbandingan komposisi material beton (semen, pasir, kerikil, air). 練り混ぜ = proses mencampur semen dan agregat hingga merata. タンピング = mengetuk permukaan bekisting slab dari atas agar beton yang sudah dituang menjadi padat dan tanpa rongga. (Sumber: text4 §4.2.6)"},{id:316,category:"jenis_kerja",source:"text4",jp:"あそび・建込み（たてこみ）",romaji:"asobi / tatekami",id_text:"Kelonggaran/toleransi pada sambungan / Mendirikan/memasang bekisting tegak",desc:"あそび = kelonggaran atau ruang gerak yang disengaja dalam suatu sambungan (agar tidak terlalu kencang). Berbeda dari 逃げ yang bersifat dimensi. 建込み = pekerjaan mendirikan bekisting (型枠) sesuai garis 墨出し — bekisting ditegakkan dan dikunci pada posisinya. (Sumber: text4 §4.2.6)"},{id:317,category:"listrik",source:"text4",jp:"配線（はいせん）・離隔（りかく）・貫通（かんつう）",romaji:"haisen / rikaku / kantsuu",id_text:"Penarikan kabel / Jarak pisah antar kabel/pipa / Melubangi dinding/lantai/plafon",desc:"配線 = memasang dan merentangkan kabel (logam maupun serat optik) di dalam atau luar gedung. 離隔 = jarak pemisahan yang wajib dijaga antar kabel/pipa yang berbeda jenis. 離隔距離 = nilai jarak minimumnya. 貫通 = membuat lubang tembus di dinding, lantai, atau plafon untuk jalur kabel/pipa. (Sumber: text4 §4.2.10)"},{id:318,category:"listrik",source:"text4",jp:"通線（つうせん）・配管する・スラブ配管・仕込む（しこむ）",romaji:"tsuusen / haikan suru / surabu haikan / shikomu",id_text:"Menarik kabel dalam pipa / Memasang konduit / Konduit tertanam dalam slab / Persiapan kerja di muka",desc:"通線 = menarik/memasukkan kabel ke dalam pipa konduit yang sudah terpasang. 配管する = memasang pipa konduit. スラブ配管 = konduit yang ditanam langsung dalam slab lantai/plafon. 仕込む = menyiapkan atau melakukan pekerjaan persiapan SEBELUMNYA agar pekerjaan utama bisa berjalan lancar. (Sumber: text4 §4.2.10)"},{id:319,category:"listrik",source:"text4",jp:"避雷針（ひらいしん）vs 避雷器（ひらいき）",romaji:"hiraishin vs hiraiki",id_text:"Penangkal petir (untuk bangunan/orang) vs Arrester (untuk peralatan komunikasi)",desc:"避雷針 = perangkat di atap gedung yang menangkap sambaran petir dan mengalirkan arus ke tanah — melindungi BANGUNAN dan ORANG. 避雷器 = perangkat yang melindungi PERALATAN KOMUNIKASI dan terminal dari lonjakan tegangan akibat petir. Keduanya berbeda fungsi dan lokasi pemasangan. (Sumber: text4 §4.2.10)"},{id:320,category:"listrik",source:"text4",jp:"被覆（ひふく）・一次側（いちじがわ）・二次側（にじがわ）",romaji:"hifuku / ichijigawa / nijigawa",id_text:"Selubung isolasi kabel / Sisi masuk listrik / Sisi keluar listrik",desc:"被覆 = lapisan vinil atau isolasi yang membungkus kawat inti (芯線). 一次側 = sisi INPUT listrik masuk ke suatu peralatan/panel. 二次側 = sisi OUTPUT listrik keluar dari peralatan/panel. Istilah ini penting saat menghubungkan atau memeriksa panel listrik. (Sumber: text4 §4.2.10)"},{id:321,category:"listrik",source:"text4",jp:"増し締め（ましじめ）・マーキング",romaji:"mashi shime / maakingu",id_text:"Pengencangan ulang baut/sekrup / Penandaan setelah pengencangan",desc:"増し締め = memeriksa dan mengencangkan kembali baut/sekrup yang mungkin longgar. Dilakukan secara berkala. マーキング = memberi tanda (garis atau titik) pada baut setelah dikencangkan — jika baut bergeser akibat getaran, tanda ini akan terlihat bergeser sehingga kelonggaran dapat dideteksi. (Sumber: text4 §4.2.10)"},{id:322,category:"listrik",source:"text4",jp:"振る（ふる）・競る（せる）・伏せる（ふせる）",romaji:"furu / seru / fuseru",id_text:"Mereroute pipa/kabel / Hampir tabrakan / Membuat ujung keluaran pipa dari slab",desc:"振る = mengubah jalur pipa/kabel untuk menghindari hambatan/obstacle. 競る = kondisi dua elemen yang hampir bersentuhan/bertabrakan — perlu tindakan. 伏せる = menggunakan end-cap/end piece untuk membuat titik exit pipa konduit dari permukaan slab. (Sumber: text4 §4.2.10)"},{id:323,category:"pipa",source:"text4",jp:"衛生設備（えいせいせつび）・死水（しにみず）",romaji:"eisei setsubi / shini mizu",id_text:"Peralatan sanitasi (toilet/kamar mandi) / Air stagnan dalam pipa",desc:"衛生設備 = peralatan yang menjaga kebersihan lingkungan menggunakan air — mencakup toilet, kamar mandi, dll. (BUKAN termasuk dapur/厨房). 死水 = air yang diam tidak bergerak dalam waktu lama di dalam tangki atau pipa. Air ini bisa terkontaminasi bakteri dan berbahaya jika digunakan. (Sumber: text4 §4.2.11)"},{id:324,category:"alat_umum",source:"text4",jp:"バリ・バリ取り",romaji:"bari / bari tori",id_text:"Gerinda/sirip sisa proses pada logam atau plastik / Proses membuang gerinda",desc:"バリ = tonjolan atau sisa material yang terbentuk di tepi produk logam/plastik akibat proses pemotongan atau pengecoran. バリ取り = proses membersihkan dan membuang バリ agar permukaan rata dan aman (tidak melukai). Dilakukan pada ujung pipa yang baru dipotong. (Sumber: text4 §4.2.11)"},{id:325,category:"pipa",source:"text4",jp:"分岐（ぶんき）・伸縮（しんしゅく）・蛇腹（じゃばら）",romaji:"bunki / shinshuku / jabara",id_text:"Percabangan pipa / Memuai dan menyusut / Konektor fleksibel berbentuk akordeon",desc:"分岐 = satu pipa yang terbagi menjadi dua atau lebih jalur. 伸縮 = sifat material yang bisa memanjang/memendek akibat perubahan suhu — penting dipertimbangkan dalam desain pipa panjang. 蛇腹 = konektor berbentuk gelombang/akordeon yang fleksibel, dipakai untuk menyerap伸縮 atau getaran. (Sumber: text4 §4.2.11)"},{id:326,category:"pipa",source:"text4",jp:"芯（しん）・先（さき）（配管用語）",romaji:"shin / saki (haikan yougo)",id_text:"Garis sumbu pipa/duct / Ujung/end pipa",desc:"芯 = garis tengah (center line) dari pipa atau duct, dipakai sebagai referensi pengukuran dan pemasangan. 先 = ujung/end dari pipa (bukan pangkal). Kedua istilah ini khas untuk konteks pekerjaan pipa (配管) dan berbeda dari makna umum sehari-hari. (Sumber: text4 §4.2.11)"},{id:327,category:"keselamatan",source:"text4",jp:"服装の注意（ふくそうのちゅうい）4項目",romaji:"fukusou no chuui",id_text:"4 pantangan pakaian di lokasi konstruksi",desc:"①半袖・短パン禁止 — hanya tangan dan wajah yang boleh terbuka. ②上着の前開け禁止 — baju tidak boleh terbuka karena bisa tersangkut tonjolan. ③袖まくり禁止 — lengan harus diturunkan sampai pergelangan. ④ポケットに手を入れて歩くな — tangan di saku saat jalan = tidak bisa menahan diri saat jatuh. (Sumber: text4 §4.3.3)"},{id:328,category:"karier",source:"text4",jp:"後片付け（あとかたづけ）・消火確認（しょうかかくにん）",romaji:"atokataduke / shouka kakunin",id_text:"Beres-beres setelah kerja / Konfirmasi pemadaman api",desc:"作業終了後 = setelah kerja selesai, WAJIB beres-beres. Beres-beres dilakukan dengan mentalitas 'mempersiapkan pekerjaan keesokan harinya (翌日の段取り)'. Jika menggunakan api (gas, las, dll.) dalam pekerjaan, pastikan api benar-benar PADAM sebelum meninggalkan lokasi. (Sumber: text4 §4.3.5)"},{id:329,category:"jenis_kerja",source:"text4",jp:"捨て（すて）材料（ざいりょう）",romaji:"sute zairyou",id_text:"Material 'sacrificial' — tidak masuk struktur/finishing, hanya untuk kemudahan konstruksi",desc:"'捨て' sebagai awalan = material yang tidak berkontribusi pada struktur atau tampilan akhir, tapi digunakan untuk memudahkan施工. Contoh paling umum: 捨てコンクリート (id:280). Konsep ini berlaku luas — ada juga 捨て板, 捨て石, dll. (Sumber: text4 §4.2.7)"},{id:330,category:"jenis_kerja",source:"text4",jp:"杭間さらい（くいまさらい）・段跳ね（だんばね）",romaji:"kui ma sarai / dan bane",id_text:"Penggalian tanah di antara tiang / Penggalian bertahap ke atas",desc:"杭間さらい = saat 床付け (finishing dasar galian), menggali dan merapikan tanah DI ANTARA tiang pondasi serta tanah yang terangkat di sekitarnya. 段跳ね = pada galian dalam, tanah hasil galian dilempar ke atas secara bertahap melalui undakan yang disisakan — karena tanah tidak bisa langsung diangkat dari dasar galian. (Sumber: text4 §4.2.3)"},{id:331,category:"jenis_kerja",source:"text4",jp:"山砂（やまずな）",romaji:"yama zuna",id_text:"Pasir gunung/daratan (berbeda dari pasir sungai)",desc:"Pasir yang diambil dari daratan (bukan dari sungai). Karakteristik utama: 保水性 (kemampuan menyimpan air) LEBIH TINGGI dibanding pasir sungai. Digunakan sebagai material urugan balik. Sifat ini perlu diperhitungkan saat memilih metode 水締め agar urugan tidak ambles. (Sumber: text4 §4.2.3)"},{id:332,category:"jenis_kerja",source:"text4",jp:"既成杭工法（きせいくいこうほう）vs 場所打ちコンクリート杭工法",romaji:"kisei kui kouhou vs bashouuchi konkuriito kui kouhou",id_text:"Tiang prefabrikasi (pabrik) vs Tiang beton cor di tempat",desc:"既成杭工法 = tiang sudah dibuat di pabrik lalu dipancang ke lokasi. 場所打ちコンクリート杭工法 = lubang dibor di lokasi lalu diisi beton cor di tempat. Keduanya adalah jenis 杭地業 (pekerjaan tiang pondasi). Pemilihan bergantung kondisi tanah, beban, dan ketersediaan alat. (Sumber: text4 §4.2.3, §4.2.4)"},{id:333,category:"jenis_kerja",source:"text4",jp:"コンクリートブロック造（ぞう）",romaji:"konkuriito burokku zou",id_text:"Struktur bata/blok beton yang ditumpuk",desc:"Jenis struktur bangunan yang menggunakan blok beton yang ditumpuk (積み上げ). Sering dipakai untuk pagar, dinding pembatas, dan bangunan kecil. Berbeda dari RC造 (yang dicor monolit) karena menggunakan unit-unit terpisah yang disusun. (Sumber: text4 §4.2.9)"},{id:334,category:"alat_umum",source:"text4",jp:"追う（おう）・寸法（すんぽう）",romaji:"ou / sunpou",id_text:"Mengukur berurutan dari titik referensi / Ukuran/dimensi",desc:"追う = mengukur/menentukan posisi secara berurutan dari satu titik referensi (基準位置) — misalnya menentukan posisi tulangan satu per satu dari ujung bekisting. 寸法 = ukuran atau dimensi panjang secara umum. Keduanya istilah dasar pengukuran di lapangan. (Sumber: text4 §4.2.8)"},{id:335,category:"listrik",source:"text4",jp:"接続（せつぞく）・結線（けっせん）",romaji:"setsuzoku / kessen",id_text:"Menghubungkan dua hal / Menyambung kabel komunikasi",desc:"接続 = istilah umum untuk menghubungkan dua hal atau lebih. 結線 = istilah khusus untuk menyambung kabel komunikasi (通信線). Dalam konteks listrik: 接続 dipakai untuk semua jenis sambungan, sedangkan 結線 lebih spesifik ke telekomunikasi. (Sumber: text4 §4.2.10)"},{id:336,category:"listrik",source:"text4",jp:"バイブレーター・打ち込み（うちこみ）",romaji:"baibureetaa / uchikomi",id_text:"Alat penggetar beton / Proses menuang dan memadatkan beton",desc:"打ち込み = menuang beton ke dalam bekisting dan memadatkannya tanpa celah. バイブレーター (vibrator) = alat yang dimasukkan ke dalam beton cair untuk menggetarkannya, menghilangkan rongga udara. Selain vibrator, 型枠をゴムハンマーで叩く (memukul bekisting dengan palu karet) juga digunakan untuk 締固め beton. (Sumber: text4 §4.2.6)"},{id:337,category:"jenis_kerja",source:"text4",jp:"面（つら）・矩（かね）・拝む（おがむ）",romaji:"tsura / kane / ogamu",id_text:"Permukaan elemen / Sudut siku-siku / Bangunan/elemen yang miring",desc:"面（つら/めん）= permukaan suatu elemen bangunan. 矩（かね）= sudut siku-siku (90°). '矩が出ていない' = sudut tidak tepat 90°. 拝む = kondisi bangunan atau elemen yang seharusnya tegak namun miring — seperti orang yang sedang membungkuk memberi hormat. (Sumber: text4 §4.2.7)"},{id:338,category:"karier",source:"text4",jp:"5Sの各定義：整理・整頓・清掃・清潔・しつけ",romaji:"5S no kaku teigi: seiri / seiton / seisou / seiketsu / shitsuke",id_text:"5 definisi individual kegiatan 5S",desc:"①整理 = memilah perlu vs tidak perlu, buang yang tidak perlu. ②整頓 = letakkan barang yang perlu di tempat yang DITENTUKAN, tegak lurus/siku. ③清掃 = bersih-bersih setelah kerja. ④清潔 = menjaga kondisi bersih dari ①②③ secara berkelanjutan dengan standar baku. ⑤しつけ = membuat aturan + mendidik agar ①–④ bisa dijalankan SEMUA orang secara konsisten. (Sumber: text4 §4.3.1)"},{id:339,category:"salam",source:"text4",jp:"お先に失礼します（おさきにしつれいします）",romaji:"osaki ni shitsurei shimasu",id_text:"Permisi, saya pulang lebih dulu",desc:"Diucapkan saat KAMU pulang lebih dulu dari rekan yang masih bekerja. Ini adalah bentuk khusus dari 失礼します. Respons yang tepat dari rekan yang ditinggal: '「お疲れさまでした」'. JANGAN digunakan ke atasan tanpa kalimat sopan tambahan. (Sumber: text4 §4.1.5)"},{id:340,category:"listrik",source:"text4",jp:"圧着（あっちゃく）ペンチ・リングスリーブ",romaji:"atsuchaku penchi / ringu suriibu",id_text:"Tang crimping / Selongsong sambungan kawat listrik",desc:"圧着 = menyambung dengan cara memberikan tekanan (memeras/menjepit). 圧着ペンチ = tang khusus untuk menekan terminal ke ujung kabel. リングスリーブ = selongsong logam berbentuk cincin yang digunakan untuk menyambung beberapa kawat listrik, kemudian di-crimp (かしめる) menggunakan 圧着ペンチ. (Sumber: text4 §4.2.10)"},{id:341,category:"keselamatan",source:"text4",jp:"ポイ捨て禁止・ガムを噛みながらの作業禁止",romaji:"poi sute kinshi / gamu wo kaminagara no sagyou kinshi",id_text:"Dilarang buang sampah sembarangan / Dilarang mengunyah permen karet saat kerja",desc:"ポイ捨て = membuang sampah bukan di tempat yang ditentukan — DILARANG. Sampah harus dipilah dan dibuang sesuai aturan daur ulang. ガム禁止 alasannya GANDA: ①berpotensi dibuang sembarangan (ポイ捨て), dan ②jika ada benda jatuh mendadak, bisa menggigit lidah secara tidak sengaja. (Sumber: text4 §4.3.2)"},// ── KARTU BARU v14 — text5l.pdf (Agent D + Wave 2 + Wave 3) ──────────────
{id:343,category:"jenis_kerja",source:"text5l",jp:"ロードローラ・タイヤローラ・振動ローラ",romaji:"roodo rooraa / taiya rooraa / shindou rooraa",id_text:"Mesin pemadat: road roller / tire roller / vibration roller",desc:"ロードローラ = rol besi (untuk subgrade/subbase jalan); タイヤローラ = rol karet (tanah biasa, aspal); 振動ローラ = rol besi bergetar (efek kuat meski ukuran kecil). (Sumber: text5l §5.1.1)"},{id:344,category:"alat_umum",source:"text5l",jp:"ホイールローダ",romaji:"hoiiru roodaa",id_text:"Wheel loader (juga disebut タイヤドーザー / タイヤショベル)",desc:"Mesin pemuat material (tanah, batu) ke truk menggunakan bucket besar di depan, bergerak dengan roda ban. Berbeda dari バックホウ yang menggali ke belakang. (Sumber: text5l §5.1.1)"},{id:345,category:"alat_umum",source:"text5l",jp:"タワークレーン（マストクライング vs フロアークライミング）",romaji:"tawaa kurein (masuto kuraingu vs furooa kuraimingu)",id_text:"Tower crane — 2 jenis naik ketinggian",desc:"マストクライング: kepala crane memanjat tiang (mast) yang diperpanjang. フロアークライミング: seluruh crane memanjat bangunan dari lantai ke lantai. Digunakan untuk gedung bertingkat tinggi. (Sumber: text5l §5.1.1)"},{id:346,category:"listrik",source:"text5l",jp:"ベンダー",romaji:"bendaa",id_text:"Alat pembengkok pipa metal (conduit bender)",desc:"Digunakan untuk membengkokkan pipa logam (金属管) sesuai sudut yang diperlukan dalam pekerjaan instalasi listrik. (Sumber: text5l §5.1.2)"},{id:347,category:"listrik",source:"text5l",jp:"CD管 vs PF管",romaji:"shii dii kan vs pii efu kan",id_text:"CD管 (Combined Duct) vs PF管 (Plastic Flexible conduit)",desc:"CD管 = 非難燃性 (tidak tahan nyala api), khusus ditanam dalam beton (埋設用), berwarna oranye. PF管 = 難燃性 (tahan nyala api), untuk instalasi umum, tidak boleh ditanam dalam beton. (Sumber: text5l §5.1.2)"},{id:348,category:"listrik",source:"text5l",jp:"C管（薄鋼電線管）vs G管（厚鋼電線管）",romaji:"shii kan (usu kou densenkan) vs jii kan (atsu kou densenkan)",id_text:"C管 = pipa baja tipis (ada ulir) vs G管 = pipa baja tebal (ada ulir, dilapisi galvanis)",desc:"C管 (薄鋼): lebih tipis, kuat terhadap benturan, untuk instalasi dalam ruangan. G管 (厚鋼): tebal, permukaan galvanis sehingga tahan cuaca (耐候性あり). (Sumber: text5l §5.1.2)"},{id:349,category:"listrik",source:"text5l",jp:"ボイド管",romaji:"boido kan",id_text:"Pipa kertas (void tube) — untuk membuat lubang di beton",desc:"Pipa berbahan kertas yang ditanam sebelum pengecoran beton untuk membentuk lubang tembus di lantai, balok, atau dinding. Dilepas setelah beton mengeras. (Sumber: text5l §5.1.2)"},{id:350,category:"listrik",source:"text5l",jp:"アウトレットボックス",romaji:"autoretto bokkusu",id_text:"Outlet box — kotak percabangan kabel",desc:"Kotak yang digunakan untuk percabangan (分岐) dan penyambungan (接続) kabel dalam instalasi listrik. Berbeda dari プルボックス yang digunakan untuk menarik/menyambung kabel antar konduit panjang. (Sumber: text5l §5.1.2)"},{id:351,category:"listrik",source:"text5l",jp:"圧着ペンチ（端子用=赤・リングスリーブ用=黄）",romaji:"acchaku penchi (tanshi you = aka / ringu suriibu you = ki)",id_text:"Tang krimping — pegangan MERAH untuk terminal, pegangan KUNING untuk ring sleeve",desc:"Ada 2 jenis: pegangan merah = untuk圧着端子 (crimp terminal); pegangan kuning = untuk リングスリーブ (ring sleeve, menyambung beberapa kabel). Warna pegangan TIDAK boleh tertukar. (Sumber: text5l §5.1.2)"},{id:352,category:"listrik",source:"text5l",jp:"リングスリーブ",romaji:"ringu suriibu",id_text:"Ring sleeve — komponen penyambung beberapa kabel",desc:"Komponen berbentuk cincin yang digunakan untuk menyambung beberapa kabel sekaligus. Kabel dimasukkan ke lubang cincin lalu dikrimping dengan 圧着ペンチ (pegangan kuning). (Sumber: text5l §5.1.2)"},{id:353,category:"listrik",source:"text5l",jp:"呼び線（よびせん）",romaji:"yobisen",id_text:"Kabel panduan (guide wire) untuk menarik kabel utama melalui konduit",desc:"Kawat yang dimasukkan terlebih dahulu ke dalam pipa konduit. Kabel utama disambungkan ke ujung kawat panduan ini, kemudian ditarik melewati pipa. (Sumber: text5l §5.1.2)"},{id:354,category:"listrik",source:"text5l",jp:"レースウェイ",romaji:"reesuwee",id_text:"Raceway — rel distribusi listrik untuk memasang lampu di gudang",desc:"Komponen penggantung lampu yang juga memiliki fungsi penyalur daya listrik (給電機能). Digantung dari baut gantung, digunakan di tempat tanpa plafon seperti gudang. (Sumber: text5l §5.1.2)"},{id:355,category:"listrik",source:"text5l",jp:"吊りボルト（全ねじボルト）",romaji:"tsuri boruto (zen neji boruto)",id_text:"Baut gantung (full-thread bolt) — tidak berkepala, berulir penuh",desc:"Baut panjang berulir penuh tanpa kepala, dipasang pada insert yang tertanam di beton lantai. Digunakan untuk menggantung konduit, kabel rack, dan raceway. (Sumber: text5l §5.1.2)"},{id:356,category:"listrik",source:"text5l",jp:"ワイヤーストリッパー",romaji:"waiyaa sutorippa",id_text:"Wire stripper — alat pengupas isolasi kabel",desc:"Alat untuk mengupas lapisan isolasi (被覆) kabel listrik tanpa merusak kawat di dalamnya. Sering dilengkapi ストリップゲージ untuk mengukur panjang kupasan. (Sumber: text5l §5.1.2)"},{id:357,category:"listrik",source:"text5l",jp:"CVケーブル vs EM-EEF",romaji:"shii bui keepuru vs ii emu ii ii efu",id_text:"CV (cross-linked polyethylene) vs EM-EEF (polyethylene jacket VVF)",desc:"EM-EEF = VVFケーブル dengan selubung polyethylene, tahan nyala lebih baik dari VVF biasa. CVケーブル = menggunakan 架橋ポリエチレン (cross-linked PE) sebagai isolator, ketahanan nyala LEBIH TINGGI dari EM-EEF. (Sumber: text5l §5.1.2)"},{id:358,category:"listrik",source:"text5l",jp:"CT / VCT（移動用電線）",romaji:"shii tii / bui shii tii (idou you densen)",id_text:"CT (karet) / VCT (vinyl) — kabel fleksibel untuk peralatan bergerak",desc:"CT = selubung karet, tahan abrasi dan benturan, untuk kabel bergerak. VCT = selubung vinyl, tahan nyala api, lentur, dan tahan air — juga untuk kabel bergerak. (Sumber: text5l §5.1.2)"},{id:359,category:"listrik",source:"text5l",jp:"サーマルリレー",romaji:"saamaru riree",id_text:"Thermal relay — pemutus sirkuit berdasarkan suhu",desc:"Jenis relay yang memutus rangkaian listrik ketika suhu naik melampaui batas. Digunakan untuk melindungi motor listrik dari panas berlebih akibat beban lebih. (Sumber: text5l §5.1.2)"},{id:360,category:"telekomunikasi",source:"text5l",jp:"クロージャ",romaji:"kuroojaa",id_text:"Closure — kotak sambungan kabel aerial di tiang listrik",desc:"Kotak yang dipasang di tiang listrik untuk menyambung/mencabang inti kabel telekomunikasi aerial (架空配線). Melindungi sambungan dari cuaca. Warna: 光ファイバー closure = abu-abu, kabel metal = hitam. (Sumber: text5l §5.1.3, text6l §6.8.1)"},{id:361,category:"telekomunikasi",source:"text5l",jp:"つり線（メッセンジャーワイヤー）",romaji:"tsurisen (messenjaa waiyaa)",id_text:"Suspension wire / messenger wire — kawat penopang kabel aerial",desc:"Kawat baja yang dipasang di atas kabel telekomunikasi aerial agar kabel tidak menahan beban tarikannya sendiri. Juga disebut メッセンジャーワイヤー. (Sumber: text5l §5.1.3)"},{id:362,category:"telekomunikasi",source:"text5l",jp:"張線器（ちょうせんき）+ 掴線器（かくせんき）",romaji:"chousenki + kakusenki",id_text:"Penegang kawat (張線器) + penjepit kawat (掴線器) — digunakan berpasangan",desc:"掴線器 = alat menjepit kawat gantung (つり線). 張線器 = dikombinasikan dengan 掴線器, menarik tuas untuk memberi tegangan pada kawat gantung agar tidak kendur. (Sumber: text5l §5.1.3)"},{id:363,category:"telekomunikasi",source:"text5l",jp:"整流器 vs 蓄電池",romaji:"seiryuuki vs chikudenchi",id_text:"Rectifier (AC→DC) vs Baterai penyimpan energi listrik",desc:"整流器 = mengubah arus bolak-balik (交流) menjadi arus searah (直流). 蓄電池 = menyimpan energi listrik dengan cara mengisi daya (充電). Keduanya digunakan dalam sistem telekomunikasi. (Sumber: text5l §5.1.3)"},{id:364,category:"telekomunikasi",source:"text5l",jp:"LANテスター",romaji:"ran tesutaa",id_text:"LAN tester — alat uji kabel LAN (8 kawat, tidak ada putus/silang)",desc:"Alat untuk memeriksa 8 kawat di dalam kabel LAN apakah ada yang putus (断線) atau bersilang (交差). Dipasang di kedua ujung konektor modular kabel. (Sumber: text5l §5.1.3)"},{id:365,category:"pipa",source:"text5l",jp:"配管（はいかん）vs ダクト",romaji:"haikan vs dakuto",id_text:"Pipa (配管) untuk air/gas vs Saluran udara (ダクト)",desc:"配管 = pipa untuk mengalirkan air atau gas. ダクト = saluran untuk mengalirkan udara. ダクト dibagi menjadi 角ダクト (kotak) dan 丸ダクト / スパイラルダクト (bundar). (Sumber: text5l §5.1.4)"},{id:366,category:"pipa",source:"text5l",jp:"チューブカッター vs パイプカッター（厚さの違い）",romaji:"chyuubu kattaa vs paipu kattaa",id_text:"Tube cutter (pipa tipis) vs Pipe cutter (pipa tebal)",desc:"チューブカッター = untuk memotong pipa tipis dari besi, baja, kuningan, tembaga, aluminium. パイプカッター = untuk pipa yang LEBIH TEBAL (baja, kuningan, tembaga, besi tempa, timbal). (Sumber: text5l §5.1.4)"},{id:367,category:"pipa",source:"text5l",jp:"フレアリングツール",romaji:"furearinguu tsuuru",id_text:"Flaring tool — alat melebar ujung pipa lunak (tembaga)",desc:"Alat untuk melebarkan (フレア加工) ujung pipa lunak seperti pipa tembaga agar dapat disambungkan. Digunakan dalam instalasi pendingin udara (AC). (Sumber: text5l §5.1.4)"},{id:368,category:"pipa",source:"text5l",jp:"エキスパンダー（拡管器）",romaji:"ekisupandaa (kakukankii)",id_text:"Expander /拡管器 — alat memperlebar ujung pipa tembaga untuk sambungan",desc:"Alat untuk memperlebar (拡管) ujung pipa tembaga sehingga pipa lain dapat dimasukkan ke dalamnya untuk disambungkan. Berbeda dari フレアリングツール yang membuat flare berbentuk kerucut. (Sumber: text5l §5.1.4)"},{id:369,category:"pipa",source:"text5l",jp:"水圧試験器（テストポンプ）",romaji:"suiatsu shikenkii (tesuto ponpu)",id_text:"Hydraulic pressure tester (test pump) — uji kebocoran pipa",desc:"Alat ukur yang digunakan saat uji tekanan air (水圧試験) pada pipa air bersih (給水管) dan pipa air panas (給湯管) untuk memastikan tidak ada kebocoran. (Sumber: text5l §5.1.4)"},{id:370,category:"pipa",source:"text5l",jp:"耐熱性硬質塩化ビニル管（HT管・HTVP管）",romaji:"tainetsusei koushitsu enka biniru kan (HT kan)",id_text:"Pipa PVC tahan panas (HT pipe) — warna merah kecoklatan",desc:"Pipa PVC keras yang ditingkatkan ketahanan panasnya. Berwarna merah kecoklatan (赤茶色). Digunakan untuk pipa pendingin-pemanas, kolam air panas. Berbeda dari VP/VU (abu-abu) dan HIVP (biru tua). (Sumber: text5l §5.1.4)"},{id:371,category:"pipa",source:"text5l",jp:"水道用硬質塩化ビニルライニング鋼管（VLP）",romaji:"suidou you koushitsu enka biniru rainingu kouukan (VLP)",id_text:"Pipa baja berlapis PVC untuk air bersih (VLP / ライニング管)",desc:"Pipa baja yang bagian dalamnya dilapisi PVC keras untuk mencegah korosi. Tahan terhadap karat (耐腐食性) dan bahan kimia. Disebut juga ライニング管. (Sumber: text5l §5.1.4)"},{id:372,category:"pipa",source:"text5l",jp:"ガスコック（末端 vs 中間）",romaji:"gasu kokku (mattan vs chuukan)",id_text:"Kran gas:末端ガスコック (ujung/terminal) vs 中間ガスコック (tengah/inline)",desc:"末端ガスコック = digunakan di ujung pipa saat menyambung ke kompor/water heater. 中間ガスコック = dipasang di tengah jalur pipa sebagai katup pengatur atau pemutus aliran gas. (Sumber: text5l §5.1.4)"},{id:373,category:"pipa",source:"text5l",jp:"ガス漏れ警報器",romaji:"gasu more keihouki",id_text:"Detektor kebocoran gas — alarm otomatis saat gas bocor",desc:"Alat yang mendeteksi kebocoran gas dan mengeluarkan alarm untuk memberitahu bahaya. Dipasang di dapur atau ruangan bergas. (Sumber: text5l §5.1.4)"},{id:374,category:"pipa",source:"text5l",jp:"弁（バルブ）vs ダンパー",romaji:"ben (barubu) vs danpaa",id_text:"Katup/valve (pipa air) vs Damper (saluran udara)",desc:"弁（バルブ）= alat untuk menghentikan atau mengatur aliran CAIRAN/GAS di dalam pipa. ダンパー = alat untuk menghentikan atau mengatur aliran UDARA di dalam duct. (Sumber: text5l §5.1.6)"},{id:375,category:"pipa",source:"text5l",jp:"トラップ（排水管）",romaji:"torappu (haisuikan)",id_text:"Perangkap bau (trap) pada pipa drainase — menahan air agar bau tidak masuk ruangan",desc:"Bagian pada pipa drainase yang selalu berisi air untuk mencegah bau busuk (臭気) dan serangga kecil dari saluran pembuangan masuk ke dalam ruangan. (Sumber: text5l §5.1.6)"},{id:376,category:"jenis_kerja",source:"text5l",jp:"衛生設備（給排水衛生設備の6分野）",romaji:"eisei setsubi (kyuu haisui eisei setsubi no roku bunya)",id_text:"Sanitasi / plumbing — 6 bidang: air bersih, drainase, fixture, air panas, gas, pemadam",desc:"給排水衛生設備 mencakup 6 bidang: ①給水設備 ②排水設備 ③衛生器具設備 (kran, WC, wastafel, bak mandi) ④給湯設備 ⑤ガス設備 ⑥消火設備. (Sumber: text5l §5.1.6)"},{id:377,category:"jenis_kerja",source:"text5l",jp:"冷却コイル vs 温水コイル",romaji:"reikyaku koiru vs onsui koiru",id_text:"Koil pendingin (冷房用) vs koil pemanas (暖房用)",desc:"冷却コイル = tabung berisi air dingin, dilewati udara untuk mendinginkan → digunakan saat 冷房 (AC pendingin). 温水コイル = tabung berisi air panas, memanaskan udara → digunakan saat 暖房 (pemanas). (Sumber: text5l §5.1.5)"},{id:378,category:"pemadam",source:"text5l",jp:"水噴霧消火設備",romaji:"mizu funmu shouka setsubi",id_text:"Sistem pemadam kabut air — untuk jalan, parkir, bahan mudah terbakar",desc:"Menyemprotkan kabut air halus untuk memadamkan kebakaran. Digunakan di jalan, area parkir, dan tempat penyimpanan bahan mudah terbakar (指定可燃物). (Sumber: text5l §5.1.8)"},{id:379,category:"pemadam",source:"text5l",jp:"泡消火設備",romaji:"awa shouka setsubi",id_text:"Sistem pemadam busa — untuk kebakaran minyak (油火災)",desc:"Digunakan untuk kebakaran minyak/oil yang tidak cocok dipadamkan dengan air. Bekerja dengan 2 cara: busa menutup permukaan api (窒息効果) + air dalam busa mendinginkan (冷却効果). (Sumber: text5l §5.1.8)"},{id:380,category:"pemadam",source:"text5l",jp:"不活性ガス消火設備",romaji:"fukaassei gasu shouka setsubi",id_text:"Sistem pemadam gas inert — melarutkan oksigen di udara",desc:"Menggunakan gas inert untuk mengurangi konsentrasi oksigen di udara (希釈) dan efek pendinginan (冷却). Tidak merusak peralatan, cocok untuk ruang server dan arsip. (Sumber: text5l §5.1.8)"},{id:381,category:"pemadam",source:"text5l",jp:"ハロゲン化物消火設備",romaji:"harogen kabutsu shouka setsubi",id_text:"Sistem pemadam halogen — untuk kebakaran minyak, listrik hidup, komputer, karya seni",desc:"Menggunakan senyawa halogen (fluor, klor, brom) yang menghambat reaksi pembakaran. Efektif untuk kebakaran minyak, peralatan listrik aktif, komputer, perpustakaan, dan koleksi seni berharga. (Sumber: text5l §5.1.8)"},{id:382,category:"alat_umum",source:"text5l",jp:"ドリルドライバー vs インパクトドライバー",romaji:"doriru doraibaa vs inpakuto doraibaa",id_text:"Drill driver (bisa ganti kecepatan & torsi) vs Impact driver (pukulan + torsi lebih kuat)",desc:"ドリルドライバー: dapat mengatur kecepatan putar dan torsi, untuk memasang sekrup dan bor. インパクトドライバー: punya mekanisme pukul (ハンマー) sehingga torsi lebih besar, kecepatan & torsi tetap. (Sumber: text5l §5.2.1)"},{id:383,category:"alat_umum",source:"text5l",jp:"ディスクグラインダー（高速型 vs 低速型）",romaji:"disuku guraindaa (kousoku gata vs teisoku gata)",id_text:"Angle grinder: disc kecepatan tinggi untuk MEMOTONG, kecepatan rendah untuk MENGAMPLAS",desc:"Mengganti disc sesuai kebutuhan: memotong pipa metal/beton → disc putaran TINGGI (高速トルク型). Mengamplas / menghaluskan permukaan → disc putaran RENDAH (低速トルク型). (Sumber: text5l §5.2.1)"},{id:384,category:"keselamatan",source:"text5l",jp:"丸のこ — キックバック",romaji:"maruno ko — kikku bakku",id_text:"Gergaji sirkel — bahaya kickback (gerakan mundur tiba-tiba)",desc:"Saat gergaji sirkel menyentuh material, material bisa mendorong pisau ke atas sehingga alat bergerak ke arah yang tidak terduga (キックバック). Bisa menyebabkan kecelakaan FATAL. Periksa safety cover sebelum digunakan. (Sumber: text5l §5.2.1)"},{id:385,category:"alat_umum",source:"text5l",jp:"高速切断機 vs チップソー切断機",romaji:"kousoku setsudan ki vs chippu soo setsudan ki",id_text:"High-speed cutter (mata gerinda) vs chip saw cutter (mata gergaji): mata high-speed lebih tahan lama",desc:"チップソー切断機: menggunakan mata gergaji bundar (丸のこ刃), mata cepat aus. 高速切断機: menggunakan batu gerinda (砥石), mata jauh lebih tahan lama. Keduanya untuk memotong pipa metal, besi tulang, baja ringan. (Sumber: text5l §5.2.1)"},{id:386,category:"alat_umum",source:"text5l",jp:"剣スコップ vs 角スコップ（てこ禁止）",romaji:"ken sukoppu vs kaku sukoppu (teko kinshi)",id_text:"Sekop runcing (menggali) vs Sekop rata (mengeruk) — KEDUANYA DILARANG sebagai pengungkit",desc:"剣スコップ: ujung runcing, kaki bisa menginjak bagian atas → untuk menggali tanah keras. 角スコップ: ujung rata, tidak ada tempat injak → untuk mengeruk tanah/aspal lunak. KEDUANYA dilarang digunakan sebagai tuas/てこ. (Sumber: text5l §5.2.2)"},{id:387,category:"alat_umum",source:"text5l",jp:"ランマ vs バイブロコンパクタ vs プレートコンパクタ",romaji:"ranma vs baiburo konpakuta vs pureeto konpakuta",id_text:"Rammer (tumbuk kuat) vs Vibratory compactor (getar, area luas) vs Plate compactor (getar halus, rata)",desc:"ランマ: gaya tumbuk kuat → untuk pemadatan dalam/solid. バイブロコンパクタ: berat + getaran, dorong-tarik → lebih lemah dari ランマ tapi cakupan lebih luas. プレートコンパクタ: plat lebih besar, getaran kecil → untuk meratakan permukaan. (Sumber: text5l §5.2.2)"},{id:388,category:"alat_umum",source:"text5l",jp:"レーザー墨出し器（赤レーザー vs 緑レーザー）",romaji:"reezaa sumidashi ki (aka reezaa vs midori reezaa)",id_text:"Laser level — garis acuan konstruksi: hijau lebih terlihat di tempat terang",desc:"Menyorotkan laser ke dinding, plafon, lantai untuk menentukan garis referensi horizontal/vertikal. Laser HIJAU (緑) lebih mudah dilihat di tempat terang dibanding laser MERAH. Wajib pakai kacamata pelindung laser. (Sumber: text5l §5.2.3)"},{id:389,category:"alat_umum",source:"text5l",jp:"水平器（すいへいき）",romaji:"suiheiki",id_text:"Waterpass / spirit level — berbeda dari レベル (theodolit surveying)",desc:"Alat genggam untuk memeriksa apakah permukaan horizontal atau vertikal dengan melihat gelembung udara di tabung (気泡管). BERBEDA dari 水準器/レベル yang merupakan alat survei besar untuk menentukan elevasi. (Sumber: text5l §5.2.4)"},{id:390,category:"alat_umum",source:"text5l",jp:"さしがね（裏面 = 表面の√2 ≈ 1.414倍）",romaji:"sashigane (ura men = omote men no √2 ≒ 1.414 bai)",id_text:"Penggaris siku baja — sisi belakang = 1.414× sisi depan (√2 untuk diagonal kayu)",desc:"Alat pengukur sudut siku-siku dari logam. Sisi depan (表面): skala meter biasa. Sisi belakang (裏面): skala 1.414× lebih besar dari depan, berguna menghitung diagonal papan kayu (teorema Pythagoras √2). (Sumber: text5l §5.2.4)"},{id:391,category:"alat_umum",source:"text5l",jp:"水糸（みずいと）",romaji:"mizuito",id_text:"Tali referensi bangunan — tidak mulur, untuk meluruskan dan meratakan",desc:"Tali yang dibuat dari bahan tidak mudah mulur, direntangkan saat membangun pondasi, memasang bata/blok untuk memastikan garis lurus dan ketinggian yang sama. (Sumber: text5l §5.2.4)"},{id:392,category:"alat_umum",source:"text5l",jp:"たがね（ハツリ作業）",romaji:"tagane (hatsuri sagyou)",id_text:"Pahat (chisel) — digunakan untuk ハツリ (memecah beton, memotong logam tipis)",desc:"Batang berbentuk pahat yang dipukul dengan palu. Fungsi: ①memotong logam tipis ②ハツリ作業 (memecah/melubangi beton atau mengeruk mortar lama). Jenisnya: 平たがね, コンクリートたがね, 目切りたがね. (Sumber: text5l §5.2.5)"},{id:393,category:"alat_umum",source:"text5l",jp:"バール（てこの原理）",romaji:"baaru (teko no genri)",id_text:"Linggis / crowbar — memanfaatkan prinsip tuas (てこ)",desc:"Alat logam berbentuk L yang digunakan sebagai pengungkit. Ujung L punya alur untuk mencabut paku (釘抜き). Dapat mengangkat benda berat, mencungkil, membongkar bekisting. バール besar disebut 大バール. (Sumber: text5l §5.2.6)"},{id:394,category:"alat_umum",source:"text5l",jp:"チェーンブロック vs レバーホイスト",romaji:"cheen burokku vs rebaa hoisuto",id_text:"Chain block (untuk mengangkat berat) vs lever hoist (lebih kecil, untuk mengencangkan muatan)",desc:"チェーンブロック: dipasang di kaki tiga (三脚) untuk mengangkat beban berat naik-turun. レバーホイスト: prinsip sama tapi lebih KECIL, digunakan untuk mengencangkan muatan (contoh: mengamankan backhoe di atas truk). (Sumber: text5l §5.2.13)"},{id:395,category:"alat_umum",source:"text5l",jp:"ワイヤーロープ（玉掛け用・台付け用）",romaji:"waiyaa roopu (tamakake you / daitsuke you)",id_text:"Wire rope — untuk玉掛け (slinging beban ke crane) dan台付け (mengikat muatan)",desc:"Tali baja dengan kekuatan tarik tinggi, tahan benturan, dan fleksibel. 両端加工済み = 玉掛け用 (mengaitkan beban ke crane/hook). 台付け用 = untuk mengikat/mengamankan muatan di atas kendaraan. (Sumber: text5l §5.2.13)"},{id:396,category:"alat_umum",source:"text5l",jp:"シャックル",romaji:"shakkuru",id_text:"Shackle — penghubung wire rope / rantai dengan beban angkut (玉掛用金具)",desc:"Alat penghubung berbentuk U berulir yang digunakan dalam operasi pengangkatan (玉掛け) untuk menyambungkan wire rope atau rantai dengan beban. (Sumber: text5l §5.2.13)"},{id:397,category:"alat_umum",source:"text5l",jp:"ジャッキ（ネジ式・歯車式・油圧式）",romaji:"jakki (neji shiki / haguruma shiki / yuatsu shiki)",id_text:"Jack — mengangkat beban berat dengan tenaga kecil: tipe ulir, gigi, atau hidrolik",desc:"Alat untuk mengangkat benda sangat berat dengan tenaga minimal. Ada 3 prinsip: ①ネジ式 (ulir) ②歯車式 (roda gigi) ③油圧式 (hidrolik). キリンジャッキ = tipe khusus ulir untuk mengangkat secara vertikal. (Sumber: text5l §5.2.13)"},{id:398,category:"keselamatan",source:"text5l",jp:"はしご（角度 約75度・補助者必須）",romaji:"hashigo (kakudo yaku 75 do / hojousha hissu)",id_text:"Tangga sandar — sudut ±75°, WAJIB ada asisten memegang",desc:"Tangga sandar harus diletakkan pada sudut sekitar 75°. Sudut terlalu tegak → bahaya jatuh ke belakang. Sudut terlalu landai → tangga bisa patah. Selalu bekerja bersama asisten yang memegang tangga. (Sumber: text5l §5.2.14)"},{id:399,category:"keselamatan",source:"text5l",jp:"脚立（きゃたつ）— 天板禁止・またぎ禁止",romaji:"kyatatsu — tenban kinshi / matagi kinshi",id_text:"Tangga A (step ladder) — DILARANG duduk/berdiri di papan atas, DILARANG menunggangi",desc:"Tangga lipat berbentuk A. Tiga larangan: ①Dilarang DUDUK di papan atas (天板). ②Dilarang BERDIRI di papan atas. ③Dilarang bekerja sambil MENUNGGANGI (またぎ乗り) kedua sisi tangga. (Sumber: text5l §5.2.14)"},{id:400,category:"keselamatan",source:"text5l",jp:"ローリングタワー（移動式足場）",romaji:"rooringu tawaa (idoushiki ashiba)",id_text:"Rolling tower (scaffolding beroda) — ada standar keselamatan berdasarkan UU K3",desc:"Perancah bertingkat beroda (kastor di 4 sudut) untuk pekerjaan di ketinggian. Dapat dipindahkan. Memiliki standar keselamatan berdasarkan 労働安全衛生法. Berbeda dari 高所作業車 yang menggunakan kendaraan. (Sumber: text5l §5.2.14)"},{id:401,category:"alat_umum",source:"text5l",jp:"モンキーレンチ（上あごに力をかけて回す）",romaji:"monkii renchi (uwa ago ni chikara wo kakete mawasu)",id_text:"Kunci inggris — putar ke arah RAHANG ATAS (upper jaw) menanggung gaya",desc:"Kunci dengan rahang dapat disesuaikan lebar-sempit sesuai ukuran baut/mur. PENTING: gaya terbesar harus pada RAHANG ATAS (上あご) yang menyatu dengan grip. Jika terbalik bisa merusak kunci atau melukai tangan. (Sumber: text5l §5.2.8)"},{id:402,category:"alat_umum",source:"text5l",jp:"養生用ポリシート",romaji:"youjou you pori shiito",id_text:"Polythene sheet untuk curing/proteksi — anti lembap, anti debu, anti hujan",desc:"Lembaran film polyethylene tipis. Fungsi: ①mencegah kelembapan dari tanah saat pengecoran beton ②proteksi saat pengecatan ③melindungi dari hujan dan debu. (Sumber: text5l §5.2.10)"},{id:403,category:"keselamatan",source:"text5l",jp:"垂直養生ネット vs 水平養生ネット",romaji:"suichoku youjou netto vs suihei youjou netto",id_text:"Jaring pengaman tegak (cegah material jatuh dari scaffolding) vs jaring mendatar (cegah orang jatuh dari ketinggian)",desc:"垂直養生ネット = dipasang tegak di tepi perancah untuk mencegah material/benda terbang dari perancah. 水平養生ネット = dipasang horizontal untuk mencegah orang atau material jatuh dari tempat tinggi. (Sumber: text5l §5.2.10)"},{id:404,category:"alat_umum",source:"text5l",jp:"トロ箱（トロ舟）",romaji:"toro bako (toro bune)",id_text:"Bak mortar (tro box/trough) — wadah mencampur beton/mortar",desc:"Bak kokoh berbentuk persegi panjang untuk mencampur dan mengaduk semen, mortar, atau beton. Juga disebut トロ舟 atau 舟. Material di dalamnya diaduk dengan alat pengaduk atau sekop. (Sumber: text5l §5.2.9)"},{id:405,category:"alat_umum",source:"text5l",jp:"釘打ち機（コンプレッサー使用）",romaji:"kugiuchi ki (konpuresshaa shiyou)",id_text:"Nail gun (menggunakan compressor — udara bertekanan)",desc:"Alat untuk memukul paku menggunakan tekanan udara dari kompresor (コンプレッサー). Jauh lebih cepat dari memukul paku manual dengan palu. Kompresor = mesin yang memampatkan udara. (Sumber: text5l §5.2.1)"},{id:406,category:"alat_umum",source:"text5l",jp:"フォークリフト",romaji:"fooku rifuto",id_text:"Forklift — kendaraan dengan garpu hidrolik untuk memindahkan palet/material",desc:"Kendaraan dengan garpu (フォーク) yang naik-turun menggunakan tekanan hidrolik. Digunakan untuk memindahkan dan menumpuk material di ketinggian di area proyek dan gudang. (Sumber: text5l §5.2.12)"},{id:407,category:"alat_umum",source:"text5l",jp:"親綱緊張器（おやづなきんちょうき）",romaji:"oyadzuna kinchouki",id_text:"Alat pengencang tali pengaman (safety line tensioner) — untuk pekerjaan ketinggian",desc:"Alat untuk memasang tali induk (親綱) tempat mengaitkan hook harness pekerja ketinggian agar tali tidak kendur. Digunakan oleh pekerja atap, scaffolding, dll. (Sumber: text5l §5.2.13)"},{id:408,category:"alat_umum",source:"text5l",jp:"油圧ショベル（バックホウ）— ブーム・アーム・バケット",romaji:"yuatsu shoberu (bakkuhou) — bumu / aamu / baketto",id_text:"Excavator (backhoe) — boom, arm, bucket + bisa ganti attachment",desc:"Mesin penggali utama konstruksi. Bergerak dengan upper body berputar (旋回体). Attachment bisa diganti: breaker (pemecah batu), ripper, crusher, dll. Berbeda dari ホイールローダ yang memuat, bukan menggali ke belakang. (Sumber: text5l §5.1.1)"},{id:409,category:"alat_umum",source:"text5l",jp:"トラクターショベル（ホイールタイプ vs クローラタイプ）",romaji:"torakutaa shoberu (hoiiru gata vs kuroora gata)",id_text:"Tractor shovel — bucket di DEPAN, ada tipe roda (wheel) dan tipe crawler",desc:"Mesin dengan bucket di bagian depan untuk menyekop dan memuat material ke dump truck. Ada 2 jenis: ホイールタイプ (beroda, lebih lincah) dan クローラタイプ (rantai, untuk medan berat). Bisa dilengkapi fork atau water gun. (Sumber: text5l §5.1.1)"},{id:410,category:"alat_umum",source:"text5l",jp:"トラッククレーン vs クローラクレーン",romaji:"torakku kurein vs kuroora kurein",id_text:"Truck crane (di atas truk) vs Crawler crane (di atas rantai, bisa di segala medan)",desc:"トラッククレーン = crane dipasang di atas truk, lebih mobile di jalan. クローラクレーン = crane bergerak dengan crawler/rantai, bisa beroperasi di salju, tanah tidak rata, dan berbagai medan sulit. (Sumber: text5l §5.1.1)"},{id:411,category:"listrik",source:"text5l",jp:"E管（ねじなし鋼製電線管）— E19, E25",romaji:"ii kan (neji nashi kousei densenkan) — E juu kyuu, E ni juu go",id_text:"E管 = pipa baja tanpa ulir — ukuran dinyatakan dalam diameter luar (E19, E25)",desc:"Pipa baja untuk instalasi listrik yang TIDAK memiliki ulir (ねじ無し). Ukurannya dinyatakan dalam diameter luar dalam mm: E19 = Ø19mm, E25 = Ø25mm. Berbeda dari C管 dan G管 yang berulir. (Sumber: text5l §5.1.2)"},{id:412,category:"listrik",source:"text5l",jp:"カップリング vs コンビネーションカップリング",romaji:"kappuringu vs konbineeshon kappuringu",id_text:"Coupling (sambungkan konduit SEJENIS) vs Combination coupling (sambungkan konduit BERBEDA JENIS)",desc:"カップリング = konektor untuk menyambung 2 konduit dari jenis yang SAMA. コンビネーションカップリング = konektor khusus untuk menyambung konduit dari jenis yang BERBEDA (misal E管 ke PF管). (Sumber: text5l §5.1.2)"},{id:413,category:"listrik",source:"text5l",jp:"ダクターチャンネル（コの字型断面）",romaji:"dakutaa channeru (ko no ji gata danmen)",id_text:"Daktar channel (profil C) — rel penopang cable rack dan konduit",desc:"Rel berbentuk 'コ' (C-channel) yang digunakan sebagai hanger untuk menopang cable rack, konduit, dan berbagai peralatan MEP dari plafon. Penampang berbentuk huruf コ itulah ciri khasnya. (Sumber: text5l §5.1.2)"},{id:414,category:"listrik",source:"text5l",jp:"ダブルナット / サドル",romaji:"daburu natto / sadoru",id_text:"Double nut (mencegah mur kendur akibat getaran) / Saddle (klip konduit ke dinding)",desc:"ダブルナット = dua mur dipasang bersama agar tidak kendur akibat getaran. サドル = braket berbentuk U untuk menempelkan konduit langsung ke dinding atau plafon. (Sumber: text5l §5.1.2)"},{id:415,category:"listrik",source:"text5l",jp:"VVR（丸型ビニルケーブル）vs VVF（平型）",romaji:"VVR (maru gata) vs VVF (hira gata)",id_text:"VVF = kabel vinyl gepeng (flat) vs VVR = kabel vinyl bundar (round)",desc:"VVF (Vinyl Vinyl Flat) = bentuk gepeng/flat, umum untuk instalasi dinding. VVR (Vinyl Vinyl Round) = bentuk bundar, untuk instalasi yang memerlukan kabel lebih fleksibel dan tahan tekanan dari berbagai sisi. (Sumber: text5l §5.1.2)"},{id:416,category:"listrik",source:"text5l",jp:"リレー（電気的スイッチ）vs サーマルリレー",romaji:"riree (denkiteki suicchi) vs saamaru riree",id_text:"Relay (saklar berbasis listrik) vs Thermal relay (pemutus berbasis suhu)",desc:"リレー = saklar yang dikontrol sinyal listrik kecil untuk mengontrol rangkaian listrik lebih besar. サーマルリレー = jenis relay khusus yang memutus sirkuit berdasarkan kenaikan SUHU, digunakan untuk proteksi motor listrik. (Sumber: text5l §5.1.2)"},{id:417,category:"listrik",source:"text5l",jp:"自己融着テープ（じこゆうちゃくテープ）",romaji:"jiko yuuchaku teepu",id_text:"Self-fusing tape — ditarik 2–3× lalu dililitkan, sisi depan & belakang menyatu sendiri",desc:"Pita yang ketika dililitkan sambil ditarik 2–3× akan menyatu sendiri antara permukaan atas dan bawah (tidak ada perekat biasa). Digunakan untuk pemasangan pada pipa air (水道管) dan mencegah kebocoran air. (Sumber: text5l §5.1.2)"},{id:418,category:"listrik",source:"text5l",jp:"差し込みコネクタ / T型コネクタ",romaji:"sashikomi konekuta / chii gata konekuta",id_text:"Insert connector (colok langsung, tanpa crimping) / T-connector (percabangan dari kabel utama)",desc:"差し込みコネクタ = sambungkan kabel hanya dengan memasukkan kawat inti, tanpa perlu crimping. T型コネクタ = digunakan saat ingin mencabangkan kabel dari tengah-tengah kabel induk (母線). (Sumber: text5l §5.1.2)"},{id:419,category:"alat_umum",source:"text5l",jp:"電工ドラム（でんこうドラム）",romaji:"denkou doramu",id_text:"Extension cord reel — gulungan kabel untuk memperpanjang jangkauan listrik",desc:"Alat berupa gulungan kabel yang digunakan untuk memperpanjang kabel listrik di lokasi konstruksi. Saat digunakan, kabel harus dikurangi sepenuhnya agar tidak terjadi panas berlebih akibat induktansi. (Sumber: text5l §5.2.1)"},{id:420,category:"telekomunikasi",source:"text5l",jp:"光ファイバー融着接続（3方式）",romaji:"hikari faibaa yuuchaku setsuzoku (san houshiki)",id_text:"Penyambungan serat optik — 3 metode: fusion splice / mechanical splice / connector",desc:"①融着接続 (fusion splice): ujung dua serat dilelehkan dan disatukan pakai mesin, losses terkecil. ②メカニカルスプライス: sambungan mekanis tanpa pemanasan. ③コネクタ接続: pakai konektor, bisa dilepas-pasang. Selalu pasang ファイバー保護スリーブ SEBELUM splice. (Sumber: text5l §5.1.3)"},{id:421,category:"telekomunikasi",source:"text5l",jp:"光パルス試験機（OTDR）",romaji:"hikari parusu shikenki (OTDR)",id_text:"OTDR — alat ukur panjang jalur serat optik, titik sambungan, dan titik anomali",desc:"Optical Time Domain Reflectometer. Mengukur: ①panjang total jalur serat ②rugi-rugi di titik sambungan (損失) ③lokasi kerusakan atau anomali (反射). Sangat penting untuk QC setelah fusion splice. (Sumber: text5l §5.1.3)"},{id:422,category:"telekomunikasi",source:"text5l",jp:"自己支持ケーブル（じこしじケーブル）",romaji:"jiko shiji keepuru",id_text:"Self-supporting cable — kabel aerial yang sudah terintegrasi dengan kawat penopang",desc:"Kabel yang sudah memiliki kawat penopang (支持線) yang terintegrasi di dalamnya. Dapat dipasang langsung ke tiang listrik tanpa memerlukan つり線 (messenger wire) terpisah. (Sumber: text5l §5.1.3)"},{id:423,category:"pipa",source:"text5l",jp:"パイプ万力 / パイプねじ切機",romaji:"paipu manriki / paipu neji kiri ki",id_text:"Pipe vise (penjepit pipa saat pemotongan) / Pipe threader (mesin buat ulir di pipa)",desc:"パイプ万力 = ragum/penjepit khusus pipa untuk mengamankan pipa saat dipotong atau disambungkan. パイプねじ切機 = mesin untuk membuat ulir (ねじ) di ujung pipa agar bisa disambung dengan fitting berulir. (Sumber: text5l §5.1.4)"},{id:424,category:"pipa",source:"text5l",jp:"面取り器（めんとりき）",romaji:"mentori ki",id_text:"Deburring tool / reamer — membersihkan burr (sisa potongan) dari ujung pipa",desc:"Alat untuk menghilangkan sisa potongan (バリ) dari ujung pipa logam atau pipa PVC setelah dipotong, sehingga permukaan menjadi halus dan aman. (Sumber: text5l §5.1.4)"},{id:425,category:"pipa",source:"text5l",jp:"シール材（液状 vs シールテープ）/ 塩ビ接着剤",romaji:"shiiru zai (ekijou vs shiiru teepu) / enbi setchakuzai",id_text:"Sealant (cair vs tape PTFE) / Lem PVC — mencegah kebocoran fluida di sambungan pipa",desc:"シール材 = material untuk mencegah kebocoran fluida di sambungan pipa berulir: ada tipe cair (液状) dan tape (シールテープ/PTFE). 塩化ビニル樹脂用接着剤 = lem khusus untuk menyambung pipa PVC. (Sumber: text5l §5.1.4)"},{id:426,category:"pipa",source:"text5l",jp:"配管用炭素鋼鋼管（白管 vs 黒管 / SGP / ガス管）",romaji:"haikan you tanso kou kouukan (shiro kan vs kuro kan / SGP)",id_text:"Carbon steel pipe (SGP): 白管 = ada lapisan galvanis, 黒管 = tanpa lapisan",desc:"Pipa baja karbon (SGP / Steel Gas Pipe) untuk uap, air, minyak, gas, udara. 白管 = ada pelapisan seng/galvanis → tahan korosi. 黒管 = tanpa pelapisan. Disebut juga 'ガス管'. (Sumber: text5l §5.1.4)"},{id:427,category:"pipa",source:"text5l",jp:"硬質ポリ塩化ビニル管（VP管 vs VU管・色=グレー）",romaji:"koushitsu pori enka biniru kan (VP kan vs VU kan / iro = guree)",id_text:"Pipa PVC keras (abu-abu): VP管 (tebal) vs VU管 (tipis) — ringan, gesekan kecil, tapi rapuh terhadap benturan",desc:"VP管 = dinding tebal (厚肉管). VU管 = dinding tipis (薄肉管). Keduanya berwarna ABU-ABU. Keunggulan: permukaan dalam sangat halus, gesekan kecil, ringan, mudah dikerjakan. Kelemahan: mudah pecah kena benturan dan panas tinggi. (Sumber: text5l §5.1.4)"},{id:428,category:"pipa",source:"text5l",jp:"ねじ込み式可鍛鋳鉄製管継手（エルボ・チーズ・ソケット・ニップル）",romaji:"nejikomi shiki katan chuutetsu sei kan tsugite (erubo / chiizu / soketto / nippuru)",id_text:"Fitting besi tempa berulir: elbow (belok) / tee (cabang 3) / socket (sambung lurus) / nipple (penghubung pendek)",desc:"Fitting untuk menyambung pipa berulir. エルボ = belok 90°. チーズ (tee) = percabangan 3 arah. ソケット = penyambung lurus. ニップル = penyambung pendek antar fitting. Digunakan dengan シール材 untuk mencegah kebocoran. (Sumber: text5l §5.1.4)"},{id:429,category:"pipa",source:"text5l",jp:"石綿セメント管（アスベスト管）— 現在生産なし",romaji:"sekimen semento kan (asubesuto kan) — genzai seisan nashi",id_text:"Pipa asbes semen — SUDAH TIDAK DIPRODUKSI lagi karena bahaya kesehatan",desc:"Pipa dari campuran asbes, semen, dan pasir kuarsa. Tahan korosi, ringan, murah. Namun karena menghirup asbes menyebabkan penyakit serius (mesothelioma dll), produksinya dihentikan. Bisa ditemui pada pipa lama yang masih terpasang. (Sumber: text5l §5.1.4)"},{id:430,category:"pemadam",source:"text5l",jp:"屋内消火栓設備（1号 / 易操作性1号 / 2号）",romaji:"okunai shouka sen setsubi (ichi gou / isousasei ichi gou / ni gou)",id_text:"Hydrant dalam gedung: 1号 (2 orang) / 易操作性1号 (1 orang, sama kuat) / 2号 (1 orang, lebih kecil)",desc:"屋内消火栓 = alat pemadam kebakaran awal di dalam gedung yang dioperasikan manusia. 1号 = butuh 2 orang. 易操作性1号 = cukup 1 orang, daya sama dengan 1号. 2号 = 1 orang, kapasitas lebih kecil, untuk gedung kecil. (Sumber: text5l §5.1.8)"},{id:431,category:"alat_umum",source:"text5l",jp:"レシプロソー（reciprocating saw）",romaji:"reshipuro soo",id_text:"Reciprocating saw — gergaji dengan gerakan maju-mundur, untuk memotong di celah sempit",desc:"Gergaji elektrik dengan blade panjang yang bergerak maju-mundur. Berguna untuk memotong material di tempat sempit atau posisi sulit yang tidak bisa dijangkau gergaji sirkel. (Sumber: text5l §5.2.1)"},{id:432,category:"alat_umum",source:"text5l",jp:"ダブルスコップ（深い穴掘り用）",romaji:"daburu sukoppu (fukai ana hori you)",id_text:"Double shovel (post hole digger) — untuk menggali lubang dalam seperti pondasi tiang atau tiang listrik",desc:"Sekop berdesain khusus dengan dua bilah yang menjepit tanah, memungkinkan menggali lubang dalam dan sempit secara vertikal. Tanah yang tergali bisa langsung diangkat ke atas. Digunakan untuk memasang tiang listrik atau pancang. (Sumber: text5l §5.2.2)"},{id:433,category:"alat_umum",source:"text5l",jp:"つるはし（鶴嘴）",romaji:"tsuruhashi",id_text:"Pickaxe / cangkul belang — untuk menggali tanah keras dan memecah aspal",desc:"Alat berbentuk kepala logam melengkung dua ujung (seperti paruh bangau), dipasang di gagang kayu. Digunakan untuk menggali tanah keras, batuan, atau memecah lapisan aspal. (Sumber: text5l §5.2.2)"},{id:434,category:"alat_umum",source:"text5l",jp:"タンパー（締め固め）vs たこ（重量突き固め）",romaji:"tanpaa vs tako (juryou tsukikatame)",id_text:"Tamper (plat metal panjang, hentakkan ke bawah) vs Taco (batu/beban berat, tumbuk tanah)",desc:"タンパー = alat pegangan panjang dengan plat datar logam di ujungnya, dihentakkan untuk memadatkan aspal atau tanah. たこ = alat berat sederhana berupa beban masif yang dijatuhkan ke tanah untuk memadatkan dengan berat badannya sendiri. (Sumber: text5l §5.2.2)"},{id:435,category:"alat_umum",source:"text5l",jp:"チョークライン（粉チョーク）vs 墨つぼ",romaji:"chooku rain (kona chooku) vs sumi tsubo",id_text:"Chalk line (menggunakan serbuk kapur) vs Sumitsubo (menggunakan tinta cina/tinta hitam)",desc:"Keduanya untuk menarik garis lurus panjang di permukaan. チョークライン = menggunakan serbuk kapur putih/berwarna, mudah dibersihkan. 墨つぼ = menggunakan tinta hitam tradisional (sumi), lebih permanen, biasa untuk kayu dan beton. (Sumber: text5l §5.2.3)"},{id:436,category:"alat_umum",source:"text5l",jp:"ポンチ（センターポンチ）— 金属にマーキング",romaji:"ponchi (sentaa ponchi) — kinzoku ni maakingu",id_text:"Punch / center punch — membuat titik cekungan di permukaan logam sebagai tanda (マーキング)",desc:"Alat berbentuk batang runcing yang dipukul dengan palu untuk membuat cekungan kecil di permukaan logam. センターポンチ digunakan untuk menandai titik (マーキング) sebelum pengeboran agar mata bor tidak bergeser. (Sumber: text5l §5.2.3)"},{id:437,category:"alat_umum",source:"text5l",jp:"トランシット / セオドライト（角度測定）",romaji:"toranshitto / seodoraiito (kakudo sokutei)",id_text:"Transit / theodolite — alat survei untuk mengukur sudut horizontal dan vertikal",desc:"Alat survei yang menggunakan teleskop kecil untuk mengukur sudut horizontal dan vertikal dari titik referensi. Kini umumnya menggunakan versi digital yang disebut セオドライト. Diletakkan di atas tripod. Berbeda dari トータルステーション yang juga mengukur jarak sekaligus. (Sumber: text5l §5.2.4)"},{id:438,category:"alat_umum",source:"text5l",jp:"おおがね（大矩）— 3:4:5 の比 / 「サシゴ」",romaji:"oogane — san shi go no hi / 'sashigo'",id_text:"Penggaris siku besar — dibuat sendiri di lapangan dengan rasio 3:4:5 (Pythagoras), disebut 'Sashigo'",desc:"Segitiga siku besar untuk mengecek sudut 90° di lapangan. Dibuat dari 3 bahan berukuran rasio 3:4:5 (teorema Pythagoras). Di lapangan konstruksi dikenal dengan nama 'サシゴ' (dari san-shi-go). (Sumber: text5l §5.2.4)"},{id:439,category:"alat_umum",source:"text5l",jp:"ハンマーの種類（ゴム・木づち・かけや・大ハンマー）",romaji:"hammaa no shurui (gomu / kizuchi / kakeya / oo hammaa)",id_text:"Jenis palu: karet (lembut, tidak merusak) / kayu (tradisional) / kayu besar/かけや (pasang struktur kayu) / palu besar (pancang, bongkar)",desc:"ゴムハンマー: kepala karet, pukulan kuat tapi tidak merusak permukaan material. 木づち: kepala kayu, pukulan lebih lemah dari palu besi. かけや: 木づち besar untuk memasang pasak kayu (ほぞ/ほぞ穴). 大ハンマー: gagang panjang + kepala besar → untuk memancang atau pembongkaran. (Sumber: text5l §5.2.6)"},{id:440,category:"alat_umum",source:"text5l",jp:"サンドペーパー（番号が大きい = 目が細かい = なめらか）",romaji:"sando peepaa (bangou ga ookii = me ga komakai = nameraka)",id_text:"Amplas — nomor kecil = kasar, nomor besar = halus",desc:"Kertas amplas dengan partikel pasir/kaca di permukaannya. Nomor KECIL (misalnya #60) = butiran kasar, untuk material kasar. Nomor BESAR (misalnya #400) = butiran halus, untuk finishing permukaan halus. Ada juga 耐水ペーパー (tahan air) dan 布ペーパー (kuat). (Sumber: text5l §5.2.7)"},{id:441,category:"alat_umum",source:"text5l",jp:"ソケットレンチ / ボックスレンチ / 六角レンチ",romaji:"soketto renchi / bokkusu renchi / rokkaku renchi",id_text:"Socket wrench (ganti kepala) / Box wrench (L/T, satu ukuran) / Hex key (untuk baut berlubang segi enam)",desc:"ソケットレンチ = handle + kepala soket yang bisa diganti-ganti untuk berbagai ukuran baut/mur. ボックスレンチ = soket dan handle menyatu (L atau T), untuk satu ukuran. 六角レンチ = batang heksagonal untuk memutar baut berlubang segi enam (六角形の穴). (Sumber: text5l §5.2.8)"},{id:442,category:"alat_umum",source:"text5l",jp:"モルタルミキサ vs コンクリートミキサ（バッチミキサ）",romaji:"morutaru mikisa vs konkuriito mikisa (bacchi mikisa)",id_text:"Mortar mixer (semen+pasir+air) vs Concrete mixer (lebih kuat) — batch mixer = aduk per siklus",desc:"モルタルミキサ = mencampur semen, air, dan pasir → mortar. Ada tipe 100V listrik dan tipe mesin. コンクリートミキサ = lebih kuat dari mortar mixer, untuk beton. バッチミキサ = jenis concrete mixer yang mengaduk satu batch sekaligus per siklus. (Sumber: text5l §5.2.9)"},{id:443,category:"alat_umum",source:"text5l",jp:"ターンバックル",romaji:"taanbukkuru",id_text:"Turnbuckle — alat pengencang tali/kawat dengan memutar badan tengahnya",desc:"Alat logam berbentuk badan berulir yang digunakan untuk mengencangkan atau memperpanjang tali, kabel, atau kawat. Diputar dari tengah untuk mengatur tegangan. (Sumber: text5l §5.2.13)"},{id:444,category:"alat_umum",source:"text5l",jp:"チルホール（手動式ウインチ）",romaji:"chiruhooiru (shuudou shiki uinchi)",id_text:"Tirfor / come-along — winch manual untuk menarik beban berat dengan lever",desc:"Winch manual (手動式) yang menarik wire rope melalui mekanisme lever. Digunakan untuk menarik beban berat di lapangan tanpa listrik. Contoh penggunaan: mengarahkan pohon besar saat ditebang ke arah yang diinginkan. (Sumber: text5l §5.2.13)"},{id:445,category:"alat_umum",source:"text5l",jp:"キリンジャッキ（ネジ推力で垂直に持ち上げる）",romaji:"kirin jakki (neji suiryoku de suichoku ni mochiageru)",id_text:"Screw jack / 'Giraffe jack' — mengangkat beban secara vertikal dengan prinsip ulir sekrup",desc:"Jenis jack yang menggunakan gaya dorong dari putaran ulir (ネジの推力) untuk mengangkat beban secara vertikal. Juga digunakan dalam 山留め工事 (retaining wall) untuk memberi gaya horizontal pada 2 penopang horisontal. (Sumber: text5l §5.2.13)"},{id:446,category:"alat_umum",source:"text5l",jp:"レバーブロック（鉄骨の建て入れ直しに使用）",romaji:"rebaa burokku (tekkotsu no tateirenaoshi ni shiyou)",id_text:"Lever block — alat angkat/kencangkan beban; juga untuk menegakkan kolom baja (建て入れ直し)",desc:"Alat serbaguna untuk mengangkat atau mengencangkan beban menggunakan mekanisme lever+rantai. Salah satu fungsi khusus di konstruksi baja: 建て入れ直し = menegakkan kolom baja agar benar-benar vertikal (垂直を出す). (Sumber: text5l §5.2.13)"},{id:447,category:"keselamatan",source:"text5l",jp:"可搬式作業台（伸び馬）— 手すり付き",romaji:"kahansiki sagyoudai (nobi uma) — tesuri tsuki",id_text:"Portable work platform / 'nobima' — meja kerja dengan kaki teleskopik dan railing",desc:"Alat kerja ketinggian dengan 2 kaki yang bisa disesuaikan panjangnya (伸縮) dan platform kerja di atasnya. Dilengkapi RAILING (手すり). Juga disebut 伸び馬. Bahaya: jangan condongkan badan ke luar atau mendorong dinding → bisa terbalik. (Sumber: text5l §5.2.14)"},{id:448,category:"alat_umum",source:"text5l",jp:"ブロアー（送風機）— 落ち葉や粉塵の吹き飛ばし",romaji:"buroaa (souhuuki) — ochiba ya funjin no fukitobashi",id_text:"Blower — kipas angin kuat untuk meniup sampah ringan, debu, sisa potongan",desc:"Alat elektrik yang menghasilkan aliran udara kencang untuk meniup dan mengumpulkan sampah ringan seperti daun kering, serbuk gergaji, atau debu konstruksi. (Sumber: text5l §5.2.15)"},{id:449,category:"alat_umum",source:"text5l",jp:"ファン（送風機 vs 排風機）",romaji:"fan (souhuuki vs haihuuki)",id_text:"Fan: 送風機 (blower, dorong udara masuk) vs 排風機 (exhaust fan, tarik udara keluar)",desc:"ファン = alat yang memberi energi ke udara di dalam duct agar dapat dialirkan. 送風機 = mengirim udara dari luar ke dalam ruangan (supply). 排風機 = menghisap udara dari dalam ruangan ke luar (exhaust). (Sumber: text5l §5.1.5)"},{id:450,category:"listrik",source:"text5l",jp:"コンテスター",romaji:"kontesutaa",id_text:"Outlet tester — memeriksa polaritas (+/-) dan arde (アース) pada colokan",desc:"Alat ukur yang dicolokkan langsung ke stop kontak untuk memeriksa apakah kabel plus/minus tidak terbalik dan apakah koneksi arde (earth/アース) sudah benar. Berbeda dari テスター/クランプメーター yang mengukur tegangan/arus. (Sumber: text5l §5.1.2)"},{id:451,category:"listrik",source:"text5l",jp:"電動ハンマー（配管経路確保・スラブはつり）",romaji:"dendou hammaa (haikan keiro kakuho / surabu hatsuri)",id_text:"Electric hammer — melubangi dinding/slab untuk jalur pipa konduit (はつり)",desc:"Alat elektrik yang digunakan untuk menghaluskan (斫る/はつる) dinding atau slab beton guna membuka jalur konduit. Bukan untuk pengeboran biasa — khusus pekerjaan ハツリ (demolisi beton parsial) dalam instalasi listrik. (Sumber: text5l §5.1.2)"},{id:452,category:"listrik",source:"text5l",jp:"廻し挽き（まわしびき）",romaji:"mawashibiki",id_text:"Keyhole saw / jigsaw — gergaji untuk membuat lubang di papan gypsum (石膏ボード) dan triplek",desc:"Gergaji khusus berbentuk panjang dan sempit untuk membuat lubang/bukaan (開口部) di papan gypsum atau triplek, misalnya untuk pemasangan saklar atau kotak instalasi. Tidak bisa digunakan untuk material keras. (Sumber: text5l §5.1.2)"},{id:453,category:"listrik",source:"text5l",jp:"塗代カバー（ぬりしろカバー）",romaji:"nurishiro kabaa",id_text:"Plaster ring — penutup sementara kotak tanam sebelum pengecoran/plesteran beton",desc:"Penutup yang dipasang pada kotak outlet yang akan ditanam dalam beton (埋め込まれるボックス). Melindungi kotak dari masuknya beton atau plester saat konstruksi. Dilepas setelah beton mengeras. (Sumber: text5l §5.1.2)"},{id:454,category:"listrik",source:"text5l",jp:"ボックスコネクタ（ねじなし管用 vs PF管用）",romaji:"bokkusu konekuta (neji nashi kan you vs PF kan you)",id_text:"Box connector — komponen penghubung konduit ke outlet box (dipasang di sisi box)",desc:"Komponen yang menyambungkan outlet box (アウトレットボックス) dengan konduit logam (E管/C管) atau konduit PF. Ada 2 tipe: ねじなし管用ボックスコネクタ dan PF管用ボックスコネクタ. Dipasang di sisi kotak, berbeda dari カップリング yang menyambungkan antar konduit. (Sumber: text5l §5.1.2)"},{id:455,category:"listrik",source:"text5l",jp:"ラジアスクランプ",romaji:"rajiasu kuranpu",id_text:"Radius clamp — penghubung listrik (bukan fisik) antara kotak baja dan konduit logam",desc:"Fitting logam yang digunakan untuk menyambungkan secara LISTRIK (電気的に接続) antara outlet box baja (鋼製アウトレットボックス) dan konduit logam. Memastikan kontinuitas pembumian/grounding antara keduanya. (Sumber: text5l §5.1.2)"},{id:456,category:"listrik",source:"text5l",jp:"圧縮端子（あっしゅくたんし）vs 圧着端子 + 圧縮機",romaji:"asshuku tanshi vs acchaku tanshi + asshuku ki",id_text:"Compression terminal (tekanan besar, pakai mesin 圧縮機) vs Crimp terminal (pakai tang 圧着ペンチ)",desc:"圧縮端子 = terminal yang dikencangkan dengan memberikan tekanan besar menggunakan mesin khusus (圧縮機). Berbeda dari 圧着端子 yang dikrimping dengan tang tangan (圧着ペンチ). 圧縮機 = alat pengencang terminal tekan. (Sumber: text5l §5.1.2)"},{id:457,category:"listrik",source:"text5l",jp:"棒端子（ぼうたんし）",romaji:"bou tanshi",id_text:"Ferrule / pin terminal — ujung terminal berbentuk batang (棒状)",desc:"Jenis 圧着端子 yang ujungnya berbentuk batang (棒状). Digunakan untuk memasukkan ujung kabel ke dalam terminal klem atau blok terminal dengan aman, mencegah kabel terurai. Dikrimping menggunakan 圧着ペンチ. (Sumber: text5l §5.1.2)"},{id:458,category:"listrik",source:"text5l",jp:"COS（Change Over Switch）",romaji:"shii ou esu (chenji oobaa suicchi)",id_text:"COS = Change Over Switch — saklar pemindah sumber daya",desc:"Singkatan dari Change Over Switch. Saklar yang digunakan untuk memindahkan (切り換える) antara dua sumber daya, misalnya dari PLN ke generator saat terjadi pemadaman. Disingkat COS dan dibaca 'シーオーエス'. (Sumber: text5l §5.1.2)"},{id:459,category:"listrik",source:"text5l",jp:"ベルマウス",romaji:"berumausu",id_text:"Bell mouth — pelindung/panduan kabel saat ditarik agar tidak tergores",desc:"Komponen berbentuk corong yang dipasang di ujung konduit atau bukaan pipa saat menarik kabel ke dalamnya. Mencegah kabel tergores atau rusak (傷をつけない) saat proses penarikan (引き込み). (Sumber: text5l §5.1.2)"},{id:460,category:"listrik",source:"text5l",jp:"アースボンド線 vs ノンボンド継手",romaji:"aasu bondo sen vs nonbondo tsugite",id_text:"Earth bond wire (sambung rak kabel secara listrik) vs Non-bond joint (tidak perlu kabel bumi)",desc:"Saat menyambung dua cable rack, perlu 電気的接続 (sambungan listrik/grounding) di antara keduanya menggunakan アースボンド線. Alternatifnya, gunakan ノンボンド継手 (fitting khusus yang sudah menyediakan koneksi listrik sendiri tanpa kabel tambahan). (Sumber: text5l §5.1.2)"},{id:461,category:"listrik",source:"text5l",jp:"エンドカバー / スタットバー",romaji:"endo kabaa / sutatto baa",id_text:"End cover (penutup di titik keluaran kabel dari plafon) / Stud bar (braket box ke tulangan baja)",desc:"エンドカバー = penutup yang dipasang di tempat keluarnya kabel dari plafon, melindungi titik keluar. スタットバー = braket logam yang memanfaatkan tulangan (配筋) dinding/slab untuk memasang kotak instalasi secara mudah tanpa mengebor. (Sumber: text5l §5.1.2)"},{id:462,category:"telekomunikasi",source:"text5l",jp:"ケーブル繰り出し機（滑車式）",romaji:"keepuru kuri dashi ki (kassha shiki)",id_text:"Cable pay-out machine (menggunakan katrol) — mempermudah penarikan kabel dari drum",desc:"Alat berbasis katrol (滑車) yang digunakan untuk mengeluarkan kabel dari drum kabel secara mudah dan terkontrol. Menghindari kerusakan kabel akibat tarikan yang tidak merata. Digunakan dalam pekerjaan pemasangan kabel aerial (架空配線). (Sumber: text5l §5.1.3)"},{id:463,category:"telekomunikasi",source:"text5l",jp:"金車（きんしゃ）",romaji:"kinsha",id_text:"Cable block / sheave — katrol yang dipasang di kawat gantung untuk memudahkan penarikan kabel",desc:"Katrol (滑車) kecil yang dipasang pada kawat gantung (つり線) selama proses penarikan kabel telekomunikasi aerial. Kabel diletakkan di atas roda katrol sehingga bisa ditarik dengan mudah tanpa gesekan berlebih. Setelah kabel terpasang, 金車 dilepas. (Sumber: text5l §5.1.3)"},{id:464,category:"pipa",source:"text5l",jp:"ポンプ（配管内の水を遠く・高くへ）",romaji:"ponpu (haikan nai no mizu wo tooku / takaku he)",id_text:"Pompa — memberi energi pada air dalam pipa agar mengalir jauh atau naik ke atas",desc:"Alat mekanis yang memberikan energi kepada air di dalam sistem pipa sehingga air dapat mengalir ke tempat yang jauh atau dipompa ke lantai yang lebih tinggi. Komponen penting dalam sistem distribusi air gedung. (Sumber: text5l §5.1.4)"},{id:465,category:"pipa",source:"text5l",jp:"ねじゲージ（管・管継手の検査用計器）",romaji:"neji geeji (kan / kan tsugite no kensa you keiki)",id_text:"Thread gauge — alat ukur kalibrasi ulir pada pipa dan fitting",desc:"Alat pengukur yang digunakan untuk memeriksa dan memverifikasi ulir pada pipa (管) dan fitting pipa (管継手) agar sesuai standar. Memastikan kecocokan ulir sehingga sambungan tidak bocor. (Sumber: text5l §5.1.4)"},{id:466,category:"alat_umum",source:"text5l",jp:"レーキ vs ジョレン",romaji:"reeki vs joren",id_text:"Rake (meratakan tanah/aspal) vs Joren/hoe (mengumpulkan tanah/sampah)",desc:"レーキ = alat bergigi banyak untuk meratakan tanah (土壌を均す) atau mengumpulkan daun. Model tanpa gigi untuk aspal. ジョレン = alat mirip cangkul lebar untuk mengumpulkan/menggeser tanah atau puing (土砂・ごみをかき集める). (Sumber: text5l §5.2.2)"},{id:467,category:"alat_umum",source:"text5l",jp:"のこぎり（のこ）",romaji:"nokogiri (noko)",id_text:"Gergaji — memotong kayu, logam, dan pipa",desc:"Alat dengan banyak mata pisau (目) pada plat logam untuk memotong kayu, logam, dan pipa. Disingkat 'のこ' di lapangan. Jenis berbeda tersedia untuk material berbeda — pastikan menggunakan gergaji yang sesuai material yang dipotong. (Sumber: text5l §5.2.5)"},{id:468,category:"alat_umum",source:"text5l",jp:"くい切り（ニッパー）vs ペンチ",romaji:"kui kiri (nippaa) vs penchi",id_text:"Diagonal cutter/nippers (memotong kawat, kepala paku) vs Pliers (membengkokkan + memotong)",desc:"くい切り (ニッパー) = alat penjepit dengan rahang mirip gunting untuk memotong kawat, tulangan kecil, atau kepala paku. ペンチ = alat dengan bagian penjepit bergigi + bagian pemotong, digunakan untuk membengkokkan dan memotong sekaligus. (Sumber: text5l §5.2.5)"},{id:469,category:"alat_umum",source:"text5l",jp:"やすり（金属用 vs 木工用）+ ワイヤーブラシ",romaji:"yasuri (kinzoku you vs mokkougou) + waiyaa burashi",id_text:"File/kikir (logam atau kayu) + Wire brush (bersihkan karat, cat, & mata kikir yang tersumbat)",desc:"やすり = alat mengamplas permukaan logam atau kayu, ada berbagai jenis sesuai material. ワイヤーブラシ = sikat dengan kawat logam keras, digunakan untuk: ①membersihkan karat ②mengelupas cat ③membersihkan sumbatan pada mata kikir (やすりの目詰まり除去). (Sumber: text5l §5.2.7)"},{id:470,category:"alat_umum",source:"text5l",jp:"タッピングねじ vs 釘（くぎ）の種類",romaji:"tappingu neji vs kugi no shurui",id_text:"Tapping screw (buat ulir sendiri, butuh obeng) vs berbagai jenis paku (butuh palu)",desc:"タッピングねじ = sekrup yang sekaligus membuat alur ulir sendiri di material saat dikencangkan — tidak butuh pre-tap. 釘 = paku dipukul dengan palu. Jenis paku: スクリュー釘, コンクリート釘, ケーシング釘, トタン釘 — dipilih sesuai material dan kondisi. (Sumber: text5l §5.2.8)"},{id:471,category:"alat_umum",source:"text5l",jp:"ふるい（目の大きさで材料を仕分け）",romaji:"furui (me no ookisa de zairyou wo shiwake)",id_text:"Saringan/ayakan — memilah material berdasarkan ukuran butir",desc:"Alat berupa rangka dengan jaring kawat (網) untuk memisahkan material berdasarkan ukuran. Contoh penggunaan: memisahkan tanah halus dari kerikil hasil galian (掘り出した土砂から細かい土と砂利を分ける). Ukuran jaring dipilih sesuai kebutuhan. (Sumber: text5l §5.2.9)"},{id:472,category:"alat_umum",source:"text5l",jp:"ウェス・バケツ（亜鉛鉄板製）・ひしゃく",romaji:"uesu / baketsu (aen teppa sei) / hishaku",id_text:"Kain lap oli (ウェス) / Ember konstruksi zinc-plated (バケツ) / Centong air (ひしゃく)",desc:"ウェス = kain untuk mengelap cairan seperti oli atau bahan kimia. バケツ = ember untuk membawa air — versi konstruksi dari pelat besi berlapis seng (亜鉛鉄板製) agar tahan lama. ひしゃく = alat bergagang untuk mengambil air dari ember/bak. (Sumber: text5l §5.2.11)"},{id:473,category:"alat_umum",source:"text5l",jp:"ブルーシート vs ベニヤ（養生材料）",romaji:"buruu shiito vs beniya (youjou zairyou)",id_text:"Blue sheet (proteksi lantai dari cat/debu) vs Plywood tipis (proteksi lantai dari goresan material)",desc:"ブルーシート = lembaran biru plastik untuk melindungi area lantai yang dilalui dari tetesan cat atau debu. ベニヤ = plywood tipis diletakkan di lantai untuk mencegah goresan akibat material atau pekerjaan berat. Keduanya adalah 養生材料 (protective sheeting). (Sumber: text5l §5.2.10)"},{id:474,category:"alat_umum",source:"text5l",jp:"そり vs ころ（重量物の移動）",romaji:"sori vs koro (juryoubutsu no idou)",id_text:"Sledge/sled (tarik beban berat di atas) vs Log rollers (batu/kayu bulat di bawah benda berat)",desc:"そり = rangka landai untuk menopang dan menarik beban berat seperti batu. ころ = beberapa batang kayu/pipa bulat (丸太) yang disusun di bawah benda berat agar bisa digeser — memanfaatkan prinsip rolling. (Sumber: text5l §5.2.12)"},{id:475,category:"alat_umum",source:"text5l",jp:"ほうき + ちりとり + ブロアー",romaji:"houki + chiritori + buroaa",id_text:"Sapu (menyapu) / Pengki (mengumpulkan sampah) / Blower (meniup debu/daun dengan udara)",desc:"ほうき = sapu dengan ijuk/serat untuk membersihkan lantai. ちりとり = pengki untuk mengumpulkan sampah sapuan. ブロアー (送風機) = alat penghasil angin kuat untuk meniup sampah ringan seperti daun kering atau serbuk gergaji agar terkumpul. (Sumber: text5l §5.2.15)"},{id:476,category:"alat_umum",source:"text5l",jp:"可搬式作業台（伸び馬）vs 脚立 vs ローリングタワー",romaji:"kahanshiki sagyoudai (nobi uma) vs kyatatsu vs rooringu tawaa",id_text:"3 alat kerja ketinggian: meja kerja teleskopik / tangga A / perancah beroda",desc:"可搬式作業台 (伸び馬): kaki disesuaikan + platform + railing. 脚立: 2 tangga digabung bentuk A, DILARANG berdiri/duduk di papan atas dan dilarang menunggangi. ローリングタワー: perancah multi-lantai beroda (kastor 4 sudut), ada standar keselamatan UU. Pilihan disesuaikan ketinggian dan luas area kerja. (Sumber: text5l §5.2.14)"},{id:477,category:"pipa",source:"text5l",jp:"チューブベンダー（銅管専用）",romaji:"chuubu bendaa (douukan senyou)",id_text:"Tube bender — alat membengkokkan pipa tembaga (AC refrigerant line)",desc:"Alat khusus untuk membengkokkan pipa tembaga (銅管) tanpa membuatnya gepeng atau retak. Penting dalam instalasi pipa refrigeran AC (冷媒配管). Berbeda dari ベンダー listrik yang digunakan untuk membengkokkan konduit logam. (Sumber: text5l §5.1.4)"},{id:478,category:"listrik",source:"text5l",jp:"盤（ばん）— 自立盤 vs 壁掛け盤 + チャンネルベース",romaji:"ban — jiritsuhan vs kabekake ban + channeru beesu",id_text:"Panel listrik: 自立盤 (berdiri di lantai) vs 壁掛け盤 (dipasang ke dinding) + Channel base (dudukan)",desc:"盤 (panel) = perangkat distribusi listrik berisi breaker untuk membagi daya ke berbagai peralatan. 自立盤 = diletakkan di lantai berdiri sendiri. 壁掛け盤 = dipasang di dinding. チャンネルベース = dudukan/alas besi canal untuk panel 自立盤 agar terangkat sedikit dari lantai. (Sumber: text5l §5.1.2)"},{id:479,category:"listrik",source:"text5l",jp:"IV（Indoor PVC）— 屋内配線用ビニル絶縁電線",romaji:"ai bui (indoa PVC) — okunai haisen you biniru zetsuen densen",id_text:"IV wire = kabel listrik berinsulasi PVC untuk penggunaan dalam ruangan (bukan kabel berselubung)",desc:"IV = Indoor PVC の略. Kawat listrik tunggal berinsulasi vinil, digunakan untuk 屋内配線 (instalasi dalam ruangan). BUKAN kabel berselubung luar — hanya insulasi tunggal. Harus dipasang dalam konduit atau cable rack. Berbeda dari VVF/VVR yang memiliki selubung luar. (Sumber: text5l §5.1.2)"},{id:480,category:"listrik",source:"text5l",jp:"露出ボックス vs 露出スイッチボックス",romaji:"roshutsu bokkusu vs roshutsu suicchi bokkusu",id_text:"Surface-mount box (dipasang menempel di luar dinding) vs Surface-mount switch box (untuk saklar & stopkontak)",desc:"露出ボックス = kotak instalasi yang dipasang menempel di permukaan dinding (露出させて取り付ける), berbeda dari kotak tanam. 露出スイッチボックス = kotak khusus untuk menyimpan komponen kabel saklar (スイッチ) dan stopkontak (コンセント) secara surface-mount. (Sumber: text5l §5.1.2)"},{id:481,category:"alat_umum",source:"text5l",jp:"集塵機（しゅうじんき）vs 集塵丸のこ",romaji:"shuujin ki vs shuujin maruno ko",id_text:"Dust collector (mesin vakum debu) vs Circular saw dengan penampung debu terintegrasi",desc:"集塵機 = mesin vakum khusus untuk mengumpulkan debu halus (粉塵) yang terbang saat memotong beton atau keramik. 集塵丸のこ = gergaji sirkel dengan fitur pengumpul debu: ada tipe dengan kotak debu (ダストボックス) terintegrasi dan tipe yang disambung ke 集塵機 terpisah. (Sumber: text5l §5.2.1)"},{id:482,category:"keselamatan",source:"text5l",jp:"高所作業車（バスケット高さ 2m以上）",romaji:"kousho sagyousha (basuketto takasa 2 meetoru ijou)",id_text:"Aerial work platform (AWP) — kendaraan dengan keranjang kerja di ketinggian ≥2m",desc:"Kendaraan khusus dengan keranjang (バスケット) yang dapat dinaikkan ke ketinggian 2 meter ke atas (2m以上) menggunakan mekanisme boom atau scissor. Berbeda dari ローリングタワー yang tidak bermesin. Operator memerlukan lisensi khusus. (Sumber: text5l §5.2.14)"},{id:483,category:"alat_umum",source:"text5l",jp:"電動ブロックカッター vs 丸のこ",romaji:"dendou burokku kattaa vs maruno ko",id_text:"Electric block cutter (khusus beton/blok) vs Circular saw (kayu, logam, dll.)",desc:"電動ブロックカッター = alat elektrik khusus untuk memotong material berbasis beton seperti blok beton, paving, dan batu. 丸のこ = gergaji sirkel serba guna untuk kayu, logam, dan bahan bangunan umum. Pilih sesuai material yang dipotong. (Sumber: text5l §5.2.1)"},{id:484,category:"alat_umum",source:"text5l",jp:"下げ振り（さげふり）— 柱・壁の垂直確認",romaji:"sagefuri — hashira / kabe no suichoku kakunin",id_text:"Plumb bob — bandul berujung runcing untuk memverifikasi vertikalitas kolom/dinding",desc:"Bandul logam berujung runcing kerucut yang digantung dengan tali untuk memeriksa apakah kolom atau dinding benar-benar tegak lurus (垂直). Dipasang pada 下げ振り保持器 (holder) di atas kolom, kemudian jarak tali ke permukaan kolom diukur dari atas dan bawah. (Sumber: text5l §5.2.4)"},// ── GAP SUPPLEMENT v14→v15 — text5l audit (19 kartu terlewat) ───────────
{id:485,category:"alat_umum",source:"text5l",jp:"ダンプトラック",romaji:"danpu torakku",id_text:"Dump truck — kendaraan angkut tanah/batu dengan bak yang bisa miring",desc:"Kendaraan khusus pengangkut tanah, batuan dll dengan bak (荷台) yang bisa dimiringkan untuk membuang muatan (ダンプ). Umumnya dikombinasikan dengan 油圧ショベル atau ホイールローダ. (Sumber: text5l §5.1.1)"},{id:486,category:"listrik",source:"text5l",jp:"VVFストリッパー",romaji:"VVF sutorippa",id_text:"VVF stripper — pengupas selubung luar DAN isolasi inti kabel VVF sekaligus",desc:"Alat khusus untuk mengupas dua lapisan sekaligus pada kabel VVF: selubung luar (外装) dan isolasi inti kawat (芯線被覆). Berbeda dari ワイヤーストリッパー yang hanya mengupas satu lapisan. (Sumber: text5l §5.1.2)"},{id:487,category:"listrik",source:"text5l",jp:"ストリップゲージ",romaji:"sutorippu geeji",id_text:"Strip gauge — alat ukur panjang kupasan isolasi, dipasang pada wire stripper",desc:"Gauge untuk mengukur panjang kupasan isolasi kabel (被覆を剥き取る長さ). Dipasang menjadi satu pada ワイヤーストリッパー dan digunakan bersama. (Sumber: text5l §5.1.2)"},{id:488,category:"listrik",source:"text5l",jp:"コンセント（埋込型・露出型）",romaji:"konsento (umekomigata / roshutsu gata)",id_text:"Stopkontak — tipe tanam (埋込型) vs surface-mount (露出型)",desc:"コンセント = stopkontak dinding, umumnya 単相100V. ①埋込型 = ditanam dalam dinding, dipasang via 埋込連用取付枠 (mounting frame tanam). ②露出型 = menempel di permukaan dinding. (Sumber: text5l §5.1.2)"},{id:489,category:"listrik",source:"text5l",jp:"役物（やくもの）",romaji:"yakumono",id_text:"Fitting/aksesori khusus — komponen bentuk spesial untuk posisi atau tujuan tertentu",desc:"Komponen berbentuk khusus (特殊な形状をした部材) yang digunakan sesuai lokasi atau tujuan tertentu, misalnya dalam instalasi kabel rack. Mencakup konektor sudut, sambungan khusus, dll. (Sumber: text5l §5.1.2)"},{id:490,category:"listrik",source:"text5l",jp:"振れ止め（ふれどめ）",romaji:"furedome",id_text:"Anti-sway brace — penopang diagonal agar raceway tidak bergoyang",desc:"Komponen penopang yang dipasang miring/diagonal (斜めに支持) agar レースウェイ tidak bergoyang (揺れない). Dipasang antara raceway dan struktur bangunan. (Sumber: text5l §5.1.2)"},{id:491,category:"listrik",source:"text5l",jp:"吊りボルト支持金具（つりボルトしじかなぐ）",romaji:"tsuri boruto shiji kanagu",id_text:"Hanging bolt bracket — pasang baut gantung ke profil baja/deck TANPA melubangi",desc:"Fitting yang memungkinkan pemasangan 吊りボルト (baut gantung) pada profil baja (形鋼) atau dek (デッキプレート) tanpa perlu melubangi (穴を開けることなく). Tersedia berbagai bentuk sesuai titik pasang. (Sumber: text5l §5.1.2)"},{id:492,category:"listrik",source:"text5l",jp:"リード端子（りーどたんし）",romaji:"riido tanshi",id_text:"Lead terminal — penghubung antara batang grounding (接地棒) dan kabel grounding (接地線)",desc:"Komponen yang menghubungkan 接地棒 (grounding rod) dengan 接地線 (kabel grounding). Berfungsi sebagai junction point antara rod yang ditancapkan ke tanah dan kabel yang diteruskan ke panel. (Sumber: text5l §5.1.2)"},{id:493,category:"telekomunikasi",source:"text5l",jp:"メタルケーブル（同軸・ツイストペア）",romaji:"metaru keepuru",id_text:"Metal cable — kabel tembaga, mencakup coaxial dan twisted pair",desc:"Kabel telekomunikasi berbasis tembaga (銅) yang mengirim sinyal secara elektrik (電気信号). Mencakup: ①同軸ケーブル (coaxial, untuk antena TV) dan ②UTPツイストペアケーブル (twisted pair, untuk LAN/telepon). Berbeda dari 光ファイバー. (Sumber: text5l §5.1.3)"},{id:494,category:"telekomunikasi",source:"text5l",jp:"ファイバー保護スリーブ",romaji:"faibaa hogo suriibu",id_text:"Fiber protection sleeve — pelindung titik sambungan fusion; WAJIB dipasang SEBELUM splicing",desc:"Sleve pelindung titik sambungan 融着接続. Dipasang dengan dipanaskan (熱で収縮). KRITIS: harus dimasukkan ke kabel SEBELUM fusion dilakukan karena tidak bisa dimasukkan dari belakang setelah selesai (後からでは挿入できない). (Sumber: text5l §5.1.3)"},{id:495,category:"telekomunikasi",source:"text5l",jp:"ファイバーホルダ",romaji:"faibaa horuda",id_text:"Fiber holder — dudukan serat optik saat proses jacket removal, cutting, dan fusion",desc:"Alat dudukan untuk memegang serat optik (光ファイバー) secara stabil saat dipasang ke ジャケットリムーバ, ファイバカッター, atau 融着接続器. (Sumber: text5l §5.1.3)"},{id:496,category:"telekomunikasi",source:"text5l",jp:"ジャケットリムーバ",romaji:"jaketto rimuuba",id_text:"Jacket remover — alat pengupas selubung/coating serat optik sebelum fusion",desc:"Alat untuk mengupas/membuang lapisan pelindung (被覆/jacket) dari ujung serat optik sebelum pemotongan dan penyambungan fusion. Berbeda dari ワイヤーストリッパー yang untuk kabel listrik biasa. (Sumber: text5l §5.1.3)"},{id:497,category:"telekomunikasi",source:"text5l",jp:"同軸ケーブルチェッカー（どうじくけーぶるちぇっかー）",romaji:"doujiku keepuru chekkaa",id_text:"Coaxial cable checker — alat verifikasi koneksi (導通) kabel koaksial",desc:"Alat untuk memeriksa kondisi sambungan/konduktivitas (導通を確認) kabel koaksial. Berbeda dari LANテスター yang memeriksa 8 kawat kabel LAN. (Sumber: text5l §5.1.3)"},{id:498,category:"pipa",source:"text5l",jp:"冷媒用銅管（れいばいようどうかん）",romaji:"reibaiyou doukan",id_text:"Refrigerant copper pipe — pipa tembaga tanpa sambungan untuk sirkulasi refrigerant AC",desc:"Pipa yang mensirkulasikan refrigerant antara unit luar (室外機) dan unit dalam (室内機) AC. Terbuat dari tembaga/paduan tembaga berupa pipa tanpa sambungan (銅及び銅合金の継目無管). (Sumber: text5l §5.1.4)"},{id:499,category:"pipa",source:"text5l",jp:"エアフィルター（空調）",romaji:"ea firutaa (kuuchou)",id_text:"Air filter (AC/HVAC) — penyaring debu dan partikel kecil dari udara",desc:"Komponen AC/HVAC yang menyaring (取り除く) debu dan partikel kecil (ほこりや小さなごみ) dari udara sebelum masuk sistem. Komponen rutin yang perlu dibersihkan berkala untuk menjaga efisiensi sistem. (Sumber: text5l §5.1.5)"},{id:500,category:"pipa",source:"text5l",jp:"衛生器具設備（えいせいきぐせつび）",romaji:"eisei kigu setsubi",id_text:"Sanitary fixtures — peralatan air: toilet, wastafel, bak mandi, sink, dll",desc:"Peralatan yang mengeluarkan, menyimpan, atau membuang air (水/お湯を出したり貯めたり排出したりする設備). Mencakup: 蛇口 (keran), 大便器 (toilet duduk), 小便器 (urinoir), 洗面器 (wastafel), 風呂 (bak mandi), 流し (sink dapur). (Sumber: text5l §5.1.6)"},{id:501,category:"alat_umum",source:"text5l",jp:"砥石（といし）",romaji:"toishi",id_text:"Whetstone/grinding stone — batu asah untuk pahat, ketam, dan alat tajam lainnya",desc:"Batu untuk mengasah (切削・磨く) logam atau batu. Versi balok kecil (直方体) digunakan untuk mengasah のみ (pahat) atau かんな (ketam kayu) agar tetap tajam. (Sumber: text5l §5.2.7)"},{id:502,category:"alat_umum",source:"text5l",jp:"ドライバー（プラス・マイナス）",romaji:"doraibaa (purasu / mainasu)",id_text:"Screwdriver — alat putar sekrup; pilih ukuran TEPAT agar alur tidak rusak (なめる)",desc:"Alat memutar sekrup (ネジを回す工具). Ada プラス (plus/Phillips) dan マイナス (flathead) sesuai bentuk alur kepala sekrup. Gunakan ukuran TEPAT agar alur tidak rusak (なめる = stripped). Khusus 電工用: gripnya besar & bulat agar mudah digenggam. (Sumber: text5l §5.2.8)"},{id:503,category:"alat_umum",source:"text5l",jp:"ボルト・ナット・ワッシャー",romaji:"boruto / natto / wasshaa",id_text:"Bolt + nut + washer — tiga komponen pengikat yang digunakan sebagai satu set",desc:"ボルト (bolt, おねじ) + ナット (nut, めねじ) = sepasang pengunci. ワッシャー (washer) dipasang di antara keduanya untuk mencegah kerusakan permukaan dan mengurangi risiko kendor. Umumnya digunakan sebagai satu set. (Sumber: text5l §5.2.8)"},// ── KARTU BARU v16 — text6l.pdf (Agent E, deep re-scan) ──────────────────
{id:504,category:"jenis_kerja",source:"text6l",jp:"建設工事の特徴②　土地の制約（とちのせいやく）",romaji:"tochi no seiyaku",id_text:"Karakteristik konstruksi: terikat pada lahan tertentu",desc:"Setiap proyek melekat pada lahan yang unik sehingga kondisi identik tidak pernah berulang; berbeda dari produksi pabrik. Tidak ada dua pekerjaan konstruksi dengan kondisi dan syarat yang sama. (Sumber: text6l §6.1.1)"},{id:505,category:"jenis_kerja",source:"text6l",jp:"建設工事の特徴③　自然条件による影響（しぜんじょうけん）",romaji:"shizen jouken ni yoru eikyou",id_text:"Karakteristik konstruksi: dipengaruhi kondisi alam",desc:"Pekerjaan konstruksi umumnya di luar ruangan sehingga terpengaruh topografi, musim, dan cuaca — faktor tidak pasti yang tidak bisa sepenuhnya dikendalikan. (Sumber: text6l §6.1.1)"},{id:506,category:"jenis_kerja",source:"text6l",jp:"建設工事の特徴④　社会的制約（しゃかいてきせいやく）",romaji:"shakai teki seiyaku",id_text:"Karakteristik konstruksi: terikat regulasi sosial",desc:"Karena produksi dilakukan di lokasi asli (現地生産), wajib memenuhi peraturan keselamatan dan lingkungan sekitar; hukum dan lingkungan sosial berbeda di tiap lokasi sehingga perlu penyesuaian. (Sumber: text6l §6.1.1)"},{id:507,category:"jenis_kerja",source:"text6l",jp:"施工計画（せこうけいかく）",romaji:"sekou keikaku",id_text:"Rencana pelaksanaan konstruksi",desc:"Rencana berdasarkan dokumen desain (gambar, spesifikasi, kontrak) untuk mengerjakan konstruksi dengan kualitas baik, biaya minimal, selesai tepat waktu, nol kecelakaan, dan ramah lingkungan. Mencakup 5M: Men, Materials, Methods, Machinery, Money. (Sumber: text6l §6.1.2)"},{id:508,category:"jenis_kerja",source:"text6l",jp:"施工要領書（せこうようりょうしょ）",romaji:"sekou youryou sho",id_text:"Dokumen prosedur pelaksanaan pekerjaan harian",desc:"Memuat detail teknis pelaksanaan pekerjaan: konfirmasi gambar, kondisi lapangan, urutan kerja, penempatan tenaga, serta persiapan alat dan material. Wajib dipahami sebelum memulai pekerjaan hari itu. (Sumber: text6l §6.1.4)"},{id:509,category:"karier",source:"text6l",jp:"キャリアアップカード・作業免許の携帯（さぎょうめんきょのけいたい）",romaji:"kyaria appu kaado / sagyou menkyo no keitai",id_text:"Kartu CCAS dan surat izin kerja — wajib dibawa saat bekerja",desc:"Salah satu item konfirmasi施工前: wajib memastikan pekerja membawa キャリアアップカード (CCAS) dan semua lisensi/sertifikat yang diperlukan untuk pekerjaan hari itu. (Sumber: text6l §6.1.4)"},{id:510,category:"keselamatan",source:"text6l",jp:"品質管理（ひんしつかんり）— QCDSE の Q",romaji:"hinshitsu kanri",id_text:"Manajemen kualitas — Q dalam QCDSE",desc:"Manajemen untuk memenuhi kualitas yang diminta pemberi kerja; mencakup inspeksi kualitas, uji material, uji konstruksi, serta kontrol dimensi dan bentuk sesuai rencana kualitas. (Sumber: text6l §6.1.3)"},{id:511,category:"keselamatan",source:"text6l",jp:"予算の管理（よさんのかんり）— QCDSE の C",romaji:"yosan no kanri",id_text:"Manajemen biaya — C dalam QCDSE",desc:"Mengelola dana yang tersedia di lapangan (biaya material, tenaga kerja, biaya lapangan) agar tidak melampaui anggaran proyek yang ditetapkan. (Sumber: text6l §6.1.3)"},{id:512,category:"keselamatan",source:"text6l",jp:"工程管理（こうていかんり）— QCDSE の D",romaji:"koutei kanri",id_text:"Manajemen jadwal — D dalam QCDSE",desc:"Koordinasi dengan kontraktor utama dan kontraktor lain agar pekerjaan selesai dalam batas waktu kontrak (工期内) tanpa keterlambatan. (Sumber: text6l §6.1.3)"},{id:513,category:"keselamatan",source:"text6l",jp:"安全管理（あんぜんかんり）— QCDSE の S",romaji:"anzen kanri",id_text:"Manajemen keselamatan — S dalam QCDSE",desc:"Mencakup pencegahan jatuh, benda jatuh, dan penyakit akibat kerja; dilaksanakan melalui KY training harian, patroli, rapat keselamatan 5S, dan target nol kecelakaan (無事故・無災害). (Sumber: text6l §6.1.3)"},{id:514,category:"keselamatan",source:"text6l",jp:"環境保全管理（かんきょうほぜんかんり）— QCDSE の E",romaji:"kankyou hozen kanri",id_text:"Manajemen pelestarian lingkungan — E dalam QCDSE",desc:"Meminimalkan dampak kebisingan, getaran, dan pencemaran air akibat konstruksi; wajib mematuhi standar yang ditetapkan undang-undang dan peraturan daerah. (Sumber: text6l §6.1.3)"},{id:515,category:"alat_umum",source:"text6l",jp:"レーザー照射器（レーザーしょうしゃき）",romaji:"reezaa shousha ki",id_text:"Alat laser untuk墨出し — penanda posisi dan level",desc:"Memancarkan cahaya laser menggantikan 墨つぼ konvensional; memudahkan pengecekan sudut siku (直角) dan kerataan horizontal (水平) dengan cepat dan akurat. (Sumber: text6l §6.1.5)"},{id:516,category:"alat_umum",source:"text6l",jp:"基準墨・親墨（きじゅんすみ・おやすみ）— 墨出し3種類",romaji:"kijun sumi / oya sumi — sumidashi 3 shurui",id_text:"Tiga jenis pekerjaan墨出し: posisi/level, komponen, pemasangan",desc:"①基準墨・親墨 = posisi, ketinggian (GL/FL), dan通り芯 sebagai acuan utama. ②部材加工用墨付け = marking potongan/dimensi komponen (pipa, tulangan, plat). ③取付け位置出し = posisi pemasangan perangkat dan fitting. (Sumber: text6l §6.1.5)"},{id:517,category:"pipa",source:"text6l",jp:"A呼称 vs B呼称（Aこしょう vs Bこしょう）",romaji:"A koshou vs B koshou",id_text:"Satuan diameter pipa: A呼称 (mm) vs B呼称 (inci)",desc:"A呼称 menyatakan diameter nominal pipa dalam satuan mm; B呼称 dalam satuan inci. Contoh: 25A = 1B. ねじ接合 umumnya digunakan untuk ukuran 15A–100A. (Sumber: text6l §6.2.1)"},{id:518,category:"alat_umum",source:"text6l",jp:"バンドソー管切断機（バンドソーかんせつだんき）",romaji:"bandosoo kan setsudan ki",id_text:"Mesin pemotong pipa band saw — potongan tegak lurus sumbu pipa",desc:"Digunakan memotong pipa baja secara tegak lurus. Penyimpangan ≥1,0 mm berupa 斜め切れ (miring) atau 段切れ (bertangga) menjadi penyebab kebocoran air. (Sumber: text6l §6.2.1)"},{id:519,category:"pipa",source:"text6l",jp:"斜め切れ・段切れ ≥1.0mm → 水漏れ原因",romaji:"naname gire / dan gire — 1.0mm ijou de mizu more",id_text:"Cacat potong pipa ≥1,0 mm menyebabkan kebocoran air",desc:"斜め切れ = potongan miring; 段切れ = potongan bertangga/beda ketinggian. Keduanya menjadi penyebab kebocoran air jika penyimpangan ≥1,0 mm. Standar: potongan 90° terhadap sumbu pipa. (Sumber: text6l §6.2.1)"},{id:520,category:"keselamatan",source:"text6l",jp:"軍手でのねじ加工は絶対禁止（ぐんてでのねじかこうぜったいきんし）",romaji:"gunte de no neji kakou zettai kinshi",id_text:"Pakai sarung tangan kain saat mengulir pipa: DILARANG KERAS",desc:"Menggunakan 軍手 (sarung tangan kain) saat mengoperasikan mesin ulir (ねじ切り機) sangat berbahaya — tangan bisa tersangkut dan tergulung mesin. Ini adalah larangan mutlak (絶対にしてはいけない). (Sumber: text6l §6.2.1)"},{id:521,category:"pipa",source:"text6l",jp:"シールテープの巻き方 — 時計回り6〜7巻き・1山残す",romaji:"shiiru teepu no makikata — tokei mawari 6-7 maki / hito yama nokosu",id_text:"Cara melilit seal tape: searah jarum jam, 6–7 lilitan, sisakan 1 ulir dari ujung",desc:"Gulung searah putaran pemasangan (時計回り); mulai dari 1 ulir dari ujung, gulung 6–7 kali. Jika tape menutup sampai ujung ulir, potongan tape masuk ke dalam pipa menjadi penyumbat. Tekan tape ke ulir dengan jari/kuku setelah selesai. (Sumber: text6l §6.2.1)"},{id:522,category:"pipa",source:"text6l",jp:"ねじ込みのコツ — 2山〜2山半残す",romaji:"nejikomi no kotsu — futa yama ~ futa yama han nokosu",id_text:"Kunci keberhasilan ねじ込み: sisakan 2–2,5 ulir dengan pipe wrench",desc:"Setelah dikencangkan tangan semaksimal mungkin, gunakan パイプレンチ dan hentikan saat masih tersisa 2 sampai 2,5 ulir (山). Mengencangkan berlebihan dapat merusak ulir (ねじ山破壊). (Sumber: text6l §6.2.1)"},{id:523,category:"pipa",source:"text6l",jp:"錆のあるねじは絶対に使用禁止（さびのあるねじぜったいしようきんし）",romaji:"sabi no aru neji wa zettai ni shiyou kinshi",id_text:"Ulir pipa yang berkarat: dilarang keras digunakan",desc:"Pipa atau fitting yang ulirnya berkarat (錆) tidak boleh digunakan dalam kondisi apapun; karat mengakibatkan sambungan tidak rapat dan menjadi penyebab kebocoran. (Sumber: text6l §6.2.1)"},{id:524,category:"alat_umum",source:"text6l",jp:"ねじゲージ — 検査タイミング5パターン",romaji:"neji geeji — kensa taimingu 5 pataan",id_text:"Thread gauge — 5 momen wajib inspeksi ulir pipa",desc:"Wajib periksa: ①3 uliran pertama, ②setiap ukuran pipa berubah, ③per ~50 uliran (untuk 25A), ④saat lot/merek pipa berubah, ⑤saat チェーザ (mata potong) diganti. (Sumber: text6l §6.2.1)"},{id:525,category:"alat_umum",source:"text6l",jp:"チェーザ（ねじ切り盤の切削工具）",romaji:"cheeza",id_text:"Chaser — mata potong pada mesin pengulir pipa",desc:"Komponen pada ねじ切り機 yang memotong ulir pada pipa; kondisinya mempengaruhi akurasi ulir. Setiap penggantian チェーザ wajib dilakukan pemeriksaan dengan ねじゲージ. (Sumber: text6l §6.2.1)"},{id:526,category:"pipa",source:"text6l",jp:"液状シール剤（えきじょうシールざい）— 使用上の注意",romaji:"ekijou shiiru zai",id_text:"Sealant cair untuk sambungan ulir — perhatian K3",desc:"Dioleskan merata ke ulir; jika terkena mata segera cuci air banyak dan ke dokter, jika terkena kulit cuci dengan sabun. Aduk rata sebelum digunakan. Simpan di tempat sejuk berventilasi. (Sumber: text6l §6.2.1)"},{id:527,category:"pipa",source:"text6l",jp:"ガス溶接接合法（ガスようせつせつごうほう）",romaji:"gasu yousetsu setsugouhou",id_text:"Las gas — untuk pipa diameter kecil (小口径管)",desc:"Tiga jenis: oksigen-asetilen (paling umum), oksigen-hidrogen, dan udara-asetilen. Banyak digunakan untuk pipa diameter kecil (小口径管). (Sumber: text6l §6.2.1)"},{id:528,category:"pipa",source:"text6l",jp:"被覆アーク溶接接合法（ひふくアークようせつせつごうほう）",romaji:"hifuku aaku yousetsu setsugouhou",id_text:"Las busur tertutup (SMAW) — untuk pipa besar ≥100A",desc:"Elektroda berlapis fluks; fluks terbakar membentuk gas pelindung yang mencegah oksidasi logam cair. Banyak digunakan bersama atau sebagai alternatif las gas untuk pipa ≥100A. (Sumber: text6l §6.2.1)"},{id:529,category:"pipa",source:"text6l",jp:"開先加工（かいさきかこう）— V型・Y型・レ型・I型",romaji:"kaisaki kakou — V gata / Y gata / re gata / I gata",id_text:"Beveling ujung pipa sebelum pengelasan — 4 jenis",desc:"Pengerjaan ujung pipa setelah pemotongan untuk meningkatkan penetrasi las; tanpa 開先 terjadi penetrasi kurang (溶け込み不足). Empat jenis: V型、Y型、レ型、I型 (I型 disebut juga ドン付け開先). (Sumber: text6l §6.2.1)"},{id:530,category:"pipa",source:"text6l",jp:"仮付け溶接（かりつけようせつ）",romaji:"karitsuke yousetsu",id_text:"Tack welding — las ikat sebelum las penuh",desc:"Las pendek sebelum pengelasan utama (本溶接) untuk menstabilkan posisi dan mencegah distorsi atau pergeseran pada area bevel (開先部). (Sumber: text6l §6.2.1)"},{id:531,category:"pipa",source:"text6l",jp:"メカニカル接合方法（メカニカルせつごうほうほう）",romaji:"mekanikaru setsugouhouhou",id_text:"Sambungan mekanis — tanpa las maupun ulir",desc:"Penyambungan menggunakan komponen mekanis: ハウジング管継手、MD継手、カップリング継手、NO-HUB継手. Disebut juga 機械的接合法. (Sumber: text6l §6.2.1)"},{id:532,category:"pipa",source:"text6l",jp:"飲み込みのマーキング（のみこみのマーキング）",romaji:"nomikomi no maakingu",id_text:"Marking kedalaman insersi pipa PVC ke dalam fitting",desc:"Tanda di sisi pipa sepanjang kedalaman masuk ke fitting; jika pipa tidak masuk sampai tanda, total panjang instalasi tidak sesuai dan dapat menyebabkan kebocoran air. (Sumber: text6l §6.2.2)"},{id:533,category:"pipa",source:"text6l",jp:"接着剤（塩ビ管用）の塗布手順（せっちゃくざい）",romaji:"secchakuzai — enbi kan you",id_text:"Adhesif pipa PVC: urutan aplikasi yang benar",desc:"Oleskan dari sisi fitting dulu (bukan pipa), lalu pipa; dorong sekaligus penuh tenaga dan tahan ±10 detik tanpa melepaskan tekanan. Adhesif yang meluber segera dilap bersih sebelum mengeras. (Sumber: text6l §6.2.2)"},{id:534,category:"keselamatan",source:"text6l",jp:"ライニング鋼管のガス溶断絶対禁止（ガスようだんきんし）",romaji:"rainingu koukan no gasu youdan zettai kinshi",id_text:"DILARANG KERAS: potong pipa lining dengan oxy-acetylene atau panas tinggi",desc:"Pemotongan pipa ライニング鋼管 dengan ガス溶断 (oxy-acetylene) atau metode yang menghasilkan panas tinggi adalah LARANGAN MUTLAK — panas merusak lapisan lining. Gunakan band saw atau metal saw. (Sumber: text6l §6.2.3)"},{id:535,category:"pipa",source:"text6l",jp:"まくれ（バリ）とライニング管用リーマ",romaji:"makure (bari) to rainingu kan you riima",id_text:"Burr pipa lining dan reamer khusus untuk menghilangkannya",desc:"Burr setelah pemotongan wajib dihilangkan dengan ライニング管用リーマ atau スクレーパ — jangan pakai reamer mesin ulir biasa karena merusak lapisan lining. (Sumber: text6l §6.2.3)"},{id:536,category:"pipa",source:"text6l",jp:"管端防食継手（かんたんぼうしょくつぎて）",romaji:"kantan boushoku tsugite",id_text:"Sambungan anti-korosi ujung pipa lining",desc:"Melindungi ujung potongan ライニング鋼管 dari korosi; sebelum dipasang, ujung pipa di-chamfer (面取り) sebesar 1/2–2/3 dari ketebalan lapisan塩ビ (塩ビ管肉厚). (Sumber: text6l §6.2.3)"},{id:537,category:"keselamatan",source:"text6l",jp:"銅管の切断に金ノコ・グラインダー使用禁止",romaji:"doukan no setsudan ni kanoko / guraindaa shiyou kinshi",id_text:"DILARANG: potong pipa tembaga dengan gergaji besi atau grinder",desc:"Memotong pipa tembaga (銅管) dengan 金ノコ (gergaji besi) atau グラインダー menghasilkan serbuk logam (切り粉) yang tertinggal di dalam pipa refrigeran. Gunakan パイプカッター. (Sumber: text6l §6.3.1)"},{id:538,category:"pipa",source:"text6l",jp:"バリ取りは銅管を下向きに（どうかんをしたむきに）",romaji:"bari tori wa doukan wo shita muki ni",id_text:"Saat buang burr pipa tembaga: arahkan ujung pipa ke bawah",desc:"Saat menghilangkan burr (まくり) dari ujung pipa tembaga dengan reamer/scraper, pipa wajib diarahkan ke bawah agar serbuk hasil pengikisan tidak masuk ke dalam pipa refrigeran. (Sumber: text6l §6.3.1)"},{id:539,category:"alat_umum",source:"text6l",jp:"サイジングツール（冷媒管用真円修正）",romaji:"saijingu tsuuru — reibai kan you shinen shuusei",id_text:"Sizing tool — alat koreksi kebulatan ujung pipa tembaga refrigeran",desc:"Setelah バリ取り, ujung pipa tembaga wajib dikoreksi kebulatan (真円修正) sebelum flaring; pipa yang tidak bulat sempurna mengakibatkan flaring miring, fitting tidak masuk, atau brazing tidak merata. (Sumber: text6l §6.3.1)"},{id:540,category:"pipa",source:"text6l",jp:"最小曲げ半径（さいしょうまげはんけい）— 冷媒用被覆銅管",romaji:"saishou mage hankei — reibai you hifuku doukan",id_text:"Radius tekukan minimum pipa tembaga refrigeran",desc:"手曲げ: dia. 6,35–12,7 mm → min 6× dia. luar; ≥15,88 mm → min 10× dia. luar. ベンダー曲げ: min 4× dia. luar. Di bawah batas ini → pipa penyok (扁平) atau retak (座屈). (Sumber: text6l §6.3.1)"},{id:541,category:"pipa",source:"text6l",jp:"フレア接合（フレアせつごう）",romaji:"furea setsugou",id_text:"Sambungan flare pipa refrigeran tembaga",desc:"Ujung pipa tembaga dikembangkan menjadi bentuk terompet (フレア加工), lalu dikencangkan dengan フレアナット sehingga bagian flare tertekan dan berfungsi sebagai seal kedap refrigeran. (Sumber: text6l §6.3.2)"},{id:542,category:"pipa",source:"text6l",jp:"ろう接合（ろうせつごう）",romaji:"rou setsugou",id_text:"Sambungan brazing pipa refrigeran tembaga",desc:"ろう材 dilelehkan ke celah sambungan tembaga; penting: bebas oksida/kotoran dan suhu brazing tepat. Setelah selesai dinginkan dengan kain basah, periksa ada tidaknya ピンホール atau ろう回り不良. (Sumber: text6l §6.3.2)"},{id:543,category:"isolasi",source:"text6l",jp:"保温材の収縮 — 最大2%（ほおんざいのしゅうしゅく）",romaji:"hoon zai no shuushuku — saidai 2%",id_text:"Penyusutan insulasi termal: maks 2% (≈8 cm per 4 m)",desc:"Insulasi menyusut hingga 2% searah panjang; celah akibat penyusutan menimbulkan kondensasi yang berpotensi jadi kecelakaan. Sambungan ditutup rapat dengan tape insulasi khusus. (Sumber: text6l §6.3.2)"},{id:544,category:"isolasi",source:"text6l",jp:"保温材の形状 — 板状・帯状・筒状（ほおんざいのけいじょう）",romaji:"hoon zai no keijou: itajou / obijou / tsutsujou",id_text:"Bentuk insulasi: lembaran / pita / selongsong",desc:"板状(保温板) dan 帯状(保温帯) = untuk duct; 筒状(保温筒) = untuk pipa. Material utama: GW (glass wool), RW (rock wool), PS (polystyrene foam). (Sumber: text6l §6.4.1)"},{id:545,category:"isolasi",source:"text6l",jp:"ALGC（アルミガラスクロス）/ ALK（アルミクラフト紙）",romaji:"ALGC / ALK",id_text:"Penutup insulasi berbasis aluminium: ALGC dan ALK",desc:"Bahan laminasi aluminium untuk membungkus insulasi di ruang tersembunyi (plafon, shaft) atau ruang mesin/garasi. ALGC = aluminium + glass cloth; ALK = aluminium + kraft paper; keduanya berfungsi sebagai penahan uap. (Sumber: text6l §6.4.1)"},{id:546,category:"isolasi",source:"text6l",jp:"亀甲金網（きっこうかなあみ）",romaji:"kikkou kanaami",id_text:"Jaring kawat hexagonal — bahan bantu pengikat insulasi",desc:"Jaring kawat berbentuk sarang lebah untuk mengikat dan menguatkan insulasi pipa di ruang mesin, garasi, atau gudang. Untuk mencegah karat, digunakan 塩ビ亀甲金網 (jaring berlapis PVC). (Sumber: text6l §6.4.1)"},{id:547,category:"pipa",source:"text6l",jp:"GX形ダクタイル鋳鉄管（GXがたダクタイルちゅうてつかん）",romaji:"GX gata dakutairu chuutetsu kan",id_text:"Pipa GX型ダクタイル鋳鉄管 — tahan gempa besar",desc:"Jenis ダクタイル鋳鉄管 paling banyak dipakai di Jepang; sambungannya memiliki fungsi tegang-susut (伸縮) dan anti-lepas (離脱防止) sehingga tahan terhadap pergeseran tanah besar saat gempa. (Sumber: text6l §6.5.1)"},{id:548,category:"pipa",source:"text6l",jp:"ロックリング / ロックリングホルダ",romaji:"rokku ringu / rokku ringu horudaa",id_text:"Lock ring & holder — pencegah pipa lepas pada GX型",desc:"Saat pipa memanjang maksimum, tonjolan (突起部) dalam pipa tertahan lock ring sehingga tidak bisa terlepas. Wajib dicek posisinya secara visual dan dengan tangan sebelum pemasangan. (Sumber: text6l §6.5.1)"},{id:549,category:"pipa",source:"text6l",jp:"滑剤（かつざい）— ダクタイル鋳鉄管継手用",romaji:"katsuzai — dakutairu chuutetsu kan tsugite you",id_text:"Pelumas khusus pemasangan pipa GX型ダクタイル",desc:"Dioleskan pada bagian dalam taper ゴム輪 dan permukaan luar ujung pipa (挿し口外面) dari garis putih ke ujung pipa; jangan dioleskan ke dalam 受口 sebelum ゴム輪 dipasang. (Sumber: text6l §6.5.1)"},{id:550,category:"pipa",source:"text6l",jp:"EF接合（エレクトロフュージョン接合）",romaji:"EF setsugou",id_text:"Sambungan electrofusion (EF) pipa polietilen",desc:"Kawat pemanas (電熱線) tertanam dalam fitting EF; setelah pipa dimasukkan dan diklem, controller dialirkan arus untuk melelehkan dan menyatukan resin. Indikator EF socket harus terangkat (隆起) setelah proses sebagai tanda keberhasilan. (Sumber: text6l §6.5.2)"},{id:551,category:"pipa",source:"text6l",jp:"EF接合の斜め切断許容限度 — 呼び径に関係なく5mm以内",romaji:"EF setsugou no naname setsudan kyoyou gendo — 5mm inai",id_text:"EF接合: toleransi kemiringan potongan pipa ≤5 mm (semua ukuran)",desc:"Saat memotong pipa polietilen untuk EF接合, toleransi kemiringan potongan adalah 5 mm ke semua arah, tidak peduli ukuran pipa (呼び径に関係なく5mm以内). (Sumber: text6l §6.5.2)"},{id:552,category:"keselamatan",source:"text6l",jp:"高速砥石タイプの切断工具 — EF接合で使用禁止",romaji:"kousoku toishi taipu no setsudan kougu — shiyou kinshi",id_text:"DILARANG: gunakan grinder untuk potong pipa polietilen (EF接合)",desc:"Panas dari 高速砥石タイプの切断工具 (angle grinder) dapat mendistorsi permukaan potongan pipa polietilen. Gunakan alat potong mekanis atau hand saw. (Sumber: text6l §6.5.2)"},{id:553,category:"keselamatan",source:"text6l",jp:"地下埋設物表示シートの色コード（ちかまいせつぶつひょうじシート）",romaji:"chika maisetsumono hyouji shiito — iro koodo",id_text:"Kode warna lembar penanda utilitas bawah tanah",desc:"Dipasang antara utilitas dan permukaan tanah sebagai peringatan saat penggalian. Kode: 通信ケーブル=赤、高低圧電力=橙、水道管=青、下水道管=茶、ガス管=緑. (Sumber: text6l §6.5.4)"},{id:554,category:"keselamatan",source:"text6l",jp:"既存埋設管の周辺50cm以内は人力掘削（じんりきくっさく）",romaji:"kison maisetsukan no shuuhen 50cm inai wa jinriki kussaku",id_text:"Dalam radius 50 cm dari utilitas bawah tanah: wajib gali manual",desc:"Saat menggunakan backhoe atau alat berat, dalam radius 50 cm dari utilitas yang sudah ada wajib beralih ke penggalian manual (人力). Kecelakaan oleh backhoe menyumbang lebih dari separuh insiden pemutusan utilitas. (Sumber: text6l §6.5.4)"},{id:555,category:"keselamatan",source:"text6l",jp:"酸素欠乏危険作業主任者（さんそけつぼうきけんさぎょうしゅにんしゃ）",romaji:"sanso ketsubou kiken sagyou shuninsha",id_text:"Kepala kerja area berbahaya rendah oksigen — wajib untuk masuk manhole",desc:"Yang boleh masuk manhole hanya pemegang 第一種/第二種酸素欠乏危険作業主任者技能講習 atau lulusan 酸素欠乏危険作業特別教育. Kadar O₂ harus ≥18%, H₂S ≤10 ppm setelah ventilasi. (Sumber: text6l §6.5.4)"},{id:556,category:"keselamatan",source:"text6l",jp:"硫化水素濃度（りゅうかすいそのうど）— 10ppm以下",romaji:"ryuuka suiso noudo — 10ppm ika",id_text:"Batas konsentrasi H₂S di manhole: ≤10 ppm",desc:"Sebelum masuk manhole: O₂ harus ≥18% DAN H₂S ≤10 ppm. Jika ventilasi tidak memungkinkan, wajib pakai 呼吸用保護具 dan tempatkan pengawas (監視員). Bahaya jatuh dari tangga akibat酸欠 juga ada — wajib pakai墜落制止用器具 meski ketinggian ≤2 m. (Sumber: text6l §6.5.4)"},{id:557,category:"alat_umum",source:"text6l",jp:"ケガキ針 / デバイダ（けがきばり / デバイダ）",romaji:"kegaki hari / debaida",id_text:"Jarum garis / jangka — alat marking plat logam (板金)",desc:"ケガキ針 = jarum untuk menggambar garis tanda pada plat logam (digunakan bersama penggaris logam); デバイダ = jangka untuk menandai jarak atau radius yang sama. Lakukan marking satu kali semaksimal mungkin. (Sumber: text6l §6.6.1)"},{id:558,category:"alat_umum",source:"text6l",jp:"金床（アンビル）/ 定盤（じょうばん）",romaji:"kanatoko (anbiru) / jouban",id_text:"Anvil / surface plate — landasan tekuk plat baja (板金)",desc:"Landasan baja keras untuk membengkokkan plat logam; sudut pinggir 定盤 digunakan sebagai tumpuan saat memukul plat dengan 影たがね + ハンマー untuk membentuk sudut yang diperlukan secara bertahap. (Sumber: text6l §6.6.1)"},{id:559,category:"jenis_kerja",source:"text6l",jp:"アングルフランジ工法（アングルフランジこうほう）",romaji:"anguru furanji kouhou",id_text:"Angle flange — sambungan duct kotak kekuatan tinggi (排煙用)",desc:"Sambungan duct kotak menggunakan flange sudut; kekuatan dan kerapatan tinggi, digunakan untuk 排煙ダクト. Pengerjaan lebih lama dibanding metode lain. (Sumber: text6l §6.6.2)"},{id:560,category:"jenis_kerja",source:"text6l",jp:"共板フランジ工法（ともいたフランジこうほう）",romaji:"tomoita furanji kouhou",id_text:"Shared-plate flange — sambungan duct kotak paling umum (non-排煙)",desc:"Flange dibuat dari bagian duct itu sendiri yang dilipat; keempat sudut dikunci dengan klip khusus. Lebih mudah dan cepat dari アングルフランジ工法; banyak dipakai untuk duct non-排煙. (Sumber: text6l §6.6.2)"},{id:561,category:"jenis_kerja",source:"text6l",jp:"スライドオンフランジ工法（スライドオンフランジこうほう）",romaji:"suraido on furanji kouhou",id_text:"Slide-on flange — kekuatan menengah antara 共板 dan アングル",desc:"Flange jadi dimasukkan ke duct lalu dilas titik, dikencangkan baut di keempat sudut + penjepit ラッツ; kekuatan lebih tinggi dari 共板フランジ dan di antara dua metode lainnya. (Sumber: text6l §6.6.2)"},{id:562,category:"jenis_kerja",source:"text6l",jp:"丸ダクトのフランジ工法 — 小径75〜100mm=板状、≥200mm=アングル",romaji:"maru dakuto furanji — 75-100mm itajou / 200mm ijou anguru",id_text:"Duct bulat フランジ工法: 75–100 mm pakai plate flange, ≥200 mm pakai angle flange",desc:"Untuk sambungan duct spiral (スパイラルダクト) dengan フランジ工法: diameter 75–100 mm menggunakan 板状のプレートフランジ; diameter ≥200 mm menggunakan アングルフランジ. Cocok untuk koneksi yang memerlukan kekuatan tinggi. (Sumber: text6l §6.6.2)"},{id:563,category:"listrik",source:"text6l",jp:"PAS（高圧気中開閉器）— ポールエアスイッチ",romaji:"PAS (pole air switch)",id_text:"PAS — sakelar udara tegangan tinggi di tiang listrik",desc:"Dipasang di tiang listrik (架空配線); listrik 6600V melewati PAS sebelum masuk ke キュービクル di gedung. Untuk bekerja aman: PAS harus dibuka (開放) terlebih dahulu. (Sumber: text6l §6.7.1)"},{id:564,category:"listrik",source:"text6l",jp:"キュービクル",romaji:"kyuubikuru",id_text:"Kubikl — panel penerima dan penurun tegangan 6600V",desc:"Mengubah tegangan 6600V menjadi 100V/200V; berisi 遮断器 (circuit breaker) dan 断路器 (disconnecting switch). Dipasang di dalam, bawah tanah, atau atap gedung. Wajib停電 saat dikerjakan. (Sumber: text6l §6.7.1)"},{id:565,category:"listrik",source:"text6l",jp:"活線（かっせん）",romaji:"kassen",id_text:"Live line — jalur listrik yang masih bertegangan aktif",desc:"Kondisi kabel yang masih dialiri arus; bekerja pada sisi活線 (一次側) dapat menyebabkan sengatan langsung atau loncatan busur listrik (放電). Semua pekerjaan wajib dilakukan setelah停電 dikonfirmasi. (Sumber: text6l §6.7.1)"},{id:566,category:"listrik",source:"text6l",jp:"地絡（ちらく）",romaji:"chiraku",id_text:"Ground fault — arus bocor ke bumi",desc:"Arus mengalir ke tanah yang seharusnya terisolasi; terjadi misalnya karena polaritas grounding (アース) terpasang terbalik. Berbeda dari 短絡 (id:103) yang terjadi antar kabel bertegangan aktif. (Sumber: text6l §6.7.2)"},{id:567,category:"listrik",source:"text6l",jp:"漏電（ろうでん）と漏電遮断機（ろうでんしゃだんき）",romaji:"rouden to rouden shadanki",id_text:"Arus bocor (漏電) dan pemutus arus bocor (ELCB)",desc:"漏電 = arus mengalir ke jalur yang tidak seharusnya; menyebabkan sengatan dan kebakaran. 漏電遮断機 / 漏電警報器 otomatis memutus atau alarm saat terjadi漏電. Perlu waspada khusus saat renovasi. (Sumber: text6l §6.7.2)"},{id:568,category:"listrik",source:"text6l",jp:"圧着不良 → 発熱・発火（あっちゃくふりょう）",romaji:"acchaku furyou → hatsunetsu / hakka",id_text:"Crimping buruk → panas berlebih → kebakaran",desc:"圧着不良 menyebabkan 発熱・発火 (panas berlebih/kebakaran). Wajib crimp tepat di tengah sleeve (スリーブの真ん中) dan gunakan terminal yang sesuai ukuran kabel (許容電流にも注意). (Sumber: text6l §6.7.3)"},{id:569,category:"keselamatan",source:"text6l",jp:"架空線の切断事故（かくうせんのせつだんじこ）",romaji:"kakuusen no setsudan jiko",id_text:"Kecelakaan pemotongan kabel overhead oleh alat berat",desc:"Terjadi saat boom alat berat, tilting dump truck, atau saat memuat/menurunkan alat berat tidak memperhatikan kabel overhead (架空配線). Solusi: pasang ケーブルカバー pada kabel di atas area kerja. (Sumber: text6l §6.7.4)"},{id:570,category:"keselamatan",source:"text6l",jp:"道路使用許可証（どうろしようきょかしょう）",romaji:"douro shiyou kyoka shou",id_text:"Surat izin penggunaan jalan — wajib dibawa penanggung jawab",desc:"作業責任者 wajib membawa surat ini; kondisi izin (jam kerja, syarat pelaksanaan) harus dipatuhi. Wajib menempatkan 交通整理員, memasang fasilitas keselamatan, dan memastikan pejalan kaki bisa lewat dengan aman. (Sumber: text6l §6.7.5)"},{id:572,category:"keselamatan",source:"text6l",jp:"架空設備の地上高 — 道路上5m以上（かくうせつびのちじょうこう）",romaji:"kakuu setsubi no chijou kou — douro jou 5m ijou",id_text:"Ketinggian kabel overhead di atas jalan raya: minimal 5 m",desc:"Untuk keselamatan lalu lintas, tinggi minimum kabel dan perangkat telekomunikasi yang dipasang di tiang di atas jalan raya adalah 5 m dari permukaan jalan. (Sumber: text6l §6.8.1)"},{id:573,category:"telekomunikasi",source:"text6l",jp:"C・C・BOX（シーシーボックス）",romaji:"shii shii bokkusu",id_text:"CC-Box — saluran kabel utilitas bentuk U di bawah jalan",desc:"Struktur beton bentuk U yang ditanam di bawah jalan untuk menampung kabel komunikasi, listrik, dan perangkat manajemen jalan; ditutup dengan penutup (ふた). (Sumber: text6l §6.8.1)"},{id:574,category:"telekomunikasi",source:"text6l",jp:"土被り（どかぶり）— 車道0.8m以上・歩道0.6m以上",romaji:"dokaburi — shadou 0.8m ijou / hodou 0.6m ijou",id_text:"Kedalaman minimal tutup tanah di atas saluran kabel bawah tanah",desc:"Jarak dari permukaan jalan ke bagian atas saluran (管路); berdasarkan 道路法施行令: di jalan kendaraan (車道) min 0,8 m, di trotoar (歩道) min 0,6 m. (Sumber: text6l §6.8.2)"},{id:575,category:"telekomunikasi",source:"text6l",jp:"管路と他所管埋設物の離隔距離（りかくきょり）",romaji:"kanro to ta shokan maisetsumono no rikaku kyori",id_text:"Jarak aman antara saluran telekomunikasi dan utilitas lain",desc:"Jarak horizontal paralel: kereta api=1,0 m↑, listrik rendah/tinggi=0,3 m↑, listrik sangat tinggi=0,6 m↑, air/gas/lain=0,3 m. Vertikal silang: kereta api=1,5 m↑, listrik/air/gas=0,15 m. (Sumber: text6l §6.8.2)"},{id:576,category:"telekomunikasi",source:"text6l",jp:"マンドレル通過試験（マンドレルつうかしけん）",romaji:"mandoreru tsuuka shiken",id_text:"Uji laluan mandrel — verifikasi koneksi saluran bawah tanah",desc:"Setelah pemasangan saluran: batang mandrel dimasukkan untuk memastikan saluran terhubung sempurna. Saluran >150 m → mandrel No.4 (Ø600 mm); jika tidak bisa lewat → pakai mandrel No.3. (Sumber: text6l §6.8.2)"},{id:577,category:"telekomunikasi",source:"text6l",jp:"気密試験（管路布設後）— 49kPa・3分間・1.96kPa以下",romaji:"kimitsu shiken: 49kPa san pun kan 1.96kPa ika",id_text:"Uji kerapatan saluran: 49 kPa, 3 menit, turun ≤1,96 kPa = lulus",desc:"Setelah pemasangan saluran: tekanan dinaikkan ke 49 kPa, dibiarkan 3 menit; penurunan tekanan harus ≤1,96 kPa untuk dinyatakan lulus. (Sumber: text6l §6.8.2)"},{id:578,category:"jenis_kerja",source:"text6l",jp:"耐火煉瓦 / 耐火断熱煉瓦（たいかれんが / たいかだんねつれんが）",romaji:"taika renga / taika dannetsu renga",id_text:"Bata tahan api / bata insulasi tahan api — material築炉",desc:"Dua jenis bata untuk築炉工事; perekatnya adalah 耐熱断熱煉瓦用モルタル (mortar khusus), bukan mortar biasa. (Sumber: text6l §6.9)"},{id:579,category:"jenis_kerja",source:"text6l",jp:"熱硬性モルタル vs 気硬性モルタル（ねっこうせい vs きこうせい）",romaji:"nekkousei morutaru vs kikousei morutaru",id_text:"Mortar築炉: mengeras panas (熱硬性) vs mengeras di udara (気硬性)",desc:"熱硬性モルタル = mengeras saat dipanaskan suhu tinggi; 気硬性モルタル = mengeras pada suhu ruangan di udara biasa. Keduanya perekat bata耐火 dalam築炉工事. (Sumber: text6l §6.9)"},{id:580,category:"jenis_kerja",source:"text6l",jp:"煉瓦積みの6原則（れんがづみのろくげんそく）",romaji:"renga zumi no roku gensoku",id_text:"6 aturan mutlak dalam penyusunan bata築炉",desc:"①材料を正しく使用。②寸法を正確に。③モルタルを十分にまわし目地均一に。④平壁積みは必ず継ぎをとる。⑤長さ1/4以下の小さな煉瓦は使用しない。⑥必ず水平・垂直を基準とする。 (Sumber: text6l §6.9)"},{id:581,category:"pemadam",source:"text6l",jp:"呼水装置（こすいそうち）",romaji:"kosui souchi",id_text:"Priming device — alat pengisian awal pompa pemadam kebakaran",desc:"Memastikan pompa pemadam terisi air sebelum beroperasi; wajib dipasang jika sumber air (水源) berada lebih rendah dari pompa. Tanpa ini, pompa berputar kosong dan tidak bisa memompa air. (Sumber: text6l §6.10)"},{id:582,category:"pemadam",source:"text6l",jp:"水温上昇防止用逃がし配管（すいおんじょうしょうぼうしようにがしはいかん）",romaji:"suion joushou boshi you nigashi haikan",id_text:"Pipa bypass panas pompa pemadam — mencegah overheat",desc:"Mencegah pompa overheat saat berputar tanpa memompa air (sisi keluar tertutup); tanpa pipa ini pompa berhenti karena kepanasan dan tidak mampu memadamkan api. (Sumber: text6l §6.10)"},{id:583,category:"pemadam",source:"text6l",jp:"性能試験装置（せいのうしけんそうち）— 消防ポンプ",romaji:"seinou shiken souchi — shoubou ponpu",id_text:"Alat uji performa pompa pemadam kebakaran",desc:"Dipasang untuk memverifikasi bahwa pompa bekerja sesuai kapasitas yang ditetapkan (定められた通りの能力). Satu dari tiga perangkat khusus pompa pemadam (bersama呼水装置 dan逃がし配管). (Sumber: text6l §6.10)"},{id:584,category:"pemadam",source:"text6l",jp:"内面ライニング鋼管の使用禁止 — 消防設備配管",romaji:"naimen rainingu koukan no shiyou kinshi — shoubou haikan",id_text:"Pipa baja berlapis dalam (lining) DILARANG untuk pipa pemadam",desc:"Jika pipa pemadam tidak berisi air dan terkena panas api, lapisan lining meleleh dan mengeras sehingga air tidak bisa mengalir (送水不能). Oleh karena itu, 内面をライニングした金属管 dilarang digunakan. (Sumber: text6l §6.10)"},// ── text1l 第1章 — Bab 1: 日本の現場で大切にしていること ──────────────────────
{id:585,category:"karier",source:"text1l",jp:"施工体制（せこうたいせい）",romaji:"sekou taisei",id_text:"Struktur manajemen pelaksanaan konstruksi",desc:"Hierarki pelaksanaan di Jepang: ①発注者 → ②監理者/設計者 → ④ゼネコン（⑤現場監督） → ⑥専門工事業者（職長→作業員）. Polanya berbeda sesuai skala proyek: besar=ゼネコン, kecil=工務店 sebagai 元請け. (Sumber: text1l §1.2)"},{id:586,category:"karier",source:"text1l",jp:"発注者（はっちゅうしゃ）",romaji:"hacchuusha",id_text:"Pihak pemberi order konstruksi (klien)",desc:"Pihak yang memesan pekerjaan konstruksi. Contoh: 国土交通省、地方自治体、民間企業、個人. Di proyek kecil (住宅) sering disebut 施主 (seshu). (Sumber: text1l §1.2)"},{id:587,category:"karier",source:"text1l",jp:"監理者（かんりしゃ）",romaji:"kanrisha",id_text:"Pengawas konstruksi — memeriksa kesesuaian gambar",desc:"Teknisi yang memastikan pekerjaan dilaksanakan sesuai 図面 (gambar/blueprint). Posisi terpisah dari 設計者 maupun 現場監督. (Sumber: text1l §1.2)"},{id:588,category:"karier",source:"text1l",jp:"設計者（せっけいしゃ）",romaji:"sekkeisha",id_text:"Perancang / Desainer — membuat dokumen desain",desc:"Teknisi yang membuat 設計図書 (dokumen desain) untuk mewujudkan permintaan 発注者. (Sumber: text1l §1.2)"},{id:589,category:"karier",source:"text1l",jp:"ゼネコン（工事全体をまとめる会社）",romaji:"zenkon",id_text:"General Contractor — perusahaan pemimpin keseluruhan proyek",desc:"Singkatan dari 'General Contractor' (通称). Menerima order dari 発注者, lalu mengelola semua 専門工事業者 sebagai 元請け. Di bawahnya ada 現場監督. (Sumber: text1l §1.2)"},{id:590,category:"karier",source:"text1l",jp:"現場監督（げんばかんとく）",romaji:"genba kantoku",id_text:"Pengawas lapangan (site supervisor)",desc:"Teknisi yang mengawasi dan memimpin pekerjaan di 工事現場. Melakukan 打合せ dengan 職長, lalu 職長 meneruskan instruksi ke para 技能者. (Sumber: text1l §1.1, §1.2)"},{id:591,category:"karier",source:"text1l",jp:"専門工事業者（せんもんこうじぎょうしゃ）",romaji:"senmon kouji gyousha",id_text:"Kontraktor spesialis per jenis pekerjaan",desc:"Kontraktor yang menerima subkontrak dari ゼネコン untuk bidang tertentu (contoh: 鉄筋工事、型枠工事、とび工事). Di bawah 職長, para 作業員 melaksanakan pekerjaan. (Sumber: text1l §1.2)"},{id:592,category:"karier",source:"text1l",jp:"職長（しょくちょう）",romaji:"shokuchou",id_text:"Mandor / Foreman — pemimpin langsung pekerja di lapangan",desc:"Menerima instruksi dari 現場監督, lalu memberi instruksi kepada para 技能者. CCUS Level 3 (シルバー) = '職長として現場に従事できる技能者'. Level 4 (ゴールド) = manajemen tinggi (登録基幹技能者など). (Sumber: text1l §1.1, §1.3)"},{id:593,category:"karier",source:"text1l",jp:"技能者（ぎのうしゃ）",romaji:"ginousha",id_text:"Pekerja terampil / Skilled worker",desc:"Pekerja yang memiliki keahlian teknis. 先輩技能者 membimbing 後輩技能者. Level CCUS: Lv1 ホワイト=初級(見習い), Lv2 ブルー=中堅(一人前), Lv3 シルバー=職長級, Lv4 ゴールド=マネジメント高度. (Sumber: text1l §1.1, §1.3)"},{id:594,category:"karier",source:"text1l",jp:"施主（せしゅ）",romaji:"seshu",id_text:"Pemilik bangunan / klien pada proyek kecil",desc:"Pihak yang memesan bangunan untuk dibangun (建物を建てる発注者). Istilah khas untuk proyek kecil seperti 一般住宅. Di proyek besar disebut 発注者. (Sumber: text1l §1.2)"},{id:595,category:"karier",source:"text1l",jp:"工務店（こうむてん）",romaji:"koumuten",id_text:"Kontraktor lokal kecil — untuk proyek rumah tinggal",desc:"Kontraktor kecil yang menangani 住宅工事. Bertindak sebagai 元請け: menerima order dari 施主, mengelola 専門工事業者. (Sumber: text1l §1.2)"},{id:596,category:"karier",source:"text1l",jp:"元請け（もとうけ）",romaji:"motouke",id_text:"Kontraktor utama (prime contractor)",desc:"Pihak yang menerima kontrak langsung dari 発注者/施主, lalu memberi subkontrak kepada 専門工事業者. Di proyek besar = ゼネコン; di proyek kecil = 工務店. (Sumber: text1l §1.2)"},{id:597,category:"karier",source:"text1l",jp:"CCUS評価の3基準（経験・知識技能・マネジメント）",romaji:"CCUS hyouka no 3 kijun",id_text:"3 kriteria naik level CCUS: hari kerja / sertifikat / manajerial",desc:"①経験（就業日数）= hari kerja tercatat di sistem. ②知識・技能（保有資格）= lisensi/sertifikat yang dimiliki. ③マネジメント能力（登録基幹技能者講習・職長経験）= kemampuan memimpin. Ketiganya menentukan level 1〜4. Level 2 butuh ≥645日(3年). (Sumber: text1l §1.3)"},{id:598,category:"salam",source:"text1l",jp:"新規入場者（しんきにゅうじょうしゃ）",romaji:"shinki nyuujousha",id_text:"Pekerja baru yang pertama kali masuk lokasi konstruksi",desc:"Pekerja yang baru pertama kali masuk ke suatu lokasi. Saat 全体朝礼, 新規入場者 diperkenalkan: wajib menyebut nama dan 所属会社 dengan SUARA KERAS dan JELAS. (Sumber: text1l §1.5.1)"},{id:599,category:"salam",source:"text1l",jp:"安全唱和・タッチアンドコール（あんぜんしょうわ）",romaji:"anzen shouwa / tatchi ando kooru",id_text:"Seruan keselamatan + tumpuk tangan bersama (Touch-and-Call)",desc:"Dilakukan saat 職種ごとの朝礼 (apel per jenis pekerjaan). Semua anggota tim menunjuk (指さし) dan berseru bersama slogan keselamatan. Bukan hanya konfirmasi keselamatan — juga membangun 一体感 tim. Contoh seruan: 'ゼロ災で行こう、ヨシ！！'. (Sumber: text1l §1.5.2)"},{id:600,category:"salam",source:"text1l",jp:"ゼロ災で行こう、ヨシ！！",romaji:"zero sai de ikou, yoshi!!",id_text:"'Zero kecelakaan, maju! Oke!!' — slogan khas apel keselamatan",desc:"Contoh slogan 安全唱和. 'ゼロ災' = zero kecelakaan (零災害). 'ヨシ！！' = konfirmasi bersama keras. Diucapkan sambil menunjuk (指さし) pada 職種ごとの朝礼. (Sumber: text1l §1.5.2)"},{id:601,category:"salam",source:"text1l",jp:"KY活動の4ステップ（危険発見→対策検討→行動目標→かけ声）",romaji:"KY katsudou 4 suteppu",id_text:"4 langkah KY: temukan bahaya → solusi → target → serukan bersama",desc:"①危険の発見: identifikasi 危険のポイント dari kegiatan hari ini — diskusi bebas/ditunjuk. ②対策の検討: bahas solusi tiap titik bahaya, catat di 危険予知活動表. ③行動目標の決定: tetapkan target terpenting hari ini. ④かけ声: 指差呼称 ke KYボード → '○○○、ヨシ！' → '今日も一日安全作業で頑張ろう！…オウッ！'. (Sumber: text1l §1.5.2)"},{id:602,category:"salam",source:"text1l",jp:"KYボード（危険予知活動表）",romaji:"KY boodo / kiken yochi katsudou hyou",id_text:"Papan/formulir KY — lembar kegiatan prediksi bahaya",desc:"Formulir yang diisi saat KY活動: kolom 危険のポイント (titik bahaya) dan 私達はこうします (solusi kami). Setelah 行動目標 ditetapkan, semua anggota 指差呼称 ke papan ini sambil berseru '○○○、ヨシ！'. (Sumber: text1l §1.5.2)"},{id:603,category:"salam",source:"text1l",jp:"全体朝礼の6項目（ぜんたいちょうれいのろっこうもく）",romaji:"zentai chorei no 6 koumoku",id_text:"6 agenda apel pagi umum (全体朝礼)",desc:"①現場監督のあいさつ (membangun一体感) ②ラジオ体操 (pemanasan, cegah cedera) ③作業内容の確認 (各職長 lapor isi kerja & jumlah orang hari ini) ④KY活動 (identifikasi bahaya seluruh lokasi) ⑤安全事項の確認 (2人1組, cek 8 item sambil bersuara) ⑥'今日もご安全に！' → mulai kerja → dilanjut apel per職種. (Sumber: text1l §1.5.1)"},{id:604,category:"salam",source:"text1l",jp:"安全確認の8項目（右・左・前方・後方・頭上・足元・あごひも・服装名札）",romaji:"anzen kakunin 8 koumoku",id_text:"8 item cek keselamatan berpasangan di akhir apel umum",desc:"Di akhir 全体朝礼, 2人1組 sambil bersuara: 右はよいか / 左はよいか / 前方はよいか / 後方はよいか / 頭上はよいか / 足元はよいか / ヘルメットあごひもはよいか / 服装名札はよいか. (Sumber: text1l §1.5.1)"},{id:605,category:"karier",source:"text1l",jp:"一体感（いったいかん）",romaji:"ittaikan",id_text:"Rasa kesatuan / kebersamaan tim di lokasi konstruksi",desc:"Muncul saat pekerja dari berbagai 職種 saling menyapa dan bekerja sama. Dibangun melalui: あいさつ (sapaan), 朝礼 (apel pagi), 安全唱和 (seruan keselamatan). Fondasi チームワーク di lapangan. (Sumber: text1l §1.4, §1.5.2)"},// ── text7l 第7章 — Bab 7: 建設工事の安全 ────────────────────────────────────
{id:606,category:"keselamatan",source:"text7l",jp:"転倒（てんとう）— 労働災害の型",romaji:"tentou",id_text:"Tersandung / Kehilangan keseimbangan & jatuh di lantai yang sama",desc:"Jenis kecelakaan kerja: benda menghalangi → tersandung, atau kehilangan keseimbangan → jatuh. BERBEDA dari 墜落・転落 (jatuh dari ketinggian). Terjadi di permukaan yang sama — sering dianggap sepele tapi menyumbang banyak kasus. (Sumber: text7l §7.1.1)"},{id:607,category:"keselamatan",source:"text7l",jp:"飛来・落下（ひらい・らっか）— 労働災害の型",romaji:"hirai rakka",id_text:"Benda melayang / jatuh menimpa pekerja dari atas",desc:"Contoh: material terlepas dari crane menimpa pekerja, alat atau bahan jatuh dari ketinggian. Penyebab: 玉掛け (rigging) tidak sempurna, 吊り荷 (beban gantung) bergoyang. ATURAN MUTLAK: 吊り荷の下には絶対に入らない — jangan pernah berdiri di bawah beban yang digantung crane. (Sumber: text7l §7.1.1, §7.1.2)"},{id:608,category:"keselamatan",source:"text7l",jp:"激突され（げきとつされ）/ はさまれ・巻き込まれ — 労働災害の型",romaji:"gekitotsu sare / hasamare makikomare",id_text:"Tertabrak alat berat / Terjepit atau terseret mesin",desc:"激突され = tertabrak secara keras oleh kendaraan berat yang bergerak (truk, excavator) atau bucket crane yang sedang berputar (旋回中). はさまれ・巻き込まれ = terjepit di antara mesin/material, atau terseret ke dalam bagian mesin yang bergerak. Keduanya banyak disebabkan oleh 建設機械・クレーン災害. (Sumber: text7l §7.1.1, §7.1.2)"},{id:609,category:"keselamatan",source:"text7l",jp:"有害物との接触（ゆうがいぶつとのせっしょく）/ おぼれ / 火災 — 労働災害の型",romaji:"yuugai butsu to no sesshoku / oboreru / kasai",id_text:"Kontak bahan berbahaya / Tenggelam / Kebakaran di lokasi konstruksi",desc:"有害物との接触: zat kimia berbahaya menyentuh kulit/tubuh → gangguan kesehatan. おぼれ: jatuh ke laut, sungai, atau saluran air (下水道工事) → tenggelam. 火災: kebakaran dari berbagai sumber di lokasi konstruksi → terjebak asap/api. Ketiganya termasuk tipe kecelakaan fatal. (Sumber: text7l §7.1.1)"},{id:610,category:"keselamatan",source:"text7l",jp:"玉掛け（たまがけ）— クレーン吊り荷のロープ掛け",romaji:"tamagake",id_text:"Pengikatan beban crane (rigging/slinging)",desc:"Teknik mengikat material/beban ke kait crane menggunakan wire rope atau sling sebelum diangkat. 玉掛けが不十分 (rigging kurang kuat) = beban bisa terlepas saat diangkat → 飛来・落下 fatal. Operator 玉掛け wajib memiliki sertifikat (技能講習 atau 特別教育 tergantung berat beban). (Sumber: text7l §7.1.2)"},{id:611,category:"keselamatan",source:"text7l",jp:"土留め（どどめ）— 掘削深さ1.5m以上で原則必要",romaji:"dodome — kussaku fukasa 1.5m ijou de gensoku hitsuyou",id_text:"Penahan tanah galian — wajib (prinsip) jika kedalaman ≥1.5m",desc:"Saat menggali parit untuk memasang pipa (掘削工事), tanah bisa longsor dan menimbun pekerja di dalam. Jika kedalaman ≥1.5m: wajib menggunakan penahan tanah (土留め), umumnya dengan 鋼矢板 (steel sheet pile). (Sumber: text7l §7.1.3)"},{id:612,category:"keselamatan",source:"text7l",jp:"鋼矢板（こうやいた）— 土留めの代表材料",romaji:"kou yaita",id_text:"Sheet pile baja — material penahan tanah galian",desc:"Lembaran baja yang dipancang vertikal di sisi galian untuk mencegah longsor tanah (崩壊). Metode utama 土留め pada galian dalam (≥1.5m) seperti pekerjaan pipa bawah tanah (管布設工事). (Sumber: text7l §7.1.3)"},{id:613,category:"keselamatan",source:"text7l",jp:"保安設備・誘導員（ほあんせつび・ゆうどういん）— 公道上の作業",romaji:"hoan setsubi / yudouin",id_text:"Perlengkapan pengaman & pemandu lalu lintas — wajib saat kerja di jalan umum",desc:"Saat bekerja di jalan umum (公道上): wajib pasang 囲い (pagar), 柵 (barrier), ガード untuk mencegah kendaraan umum masuk area kerja. Wajib tempatkan 誘導員 (traffic guide). Pekerja juga dilarang bekerja di luar 作業範囲 yang ditentukan. (Sumber: text7l §7.1.2)"},{id:614,category:"keselamatan",source:"text7l",jp:"キーロック方式ロープ（移動用ロープの安全機構）",romaji:"kii rokku houshiki roopu",id_text:"Sistem kunci kait tali pengaman — tali lama tidak bisa dilepas sebelum tali baru dikaitkan",desc:"Sistem keselamatan pada フルハーネス型墜落制止用器具: ロープを外す (melepas tali pengaman) paling sering terjadi saat pindah titik. キーロック方式 = tali lama TIDAK BISA dilepas sebelum tali baru sudah terpasang di titik berikutnya → mencegah jeda tanpa pengaman. (Sumber: text7l §7.1.2)"},{id:615,category:"keselamatan",source:"text7l",jp:"安全施工サイクルの8ステップ",romaji:"anzen sekou saikuru no 8 suteppu",id_text:"8 langkah siklus keselamatan harian di lokasi konstruksi",desc:"①作業前の安全朝礼 (apel pagi + laporan patroli kemarin) ②安全ミーティング (職長主導, KY活動, 新規入場者教育) ③作業開始前点検 (cek mesin & alat) ④作業中の指導・監督 (pengawasan lapangan) ⑤安全パトロール (ronda keselamatan) ⑥安全工程打合せ (koordinasi antar job besok) ⑦持ち場の後片付け (bersih-bersih) ⑧終業時の安全確認 (cek kebakaran, pencurian, bahaya publik). (Sumber: text7l §7.2.1)"},{id:616,category:"keselamatan",source:"text7l",jp:"新入者安全衛生教育の8項目（しんにゅうしゃあんぜんえいせいきょういく）",romaji:"shinnyuusha anzen eisei kyouiku 8 koumoku",id_text:"8 materi wajib pendidikan K3 untuk pekerja baru yang direkrut perusahaan",desc:"[1]機械・原材料の危険性と取扱い [2]安全装置・保護具の性能と取扱い [3]作業手順 [4]作業開始時の点検 [5]業務に関する疾病の原因と予防 [6]整理整頓・清潔の保持 [7]事故時の応急措置と退避 [8]その他安全衛生に必要な事項. 根拠: 労働安全衛生規則. (Sumber: text7l §7.2.2)"},{id:617,category:"keselamatan",source:"text7l",jp:"新規入場者教育 — 死亡の半数が入場1週間以内・実施30分",romaji:"shinki nyuujousha kyouiku: shibou no hanbun ga nyuujou 1 shuukan inai / jisshi 30 pun",id_text:"Pendidikan pekerja baru lokasi: 50% kematian terjadi dalam 1 minggu pertama — durasi 30 menit",desc:"建設現場での死亡災害は、入場1週間以内に半数近くが発生 → maka 新規入場者教育 diwajibkan. Dilaksanakan oleh 職長・安全衛生責任者 pada hari pertama masuk. Tempat: 現場事務所の会議室 dll. Durasi: 30分程度. 8 materi: situasi lokasi, zona bahaya, koordinasi, evakuasi, rantai komando, isi pekerjaan, regulasi K3, kebijakan keselamatan. (Sumber: text7l §7.2.3)"},{id:618,category:"keselamatan",source:"text7l",jp:"フルハーネス義務高さ：6.75m（一般）/ 5m超（建設業）",romaji:"furu haanesugata gimu takasa: 6.75m ippan / 5m cho kensetsu gyou",id_text:"Ambang batas WAJIB full harness: 6.75m umum / >5m untuk konstruksi",desc:"2022年1月2日施行: 作業床の高さ 6.75m を超える場合 → 一般的に全業種でフルハーネス型墜落制止用器具の装着が義務化. 建設業は墜落事故が多いため、さらに厳しく: 5mを超える高さでも使用が求められる. 装備していても使わない事故があるため、必ず使用すること. (Sumber: text7l §7.2.4)"},{id:619,category:"keselamatan",source:"text7l",jp:"保護メガネ（ほごめがね）— 目を守る保護具",romaji:"hogo megane",id_text:"Kacamata pelindung — melindungi mata dari debu, percikan, sinar berbahaya",desc:"Melindungi mata dari: 金属・木の粉じん (debu logam/kayu), 火花 (percikan api las), 熱・煙 (panas & asap termasuk gas beracun), レーザー・有害光線 (sinar laser/UV). Pilih sesuai jenis bahaya. (Sumber: text7l §7.2.4)"},{id:620,category:"keselamatan",source:"text7l",jp:"保護マスク・じん肺（ほごますく・じんぱい）",romaji:"hogo masuku / jinpai",id_text:"Masker pelindung debu — wajib untuk mencegah penyakit paru-paru (じん肺)",desc:"保護マスク: melindungi dari debu (ホコリ). Ada 使い捨て式 dan フィルタ取換え式. じん肺 (pneumoconiosis) = kerusakan fungsi paru akibat menghirup debu logam/batu jangka panjang (las busur listrik, pemotongan batu) → WAJIB pakai masker. Standar ditetapkan Kementerian Kesehatan. (Sumber: text7l §7.2.4)"},{id:621,category:"keselamatan",source:"text7l",jp:"手袋（軍手）禁止 — 回転する刃物使用時",romaji:"tebukuro (gunto) kinshi — kaiten suru hamono shiyouji",id_text:"DILARANG pakai sarung tangan (軍手) saat menggunakan alat potong berputar",desc:"丸のこ (gergaji bundar), ボール盤 (bor), 面取り盤, パイプねじ切機 など 回転する刃物 → sarung tangan (軍手) bisa tersangkut di mata pisau yang berputar → kecelakaan serius. CATATAN: sarung tangan BOLEH dipakai untuk pekerjaan lain (las, kimia, potong manual). (Sumber: text7l §7.2.4)"},{id:622,category:"keselamatan",source:"text7l",jp:"シールド面付きヘルメット / 安全靴（あんぜんぐつ）",romaji:"shiirudo mentsuki herumetto / anzen gutsu",id_text:"Helm pelindung wajah (untuk las) / Sepatu safety",desc:"シールド面付きヘルメット = helm yang dilengkapi pelindung wajah penuh (shield) → terutama untuk 溶接工事 (pekerjaan las) — melindungi dari percikan api dan radiasi UV. 安全靴 = sepatu pelindung kaki yang keras — perlengkapan dasar wajib di semua lokasi konstruksi. (Sumber: text7l §7.2.4)"},{id:623,category:"keselamatan",source:"text7l",jp:"WBGT（暑さ指数）・真夏日・猛暑日",romaji:"WBGT (atsusa shisuu) / manatsubi / moushobi",id_text:"Indeks panas WBGT / Hari panas 30℃+ / Hari terik 35℃+",desc:"WBGT (Wet Bulb Globe Temperature) = indeks risiko 熱中症 yang diterbitkan 気象庁. 真夏日 = suhu >30℃. 猛暑日 = suhu >35℃. Manajer lokasi wajib mengambil tindakan: 大型扇風機、遮光ネット、ドライミスト、休憩場所・エアコン・給水器設置. Pada 猛暑日 bisa mengubah jam kerja. (Sumber: text7l §7.2.5)"},{id:624,category:"keselamatan",source:"text7l",jp:"熱中症の症状（ねっちゅうしょうのしょうじょう）",romaji:"netchuushou no shoujou",id_text:"Gejala-gejala heatstroke (熱中症) — dari ringan hingga fatal",desc:"Gejala bertahap: ①めまい・失神 (pusing, pingsan) ②筋肉痛・硬直 (nyeri & kram otot) ③大量の発汗 (keringat berlebih) ④頭痛・吐き気・嘔吐・倦怠感・虚脱感 ⑤意識障害・痙攣・手足の運動障害 ⑥高体温 → 死亡. Pencegahan: 水分・塩分を作業の前後に補給, beristirahat di tempat ber-AC. (Sumber: text7l §7.2.5)"},{id:625,category:"keselamatan",source:"text7l",jp:"緑十字（みどりじゅうじ）・安全衛生旗（あんぜんえいせいき）・救急箱",romaji:"midori juuji / anzen eisei ki / kyuukyuu bako",id_text:"Simbol K3: Palang Hijau / Bendera keselamatan-kesehatan / Kotak P3K",desc:"緑十字 (palang hijau di latar putih) = simbol 安全・衛生 di lokasi konstruksi. Sering ditampilkan bersama '安全第一 (SAFETY FIRST)'. Terpasang di: helm, 救急箱 (kotak P3K berisi obat & alat pertolongan pertama). 安全衛生旗 = gabungan 緑十字 (安全) + 白十字 (衛生) — dikibarkan di lokasi. (Sumber: text7l §7.2.6)"},{id:626,category:"keselamatan",source:"text7l",jp:"ヒューマンエラー（12種類の概要）",romaji:"hyuuman eraa 12 shurui",id_text:"Human Error — 12 jenis penyebab kesalahan manusia di konstruksi",desc:"Kesalahan akibat manusia yang menyebabkan kecelakaan, penurunan kualitas bangunan, dan keterlambatan proyek. 12 jenis: ①認知ミス ②不注意 ③注意・意識低下 ④経験・知識不足 ⑤慣れによる手抜き ⑥集団欠陥 ⑦近道・省略行動 ⑧連絡不足 ⑨場面行動本能 ⑩パニック ⑪心身の機能低下 ⑫疲労. (Sumber: text7l §7.2.7)"},{id:627,category:"keselamatan",source:"text7l",jp:"ヒューマンエラー①〜③：認知ミス・不注意・注意低下",romaji:"HA: ninchi misu / fuchuui / chuui teika",id_text:"Human Error 1–3: salah tangkap informasi / kurang perhatian / kesadaran menurun",desc:"①認知ミス = asumsi salah → salah membaca instruksi/sinyal ('pasti instruksinya begini'). ②不注意 = terlalu fokus pada 1 hal → tidak waspada sekitar → jatuh ke lubang. ③注意・意識の低下 = pekerjaan monoton/berulang → bergerak tanpa berpikir (無意識の動作) → lalai tanpa sadar. (Sumber: text7l §7.2.7)"},{id:628,category:"keselamatan",source:"text7l",jp:"ヒューマンエラー④〜⑤：経験不足・慣れによる手抜き",romaji:"HA: keiken busoku / nare ni yoru tenuki",id_text:"Human Error 4–5: kurang pengalaman / terbiasa → mulai potong kompas",desc:"④経験・知識不足 = tidak tahu cara pakai alat dengan benar, tidak bisa prediksi bahaya. Solusi: KY活動 memungkinkan pekerja baru belajar dari pengalaman senior. ⑤慣れによる手抜き = makin terbiasa → percaya diri berlebih → mulai skip prosedur. Kecelakaan sering terjadi saat hati mulai 緩む (lengah). Wajib: selalu cek alat, cek APD sebelum kerja. (Sumber: text7l §7.2.7)"},{id:629,category:"keselamatan",source:"text7l",jp:"ヒューマンエラー⑥〜⑧：集団欠陥・近道行動・連絡不足",romaji:"HA: shuudan kekkan / chikamichi koudou / renraku busoku",id_text:"Human Error 6–8: tekanan kelompok / shortcut / komunikasi buruk",desc:"⑥集団欠陥 = tekanan deadline menciptakan atmosfer 'terpaksa ambil jalan tidak aman' — keselamatan jiwa tetap prioritas utama; unsafe behavior justru memperparah keterlambatan. ⑦近道・省略行動 = demi efisiensi → skip langkah prosedur yang seharusnya dilakukan. ⑧連絡不足 = instruksi tidak tersampaikan jelas → pekerja bertindak berdasarkan salah paham → kecelakaan/keterlambatan. (Sumber: text7l §7.2.7)"},{id:630,category:"keselamatan",source:"text7l",jp:"ヒューマンエラー⑨〜⑫：場面本能・パニック・心身低下・疲労",romaji:"HA: bamen honnou / panikku / shinshin teika / hirou",id_text:"Human Error 9–12: refleks bahaya / panik / kemunduran fisik / kelelahan",desc:"⑨場面行動本能 = refleks mengutamakan keselamatan diri → melempar alat secara tiba-tiba → mengenai orang lain. ⑩パニック = terkejut mendadak → tindakan tidak aman atau instruksi keliru. ⑪心身の機能低下 = penuaan → fungsi fisik & penglihatan menurun perlahan (tidak disadari) → hindari gerakan dan postur memaksa. ⑫疲労 = kelelahan → konsentrasi menurun. Solusi: tidur cukup, asupan gizi baik, jaga kesehatan harian. (Sumber: text7l §7.2.7)"},// ── text2l 第2章 — Bab 2: Hukum — gap fill v22 ──────────────────────────────
{id:631,category:"hukum",source:"text2",jp:"パワーハラスメント防止法（労働施策総合推進法）",romaji:"pawaa harasumento boushi hou (roudou shisaku sougou suishin hou)",id_text:"UU Pencegahan Power Harassment — kewajiban perusahaan: buat kebijakan + buka konsultasi",desc:"通称パワハラ防止法 = 労働施策総合推進法. Kewajiban pemberi kerja: ①職場においてパワハラを行ってはならない旨の方針の規定を設けること ②相談窓口 (loket konsultasi) を設けるなどの防止措置を講じること. Publik: 労働局 (kantor tenaga kerja prefektur) memiliki 相談コーナー. BEDA dari id:102 yang hanya mendefinisikan パワハラ. (Sumber: text2l §2.1.1)"},{id:632,category:"hukum",source:"text2",jp:"年次有給休暇の付与テーブル（ねんじゆうきゅうきゅうかのふよテーブル）",romaji:"nenji yuukyuu kyuuka no fuyo teeburu",id_text:"Tabel pemberian cuti berbayar tahunan — syarat: 6 bulan kerja + hadir ≥80%",desc:"Syarat: 雇入れから6ヶ月間継続勤務 + 全労働日の8割以上出勤. Tabel付与日数: 0.5年→10日 / 1.5年→11日 / 2.5年→12日 / 3.5年→14日 / 4.5年→16日 / 5.5年→18日 / 6.5年以上→20日(上限). Setelah 2.5年 kenaikan 2日/tahun. Angka kunci: 6ヶ月・8割・20日上限. Diatur 労働基準法. (Sumber: text2l §2.1.1)"},{id:633,category:"hukum",source:"text2",jp:"安全衛生教育の2トリガー：雇い入れ時・作業内容変更時",romaji:"anzen eisei kyouiku no 2 torigaa: yatoiire ji / sagyou naiyou henkou ji",id_text:"2 wajib pendidikan K3: saat rekrut BARU + saat GANTI isi pekerjaan",desc:"労働安全衛生法: 安全衛生教育が必要なのは ①労働者を新たに雇い入れる時 ②作業内容を変更した時 — KEDUANYA wajib, bukan hanya saat rekrut. Selain itu, クレーンの運転 dll → 技能講習など特別の教育が別途必要. BEDA dari id:616 (8 materi K3 rekrut baru) dan id:617 (新規入場者教育). (Sumber: text2l §2.1.2)"},{id:634,category:"hukum",source:"text2",jp:"労働者の責務（ろうどうしゃのせきむ）— 労働安全衛生法",romaji:"roudousha no sekimu — roudou anzen eisei hou",id_text:"Kewajiban PEKERJA menurut UU K3 — bukan hanya pengusaha yang punya kewajiban",desc:"労働安全衛生法: 労働者は ①労働災害を防止するため必要な事項を守る ②事業者その他の関係者が実施する労働災害の防止に関する措置に協力する — ini adalah kewajiban pekerja itu sendiri, bukan hanya pemberi kerja. Artinya: pekerja yang SENGAJA mengabaikan APD atau prosedur keselamatan juga bisa dipersalahkan. (Sumber: text2l §2.1.2)"},{id:635,category:"keselamatan",source:"text2",jp:"安全旗 vs 安全衛生旗（あんぜんき vs あんぜんえいせいき）",romaji:"anzen ki vs anzen eisei ki",id_text:"Bendera Keselamatan (安全旗) vs Bendera Keselamatan-Kesehatan (安全衛生旗) — BEDA objek",desc:"安全旗 = 安全週間 (minggu keselamatan) のシンボルマーク — dikibarkan khusus selama periode 安全週間. 安全衛生旗 = シンボルマーク yang mempromosikan 安全 + 健康 + 衛生 secara terpadu — dikibarkan permanen di lokasi kerja. Keduanya bertujuan mengingatkan 無事故・無災害 dan meningkatkan kesadaran K3. BERBEDA satu sama lain. (Sumber: text2l §2.1.2)"},{id:636,category:"keselamatan",source:"text2",jp:"労災死亡原因ランキング5位（令和3年度・建設業）",romaji:"rousai shibou genin rankingu 5i — reiwa 3 nendo kensetsu gyou",id_text:"Top 5 penyebab kematian kecelakaan kerja konstruksi 2021 — dengan angka spesifik",desc:"令和3年度 建設業 死亡者288件の原因別ランキング: ①墜落・転落=110件 (38%) ②崩壊・倒壊=31件 ③はさまれ・巻き込まれ=27件 ④交通事故（道路）=25件 ⑤激突され=19件. 墜落が圧倒的に多い. 高所作業での 足場・フルハーネス義務化 の根拠. Angka kunci: 288・110・31・27・25・19. (Sumber: text2l §2.1.2)"},{id:637,category:"hukum",source:"text2",jp:"建設業法の5つの目的（けんせつぎょうほうのいつつのもくてき）",romaji:"kensetsu gyou hou no itsutsu no mokuteki",id_text:"5 tujuan UU Industri Konstruksi — beserta instrumen hukumnya",desc:"建設業法の5つの目的: ①建設業を営む者の資質の向上（→建設業許可） ②建設工事の請負契約の適正化（→見積書・契約書） ③適正な施工の確保（→主任技術者・監理技術者） ④発注者の保護（→現場代理人・施工体制台帳・施工体系図） ⑤建設業の健全な発達の促進. Semua menuju: 公共の福祉の増進. (Sumber: text2l §2.2)"},{id:638,category:"hukum",source:"text2",jp:"建築基準法：単体規定 vs 集団規定（たんたいきてい vs しゅうだんきてい）",romaji:"kenchiku kijun hou: tantai kitei vs shuudan kitei",id_text:"UU Standar Bangunan: 2 jenis peraturan — bangunan itu sendiri vs bangunan di lingkungan kota",desc:"単体規定: 建築物そのものの基準 → 安全性・耐久性・耐震性・防火・採光・換気・トイレ・電気設備など. 集団規定: 建築物が集まる市街地環境を保全する基準 → 敷地と道路の関係・建ぺい率・容積率・高さ制限・各種斜線制限・防火地域など. ⚠集団規定は原則として都市計画区域内・準都市計画区域内のみ適用. (Sumber: text2l §2.3)"},{id:639,category:"hukum",source:"text2",jp:"廃棄物処理法：産業廃棄物の収集運搬許可 + 元請け・下請けの責任分担",romaji:"haikibumono shori hou: sangyou haikibumono shuuryou unpan kyoka + motouke shitauke sekinin buntan",id_text:"UU Pengelolaan Limbah: siapa yang wajib urus pengangkutan + tanggungjawab sub-kontraktor",desc:"事業のごみ = ①産業廃棄物 + ②事業系一般廃棄物. 現場から廃棄物を排出するには廃棄物収集運搬業の許可が必要 → 原則として発注者から直接受注した元請け業者が行う. 下請け業者も現場での産業廃棄物の「保管」に関しては本法が適用される. 最終処分にはリサイクルも含まれる. マニフェスト義務は元請けが負担. (Sumber: text2l §2.4)"},{id:640,category:"hukum",source:"text2",jp:"下水道法：禁止排水の6理由 + 工事現場の排水種類",romaji:"gesuidou hou: kinshi haisui no 6 riyuu + kouji genba no haisui shurui",id_text:"UU Saluran Pembuangan: 6 alasan larangan + jenis air limbah dari lokasi konstruksi",desc:"下水道に流してはいけない6理由: ①施設を腐食させる ②他の排水と混ざると有毒ガス発生 ③管を詰まらせる ④管内作業を危険にする ⑤生物処理機能を低下させる ⑥汚泥の処理・処分を困難にする. 禁止物質: カドミウム・鉛・総クロム・銅・亜鉛など基準値以上. 工事現場の排水例: バッチャープラント洗浄水・コンクリート接触雨水・ウェルポイント排水 → 高アルカリ → 要中和処理（→id:178参照）. (Sumber: text2l §2.11)"},// ── text3l 第3章 — Gap Fill v23 ─────────────────────────────────────────
{id:641,category:"jenis_kerja",source:"text3",jp:"建設工事の3大分類",romaji:"kensetsu kouji no sandai bunrui",id_text:"3 kategori besar pekerjaan konstruksi",desc:"①土木工事（どぼく）= pekerjaan terhadap alam: laut, sungai, gunung → dam, jalan, terowongan, jembatan, pelabuhan, kereta api. ②建築工事（けんちく）= membangun gedung tempat tinggal & kegiatan: rumah, apartemen, RS, sekolah, restoran. ③ライフライン・設備工事 = infrastruktur kehidupan: listrik, gas, air, telekomunikasi + AC, pemadam, insulasi termal. (Sumber: text3l §3.1)"},{id:642,category:"jenis_kerja",source:"text3",jp:"ダム工事の目的：治水 vs 利水",romaji:"damu kouji: chisui vs risui",id_text:"Tujuan bendungan: pengendalian banjir vs pemanfaatan air",desc:"治水（ちすい）= mencegah banjir — saat hujan besar, menampung air dan mengatur debit sungai agar tidak meluap. 利水（りすい）= pemanfaatan air stabil untuk pertanian + industri + 水力発電（pembangkit listrik tenaga air）. Jepang punya 3000以上の bendungan karena banyak sungai dari pegunungan. (Sumber: text3l §3.1.1)"},{id:643,category:"jenis_kerja",source:"text3",jp:"トンネルの4種類（工法で分類）",romaji:"tonneru no yonshurui kouhou de bunrui",id_text:"4 jenis terowongan berdasarkan metode konstruksi",desc:"①山岳（さんがく）トンネル = gali batu keras di gunung, pakai NATM. ②開削（かいさく）トンネル = gali dari permukaan → bangun terowongan di dalam → timbun kembali. ③シールドトンネル = mesin shield menggali + pasang segmen panel → cocok tanah lunak & ada bangunan di atas. ④推進（すいしん）トンネル = pipa pabrik ditekan masuk tanah dengan dongkrak dari 立坑（poros vertikal）. (Sumber: text3l §3.1.1)"},{id:644,category:"jenis_kerja",source:"text3",jp:"NATM工法（山岳トンネル）— 3要素",romaji:"NATM kouhou sangaku tonneru san youso",id_text:"Metode NATM terowongan gunung — 3 elemen penyangga",desc:"New Austrian Tunneling Method. Gali batu keras gunung dengan 発破（はっぱ/peledakan）atau mesin penggali. 3 elemen untuk menyangga terowongan setelah digali: ①吹付けコンクリート（ふきつけ）= semprot beton langsung ke dinding galian ②鋼製支保工（こうせいしほこう）= rangka baja penopang ③ロックボルト = baut yang mengikat lapisan batu agar tidak runtuh. (Sumber: text3l §3.1.1)"},{id:645,category:"jenis_kerja",source:"text3",jp:"シールドトンネル工法（立坑・セグメント）",romaji:"shiirudo tonneru kouhou tatekou segumento",id_text:"Metode terowongan shield — cocok tanah lunak & ada bangunan di atas",desc:"Prosedur: ①Bangun 立坑（たてこう）= poros vertikal sebagai pangkalan mesin shield ②Mesin shield menggali maju dari 立坑 ③Di belakang mesin: pasang セグメント = panel beton atau besi yang menjadi dinding/tube terowongan. Keunggulan: bisa di 軟弱地盤（なんじゃく/tanah lunak）, bisa melewati bawah bangunan yang sudah ada（既存構造物の直上も適用可能）. (Sumber: text3l §3.1.1)"},{id:646,category:"jenis_kerja",source:"text3",jp:"橋梁工事：種類と下部工・上部工",romaji:"kyouryou kouji shurui to kabukou joubukou",id_text:"Pekerjaan jembatan: 6 jenis + 2 tahapan utama",desc:"Jenis jembatan: 桁橋（けたばし）・トラス橋・アーチ橋・ラーメン橋・斜張橋（しゃちょう）・吊橋（つりばし）. 2 tahapan: 下部工（かぶこう）= fondasi yang menopang jembatan → 上部工（じょうぶこう）= badan jembatan (untuk kendaraan/pejalan kaki). Metode: ベント・ケーブルエレクション・送り出し・トラベラークレーンベント・フローティングクレーン工法など。 (Sumber: text3l §3.1.1)"},{id:647,category:"jenis_kerja",source:"text3",jp:"海洋土木工事の特徴と主要施設",romaji:"kaiyo doboku kouji no tokucho to shuyo shisetsu",id_text:"Ciri khas pekerjaan sipil laut + fasilitas yang dibangun",desc:"Membangun fasilitas di laut/sungai: pelabuhan, bandara laut, jembatan laut, terowongan bawah laut, menara turbin angin. Ciri khas: ①作業船（さぎょうせん）= kapal kerja besar untuk menggali dasar laut atau mengangkat material berat ②潜水士（せんすいし）= penyelam yang bisa bekerja di dalam air ③alat ukur batimetri untuk mengukur bentuk dasar laut. (Sumber: text3l §3.1.1)"},{id:648,category:"jenis_kerja",source:"text3",jp:"建築物の構造5種類",romaji:"kenchikubutsu no kouzou goshurui",id_text:"5 jenis struktur bangunan beserta karakteristiknya",desc:"①鉄筋コンクリート造（RC造）= besi tulangan + beton cor dalam cetakan ②鉄骨造（S造）= kolom-balok dari baja → gedung pabrik/komersial ③鉄骨鉄筋コンクリート造（SRC造）= rangka baja + tulangan besi + beton → gedung tinggi ④木造（もくぞう）= kolom-balok dari kayu → rumah biasa, paling umum untuk rumah tinggal ⑤コンクリートブロック造（CB造）= blok beton ditumpuk, lubang diisi tulangan + mortar. (Sumber: text3l §3.1.2)"},{id:649,category:"jenis_kerja",source:"text3",jp:"建築工事の流れ（大規模ビル・マンション）",romaji:"kenchiku kouji no nagare daikibo biru",id_text:"Urutan tahapan konstruksi gedung besar",desc:"①準備工事 = pasang pagar lokasi, bangun kantor sementara, survei tanah: ボーリング調査（地盤調査）= borlog cek lapisan keras pendukung（支持層）. ②山留め工事 = dinding sementara agar galian tidak runtuh. ③杭工事 = pancang tiang sampai lapisan keras. ④土工事 = gali (掘削), angkut sisa tanah（残土）. ⑤地下躯体工事 = tulangan + bekisting + cor beton. ⑥地上躯体工事 = rangka baja + tower crane. ⑦内外装仕上げ工事 = finishing dalam & luar. (Sumber: text3l §3.1.2)"},{id:650,category:"jenis_kerja",source:"text3",jp:"耐震・制振・免振の3種類（地震対策）",romaji:"taishin seishin menshin no sanshurui",id_text:"3 metode proteksi gempa bangunan — beda cara kerjanya",desc:"①耐震工事（たいしん）= perkuat kolom & balok agar TAHAN/melawan gaya gempa. ②制振工事（せいしん）= pasang ダンパー（peredam energi）di dalam struktur → kendalikan/kurangi goyangan. ③免振工事（めんしん）= pasang アイソレータ + ダンパー di fondasi → TIDAK teruskan energi gempa ke bangunan. 建築基準法の基準: 震度5強 = bangunan masih berfungsi normal / 震度6強〜7 = tidak runtuh. (Sumber: text3l §3.1.2)"},{id:651,category:"jenis_kerja",source:"text3",jp:"土工事の作業6種類",romaji:"do kouji no sagyou rokushurui",id_text:"6 jenis pekerjaan tanah (土工事)",desc:"①掘削（くっさく）= menggali & mengangkat tanah/batu. 発破（はっぱ）= peledakan batu. 根切り（ねぎり）= menggali untuk fondasi bangunan. ②積み込み・運搬 = muat & angkut tanah sisa（残土/ざんど）. ③盛り土（もりど）= tambah tanah untuk meratakan. 切り土（きりど）= potong/kurangi tanah untuk meratakan. ④埋め戻し（うめもどし）= isi kembali ruang kosong setelah pekerjaan bawah tanah selesai. ⑤締固め（しめかため）= padatkan tanah agar tidak ambles. ⑥法面（のりめん）の塗布・植え付け = stabilisasi lereng dengan mortar atau vegetasi. (Sumber: text3l §3.2.1)"},{id:653,category:"jenis_kerja",source:"text3",jp:"ウェルポイント工法（地下水排水・最大10m）",romaji:"weru pointo kouhou chikasui haisui saidai ju meetoru",id_text:"Metode well point — dewatering max 10 m untuk pekerjaan kering",desc:"Metode mengeringkan air tanah agar pekerjaan bisa dilakukan kondisi kering: ドライワーク（dry work）. Cara: tancapkan banyak 揚水管（ようすいかん/pipa pompa）ke tanah → pompa vakum menyedot air tanah → air dikumpulkan lewat 集水管（しゅうすいかん）. Max kedalaman efektif: 10m. Lebih dari 10m → pakai ディープウェル工法. Bonus: menstabilkan tanah yang lemah (軟弱地盤の安定化). (Sumber: text3l §3.2.5)"},{id:654,category:"jenis_kerja",source:"text3",jp:"舗装工事の4層構造（基層を忘れずに！）",romaji:"hosou kouji no yonsoukouzou (kisou wo wasurezu ni)",id_text:"4 lapisan jalan beraspal — 基層 adalah lapisan yang sering terlewat",desc:"Dari bawah: ①路床（ろしょう）= lapisan paling bawah, menahan semua beban. Digali ±1m, isi pasir. ②路盤（ろばん）= batu pecah（砕石）dipadatkan dengan roller (2 sub-lapis). ③基層（きそう）＝ lapisan aspal pertama, dipasang dengan アスファルトフィニッシャー lalu dipadatkan roller. ④表層（ひょうそう）= lapisan aspal paling atas: tahan lama（耐久性）, kedap air, anti selip. ⚠ id:149 hanya menyebut 3 lapisan — 基層 JANGAN terlewat di ujian! (Sumber: text3l §3.2.6)"},{id:655,category:"jenis_kerja",source:"text3",jp:"とび工事の6種類",romaji:"tobi kouji no rokushurui",id_text:"6 jenis pekerjaan tobi (ahli kerja ketinggian)",desc:"Pekerjaan yang menggunakan tali baja untuk bekerja di ketinggian. 6 jenis: 足場とび (perancah), 鉄骨とび (rangka baja gedung tinggi), 橋梁とび (jembatan/menara), 重量とび (pindahkan mesin ratusan ton), 送電とび (kabel tegangan tinggi menara), 町場とび (perancah rumah/apartemen). (Sumber: text3 §3.2.9)"},{id:656,category:"jenis_kerja",source:"text3",jp:"鉄筋継手の4種類",romaji:"tekkinhitsugite no yonshurui",id_text:"4 jenis sambungan besi tulangan (継手)",desc:"Besi tulangan standar: max panjang 12m → jika perlu lebih panjang, sambung dengan継手（つぎて）. ①ガス圧接継手（PALING UMUM）= panaskan dengan nyala O₂+アセチレン/天然ガス, tekan arah sumbu → kedua besi menyatu. ②溶接継手 = las busur (アーク溶接) → untuk besi besar/precast/kondisi tidak bisa dipres. ③機械式継手 = besi berulir disambung dengan カプラー (coupler). ④重ね接手（かさね）= besi tipis, ditumpuk lalu disatukan oleh beton cor. (Sumber: text3l §3.2.12)"},{id:657,category:"jenis_kerja",source:"text3",jp:"溶接の3大分類：融接・圧接・ろう接",romaji:"yousetsu no sandai bunrui: yuusetsu assetsu rousetsu",id_text:"3 metode pengelasan: melelehkan / menekan / brazing",desc:"①融接（ゆうせつ）= PALING UMUM: lelehkan material（母材）untuk menyambungnya. Jenis: アーク・ガス・レーザー・ビーム溶接など. Cepat, bisa material besar, tapi kualitas tergantung keahlian operator. ②圧接（あっせつ）= panas + tekanan → sambung TANPA melelehkan sempurna → 固相接合（こそうせつごう）. Di konstruksi: ガス圧接 paling sering untuk sambung tulangan. ③ろう接 = lelehkan 'lem logam'（溶剤）bersuhu lebih rendah dari material → berfungsi seperti adhesif. (Sumber: text3l §3.2.13)"},{id:658,category:"jenis_kerja",source:"text3",jp:"型枠工事と支保工（かたわく大工）",romaji:"katawaku kouji to shihokou katawakudaiku",id_text:"Pekerjaan bekisting & perancah penopang — dibuat oleh型枠大工",desc:"型枠（かたわく）= cetakan kayu untuk beton cor → dibuat oleh 型枠大工（かたわくだいく）dengan memproses kayu（大工同様）. Saat beton cair masuk: tekanan dalam cetakan sangat besar → wajib perkuat dari luar dengan pipa besi = 支保工（しほこう）. Perlu baca 加工図（かこうず）= gambar detail pemrosesan. Setelah beton mengeras & cukup kuat: cetakan dibongkar → di gedung tinggi cetakan dipakai ulang di lantai berikutnya（再利用）. (Sumber: text3l §3.2.14)"},{id:659,category:"jenis_kerja",source:"text3",jp:"コンクリート圧送工事と3者チームワーク",romaji:"konkuriito assou kouji to sansha chiimuwaaku",id_text:"Pengecoran beton dengan pompa — 3 peran yang wajib sinkron",desc:"生コン（なまコン/レディミクスドコンクリート）= beton segar dari pabrik, dikirim pakai トラックアジテータ（生コン車）. Di lokasi: dipompa masuk cetakan pakai コンクリートポンプ車（コンクリート圧送）. Selama pengecoran: gunakan バイブレータ → getar beton → hilangkan rongga udara（締固め）. 3 pihak WAJIB koordinasi: ①操作オペレータ（操作ポンプ）②筒先作業員（arahkan ujung selang）③土工作業員（締固め）. Beton segar mengeras cepat → efisiensi wajib. (Sumber: text3l §3.2.15)"},{id:660,category:"jenis_kerja",source:"text3",jp:"塗装工事の3工法（はけ・ローラー・エアスプレー）",romaji:"tosou kouji no san kouhou",id_text:"3 metode pengecatan — pilih sesuai luas & kualitas yang dibutuhkan",desc:"①はけ塗り = menggunakan kuas（はけ）. Hasil akhir PALING INDAH di antara tiga metode. ②ローラー塗り = menggunakan rol kuas（ローラーブラシ）. Efisien untuk permukaan luas seperti 外壁（dinding luar）. Hasil kurang halus. ③エアスプレー塗装 = cat dicampur udara bertekanan dari エアコンプレッサ, disemprotkan dengan エアスプレーガン. Pilihan 塗料（cat）disesuaikan dengan jenis 素地（そじ/permukaan）yang akan dicat. (Sumber: text3l §3.2.16)"},{id:662,category:"jenis_kerja",source:"text3",jp:"左官工事と特殊仕上げ（研ぎ出し・洗い出し・漆喰）",romaji:"sakan kouji to tokushu shiage togidashi araidashi shikkui",id_text:"Pekerjaan plester dinding + 2 finishing khusus Jepang",desc:"左官工事 = mengoles bahan finishing ke dinding/lantai menggunakan こて（trowel）. Bahan: 壁土（かべつち）・モルタル・漆喰（しっくい）・プラスター・繊維など. 漆喰 adalah bahan khas Jepang sejak zaman dulu. 2 teknik khusus: ①研ぎ出し（とぎだし）= asah permukaan batu/beton hingga halus & mengkilat. ②洗い出し（あらいだし）= pasang 種石（たねいし/batu kecil dekoratif）dengan semen → sebelum mengeras sempurna: sapu permukaan semen dengan sikat → batu-batu kecil timbul menonjol. (Sumber: text3l §3.2.18)"},{id:664,category:"jenis_kerja",source:"text3",jp:"吹付けウレタン断熱工事（2成分・施工前後確認）",romaji:"fukitsuke uretan dannetsu kouji niseibun",id_text:"Insulasi semprot uretan keras — 2 komponen + prosedur QC wajib",desc:"Semprot 硬質ウレタンフォーム（busa poliuretan keras）ke permukaan bangunan（躯体）dengan mesin semprot → lapisan insulasi tanpa celah. Bahan: 2 komponen: ①ポリオール成分（触媒・発泡剤・整泡剤入り）+ ②ポリイソシアネート成分. Prosedur QC: SEBELUM施工: semprot uji ke papan 450mm正方形 → cek kepadatan busa（発泡密度）. SELAMA施工: cek ketebalan setiap 4〜5m interval dengan ウレタン厚測定機. Wajib bersihkan debu & minyak dari permukaan sebelum disemprot. (Sumber: text3l §3.2.27)"},{id:665,category:"jenis_kerja",source:"text3",jp:"海洋土木の4工事：浚渫・埋立・岸壁・防波堤（ケーソン）",romaji:"kaiyo doboku no yon kouji: shunsetsu umetate ganpeki boohatei keeson",id_text:"4 pekerjaan sipil laut: pengerukan / reklamasi / dermaga / pemecah gelombang",desc:"①浚渫工事（しゅんせつ）= keruk lumpur/pasir dasar laut/sungai dengan 浚渫船 → dalami jalur kapal/pelabuhan. ②埋立工事（うめたて）= angkut tanah hasil keruk → timbun di laut → buat daratan baru. ③岸壁工事（がんぺき）= dermaga tempat kapal bersandar & bongkar-muat: 鋼矢板（sheet pile baja）buat dinding + 杭（tiang）buat kolom. ④防波堤工事（ぼうはてい）= pemecah gelombang: ratakan dasar laut dengan batu → letakkan ケーソン（kotak beton besar）→ isi dalam ケーソン dengan pasir/tanah untuk memberatkan. (Sumber: text3l §3.2.3)"},{id:666,category:"jenis_kerja",source:"text3",jp:"内装仕上げ工事（LGS・ボード・クロス・床・カーテン）",romaji:"naisou shiage kouji LGS boodo kurosu yuka kaaten",id_text:"Pekerjaan finishing interior — rangka baja ringan hingga wallpaper & lantai",desc:"①鋼製下地工事（LGS/スタッド）= Light Gauge Steelで壁・天井の骨組みを作る → 軽天工事（けいてん）とも言う. ②ボード貼り = 石膏ボード（プラスタボード）を骨組みに貼り付け。つなぎ目はパテで平滑に。③クロス貼り = 石膏ボード上にクロス（壁紙）を貼る。④塗装仕上げ = クロスの代わりに塗料で仕上げ。⑤床仕上げ = タイル・カーペット・畳などを敷く。⑥カーテン工事 = 生地を裁断・縫製して取り付け。 (Sumber: text3l §3.2.23)"},{id:667,category:"jenis_kerja",source:"text3",jp:"サッシ工事とカバー工法（金属建具の取付け）",romaji:"sasshi kouji to kabaa kouhou kinzoku tategu",id_text:"Pekerjaan sash/kusen logam + metode renovasi hemat カバー工法",desc:"サッシ工事 = memasang 建具（たてぐ）berbahan logam: jendela aluminium sash, pintu kamar mandi, kasa nyamuk（網戸）, curtain wall, dll. Renovasi: mengganti kusen（枠）lama → butuh大工+左官+塗装 = biaya & waktu besar. カバー工法 = solusi: TANPA copot kusen lama, pasang kusen baru di atasnya langsung → hemat biaya & waktu. (Sumber: text3l §3.2.26)"},{id:668,category:"jenis_kerja",source:"text3",jp:"解体工事（解体ガラ・アスベスト対策）",romaji:"kaitai kouji kaitai gara asubesuto taisaku",id_text:"Pekerjaan pembongkaran — penanganan limbah & prosedur asbes",desc:"解体工事 = membongkar bangunan/struktur tua atau yang perlu diganti. Termasuk bagian bawah tanah（躯体）. Di area padat: wajib waspada getaran, kebisingan, jatuhnya material. 解体ガラ = limbah hasil pembongkaran → dipilah berdasarkan bahan（beton, besi, dll.）untuk dibuang sesuai 建設リサイクル法. アスベスト対策: bangunan lama mungkin mengandung asbes → wajib survei lebih dulu, pastikan serat asbes tidak beterbangan selama pembongkaran（飛散防止対策）. (Sumber: text3l §3.2.38)"},// §3.3 建設工事に必要な資格 — Qualification System
{id:669,category:"karier",source:"text3",jp:"建設工事の資格3種類（国家免許・技能講習・特別教育）",romaji:"kensetsu kouji no shikaku sanshurui",id_text:"3 tingkat kualifikasi konstruksi berdasarkan 労働安全衛生法",desc:"①国家免許（こっかめんきょ）= lisensi negara tertinggi, dikeluarkan pemerintah pusat. ②技能講習（ぎのうこうしゅう）= pelatihan keterampilan oleh lembaga terdaftar di 都道府県労働局. Lulus → dapat 技能講習修了証. ③特別教育（とくべつきょういく）= pendidikan K3 sebelum mengerjakan tugas berbahaya, bisa oleh perusahaan sendiri（社内）atau lembaga luar（社外）. 作業主任者（さぎょうしゅにんしゃ）= pengawas kerja yang wajib ditempatkan di lokasi untuk pekerjaan tertentu, dipilih dari pemegang 技能講習修了証. (Sumber: text3l §3.3.1)"},{id:670,category:"karier",source:"text3",jp:"クレーン・移動式クレーン・玉掛けの資格基準（荷重別）",romaji:"kureen idoushiki kureen tamakake no shikaku kijun kajuubetsu",id_text:"Kualifikasi crane, mobile crane, rigging berdasarkan kapasitas angkat（t）",desc:"クレーン/デリック: 5t以上 → 免許（クレーン運転士）/ 1t以上5t未満 → 技能講習 / 1t未満 → 特別教育. 移動式クレーン（mobile crane）: 5t以上 → 免許（移動式クレーン運転士）/ 1t以上5t未満 → 技能講習 / 1t未満 → 特別教育. 玉掛け（たまかけ/rigging）: 1t以上 → 技能講習 / 1t未満 → 特別教育. 境目: 5t（クレーン免許の境）・1t（玉掛け技能講習の境）. (Sumber: text3l §3.3.2)"},{id:671,category:"karier",source:"text3",jp:"車両系建設機械・高所作業車・フォークリフトの資格基準",romaji:"sharyokei kensetsu kikai kousho sagyousha footokku rifuto no shikaku",id_text:"Kualifikasi alat berat berdasarkan berat mesin / tinggi kerja / kapasitas angkat",desc:"車両系建設機械（ブルドーザ・油圧ショベル等）: 機体重量3t以上 → 技能講習 / 3t未満 → 特別教育. 高所作業車（aerial work platform）: 作業床の高さ10m以上 → 技能講習 / 10m未満 → 特別教育. フォークリフト: 最大荷重1t以上 → 技能講習 / 1t未満 → 特別教育. 覚え方: 車両系=3t / 高所作業車=10m / フォーク=1t が技能講習の境界線。 (Sumber: text3l §3.3.2)"},{id:672,category:"karier",source:"text3",jp:"溶接・酸欠・発破・足場の資格区分",romaji:"yousetsu sankketsu happa ashiba no shikaku kubun",id_text:"Kualifikasi las / oksigen rendah / peledakan / scaffolding",desc:"ガス溶接作業者 → 技能講習. ガス溶接作業主任者（アセチレン装置使用の監督者）→ 免許. アーク溶接作業者 → 特別教育. 酸素欠乏危険作業主任者（さんそけつぼう）→ 技能講習（第一種・第二種）. 酸素欠乏危険作業者 → 特別教育. 発破技士（はっぱぎし）→ 免許（国家資格、最高レベル）. 足場の組立等作業主任者（高さ5m以上の足場）→ 技能講習. 足場作業員 → 特別教育. 石綿（アスベスト）作業者 → 特別教育. (Sumber: text3l §3.3.2)"},{id:673,category:"jenis_kerja",source:"text3",jp:"建築大工工事の種類（町大工・造作大工・宮大工）",romaji:"kenchiku daiku kouji no shurui machi zousaku miya",id_text:"Jenis tukang kayu bangunan: rumah biasa / finishing / kuil-shrine",desc:"①町大工（まちだいく）= 家屋大工: tukang kayu rumah tinggal, yang paling umum. Bayangan orang Jepang saat dengar 'daiku-san'. ②造作大工（ぞうさくだいく）= setelah struktur selesai: buat & pasang pintu（戸）, 障子, ふすま, dan dekorasi interior（室内装飾）. ③宮大工（みやだいく）= khusus kuil（お寺）dan shrine（神社）: butuh teknik sambungan kayu tertinggi agar tahan ratusan tahun. ④型枠大工 → lihat id:658. (Sumber: text3l §3.2.19)"},{id:674,category:"jenis_kerja",source:"text3",jp:"屋根工事：瓦ぶきと雨仕舞い + 5種の屋根工事",romaji:"yane kouji kawarabuki amajimai goshurui",id_text:"Pekerjaan atap — genteng, drainase air hujan, dan 5 jenis pekerjaan",desc:"瓦（かわら）= genteng tanah liat yang dibakar dalam kiln（窯/かま）. 瓦ぶき = memasang genteng. 雨仕舞い（あまじまい）= sistem mengalirkan air hujan agar tidak masuk bangunan → pengetahuan wajib apapun bahan atapnya. 5 jenis pekerjaan atap: ①ふき替え（ganti atap lama）②重ねぶき（tumpuk atap baru di atas lama）③漆喰補修（perbaiki plester genteng yang retak → mencegah bocor）④雨どい交換（ganti talang air rusak）⑤屋根塗装（cat ulang atap yang lapuk）. (Sumber: text3l §3.2.20)"},{id:675,category:"jenis_kerja",source:"text3",jp:"建築板金工事のダクト3種（排煙・空調・排気）",romaji:"kenchiku bankin kouji no dakuto sanshurui haien kuuchou haiki",id_text:"Pekerjaan plat logam: 3 jenis saluran udara (duct)",desc:"建築板金工事 = memproses pelat logam tipis（potong, tekuk, bentuk, sambung）untuk bangunan. Pekerjaan inti termasuk ダクト工事. ダクト（風道/ふうどう）= saluran udara. 3 jenis: ①排煙ダクト（はいえん）= saluran asap keluar saat kebakaran. ②空調ダクト（くうちょう）= alirkan udara dingin/panas/segar ke ruangan（sistem AC）. ③排気ダクト（はいき）= buang panas & bau dari ruang mesin, kamar mandi, toilet keluar gedung. Lainnya: atap logam, 雨仕舞い, papan luar gedung（外壁工事）, papan nama & aksesori logam. (Sumber: text3l §3.2.21)"},{id:676,category:"jenis_kerja",source:"text3",jp:"石工事（石工・大理石・御影石・擬石）",romaji:"ishi kouji ishiku dairiseki mikageishi giiseki",id_text:"Pekerjaan batu — memasang material batu alam/buatan di bangunan",desc:"石工（いしく）= pengrajin batu. Pekerjaan: memproses dan memasang batu alam/buatan ke bangunan（不関与struktur, hanya estetika/高級感）. Material: 大理石（だいりせき/marble）・御影石（みかげいし/granit）・擬石（ぎせき/batu tiruan）・コンクリートブロックなど. Karakteristik: ①batu sangat mahal → TIDAK boleh gagal saat diproses（失敗が許されない）. ②乱形石（らんけいせき）= batu bentuk tidak beraturan → butuh pengalaman panjang untuk menyusun indah. (Sumber: text3l §3.2.29)"},{id:677,category:"salam",source:"text4",jp:"おはようございます（朝のあいさつの基本）",romaji:"ohayou gozaimasu",id_text:"Selamat pagi — salam dasar di pagi hari",desc:"Ucapkan kepada orang yang PERTAMA KALI ditemui di pagi hari. Fungsi ganda: ①memberi kesan baik kepada lawan bicara ②membuat lawan bicara bersemangat. Tidak perlu kenal — tetap ucapkan dengan semangat. (Sumber: text4l §4.1.1)"},{id:678,category:"salam",source:"text4",jp:"ご安全に（建設現場専用のあいさつ）",romaji:"go anzen ni",id_text:"Semoga selamat — salam khas lokasi konstruksi",desc:"Ungkapan harapan agar lawan bicara selamat, tidak kecelakaan, bisa selesaikan pekerjaan harian dengan aman. Digunakan: ①akhir朝礼: 「今日も１日、ご安全に！」seluruh tim bersama ②saat berpapasan dengan orang yang akan mengerjakan tugas berbahaya. Yang mendengar akan termotivasi untuk lebih waspada. (Sumber: text4l §4.1.2)"},{id:679,category:"salam",source:"text4",jp:"おつかれさまです（感謝・労い — どこでも使える）",romaji:"otsukaresama desu",id_text:"Kerja keras ya — bisa dipakai di mana saja, bukan hanya konstruksi",desc:"Ungkapan terima kasih & penghargaan atas kerja keras lawan bicara. Beda dengan「ご安全に」: 「おつかれさまです」bisa dipakai di MANA SAJA tempat orang bekerja — kantor, ruang istirahat, koridor. Untuk orang yang sudah selesai & pulang: 「おつかれさまでした！」dengan semangat. (Sumber: text4l §4.1.3)"},{id:680,category:"salam",source:"text4",jp:"ご苦労さま vs おつかれさまです（上下関係の注意）",romaji:"gokurosama vs otsukaresama — chigai",id_text:"Perbedaan penggunaan — ご苦労さま TIDAK SOPAN untuk atasan",desc:"ご苦労さま = ungkapan terima kasih atas sesuatu yang dilakukan UNTUK DIRI SENDIRI. ⚠ Banyak orang Jepang menganggap 「ご苦労さま」tidak sopan jika diucapkan kepada 監督・職長・先輩 (atasan). → Gunakan 「おつかれさまです」untuk atasan. Jika atasan berkata 「ご苦労さま！」kepada kamu → mereka berterima kasih → jawab 「ありがとうございます！」dengan semangat. (Sumber: text4l §4.1.4)"},{id:681,category:"salam",source:"text4",jp:"失礼します（3つの場面での使い方）",romaji:"shitsurei shimasu — mittsu no bamen",id_text:"Permisi / maaf mengganggu — 3 situasi penggunaan",desc:"「礼」=sopan santun, 「失」=kehilangan → makna: 'saya berperilaku kurang sopan'. Bukan ungkapan negatif. 3 situasi: ①Masuk ruangan: 「失礼します」= maaf mengganggu orang yang sedang bekerja. ②Menyela percakapan yang sedang berlangsung untuk menyampaikan hal mendesak. ③Pulang lebih dulu: 「お先に失礼します」→ dijawab 「お疲れさまでした」. (Sumber: text4l §4.1.5)"},{id:682,category:"salam",source:"text4",jp:"危ない！よけろっ！（緊急の呼びかけ）",romaji:"abunai! yokero!",id_text:"Awas! Minggir! — seruan darurat saat ada bahaya mendekat",desc:"Saat seseorang tidak menyadari bahaya yang mendekat → orang sekitar berteriak spontan 「危ない！」. Jika bahaya berupa benda jatuh dari atas atau benda datang dari samping: 「危ない！よけろっ！」⚠ Dengar seruan ini → LANGSUNG BEREAKSI tanpa pikir panjang. (Sumber: text4l §4.1.6)"},{id:683,category:"jenis_kerja",source:"text4",jp:"墨出し・基準墨・通り芯（位置出し基本3語）",romaji:"sumidashi / kijunzumi / toorishin",id_text:"3 istilah dasar penandaan garis konstruksi",desc:"【墨出し】menarik berbagai garis referensi yang dibutuhkan untuk konstruksi di lantai dll. Alat: すみつぼ (tradisional) atau レーザー墨出し器. 【基準墨】garis horizontal/vertikal lurus yang menjadi referensi utama bangunan → dari sini ditarik 通り芯. 【通り芯】garis yang melewati titik tengah komponen =「壁芯」「柱芯」. (Sumber: text4l §4.2.1)"},{id:684,category:"jenis_kerja",source:"text4",jp:"逃げ墨・陸墨・立て墨・地墨・仕上げ墨（5種類の墨）",romaji:"nigezumi / rokuzumi / tatezumi / jizumi / shiagazumi",id_text:"5 jenis garis tinta konstruksi berdasarkan fungsinya",desc:"【逃げ墨/返り墨】jika ada halangan → tarik garis paralel dengan jarak tertentu dari referensi; tulis jarak pelariannya. 【陸墨(りくずみ)】garis referensi ketinggian horizontal (=腰墨・水墨・水平墨). 【立て墨】garis vertikal di permukaan dinding/kolom. 【地墨】garis yang ditandai langsung di lantai/permukaan horizontal. 【仕上げ墨】garis yang menunjukkan dimensi finishing dari 通り芯 atau permukaan struktur. (Sumber: text4l §4.2.1)"},{id:685,category:"jenis_kerja",source:"text4",jp:"壁芯・柱芯・親墨・矩を振る・墨付け（墨出し追加5語）",romaji:"kabeshiin / hashirashiin / oyazumi / kane wo furu / sumitsuke",id_text:"5 istilah墨出し lanjutan — garis tengah & referensi proses berikutnya",desc:"【壁芯】garis yang melewati tengah dinding. 【柱芯】garis yang melewati tengah kolom. 【親墨】garis seperti 通り芯 atau 陸墨 yang menjadi REFERENSI untuk operasi墨出し proses berikutnya. 【矩を振る】pekerjaan menarik garis sudut 90°. 【墨付け】memberi tanda pengerjaan pada komponen kayu (untuk 木造). (Sumber: text4l §4.2.1)"},{id:686,category:"jenis_kerja",source:"text4",jp:"遣り方・水貫・水盛り・地縄張り・水糸（仮設基準5語）",romaji:"yarikata / mizunuki / mizumori / jinawahari / mizuito",id_text:"5 istilah 遣り方 — pagar referensi sementara sebelum konstruksi",desc:"【遣り方】'pagar sementara' dari pasak kayu + 水貫 untuk menunjukkan posisi, sudut siku, ketinggian bangunan. Di pekerjaan sipil disebut「丁張り」. 【水貫】papan kayu yang dipaku HORIZONTAL ke pasak untuk membuat 遣り方. 【水盛り】menentukan referensi horizontal (tinggi) bangunan, menggunakan 水盛り缶. 【地縄張り】menandai posisi bangunan di tanah dengan tali/pita. 【水糸】tali horizontal yang direntangkan antar 水貫 sebagai referensi 通り芯. (Sumber: text4l §4.2.2)"},{id:687,category:"jenis_kerja",source:"text4",jp:"BM・GL・FH・FL・SL・CH（高さ基準6語）",romaji:"benchmark / GL / FH / FL / SL / CH",id_text:"6 istilah referensi ketinggian — dari tanah sampai langit-langit",desc:"【BM/ベンチマーク】titik referensi ketinggian di area proyek — tidak boleh dibongkar sampai bangunan selesai. Di atas BM='+', di bawah='−'. Contoh: GL=BM+200. 【GL】Ground Level/Line = tinggi permukaan tanah tempat bangunan berdiri. 【FH】Formation Height = tinggi tanah yang direncanakan. 【FL】Floor Level/Line = tinggi permukaan lantai jadi (1FL, 2FL...). 【SL】Slab Level/Line = tinggi permukaan slab jadi. 【CH】Ceiling Height = tinggi dari FL ke permukaan langit-langit jadi. (Sumber: text4l §4.2.2)"},{id:688,category:"jenis_kerja",source:"text4",jp:"盛り土・段切り・締固め・転圧・埋め戻し・突き固め（土工事基本6語）",romaji:"morito / dangiri / shimekatame / ten'atsu / umemodoshi / tsukigatame",id_text:"6 istilah operasi tanah dasar",desc:"【盛り土】tambahkan tanah ke area miring/rendah untuk meratakan permukaan. 【段切り】saat盛り土 di lereng curam → gali bertingkat seperti tangga agar tanah tidak longsor. 【締固め】tambahkan tekanan pada tanah/aspal → kurangi rongga antar partikel → tingkatkan kepadatan（「密実」）. 【転圧】padatkan tanah menggunakan タイヤローラー atau ランマ. 【埋め戻し】setelah pekerjaan bawah tanah selesai → isi kembali dengan tanah. 【突き固め】gunakan ランマ/プレート untuk padatkan tanah hasil埋め戻し. (Sumber: text4l §4.2.3)"},{id:689,category:"jenis_kerja",source:"text4",jp:"路盤・路床・表層（舗装土工事3語）",romaji:"roban / roshou / hyousou (doukouji)",id_text:"3 lapisan perkerasan jalan — definisi teknis tanah dasar",desc:"【路盤】lapisan di atas 路床 pada perkerasan aspal → menyebarkan beban dari 表層 ke 路床. 【路床】lapisan tanah dasar penopang perkerasan, berada ~1m dari permukaan perkerasan. 【表層】lapisan paling atas pada perkerasan aspal. ⚠ Cf. id:654 yang membahas 4 lapisan termasuk 基層 — di konteks土工事 ini 3 lapisan dalam perspektif tanah dasar. (Sumber: text4l §4.2.3)"},{id:690,category:"jenis_kerja",source:"text4",jp:"地縄はり・根切り・根入れ長さ・素掘り（掘削前後4語）",romaji:"jinawahari / negiri / neirenagasa / subori",id_text:"4 istilah pra/pasca penggalian pondasi",desc:"【地縄はり】tandai batas pondasi di tanah dengan tali/vinyl (istilah dalam 建築). 【根切り】gunakan alat berat untuk gali lubang sampai kedalaman dasar pondasi (= 掘削). 【根入れ長さ】panjang/kedalaman dari dasar galian（根切り底）ke ujung pondasi atau tiang. 【素掘り】penggalian TANPA土留め — hanya jika tanah kokoh dan tidak ada risiko longsor. (Sumber: text4l §4.2.3)"},{id:691,category:"jenis_kerja",source:"text4",jp:"土留め・擁壁・矢板・鋼矢板・山留め（崩壊防止5語）",romaji:"dodome / youheki / yaita / kou yaita / yamadome",id_text:"5 istilah penahan tanah & pencegahan longsor galian",desc:"【土留め】menahan tanah agar lereng/galian tidak longsor. 【擁壁】土留め berbentuk dinding — disebut khusus「擁壁」. 【矢板】papan penahan tanah. 【鋼矢板】矢板 dari baja dengan ujung berbentuk alur sehingga bisa saling menyambung. 【山留め】menahan tanah dengan 矢板 agar tidak longsor. Lahan luas → 「オープンカット工法」(gali miring). Lahan sempit → 「山留め壁オープンカット工法」(tambah dinding + 支保工). (Sumber: text4l §4.2.3)"},{id:692,category:"jenis_kerja",source:"text4",jp:"場所打ち・打つ（打設）— コンクリート現場施工2語",romaji:"bashouchi / utsu (dasetsu)",id_text:"2 istilah pengecoran beton di lokasi kerja",desc:"【場所打ち/現場打ち】mengecor beton LANGSUNG di lokasi (bukan menggunakan produk beton pabrik). Contoh: 杭 ada 2 metode:「既成杭工法」vs「場所打ちコンクリート杭工法」. 【打つ/打設する】dalam terminologi konstruksi: mengalirkan beton ke dalam cetakan (bukan memukul). 「コンクリートを打つ」=「打設する」=mengecor. (Sumber: text4l §4.2.3)"},{id:693,category:"jenis_kerja",source:"text4",jp:"余堀り・鋤取り・床付け・杭間さらい・段跳ね（掘削精度5語）",romaji:"yobori / sukitori / tokozuke / kuimasarai / danbane",id_text:"5 istilah presisi penggalian & persiapan dasar pondasi",desc:"【余堀り】gali sedikit lebih dari yang dibutuhkan untuk ruang kerja. 【鋤取り】ratakan permukaan dasar galian ke ketinggian yang ditentukan. 【床付け】setelah galian hampir mencapai kedalaman rencana → ratakan dasar galian dengan presisi. 【杭間さらい】saat床付け: bersihkan tanah di antara tiang dan tanah yang terangkat di sekitar tiang. 【段跳ね】jika galian dalam → tanah hasil galian diangkat bertahap ke atas menggunakan 地山 yang dibiarkan bertingkat-tangga, lalu排土. (Sumber: text4l §4.2.3)"},{id:694,category:"jenis_kerja",source:"text4",jp:"地山・法面・山がくる（自然地盤と崩壊危険）",romaji:"jiyama / norimen / yama ga kuru",id_text:"3 istilah kondisi tanah alami & lereng galian yang berbahaya",desc:"【地山】tanah dalam kondisi alami (belum diubah manusia). 【法面（のり）】permukaan miring — di lokasi konstruksi: permukaan galian yang memiliki kemiringan（勾配）. 【山がくる】山留め atau 法面 yang digali RUNTUH/LONGSOR → sering menjadi penyebab kecelakaan serius di lokasi kerja. (Sumber: text4l §4.2.3)"},{id:695,category:"jenis_kerja",source:"text4",jp:"水替え・釜場・山砂・水締め・万棒（排水・管理5語）",romaji:"mizukae / kamaba / yamazuna / mizushime / manbou",id_text:"5 istilah drainase & manajemen material di lokasi proyek",desc:"【水替え】pompa/kuras air yang menggenang di dasar galian menggunakan 釜場 atau pompa. 【釜場】lubang untuk memasang pompa penguras air. 【山砂】pasir dari daratan — lebih tinggi daya serap airnya dibanding pasir sungai. 【水締め】padatkan tanah timbunan sambil menyiram air agar lebih padat; dipakai saat cabut 鋼矢板 → cegah penurunan tanah. 【万棒】menghitung jumlah truk, orang, kayu gelondongan, tiang kayu yang masuk ke lokasi. (Sumber: text4l §4.2.3)"},{id:696,category:"jenis_kerja",source:"text4",jp:"地業・基礎・直接基礎（ベタ基礎・フーチング）",romaji:"jigyou / kiso / chokusetsu kiso (beta kiso / fuuchingu)",id_text:"Pekerjaan tanah dasar & pondasi langsung — 3 istilah utama",desc:"【地業】bagian di bawah lantai dasar pondasi, atau pekerjaannya. Isi: pasir, kerikil, 割栗石, 捨てコン, 杭 dll → menopang 基礎スラブ. 【基礎】bagian yang meneruskan berat bangunan（建造物荷重）ke tanah. 2 jenis: 直接基礎 dan 杭基礎. 【直接基礎】pondasi langsung ke tanah. ベタ基礎=cor beton di seluruh dasar bangunan (tanah keras). フーチング=pondasi berbentuk T terbalik hanya di bagian menanggung beban. (Sumber: text4l §4.2.4)"},{id:697,category:"jenis_kerja",source:"text4",jp:"杭基礎・スラブ・杭地業・基礎免振（弱い地盤対策4語）",romaji:"kui kiso / surabu / kui jigyou / kiso menshin",id_text:"4 istilah pondasi tiang, pelat beton & isolasi gempa",desc:"【杭基礎】pondasi untuk tanah lemah — tancapkan杭（kolom silinder）sampai lapisan tanah keras untuk menopang beban bangunan. 【スラブ】bagian datar bangunan: 構造スラブ=menopang bangunan / 基礎スラブ=pondasi / フラットスラブ=tanpa balok. 【杭地業】pekerjaan tanah dasar menggunakan tiang: 既成コンクリート杭・鋼杭・場所打ちコンクリート杭. 【基礎免振】sistem di antara tanah dan pondasi → serap gaya horizontal saat gempa → cegah gaya diteruskan ke bangunan. (Sumber: text4l §4.2.4)"},{id:698,category:"jenis_kerja",source:"text4",jp:"足場の種類・作業床・仮囲い（仮設工事3語）",romaji:"ashiba no shurui / sagyouyuka / karigakoi",id_text:"Jenis perancah, lantai kerja & pagar sementara",desc:"【足場】lantai/jalur sementara untuk bekerja di ketinggian. Jenis yang sering dipakai: 枠組み足場, 単管足場, くさび緊結式足場. Dibuat dari 単管 atau komponen khusus. 【作業床】lantai perancah yang bisa diinjak untuk bekerja — dibuat dengan 足場板（布板）yang direntangkan. 【仮囲い】pembatas sementara antara lokasi proyek dengan tanah tetangga/jalan → cegah bahaya, pencurian & batasi akses orang tidak berkepentingan. (Sumber: text4l §4.2.5)"},{id:699,category:"jenis_kerja",source:"text4",jp:"配筋・拾い出し・あそび・あき・間隔（鉄筋基本5語）",romaji:"haikin / hiroidashi / asobi / aki / kankaku",id_text:"5 istilah dasar pemasangan & perhitungan besi tulangan",desc:"【配筋】menempatkan dan merakit besi tulangan. Metode: ダブル配筋, シングル配筋, 千鳥配筋. 【拾い出し】menghitung kebutuhan material, jumlah, dan jam kerja dari gambar/spesifikasi. 【あそび】toleransi/kelonggaran. 【あき】jarak antara besi tulangan satu dengan besi tulangan lainnya. 【間隔】jarak antar titik TENGAH besi tulangan. (Sumber: text4l §4.2.6)"},{id:700,category:"jenis_kerja",source:"text4",jp:"捨てコンクリート・結束（ハッカー）・かぶり厚さ（施工精度3語）",romaji:"sutekkon / kessoku (hakkaa) / kaburi atsusa",id_text:"3 istilah presisi konstruksi beton bertulang",desc:"【捨てコン(捨てコンクリート)】cor beton tipis 5〜10㎝ untuk: ①buat referensi ketinggian, ②dasar agar tulangan & bekisting bisa dipasang tepat. 【結束】ikat persilangan besi tulangan menggunakan 結束線 dengan alat 「ハッカー」. Cara ikat:「たすき掛け」atau「片だすき」. 【かぶり厚さ】jarak dari besi tulangan ke permukaan beton yang menutupinya. (Sumber: text4l §4.2.6)"},{id:701,category:"jenis_kerja",source:"text4",jp:"建込み・ノロ・アンコ・転用・パンク・釘仕舞（型枠6語）",romaji:"tatekomi / noro / anko / ten'you / panku / kugijimai",id_text:"6 istilah pekerjaan bekisting",desc:"【建込み】dirikan bekisting sesuai garis墨出し. 【ノロ】① semen diencerkan air ② bocoran beton dari sambungan bekisting. 【アンコ】pengisi agar beton tidak masuk ke bagian alur/lekukan — dilepas setelah beton mengeras. 【転用】gunakan bekisting yang sama di lokasi lain atau lantai berikutnya (re-use). 【パンク】bekisting jebol saat pengecoran karena 支保工 kurang kuat → beton mengalir keluar. 【釘仕舞】cabut paku dari bekisting untuk re-use → juga dipakai bermakna 'beres-beres bekisting'. (Sumber: text4l §4.2.6)"},{id:702,category:"jenis_kerja",source:"text4",jp:"打ち込み・打ち重ね（150/120分）・コールドジョイント・打ち継ぎ",romaji:"uchikomi / uchikasane (hyakugojuupun/hyakunijuupun) / cold joint / uchitsugi",id_text:"Pengecoran beton berlapis — waktu kritis & jenis sambungan",desc:"【打ち込み】alirkan beton ke dalam bekisting tanpa rongga. 【打ち重ね】cor di atas beton yang BELUM mengeras. ⚠ Batas waktu: suhu <25℃ → dalam 150 menit / suhu ≥25℃ → dalam 120 menit. Jika terlambat → 【コールドジョイント】sambungan cacat. 【打ち継ぎ】cor di atas beton yang SUDAH mengeras — hanya di posisi yang struktural & kedap air dianggap aman. (Sumber: text4l §4.2.6)"},{id:703,category:"jenis_kerja",source:"text4",jp:"締固め（コンクリート）・タンピング・練り混ぜ・配合（打設品質4語）",romaji:"shimekatame / tanpingu / nerimaze / haigou (konkuriito)",id_text:"4 istilah kualitas pengecoran beton",desc:"【締固め（コンクリート）】gunakan バイブレータ untuk getar beton / pukul bekisting dengan palu karet → hilangkan rongga udara. 【タンピング】pukul permukaan bekisting slab agar beton slab menjadi padat. 【練り混ぜ】mencampur semen dan agregat secara merata. 【配合】perbandingan masing-masing bahan dalam membuat beton. (Sumber: text4l §4.2.6)"},{id:704,category:"jenis_kerja",source:"text4",jp:"納まり・取合い・見付け・見え掛かり・見え隠れ（仕上げ状態5語）",romaji:"osamari / toriaia / mitsuke / miegakari / miegakure",id_text:"5 istilah kondisi finishing & keselarasan komponen",desc:"【納まり】keseimbangan penempatan komponen.「納まりがいい/悪い」. 【取合い】bagian pertemuan 2+ komponen berbeda / penanganannya. Jika bertabrakan padahal seharusnya tidak:「取り合いが悪い」(=「納まりが悪い」). 【見付け】permukaan komponen yang terlihat dari DEPAN saat finishing. 【見え掛かり】bagian yang terlihat dari celah/sudut (lebih luas dari 見付け). 【見え隠れ】kebalikan 見え掛かり — hanya tampak saat sesuatu digerakkan/diangkat. (Sumber: text4l §4.2.7)"},{id:705,category:"jenis_kerja",source:"text4",jp:"通り・面（つら）・面一・反り・起り・陸・不陸（形状7語）",romaji:"toori / tsura / tsuraichi / sori / mukuri / roku / furoku",id_text:"7 istilah kondisi kelurusan, kerataan & kelengkungan permukaan",desc:"【通り】kondisi lurus.「通りが悪い」=bengkok.「通りを見る」=cek kelurusan. 【面(つら/めん)】permukaan. 【面一(つらいち)】2 komponen yang permukaannya rata sejajar.「面一にする」. 【反り(そり)】garis/bidang yang melengkung CEKUNG (concave). 【起り(むくり)】garis/bidang yang melengkung CEMBUNG (convex). 【陸(ろく/りく)】kondisi HORIZONTAL. Misal: 陸屋根=atap datar. 【不陸(ふろく/ふりく)】permukaan yang tidak rata/bergelombang. (Sumber: text4l §4.2.7)"},{id:706,category:"jenis_kerja",source:"text4",jp:"目違い・拝む・矩・転び・逃げ・見切る（不具合・調整6語）",romaji:"mechigai / ogamu / kane / korobi / nige / mikiru",id_text:"6 istilah cacat konstruksi & penanganan sambungan",desc:"【目違い】saat papan/tile/board disambung → permukaan tidak rata atau sendi tidak sejajar. 【拝む】bangunan/kolom yang seharusnya tegak lurus tampak miring. 【矩(かね)】sudut 90°. 【転び】kolom/dinding yang seharusnya vertikal menjadi miring. 【逃げ】toleransi dimensi yang diambil sebelumnya untuk menyerap kesalahan pengerjaan/pemasangan. 【見切る】menyelesaikan sambungan dua pekerjaan dengan rapi menggunakan「見切り材」. Misal: batas lantai-dinding. (Sumber: text4l §4.2.7)"},{id:707,category:"jenis_kerja",source:"text4",jp:"馴染み・捨て・ベタ・ふかし・手戻り・段取り・手直し・駄目（施工8語）",romaji:"najimi / sute / beta / fukashi / temodori / dandori / tenaoshi / dame",id_text:"8 istilah kondisi pemasangan & proses kerja konstruksi",desc:"【馴染み】sambungan 2+ komponen yang menempel sempurna. 【捨て】material non-struktural untuk kelancaran kerja. 【ベタ】menyebar merata tanpa celah. 【ふかし】bagian dibuat lebih besar dari rencana. 【手戻り】mengulang proses yang selesai. 【段取り】rencanakan metode & urutan kerja. 【手直し】koreksi pekerjaan ada gambar tidak sesuai. 【駄目】bagian tertinggal saat hampir selesai.「駄目直し」menyelesaikannya. (Sumber: text4l §4.2.7)"},{id:709,category:"jenis_kerja",source:"text4",jp:"ピッチ・追う・寸法・一間・一尺・一寸・一坪（寸法7語）",romaji:"picchi / ou / sunpou / ikken / isshaku / issun / hitotsubo",id_text:"7 istilah ukuran — termasuk satuan tradisional Jepang",desc:"【ピッチ】interval/jarak antar pemasangan. 【追う】mengukur dimensi dari posisi referensi. 【寸法】panjang/ukuran. 【一間(いっけん)】satuan panjang Jepang tradisional ≈1.8m (tepatnya 1818mm). 【一尺(いっしゃく)】≈30.3cm. 【一寸(いっすん)】1/10 一尺 ≈3.03cm. 【一坪(ひとつぼ)】satuan luas Jepang tradisional = 一間×一間. (Sumber: text4l §4.2.8)"},{id:710,category:"jenis_kerja",source:"text4",jp:"RC造・S造・SRC造・木造・CB造（構造略語の定義）",romaji:"RC-zou / S-zou / SRC-zou / moku-zou / CB-zou",id_text:"5 singkatan struktur bangunan — definisi akronim resmi",desc:"【RC造】Reinforced Concrete = 鉄筋コンクリート造. 【S造】Steel = 鉄骨造. 【SRC造】Steel+RC = 鉄骨鉄筋コンクリート造 (rangka baja + tulangan + beton). 【木造】kolom-balok dari kayu. 【コンクリートブロック造(CB造)】tumpukan blok beton. ⚠ Cf. id:648 untuk karakteristik masing-masing struktur lebih detail. (Sumber: text4l §4.2.9)"},{id:711,category:"listrik",source:"text4",jp:"接続・配線・離隔・絶縁・貫通・管路（電気通信基本6語）",romaji:"setsuzoku / haisen / rikaku / zetsuen / kantsuu / kanro",id_text:"6 istilah dasar listrik & telekomunikasi",desc:"【接続】menghubungkan 2+ hal. Khusus kabel komunikasi:「結線」. 【配線】memasang/merentangkan kabel metal atau fiber optik. 【離隔】memisahkan kabel/pipa dengan jarak tertentu.「離隔距離」=jarak tersebut. 【絶縁】cegah arus listrik mengalir ke bagian yang tidak seharusnya. 【貫通】melubangi dinding/lantai/langit-langit sampai sisi lain. 【管路】pipa untuk kabel listrik. Metode tanam di tanah =「管路式」. (Sumber: text4l §4.2.10)"},{id:712,category:"listrik",source:"text4",jp:"埋設（管路式・直接埋設式・とう道）・架空配線（ケーブル敷設2語）",romaji:"maisetsu sanshiki / kakuu haisen",id_text:"3 cara penanaman kabel di tanah + kabel udara",desc:"【埋設】mengubur kabel di dalam tanah. 3 metode: ①管路式=kubur pipa keras (vinyl/logam) → masukkan kabel di dalamnya. ②直接埋設式/直埋=gunakan kabel khusus直埋, tanam langsung. ③とう道=buat terowongan khusus/共同溝 untuk kabel. 【架空配線】rentangkan kabel menggunakan tiang listrik（電柱）sampai ke dalam gedung. (Sumber: text4l §4.2.10)"},{id:713,category:"listrik",source:"text4",jp:"配管する・通線・スラブ配管・MDF・隠ぺい・露出・伏せる（配管7語）",romaji:"haikan suru / tsuusen / surabu haikan / MDF / inpei / roshutsu / fuseru",id_text:"7 istilah pemasangan pipa kabel & manajemen jalur",desc:"【配管する】memasang pipa untuk kabel. 【通線】memasukkan kabel ke dalam pipa. 【スラブ配管】pipa ditanam埋設式 di lantai/langit-langit bangunan. 【MDF】Main Distribution Frame = panel manajemen saluran komunikasi dari luar ke dalam gedung. 【隠ぺい】sembunyikan di balik sesuatu.「隠ぺい配管」=pipa di dalam dinding. 【露出】tidak disembunyikan.「露出配管」=pipa tampak. 【伏せる】buat lubang keluar pipa dari slab langit-langit menggunakan エンド部材. (Sumber: text4l §4.2.10)"},{id:714,category:"listrik",source:"text4",jp:"感電・漏電・接地（アース）・避雷針・避雷器（電気安全5語）",romaji:"kanden / rouden / secchi (aasu) / hiraishin / hiraiki",id_text:"5 istilah keselamatan listrik — bahaya & proteksi",desc:"【感電】arus listrik mengalir melalui tubuh manusia. 【漏電】listrik mengalir ke bagian yang tidak seharusnya mengalirkan listrik. 【接地/アース】hubungkan peralatan listrik/sirkuit ke tanah（大地）secara elektrik → cegah感電 saat漏電 & lindungi peralatan komunikasi. 【避雷針】lindungi bangunan/manusia dari petir → terima petir & lepas arus ke atmosfer cepat. 【避雷器】lindungi peralatan komunikasi & terminal dari sambaran petir. (Sumber: text4l §4.2.10)"},{id:715,category:"listrik",source:"text4",jp:"短絡・低圧・高圧・特別高圧・圧着・直流・交流（電圧・接続7語）",romaji:"tanraku / teiatsu / kouatsu / tokubetsu kouatsu / acchaku / chokuryuu / kouryuu",id_text:"7 istilah tegangan listrik & metode penyambungan",desc:"【短絡/ショート】hubungkan 2 titik sirkuit dengan konduktor resistansi rendah. ⚠ Batas tegangan (電気設備技術基準): 【低圧】DC≤750V / AC≤600V. 【高圧】DC 750V〜7000V / AC 600V〜7000V. 【特別高圧】DC & AC >7000V. 【圧着】sambung dengan tekanan → gunakan 圧着ペンチ untuk sambung 芯線 dengan 圧着端子. 【直流/DC】arus yang besar & arahnya tidak berubah terhadap waktu. 【交流/AC】arus yang besar & arahnya berubah secara periodik. (Sumber: text4l §4.2.10)"},{id:716,category:"listrik",source:"text4",jp:"点滅・被覆・一次側/二次側・増し締め・マーキング・通電（電気作業6語）",romaji:"tenmetsu / hifuku / ichijigawa/nijigawa / mashishime / maakingu / tsuuden",id_text:"6 istilah operasi & pemeliharaan pekerjaan listrik",desc:"【点滅】menyala dan mati bergantian. 【被覆】vinyl/bagian isolasi yang menutupi 芯線 kabel. 【一次側】sisi MASUK listrik ke peralatan. 【二次側】sisi KELUAR listrik dari peralatan. 【増し締め】cek apakah baut kendur → kencangkan kembali. 【マーキング】setelah増し締め, beri tanda agar tau jika baut kembali kendur akibat getaran dll. 【通電】kondisi listrik sedang mengalir. (Sumber: text4l §4.2.10)"},{id:717,category:"listrik",source:"text4",jp:"あたる・かしめる・仕込む・振る・競る・飛ぶ/落ちる・Φ（電気現場俗語7語）",romaji:"ataru / kashimeru / shikomu / furu / seru / tobu/ochiru / pai",id_text:"7 istilah slang khas pekerjaan listrik di lapangan",desc:"【あたる】memeriksa sesuatu — di listrik: cek 通電 dengan 検電器 atau ukur voltase/arus dengan 測定器. 【かしめる】gunakan 圧着ペンチ untuk pipihkan 圧着端子（ring sleeve dll）→ kunci sambungan kabel. 【仕込む】persiapkan pekerjaan terlebih dahulu. 【振る】ubah rute pipa/kabel untuk menghindari halangan. 【競る】kondisi 2 benda hampir saling berbenturan. 【飛ぶ/落ちる】breaker aktif → sirkuit terbuka. 【Φ(ぱい)】diameter. Bacaan benar=「ふぁい」tapi di industri konstruksi dibaca「ぱい」. (Sumber: text4l §4.2.10)"},{id:718,category:"pipa",source:"text4",jp:"空調・温度・湿度・換気・排煙・衛生（設備基本6語）",romaji:"kuuchou / ondo / shitsudo / kanki / haien / eisei",id_text:"6 istilah dasar pekerjaan mekanikal & sanitasi",desc:"【空調】mengatur suhu & kelembaban ruangan =「空気調和設備」(略). 【温度】derajat panas/dingin, satuan ℃（摂氏）. 【湿度】persentase uap air dalam udara, satuan %. Tinggi=lembab（ジメジメ）. 【換気】mengganti udara kotor dalam ruangan dengan udara segar. 【排煙】mengeluarkan asap dari dalam ruangan ke luar saat kebakaran. 【衛生】menjaga kesehatan & kebersihan.「衛生設備」=peralatan air selain dapur: toilet, kamar mandi dll. (Sumber: text4l §4.2.11)"},{id:719,category:"pipa",source:"text4",jp:"死水・バリ・逆流・分岐・伸縮・蛇腹・ライニング（設備7語）",romaji:"shinimizu / bari / gyakuryuu / bunki / shinshuku / jabara / rainingu",id_text:"7 istilah kondisi & material pipa/saluran",desc:"【死水】air dalam tangki/pipa yang diam tidak bergerak dalam waktu lama. 【バリ】sisa berlebih pada tepi produk logam/plastik akibat manufaktur.「バリ取り」=menghilangkannya. 【逆流】cairan/gas mengalir berlawanan arah yang seharusnya. 【分岐】satu pipa terbagi menjadi dua. 【伸縮】memanjang dan memendek. 【蛇腹】benda berbentuk tabung yang bisa伸縮. 【ライニング】melapisi permukaan pipa/duct dengan lapisan tipis（=コーティング）. Tebal=ライニング, tipis=コーティング — tapi sering dipakai bergantian. (Sumber: text4l §4.2.11)"},{id:720,category:"pipa",source:"text4",jp:"漏洩試験・水圧試験・満水試験・勾配・汚水・雑排水（排水6語）",romaji:"rouei shiken / suiatsu shiken / mansui shiken / koubai / osui / zatsu haisui",id_text:"6 istilah uji kebocoran & sistem drainase",desc:"【漏洩試験】uji kebocoran setelah pemasangan pipa — jenis: 水圧試験 dan 満水試験. 【水圧試験】isi給水管/給湯管 dengan air → berikan tekanan → periksa kebocoran. 【満水試験】isi排水管 penuh dengan air → periksa kebocoran. 【勾配】kemiringan ringan yang dibuat agar air bisa mengalir. 【汚水】air limbah dari toilet（大便器・小便器）. 【雑排水】air limbah dari kamar mandi, wastafel, dapur. (Sumber: text4l §4.2.11)"},{id:721,category:"pipa",source:"text4",jp:"芯・先・面（設備工事の3短語）",romaji:"shin / saki / tsura (setsubi yougo)",id_text:"3 istilah pendek dengan makna teknis spesifik dalam pekerjaan設備",desc:"【芯(しん)】garis tengah（center line）pipa atau duct. 【先(さき)】ujung pipa. 【面(つら)】permukaan flange. ⚠ Kata-kata ini pendek namun memiliki makna teknis spesifik di lingkungan pekerjaan設備 — berbeda dengan pemakaian sehari-hari. (Sumber: text4l §4.2.11)"},{id:722,category:"keselamatan",source:"text4",jp:"5S活動（整理・整頓・清掃・清潔・しつけ）",romaji:"go-esu katsudou — seiri / seiton / seisou / seiketsu / shitsuke",id_text:"Program 5S — 5 kebiasaan menciptakan lingkungan kerja aman & nyaman",desc:"5S = 5 kata berawalan S: ①整理(Seiri)=pisahkan perlu & tidak perlu. ②整頓(Seiton)=tempatkan di tempat yang ditentukan, kembalikan setelah pakai. ③清掃(Seisou)=bersihkan setelah selesai kerja. ④清潔(Seiketsu)=pertahankan kondisi bersih dari ①〜③ secara konsisten. ⑤しつけ(Shitsuke)=aturan agar ①〜④ dilaksanakan disiplin. (Sumber: text4l §4.3.1)"},{id:723,category:"keselamatan",source:"text4",jp:"作業員詰め所の6ルール",romaji:"sagyouin tsumesho no roku ruuru",id_text:"6 aturan ruang istirahat pekerja di lokasi konstruksi",desc:"作業員詰め所=tempat ganti pakaian, makan & istirahat pekerja. ①喫煙は指定場所のみ — lokasi & 詰め所 adalah禁煙; tidak boleh merokok sembunyi-sembunyi. ②ゴミのポイ捨て禁止 — buang sampah di tempat & pilah; tidak mengunyah permen karet saat kerja（risiko tergigit saat ada落下物）. ③ヘルメット・安全帯は決められた場所に置く — jangan taruh sembarangan setelah pakai. ④私物はロッカーに保管 — cegah kehilangan & konflik. ⑤手洗い・消毒・うがいを実施 — higienitas saat keluar-masuk. ⑥掲示板を確認する — ada info penting termasuk asuransi pribadi. (Sumber: text4l §4.3.2)"},{id:724,category:"keselamatan",source:"text4",jp:"服装の4禁止事項（建設現場）",romaji:"fukusou no yon kinshi jikou (kensetsu genba)",id_text:"4 hal yang DILARANG terkait pakaian di lokasi konstruksi",desc:"「服装の乱れは心の乱れ」— di konstruksi tambah makna K3. Saat kerja: hanya tangan & wajah yang boleh terbuka. ①半袖・短パンで入場 DILARANG — pakai pakaian kerja lengkap; pakaian kerja harus dicuci & dijaga bersih. ②上着の前開け DILARANG — banyak突起物 di lokasi → bisa tersangkut → bahaya. ③袖まくり DILARANG — lengan harus diturunkan sampai pergelangan tangan untuk proteksi. ④ポケットに手を入れての歩行 DILARANG — saat terjatuh tiba-tiba tidak bisa melindungi diri → cedera. (Sumber: text4l §4.3.3)"},{id:725,category:"karier",source:"text4",jp:"ほうれんそう（報告・連絡・相談）— 職場コミュニケーション",romaji:"hourensou — hookoku / renraku / soudan",id_text:"Hokren-Sou — 3 pilar komunikasi efektif di tempat kerja",desc:"「ほうれんそう」= diambil dari nama sayuran bayam（ホウレンソウ）sebagai akronim. Cara: terang, fokus poin, kesimpulan disampaikan DULU. ①報告(ほうこく)=sampaikan perkembangan/hasil pekerjaan kepada 先輩 atau 職長. ②連絡(れんらく)=sampaikan informasi terkait pekerjaan atau jadwal pribadi. ③相談(そうだん)=sampaikan masalah yang muncul atau hal yang tidak dipahami. (Sumber: text4l §4.3.4)"},{id:726,category:"keselamatan",source:"text4",jp:"後片付け（作業終了後の義務・火の確認）",romaji:"atokatazuke — sagyou shuuryougo no gimu",id_text:"Aturan beres-beres wajib setelah selesai bekerja",desc:"Setelah selesai bekerja: WAJIB後片付け. Mindset: lakukan seolah sedang mempersiapkan段取り untuk pekerjaan esok hari → esok bisa langsung kerja dengan kondisi siap. ⚠ Jika menggunakan api: pastikan benar-benar sudah padam（確実に消火を確認）. (Sumber: text4l §4.3.5)"},{id:727,category:"hukum",source:"text2",jp:"職業能力開発促進法（技能検定）",romaji:"shokugyou nouryoku kaihatsu sokushin hou",id_text:"UU Pengembangan Kemampuan Kerja",desc:"Tujuan: tingkatkan 職業能力 melalui pelatihan dan ujian sertifikasi. 職業訓練: pelatihan yang diakreditasi gubernur prefektur → disebut 認定訓練. 技能検定: ujian nasional — lulus → dapat 合格証書 dan boleh menyebut diri 技能士. Ada tingkat: 特級・1級・2級・3級・基礎級. Konstruksi memiliki 32 jenis 技能検定 (per April 2022). Berbeda dari 国家免許: 技能士 adalah gelar, bukan izin wajib untuk bekerja. (Sumber: text2 §2.1.7)"},{id:728,category:"jenis_kerja",source:"text3",jp:"道路工事",romaji:"douro kouji",id_text:"Pekerjaan jalan",desc:"Membuat/memperbaiki jalan untuk manusia dan kendaraan. Jenis jalan: 高速道路, 国道, 都道府県道, 市町村道, jalan pertanian/kehutanan. Bukan hanya menghampar aspal — juga melibatkan: pemasangan rambu (標識), lampu lalu lintas dan listriknya, trotoar, marka jalan putih, lanskap (造園). Saat ini lebih banyak pekerjaan perbaikan jalan yang sudah ada. (Sumber: text3 §3.1.1)"},{id:729,category:"hukum",source:"text2",jp:"法定労働時間（週40時間・1日8時間）",romaji:"houtei roudou jikan",id_text:"Jam kerja legal",desc:"労働基準法: DILARANG menyuruh bekerja melebihi 週40時間・1日8時間 (prinsip dasar). Pengecualian: ①kasus darurat (災害復旧) ②ada 36協定 → lembur dibayar 割増賃金. Batas上限 lembur: 月45時間・年360時間. Lembur biasa=25%↑, hari libur=35%↑, malam=25%↑. (Sumber: text2 §2.1.1)"},{id:730,category:"jenis_kerja",source:"text3",jp:"表装工事（ひょうそうこうじ）",romaji:"hyousou kouji",id_text:"Pekerjaan pelapis permukaan interior",desc:"Bagian dari 内装仕上げ工事, TIDAK termasuk LGS dan pemasangan papan. Meliputi pelapis akhir dinding/langit-langit/lantai. Jenis: ①壁仕上げ (クロス/wallpaper, nat diisi pate dulu) ②天井仕上げ (kerja menghadap atas, sulit pasang wallpaper lurus) ③床仕上げ (タイル/karpet/tatami) ④塗装仕上げ (cat pengganti wallpaper) ⑤カーテン工事 (termasuk tirai panggung). (Sumber: text3 §3.2.24)"},{id:731,category:"pipa",source:"text3",jp:"配管工事（はいかんこうじ）の概要",romaji:"haikan kouji gaiyou",id_text:"Gambaran umum pekerjaan pipa",desc:"Mengalirkan air, minyak, gas, uap air ke tempat yang diperlukan menggunakan pipa logam. Mencakup: 給水, 排水, 消火設備, AC (冷媒管). 3 kemampuan dasar wajib: ①切断 (memotong pipa) ②接合 (menyambung pipa ke pipa) ③組み立て (merakit sistem). Menopang kehidupan kota yang aman dan nyaman. (Sumber: text3 §3.2.32)"},{id:732,category:"jenis_kerja",source:"text3",jp:"土木工事（どぼくこうじ）の特徴",romaji:"doboku kouji tokucho",id_text:"Karakteristik pekerjaan sipil",desc:"土木工事 = pekerjaan yang berhadapan dengan alam (laut, sungai, gunung, hutan). Tujuan: membangun infrastruktur penopang kehidupan dan ekonomi. Jenis: ダム, 河川・海岸, 道路, トンネル, 橋梁, 海洋土木, 鉄道, 上下水道, 災害復旧. Berbeda dari 建築工事 yang membangun bangunan untuk manusia tinggal. (Sumber: text3 §3.1.1)"},{id:733,category:"listrik",source:"text5l",jp:"過電流遮断機（かでんりゅうしゃだんき）/ ブレーカー / NFB",romaji:"kadenryuu shadanki / bureekaa / NFB",id_text:"Pemutus arus lebih — circuit breaker / NFB (No-Fuse Breaker)",desc:"電路に過大電流が流れたときに自動的に機器への電気供給を止める安全装置。ブレーカーとも呼ばれる。現在の配線用は「ノーヒューズブレーカー(NFB)」が主流。ブレーカーが作動することを「飛ぶ・落ちる」という。 (Sumber: text5l §5.1.2)"},{id:734,category:"alat_umum",source:"text5l",jp:"レベル（水準測量機）/ レーザーレベル",romaji:"reberu (suijun sokuryouki) / reezaa reberu",id_text:"Alat ukur ketinggian (water level / laser level)",desc:"レベル: 水準測量の機械。三脚に取り付け、内蔵の気泡管を見ながら手動で水平に合わせる。自動水平機構付きは「オートレベル」。レーザーレベル: レーザー光で壁・天井・床に水平/垂直基準線を出す機器。緑レーザーは明るい場所でも見やすい。作業時は保護メガネ必須。 (Sumber: text5l §5.2.4)"},{id:735,category:"alat_umum",source:"text5l",jp:"メジャー（巻き尺）・定規（じょうぎ）",romaji:"mejaа (makijaku) / jougi",id_text:"Meteran gulung / Penggaris (mistar lurus)",desc:"メジャー（巻き尺）: テープ状の長さ測定具。スチル製とビニル製がある。薄い金属テープのものを「コンベックス（コンベックスルール）」と呼ぶ。定規: 直線を引いたり長さを測ったりする道具。素材はアルミ・ステンレス・竹など。建具など材料に傷をつけたくない場合は竹製定規を使用。 (Sumber: text5l §5.2.4)"},{id:736,category:"alat_umum",source:"text5l",jp:"はさみ・カッターナイフ",romaji:"hasami / kattaa naifu",id_text:"Gunting / Cutter (pisau kater dengan mata patah)",desc:"はさみ: 2枚の刃ではさむようにして物を切断する道具。カッターナイフ: 刃を折ることで切れ味を持続させるナイフ。養生シート・絶縁テープ・梱包材などのカットに使用する。折り取った刃の処理は安全に行う。 (Sumber: text5l §5.2.5)"},{id:737,category:"alat_umum",source:"text5l",jp:"ハンドミキサ・かくはん機（ミキサ）",romaji:"hando mikisa / kakuhanki (mikisa)",id_text:"Pengaduk material — hand mixer / mesin pengaduk (mixer)",desc:"ハンドミキサ: 塗料・モルタル・コンクリート用の手持ち式かくはん機。トロ箱やバケツに入れた材料を手で持って練り混ぜる。かくはん機（ミキサ）: 液体および建築資材を混ぜる機械の総称。モルタルミキサ・コンクリートミキサ・バッチミキサなど複数の種類がある。 (Sumber: text5l §5.2.9)"},{id:738,category:"alat_umum",source:"text5l",jp:"ブラシ（汚れ落とし）・スポンジ",romaji:"burashi (yogore otoshi) / suponji",id_text:"Sikat pembersih / Spons pembersih (bukan sikat kawat baja)",desc:"ブラシ: 棒の先に毛の束を植えたもの。こすって汚れを落とす。石貼りでは石材からはみ出したノロをぬらしたブラシで除去。スポンジ: ポリウレタン等を発泡成形したもの。ノロで汚れた石材表面の拭き取りに使用。どちらも仕上げ工事の清掃に不可欠。金属製の「ワイヤーブラシ」とは別の用途。 (Sumber: text5l §5.2.11)"},// ── GAP FILL v45: text6l & text7l 100% coverage ─────────────────────────
// text6l §6.4 保温材の種類
{id:739,category:"pipa",source:"text6l",jp:"グラスウール（GW）・ロックウール（RW）・ポリスチレンフォーム（PS）",romaji:"gurasuu-ru (GW) / rokkuu-ru (RW) / porisuchiren fo-mu (PS)",id_text:"3 jenis utama bahan insulasi termal (保温材)",desc:"①GW（グラスウール）: serat kaca, ringan & murah, dipakai luas. ②RW（ロックウール）: serat batu, tahan api lebih baik dari GW. ③PS（ポリスチレンフォーム）: plastik busa, dipakai untuk pipa air bersih/air kotor (給水・排水配管). Semua dipasang di dalam 保温筒 (tabung insulasi). (Sumber: text6l §6.4.1)"},// text6l §6.4.2 保温保冷工事 4場所別
{id:740,category:"pipa",source:"text6l",jp:"保温工事の場所別仕上げ（4種類）",romaji:"hoon kouji no basho betsu shiage (4 shurui)",id_text:"Finishing insulasi pipa sesuai lokasi — 4 jenis",desc:"①天井内・隠蔽部: ALGC/ALK で包み固定（仕上材なし）。②屋内露出: 合成樹脂カバーまたはラッキング仕上材。③機械室・車庫・倉庫: ALGC/ALK + 鉄線 or 塩ビ亀甲金網。④屋外露出: ラッキングカバー（薄鉄板を板金加工）で覆う。湿気が多い屋外はポリエチレンフィルムで防湿も必要。 (Sumber: text6l §6.4.2)"},// text6l §6.4.2 ラッキングカバー
// text6l §6.4.3 ダクトの保温保冷
{id:742,category:"pipa",source:"text6l",jp:"ダクトの保温保冷工事 — 結露→腐食・カビ",romaji:"dakuto no hoon horei kouji — ketsuro → fushoku / kabi",id_text:"Insulasi termal duct — tanpa insulasi → kondensasi → korosi & jamur",desc:"ダクトに保温材を巻くことで冷暖房効率を高め省エネできる。保温工事を行わない空調用ダクトでは結露（けつろ）が発生しやすくなる。結露による水がダクト内外に発生すると、腐食（ふしょく）やカビの原因となる。固定材: 鋲またはアルミガラスクロス粘着テープや亀甲金網。(Sumber: text6l §6.4.3)"},// text6l §6.6.2 差し込み継手工法
{id:743,category:"pipa",source:"text6l",jp:"差し込み継手工法 — ダクト真下にビス禁止",romaji:"sashikomi tsugite kouhou — dakuto mashita ni bisu kinshi",id_text:"Insert joint method — jangan pasang sekrup langsung di bawah duct",desc:"丸ダクト（スパイラルダクト）の接続: ニップル（専用継手）を差し込み → 鉄板ビス（ピアスビス）で2〜3点固定 → 外側からダクトテープを巻く。注意: ダクト内に水が流れても漏水しないよう、ダクトの真下にビスを打たないこと。施工が比較的簡単で広く利用される。(Sumber: text6l §6.6.2)"},// text6l §6.2.1 ガス溶接3種類
{id:744,category:"pipa",source:"text6l",jp:"ガス溶接の3種類（酸素アセチレン・酸素水素・空気アセチレン）",romaji:"gasu yousetsu no 3 shurui (sanso asechirennn / sanso suiso / kuuki asechiren)",id_text:"3 jenis las gas — paling umum: oksi-asetilen",desc:"ガス溶接接合法の3種類: ①酸素アセチレン溶接（最もよく使用される）②酸素水素溶接 ③空気アセチレン溶接。ガス溶接は小口径管（しょうこうけいかん）の溶接に採用されることが多い。被覆アーク溶接法と共に配管工事で広く使用。(Sumber: text6l §6.2.1)"},// text6l §6.2.2 塩ビ管 継手挿入
{id:745,category:"pipa",source:"text6l",jp:"硬質塩化ビニル管 — 継手挿入10秒押さえ",romaji:"koushitsu enka biniru kan — tsugite sounyuu 10-byou osaeru",id_text:"Pipa PVC keras — setelah dimasukkan ke fitting, tahan 10 detik",desc:"塩ビ管の接着剤接合手順: 接着剤を塗る→一気に力を入れて挿入→マーキングまで入ったら、接着剤が乾くまで10秒くらいは力を抜かずに押さえておく→はみ出した接着剤はきれいに拭き取る。押さえないと戻ってしまい水漏れ原因になる。(Sumber: text6l §6.2.2)"},// text6l §6.2.2 面取り給水給湯
{id:746,category:"pipa",source:"text6l",jp:"硬質塩化ビニル管の面取り — 給水・給湯用は外面をよりしっかり",romaji:"koushitsu enka biniru kan no mentori — kyuusui kyuutou you wa gaimen wo yori shikkari",id_text:"Chamfering PVC — pipa air bersih/panas, bevel luar lebih kuat",desc:"塩ビ管を切断後、管が継手に入りやすくなるよう内外面ともにカッターで面取りする。外面はのり付けに関係し、内面もバリが残るとつまりの原因になる。給水・給湯用の管は入りにくいので、特に外面をよりしっかりと面取りすること。(Sumber: text6l §6.2.2)"},// text6l §6.2.1 ねじ込み後の通水
{id:747,category:"pipa",source:"text6l",jp:"ねじ込み配管 — 通水は養生時間を十分とってから",romaji:"nejikomi haikan — tsuusui wa youjou jikan wo juubun totte kara",id_text:"Pipa ulir — aliri air setelah curing time yang cukup",desc:"シール剤の塗布とねじ込みが終わったら、配管の通水（つうすい）は締め付け後に養生時間（ようじょうじかん）を十分とってから行う。養生時間前に通水するとシール剤が固まらず水漏れの原因となる。(Sumber: text6l §6.2.1)"},// text6l §6.7.1 キュービクル6600V変換
{id:748,category:"listrik",source:"text6l",jp:"キュービクル — 6600V→100V・200Vへ変換",romaji:"kyuubikuru — 6600V kara 100V / 200V e henkan",id_text:"Cubicle — trafo 6600V menjadi 100V/200V",desc:"電力会社から引き込まれる6600Vの電気は、PAS（高圧気中開閉器）を経由してキュービクルに供給される。キュービクルでは受電した6600Vの電圧が100Vや200Vに変換される。内部には遮断器と断路器があり電気を遮断できる。高圧受変電設備工事は必ず停電状態で作業する。(Sumber: text6l §6.7.1)"},// text6l §6.5.2 EF接合インジケーター
{id:749,category:"pipa",source:"text6l",jp:"EF接合 — 融着完了の確認：インジケーターの隆起",romaji:"EF setugou — yuuchaku kanryou no kakunin: injike-taa no ryuuki",id_text:"EF joint — konfirmasi selesai: indikator menonjol kiri & kanan",desc:"EF接合（エレクトロフュージョン）の検査: EFソケットのインジケーターが左右とも隆起（りゅうき）していることを確認する。コントローラーの表示が正常終了していることも確認。通電は自動的に終了する。冷却後にクランプを取り外し、チェックシートに記載する。(Sumber: text6l §6.5.2)"},// text6l §6.5.2 EF接合バーコードリーダー
{id:750,category:"pipa",source:"text6l",jp:"EF接合 — バーコードリーダーで融着データ読み込み",romaji:"EF setugou — baakoodo riidaa de yuuchaku deeta yomikomi",id_text:"EF joint — scan barcode untuk input data fusioning",desc:"EF接合の融着準備手順: ①コントローラーの電源プラグをコンセントに差し込む ②スイッチを入れる ③継手の端子に出力ケーブルを接続 ④コントローラーに付属のバーコードリーダーで融着データを読み込ませる → その後スタートボタンを押して通電開始。(Sumber: text6l §6.5.2)"},// text6l §6.8.2 マンドレル試験の詳細
{id:751,category:"telekomunikasi",source:"text6l",jp:"マンドレル通過試験 — 150m超は4号、150m以内で4号不可なら3号",romaji:"mandoreru tsuuka shiken — 150m choo wa 4-gou, 150m inai de 4-gou fuka nara 3-gou",id_text:"Mandrel test — >150m pakai No.4, ≤150m gagal No.4 → pakai No.3",desc:"管路布設後の試験: 150mを超える管路では直径600mmの4号マンドレルを通過させる。150m以内の管路で4号マンドレルの通過が不可能な場合は3号マンドレルを通過させる。目的: 管路が完全に接続されているかどうかを点検する。(Sumber: text6l §6.8.2)"},// text6l §6.5.1 ダクタイル管 曲げ角度
{id:752,category:"pipa",source:"text6l",jp:"GX形ダクタイル鋳鉄管の曲げ配管 — 2°以内・複数管で分散",romaji:"GX gata dakutairu chuutetsu kan no magari haikan — 2-do inai / fukusuu kan de bunsan",id_text:"Ductile iron GX — bending max 2°, dibagi ke beberapa pipa",desc:"GX形ダクタイル鋳鉄管の曲げ配管施工要領: ①接合後に許容曲げ角度まで曲げることができる ②2本の管の曲げ角度が2°以内になるようにする ③1箇所の継手で許容曲げ角度を曲げるのではなく、複数の管で目的の角度まで曲げる。(Sumber: text6l §6.5.1)"},// text6l §6.8.1 クロージャの色分け
{id:753,category:"telekomunikasi",source:"text6l",jp:"クロージャの色分け — グレー（光）・黒（メタル）",romaji:"kuuroojaa no iro wake — gure- (hikari) / kuro (metaru)",id_text:"Closure — abu-abu untuk serat optik, hitam untuk kabel metal",desc:"クロージャ: 光ファイバーケーブルやメタルケーブルの接続箇所・分岐箇所に設置する箱状の機器。色分け: 光ファイバー用 → グレー（灰色）。メタルケーブル用 → 黒。電柱（架空設備）に取り付けられている設備の一つ。(Sumber: text6l §6.8.1)"},// text6l §6.7.4 電線共同溝の目的
{id:754,category:"telekomunikasi",source:"text6l",jp:"電線共同溝（でんせんきょうどうこう）— 景観向上・通行しやすく",romaji:"densen kyoudoukou — keikan koujou / tsuukou shiyasuku",id_text:"Common utility duct — tujuan: estetika kota & kemudahan lalu lintas",desc:"電線共同溝: 地上の電柱や上空の電線を地下空間に収容するための施設。目的: ①景観を良くする ②道路の通行をしやすくする。注意: 工事は上下水道管・ガス管・通信管・電線管などの既存ライフラインの切断事故が発生する可能性があるため、事前調査と仮設工事が必要。(Sumber: text6l §6.7.4)"},// text6l §6.8.1 電柱建設の5手順
{id:755,category:"telekomunikasi",source:"text6l",jp:"電柱を建てる手順（5ステップ）",romaji:"denchuu wo tateru tejun (5 suteppu)",id_text:"5 langkah mendirikan tiang listrik",desc:"①電柱を建てる位置を確認 ②手掘りや探針棒（たんしんぼう）を使って埋設物（まいせつぶつ）を確認 ③手掘りと穴掘建柱車（あなほりけんちゅうしゃ）によって掘削 ④電柱を建てる ⑤埋め戻しをする。手順②で探針棒を使う点が試験で問われやすい。(Sumber: text6l §6.8.1)"},// text6l §6.2.1 冷媒銅管 ベンダー曲げ
{id:756,category:"pipa",source:"text6l",jp:"ベンダー曲げ加工 — 最小曲げ半径は銅管外径の4倍以上",romaji:"bendaa mage kakou — saishou mage hankei wa doukan gaikei no 4-bai ijou",id_text:"Bender bending — radius min: 4x diameter luar pipa tembaga",desc:"冷媒用被覆銅管のベンダー曲げ加工: 曲げ半径を小さくキレイにするには、銅管の質・肉厚に合ったベンダーを使用する。最小曲げ半径は銅管外径の4倍以上まで小さくできる（手曲げより小さくできる）。ポイント: しわを作らないようにすること。(Sumber: text6l §6.3.1)"},// text6l §6.3.2 ろう付け後の確認
{id:757,category:"pipa",source:"text6l",jp:"ろう付け後の確認 — 濡れタオルで冷却・ピンホール外観確認",romaji:"rou duke go no kakunin — nureta taoru de reikyaku / pinhoooru gaikan kakunin",id_text:"Setelah brazing — dinginkan dengan kain basah, cek pinhole",desc:"冷媒用配管のろう接合後の手順: ①配管が高温になっているため濡れタオルなどで冷却する ②ピンホール（細かい穴）やろう回り不良（ろうざいまわりふりょう）がないか外観を確認する。ろう付け条件: 酸化被膜・異物がないこと、適正なろう付け温度が確保されていること。(Sumber: text6l §6.3.2)"},// text7l §7.1 三大災害
{id:758,category:"keselamatan",source:"text7l",jp:"三大災害（さんだいさいがい）— 墜落転落・建設機械クレーン・崩壊倒壊",romaji:"sandai saigai — tsuiraku tenraku / kensetsu kikai kureeen / houkai toukai",id_text:"3 Bencana Besar Konstruksi — 4〜7割 dari total kecelakaan fatal",desc:"建設業における三大災害（全体の4〜7割を占める）: ①墜落・転落（最も多い・高所作業中） ②建設機械・クレーン災害（「激突され」「はさまれ・巻き込まれ」の多くを占める） ③崩壊・倒壊災害。三大災害以外で多いのが交通事故（道路）。(Sumber: text7l §7.1)"},// text7l §7.1.1 外国人労働者統計
{id:759,category:"keselamatan",source:"text7l",jp:"外国人労働者の死亡災害 — 建設業が最も多い",romaji:"gaikokujin roudousha no shibou saigai — kensetsu gyou ga mottomo ooi",id_text:"Kecelakaan fatal TKA — sektor konstruksi paling banyak",desc:"厚生労働省データ（令和2・3年度）: 外国人労働者の死亡災害発生件数は建設業が最も多い（製造業・その他より多い）。事故の型別では墜落・転落が最多、続いて交通事故（道路）。建設業で働く外国人は特にこのリスクに注意が必要。(Sumber: text7l §7.1.1)"},// text7l §7.1.2 崩壊倒壊の建設特有例
{id:760,category:"keselamatan",source:"text7l",jp:"崩壊・倒壊災害の建設特有例 — 仮設電柱・積載電柱",romaji:"houkai toukai saigai no kensetsu tokuyuu rei — kasetsu denchuu / sekisai denchuu",id_text:"Collapse/topple — contoh: tiang sementara patah, tiang di truk rubuh",desc:"電気工事における崩壊・倒壊事故の例: ①仮設電柱（かせつでんちゅう）が折れて倒壊する事故 ②トラックに積んでいた電柱が崩れ落ちて下敷きになる事故。上下水道工事では掘削した穴での土砂崩れによる生き埋め（1.5m以上で鋼矢板など土留め必須）。(Sumber: text7l §7.1.2, §7.1.3)"},// text7l §7.1.3 機械設置工事
{id:761,category:"keselamatan",source:"text7l",jp:"機械設置工事の死亡事故 — 大型機械の転倒による下敷き",romaji:"kikai secchi kouji no shibou jiko — oogata kikai no tentou ni yoru shitajiki",id_text:"Pekerjaan pemasangan mesin — mesin besar terbalik → tertimpa",desc:"機械設置工事（機械器具設置工事）の特徴的な死亡事故: 大型の機械の設置の場合、機械の転倒（てんとう）により下敷きになる事故が発生する。重量物の取り扱い時は転倒防止措置が不可欠。(Sumber: text7l §7.1.3)"},// text7l §7.1.3 上下水道工事3事故
{id:762,category:"keselamatan",source:"text7l",jp:"上下水道工事の3種類の事故リスク",romaji:"jougesuidou kouji no 3 shurui no jiko risuku",id_text:"3 risiko kecelakaan pekerjaan saluran air — tanah longsor, tersandung, Backhoe",desc:"上下水道工事の事故リスク: ①掘削した穴に入っている状態で土砂（どしゃ）が崩れて生き埋めになる（1.5m以上→鋼矢板で土留め必須）②舗装段差・覆工板周りの陥没・ケーブルにつまずく転落事故③バックホウのブーム旋回による接触事故・バックする時に轢かれる事故（専任誘導員を置く）。(Sumber: text7l §7.1.3)"},// text7l §7.2.3 新規入場者教育8項目
{id:763,category:"keselamatan",source:"text7l",jp:"新規入場者教育の8項目（しんきにゅうじょうしゃきょういく）",romaji:"shinki nyuujoousha kyouiku no 8 koumoku",id_text:"8 materi wajib orientasi pekerja baru di lapangan",desc:"[1]混在作業場所の状況 [2]危険有害箇所と立入禁止区域 [3]混在作業場所での作業相互の連絡・調整 [4]災害発生時の避難の方法 [5]指揮命令系統 [6]担当する作業内容と労働災害防止対策 [7]安全衛生に関する規程 [8]基本方針・目標など。死亡の半数近くが入場1週間以内に発生するため義務化。実施時間: 30分程度。(Sumber: text7l §7.2.3)"},// ── VOCAB CARDS (v46-v48: IDs 764-1040, moved from DANGER_PAIRS) ──
// ── CARDS v46: 5 new (gap fill tt_sample/tt_sample2 100% coverage) ──────
{id:764,category:"karier",source:"tt_sample",jp:"専門工事業者間のチームワーク",romaji:"senmon kouji gyousha kan no chiimu waaku",id_text:"Kerja tim antar kontraktor spesialis",desc:"Untuk memajukan konstruksi dengan lancar (流れよく工事を進める), kerja tim (チームワーク) antar kontraktor spesialis sangat penting. Masing-masing sub-kontraktor bekerja sesuai jadwal dan berkoordinasi ketat satu sama lain. (Sumber: tt_sample Q1)"},{id:765,category:"jenis_kerja",source:"tt_sample",jp:"鉄骨工事（てっこつこうじ）",romaji:"tekkotsu kouji",id_text:"Pekerjaan struktur baja (steel frame)",desc:"Membangun rangka bangunan menggunakan baja (鉄骨): kolom (柱), balok (梁), dan elemen diagonal. Struktur baja dibagi: ブレース, ラーメン構造, トラス. BEDA dari 鉄筋工事 (tulangan beton). Teknisi wajib: 鉄骨工事 = pekerjaan terpisah dari 鉄筋工事. (Sumber: tt_sample Q14)"},{id:766,category:"jenis_kerja",source:"tt_sample",jp:"コンクリート打設工事（コンクリートだせつこうじ）",romaji:"konkuriito dasetsu kouji",id_text:"Pekerjaan pengecoran beton",desc:"Menuangkan beton cair (生コン) ke dalam bekisting (型枠) untuk membentuk struktur. Alur: muat beton → pompa → tuang → padatkan (バイブレータ) → finishing. Tim: 3 peran (筒先・振動機操作・補助). Ciri visual: selang beton, helm. (Sumber: tt_sample Q16)"},{id:767,category:"jenis_kerja",source:"tt_sample2",jp:"躯体（くたい）",romaji:"kutai",id_text:"Struktur utama bangunan",desc:"Bagian struktural bangunan: 基礎 (pondasi) + 柱 (kolom) + 梁 (balok) + 壁面 (dinding) + 床 (lantai). = tulang/kerangka utama. BUKAN: 内装仕上げ (finishing dalam), 建具 (kusen pintu/jendela), 屋根 (atap). (Sumber: tt_sample2 Q13)"},{id:768,category:"jenis_kerja",source:"tt_sample2",jp:"敷き均し作業（しきならしさぎょう）",romaji:"shiki narashi sagyou",id_text:"Pekerjaan penghamparan dan perataan material",desc:"Menyebarkan dan meratakan material (aspal, agregat, tanah) secara merata di atas permukaan menggunakan mesin paver/finisher. Ciri visual: mesin hijau besar mendorong material di depannya. BEDA dari: 盛り土 (menumpuk tanah), 積み込み (memuat). (Sumber: tt_sample2 Q18)"},// ── LIFELINE4 VOCAB (v47: +164 設備工事実技 cards, IDs 769-932, source: lifeline4) ──
{id:769,category:"pipa",source:"lifeline4",furi:"はいかん",jp:"配管",romaji:"haikan",id_text:"Perpipaan / pipa",desc:"Sistem pipa untuk mengalirkan fluida (air, gas, refrigeran, dll)."},{id:770,category:"pipa",source:"lifeline4",furi:"まいせつ",jp:"埋設",romaji:"maisetsu",id_text:"Instalasi bawah tanah",desc:"Pemasangan pipa/kabel di bawah permukaan tanah."},{id:771,category:"pipa",source:"lifeline4",furi:"ちか",jp:"地下",romaji:"chika",id_text:"Bawah tanah",desc:"Area di bawah permukaan tanah. 地下配管 = pipa bawah tanah."},{id:772,category:"pipa",source:"lifeline4",furi:"とうけつ",jp:"凍結",romaji:"touketsu",id_text:"Pembekuan",desc:"Air/fluida dalam pipa membeku di cuaca dingin → pipa bisa pecah."},{id:774,category:"pipa",source:"lifeline4",furi:"れいばい",jp:"冷媒",romaji:"reibai",id_text:"Refrigeran",desc:"Zat pendingin yang bersirkulasi dalam sistem AC. Contoh: R-410A."},{id:775,category:"pipa",source:"lifeline4",furi:"しんくうびき",jp:"真空引き",romaji:"shinkuubiki",id_text:"Pemvakuman",desc:"Proses mengeluarkan udara & uap air dari pipa refrigeran sebelum mengisi refrigeran."},{id:776,category:"pipa",source:"lifeline4",furi:"かんたん",jp:"管端",romaji:"kantan",id_text:"Ujung pipa",desc:"Bagian ujung pipa/selang. シーリング材を充填する = isi sealant di ujung pipa."},{id:777,category:"pipa",source:"lifeline4",furi:"がすはいかん",jp:"ガス配管",romaji:"gasu haikan",id_text:"Perpipaan gas",desc:"Sistem pipa untuk mengalirkan gas kota. Wajib uji kebocoran setelah sambungan."},{id:778,category:"pipa",source:"lifeline4",furi:"せつぞく",jp:"接続",romaji:"setsuzoku",id_text:"Penyambungan / koneksi",desc:"Menghubungkan dua bagian pipa atau kabel."},{id:779,category:"pipa",source:"lifeline4",furi:"せつぞくぶ",jp:"接続部",romaji:"setsuzoku bu",id_text:"Bagian sambungan",desc:"Titik di mana dua pipa atau komponen bertemu/terhubung."},{id:780,category:"pipa",source:"lifeline4",furi:"こうばい",jp:"勾配",romaji:"koubai",id_text:"Kemiringan / gradien",desc:"Sudut kemiringan pipa. Kurang kemiringan → aliran buruk → genangan."},{id:781,category:"pipa",source:"lifeline4",furi:"さどる",jp:"サドル",romaji:"sadoru",id_text:"Saddle (gantungan pipa)",desc:"Penopang berbentuk pelana untuk menahan pipa di langit-langit atau dinding."},{id:782,category:"pipa",source:"lifeline4",furi:"かんかく",jp:"間隔",romaji:"kankaku",id_text:"Jarak / interval",desc:"Jarak antar saddle penyangga pipa. Jika terlalu jauh → lendutan (たわみ)."},{id:783,category:"pipa",source:"lifeline4",furi:"たわみ",jp:"たわみ",romaji:"tawami",id_text:"Lendutan / defleksi",desc:"Pipa melengkung ke bawah akibat beratnya sendiri. Terjadi jika interval saddle terlalu lebar."},{id:784,category:"pipa",source:"lifeline4",furi:"ばるぶ",jp:"バルブ",romaji:"barubu",id_text:"Katup / valve",desc:"Alat untuk mengatur atau memutus aliran fluida dalam pipa."},{id:785,category:"pipa",source:"lifeline4",furi:"りゅうりょう",jp:"流量",romaji:"ryuuryou",id_text:"Laju aliran / debit",desc:"Jumlah fluida yang mengalir per satuan waktu. Satuan: m³/h, L/min."},{id:786,category:"isolasi",source:"lifeline4",furi:"ほおんざい",jp:"保温材",romaji:"hoonzai",id_text:"Material insulasi panas",desc:"Bahan yang membungkus pipa panas agar panas tidak hilang ke lingkungan."},{id:787,category:"isolasi",source:"lifeline4",furi:"だんねつざい",jp:"断熱材",romaji:"dannetsu zai",id_text:"Material insulasi termal",desc:"Bahan pencegah perpindahan panas. Dipakai pada pipa panas & dingin."},{id:788,category:"isolasi",source:"lifeline4",furi:"でんねつせん",jp:"電熱線",romaji:"dennetsu sen",id_text:"Kawat pemanas (heating wire)",desc:"Kawat yang menghasilkan panas dari listrik. Dipasang bersama 保温材 untuk mencegah pembekuan pipa bawah tanah."},{id:789,category:"isolasi",source:"lifeline4",furi:"しーりんぐざい",jp:"シーリング材",romaji:"sheeringu zai",id_text:"Bahan sealant / penyegel",desc:"Material yang digunakan untuk menutup celah dan mencegah masuknya air/udara."},{id:790,category:"isolasi",source:"lifeline4",furi:"ぜつえんてーぷ",jp:"絶縁テープ",romaji:"zetsunen teepu",id_text:"Selotip insulasi listrik",desc:"Pita perekat untuk mengisolasi kabel listrik. Berbeda fungsi dari sealant."},{id:791,category:"isolasi",source:"lifeline4",furi:"あぶら",jp:"油",romaji:"abura",id_text:"Minyak / oli",desc:"Jika menempel pada sambungan 冷媒管 → シール性が低下 (kemampuan seal menurun)."},{id:792,category:"isolasi",source:"lifeline4",furi:"たいこうせい",jp:"耐候性",romaji:"taikousei",id_text:"Ketahanan cuaca",desc:"Kemampuan material bertahan terhadap sinar UV, hujan, dan perubahan suhu di luar ruangan."},{id:793,category:"isolasi",source:"lifeline4",furi:"あつさ",jp:"厚さ",romaji:"atsusa",id_text:"Ketebalan",desc:"Tebal material insulasi. Jika 断熱材 terlalu tipis → 結露 (kondensasi) sering terjadi."},{id:794,category:"keselamatan",source:"lifeline4",furi:"とうけつぼうし",jp:"凍結防止",romaji:"touketsu boushi",id_text:"Pencegahan pembekuan",desc:"Kombinasi 保温材 + 電熱線 untuk mencegah pipa bawah tanah membeku."},{id:795,category:"keselamatan",source:"lifeline4",furi:"けつろ",jp:"結露",romaji:"ketsuro",id_text:"Kondensasi / embun",desc:"Air mengembun pada permukaan pipa dingin karena suhu lebih rendah dari titik embun udara."},{id:796,category:"keselamatan",source:"lifeline4",furi:"たはつ",jp:"多発",romaji:"tahatsu",id_text:"Sering terjadi / berulang",desc:"Kejadian yang terjadi berulang-ulang. 結露が多発 = kondensasi sering terjadi."},{id:797,category:"keselamatan",source:"lifeline4",furi:"すいぶん",jp:"水分",romaji:"suibun",id_text:"Kandungan air / kelembapan",desc:"Jika 真空引き tidak tuntas → 水分が残る → pipa refrigeran rusak."},{id:798,category:"keselamatan",source:"lifeline4",furi:"こしょう",jp:"故障",romaji:"koshou",id_text:"Kerusakan / gangguan",desc:"Kegagalan fungsi peralatan. Refrigeran yang lembab → 内部故障."},{id:799,category:"keselamatan",source:"lifeline4",furi:"もれ",jp:"漏れ",romaji:"more",id_text:"Kebocoran",desc:"Cairan atau gas yang keluar dari tempat yang seharusnya tertutup."},{id:800,category:"keselamatan",source:"lifeline4",furi:"さび",jp:"錆",romaji:"sabi",id_text:"Karat",desc:"Oksidasi pada permukaan logam. Pipa berkarat → wajib 洗浄 & 防錆処理 sebelum konstruksi."},{id:801,category:"keselamatan",source:"lifeline4",furi:"れっか",jp:"劣化",romaji:"rekka",id_text:"Degradasi / kemunduran",desc:"Material melemah seiring waktu. Sinar UV menyebabkan 劣化 pada kabel di luar ruangan."},{id:802,category:"keselamatan",source:"lifeline4",furi:"ふちゃく",jp:"付着",romaji:"fuchaku",id_text:"Menempel / melekat",desc:"油が付着する = minyak menempel. Pada 冷媒管接続部 → シール性が低下."},{id:803,category:"keselamatan",source:"lifeline4",furi:"しんにゅう",jp:"侵入",romaji:"shinnyuu",id_text:"Masuk / infiltrasi",desc:"水が侵入する = air masuk ke dalam. Perlu dicegah pada 電線管."},{id:804,category:"keselamatan",source:"lifeline4",furi:"たわみはっせい",jp:"たわみ発生",romaji:"tawami hassei",id_text:"Timbulnya lendutan",desc:"Ketika jarak saddle terlalu lebar, pipa melengkung ke bawah."},{id:805,category:"keselamatan",source:"lifeline4",furi:"いおん",jp:"異音",romaji:"ion",id_text:"Suara abnormal",desc:"Suara tidak normal pada sistem pipa/mesin. Membuka katup terlalu cepat → aliran mendadak → 異音."},{id:806,category:"keselamatan",source:"lifeline4",furi:"ひーとろす",jp:"ヒートロス",romaji:"hiitorosu",id_text:"Heat loss (kehilangan panas)",desc:"Panas yang terbuang keluar dari sistem insulasi melalui celah 断熱材."},{id:807,category:"keselamatan",source:"lifeline4",furi:"すきま",jp:"隙間",romaji:"sukima",id_text:"Celah / gap",desc:"Celah pada material insulasi tempat panas bisa bocor keluar → ヒートロス."},{id:808,category:"alat_umum",source:"lifeline4",furi:"あつりょくしけん",jp:"圧力試験",romaji:"atsuryoku shiken",id_text:"Uji tekanan",desc:"Pengujian pipa dengan memberikan tekanan di atas tekanan kerja untuk mengecek kebocoran."},{id:809,category:"alat_umum",source:"lifeline4",furi:"がすもれしけん",jp:"ガス漏れ試験",romaji:"gasu more shiken",id_text:"Uji kebocoran gas",desc:"Wajib dilakukan setiap kali menyambung pipa gas. Menggunakan air sabun atau detektor gas."},{id:810,category:"alat_umum",source:"lifeline4",furi:"もれけんさ",jp:"漏れ検査",romaji:"more kensa",id_text:"Inspeksi kebocoran",desc:"Pemeriksaan setelah pengelasan. Wajib dilakukan untuk memastikan sambungan kedap."},{id:811,category:"alat_umum",source:"lifeline4",furi:"あんぜんかくにん",jp:"安全確認",romaji:"anzen kakunin",id_text:"Pemeriksaan keamanan",desc:"Langkah verifikasi bahwa kondisi sudah aman sebelum/sesudah pekerjaan."},{id:812,category:"alat_umum",source:"lifeline4",furi:"かくにん",jp:"確認",romaji:"kakunin",id_text:"Konfirmasi / pengecekan",desc:"Memastikan suatu hal sudah benar. 施工前に確認する = periksa sebelum mulai konstruksi."},{id:813,category:"alat_umum",source:"lifeline4",furi:"きろく",jp:"記録",romaji:"kiroku",id_text:"Pencatatan / dokumentasi",desc:"埋設配管の位置を図面に記録する = catat lokasi pipa bawah tanah di gambar teknik."},{id:814,category:"keselamatan",source:"lifeline4",furi:"ぼうし",jp:"防止",romaji:"boushi",id_text:"Pencegahan",desc:"凍結防止、感電防止、結露防止 — istilah pencegahan sering muncul di soal ujian."},{id:815,category:"keselamatan",source:"lifeline4",furi:"こうしょさぎょう",jp:"高所作業",romaji:"kousho sagyou",id_text:"Pekerjaan di ketinggian",desc:"Pekerjaan di atas 2m dari lantai/tanah. Bahaya utama: 落下 (jatuh) dan 感電 (kesetrum)."},{id:817,category:"keselamatan",source:"lifeline4",furi:"らっか",jp:"落下",romaji:"rakka",id_text:"Jatuh",desc:"Bahaya utama pekerjaan di ketinggian. Wajib pakai harness & jaring pengaman."},{id:818,category:"keselamatan",source:"lifeline4",furi:"そうおん",jp:"騒音",romaji:"souon",id_text:"Kebisingan",desc:"Bahaya yang juga perlu diperhatikan, tapi bukan bahaya utama di 高所溶接作業."},{id:819,category:"keselamatan",source:"lifeline4",furi:"きけん",jp:"危険",romaji:"kiken",id_text:"Bahaya",desc:"危険予知活動 (KY活動) = kegiatan identifikasi bahaya sebelum bekerja."},{id:820,category:"keselamatan",source:"lifeline4",furi:"あーす",jp:"アース",romaji:"aasu",id_text:"Grounding / pentanahan",desc:"Menghubungkan peralatan listrik ke tanah. Tujuan utama: 感電防止 (mencegah sengatan listrik)."},{id:821,category:"keselamatan",source:"lifeline4",furi:"しょち",jp:"処置",romaji:"shochi",id_text:"Tindakan penanganan",desc:"Langkah yang diambil untuk mengatasi/mencegah masalah. 水侵入を防ぐための処置."},{id:822,category:"keselamatan",source:"lifeline4",furi:"しようちゅうし",jp:"使用中止",romaji:"shiyou chuushi",id_text:"Menghentikan penggunaan",desc:"Jika kabel 電動工具 panas → segera hentikan penggunaan (使用を中止する)."},{id:823,category:"jenis_kerja",source:"lifeline4",furi:"せこうほうほう",jp:"施工方法",romaji:"sekou houhou",id_text:"Metode konstruksi",desc:"Cara/prosedur pelaksanaan pekerjaan konstruksi."},{id:824,category:"jenis_kerja",source:"lifeline4",furi:"ほれいこうじ",jp:"保冷工事",romaji:"horei kouji",id_text:"Pekerjaan insulasi dingin",desc:"Pemasangan insulasi pada pipa/peralatan bersuhu rendah. Mencegah 結露 dan kehilangan suhu dingin."},{id:825,category:"jenis_kerja",source:"lifeline4",furi:"ほおん",jp:"保温",romaji:"hoon",id_text:"Retensi panas / insulasi panas",desc:"Menjaga suhu pipa/peralatan panas agar tidak dingin. 保温 ≠ 断熱 (断熱 lebih umum)."},{id:826,category:"jenis_kerja",source:"lifeline4",furi:"ようせつ",jp:"溶接",romaji:"yousetsu",id_text:"Pengelasan",desc:"Menyambung logam dengan panas tinggi. Setelah selesai → wajib 漏れ検査."},{id:827,category:"jenis_kerja",source:"lifeline4",furi:"ついかせこう",jp:"追加施工",romaji:"tsuika sekou",id_text:"Pekerjaan tambahan",desc:"Pekerjaan konstruksi yang ditambahkan setelah konstruksi utama. 屋外保温の追加施工."},{id:828,category:"jenis_kerja",source:"lifeline4",furi:"じゅうてん",jp:"充填",romaji:"juuten",id_text:"Pengisian / penyumbatan",desc:"管端にシーリング材を充填する = isi sealant di ujung pipa konduit."},{id:829,category:"jenis_kerja",source:"lifeline4",furi:"はっせい",jp:"発生",romaji:"hassei",id_text:"Timbul / terjadi",desc:"錆が発生した = karat timbul. 異音が発生する = suara abnormal terjadi."},{id:830,category:"jenis_kerja",source:"lifeline4",furi:"せんじょう",jp:"洗浄",romaji:"senjou",id_text:"Pembersihan",desc:"配管内面に錆が発生した場合 → 施工前に洗浄と防錆処理が必要."},{id:831,category:"jenis_kerja",source:"lifeline4",furi:"ぼうせいしょり",jp:"防錆処理",romaji:"bousei shori",id_text:"Perawatan anti-karat",desc:"Proses melapisi permukaan logam untuk mencegah karat. Dilakukan setelah pembersihan pipa."},{id:832,category:"jenis_kerja",source:"lifeline4",furi:"へいよう",jp:"併用",romaji:"heiyou",id_text:"Penggunaan bersamaan",desc:"Menggunakan dua hal sekaligus. 保温材と電熱線を併用する = pakai insulasi + kawat pemanas bersamaan."},{id:833,category:"jenis_kerja",source:"lifeline4",furi:"ぼうすいかばー",jp:"防水カバー",romaji:"bousui kabaa",id_text:"Penutup anti-air",desc:"Penutup tahan air untuk melindungi insulasi pipa di luar ruangan dari hujan."},{id:835,category:"listrik",source:"lifeline4",furi:"はいせん",jp:"配線",romaji:"haisen",id_text:"Pengkabelan / instalasi kabel",desc:"Pemasangan dan pengaturan kabel listrik. 屋外配線 = kabel di luar ruangan."},{id:836,category:"listrik",source:"lifeline4",furi:"でんきせつび",jp:"電気設備",romaji:"denki setsubi",id_text:"Peralatan listrik",desc:"Sistem & peralatan yang berhubungan dengan listrik. アース取付が義務."},{id:837,category:"listrik",source:"lifeline4",furi:"でんどうこうぐ",jp:"電動工具",romaji:"dendou kougu",id_text:"Alat listrik (power tool)",desc:"Alat kerja yang ditenagai listrik. Jika kabel panas saat dipakai → segera 使用中止."},{id:838,category:"listrik",source:"lifeline4",furi:"でんげん",jp:"電源",romaji:"dengen",id_text:"Sumber daya / power supply",desc:"Sumber listrik untuk peralatan. 電源を強くする = memperkuat daya (bukan solusi jika kabel panas)."},{id:839,category:"listrik",source:"lifeline4",furi:"しがいせん",jp:"紫外線",romaji:"shigaisen",id_text:"Sinar ultraviolet (UV)",desc:"Sinar UV dari matahari menyebabkan 劣化 (degradasi) pada kabel dan material di luar ruangan."},{id:840,category:"listrik",source:"lifeline4",furi:"ふくすう",jp:"複数",romaji:"fukusuu",id_text:"Beberapa / jamak",desc:"複数の電線を束ねて配管に通す場合 = saat memasukkan beberapa kabel dalam satu konduit."},{id:841,category:"listrik",source:"lifeline4",furi:"ねつがこもる",jp:"熱がこもる",romaji:"netsu ga komoru",id_text:"Panas terperangkap",desc:"Bahaya memasukkan banyak kabel dalam satu konduit → panas menumpuk → risiko kebakaran."},{id:842,category:"karier",source:"lifeline4",furi:"ふじゅうぶん",jp:"不十分",romaji:"fujuubun",id_text:"Tidak mencukupi / kurang",desc:"真空引きを不十分に行った場合 = jika pemvakuman dilakukan secara tidak mencukupi."},{id:843,category:"karier",source:"lifeline4",furi:"ふそく",jp:"不足",romaji:"fusoku",id_text:"Kekurangan / kurang",desc:"勾配不足が原因で起こる問題 = masalah yang terjadi akibat kemiringan pipa kurang."},{id:844,category:"karier",source:"lifeline4",furi:"あんてい",jp:"安定",romaji:"antei",id_text:"Stabil",desc:"圧力試験の結果が安定しない場合の原因 = penyebab hasil uji tekanan tidak stabil."},{id:845,category:"karier",source:"lifeline4",furi:"げんいん",jp:"原因",romaji:"gen'in",id_text:"Penyebab",desc:"Faktor yang menyebabkan masalah. 圧力不安定の原因 = 漏れの有無 (ada tidaknya kebocoran)."},{id:846,category:"karier",source:"lifeline4",furi:"きゅうへん",jp:"急変",romaji:"kyuuhen",id_text:"Perubahan mendadak",desc:"バルブを開いた直後に流量が急変する → 異音発生の原因."},{id:847,category:"karier",source:"lifeline4",furi:"ちょくご",jp:"直後",romaji:"chokugo",id_text:"Segera setelah",desc:"バルブを開いた直後 = segera setelah katup dibuka. 直後 = langsung setelah."},{id:848,category:"karier",source:"lifeline4",furi:"ないめん",jp:"内面",romaji:"naimen",id_text:"Permukaan dalam",desc:"配管の内面に錆が発生した場合 = ketika karat muncul di permukaan dalam pipa."},{id:849,category:"karier",source:"lifeline4",furi:"ないぶ",jp:"内部",romaji:"naibu",id_text:"Bagian dalam / interior",desc:"内部に水分が残り故障する = kelembapan tersisa di bagian dalam → menyebabkan kerusakan."},{id:850,category:"karier",source:"lifeline4",furi:"ずめん",jp:"図面",romaji:"zumen",id_text:"Gambar teknik / denah",desc:"埋設配管の位置を将来確認するために、施工時に図面に記録する."},{id:851,category:"karier",source:"lifeline4",furi:"しーるせい",jp:"シール性",romaji:"shiiru sei",id_text:"Kemampuan penyegelan (sealing)",desc:"Kemampuan sambungan untuk tidak bocor. 油が付着すると→シール性が低下する."},{id:852,category:"karier",source:"lifeline4",furi:"おんど",jp:"温度",romaji:"ondo",id_text:"Suhu / temperatur",desc:"Besaran fisik panas suatu benda. Muncul sebagai pengecoh: '温度が一定になる', '温度の変化'."},{id:853,category:"karier",source:"lifeline4",furi:"うむ",jp:"有無",romaji:"umu",id_text:"Ada tidaknya / keberadaan",desc:"漏れの有無を確認する = periksa ada tidaknya kebocoran. Penyebab hasil uji tekanan tidak stabil."},{id:854,category:"isolasi",source:"lifeline4",furi:"ざいりょう",jp:"材料",romaji:"zairyou",id_text:"Material / bahan",desc:"Bahan yang digunakan dalam konstruksi. 材料の色 sering muncul sebagai pengecoh di soal ujian."},{id:855,category:"listrik",source:"lifeline4",furi:"こーど",jp:"コード",romaji:"koodo",id_text:"Kabel / kord (power tool)",desc:"Kabel listrik pada 電動工具. コードが熱くなる = kabel terasa panas → tanda bahaya → 使用中止."},{id:856,category:"karier",source:"lifeline4",furi:"げんしょう",jp:"現象",romaji:"genshou",id_text:"Fenomena / gejala",desc:"Kejadian atau gejala fisik. 断熱材の隙間から熱が漏れる現象 = fenomena panas bocor dari celah insulasi."},{id:857,category:"karier",source:"lifeline4",furi:"じゅうりょう",jp:"重量",romaji:"juuryou",id_text:"Berat / massa",desc:"Beban fisik suatu objek. Sering muncul sebagai pilihan pengecoh: '重量が増える' (berat bertambah)."},{id:858,category:"alat_umum",source:"lifeline4",furi:"あつりょくけい",jp:"圧力計",romaji:"atsuryoku kei",id_text:"Manometer / alat ukur tekanan",desc:"Alat untuk mengukur tekanan fluida dalam pipa. Berbeda dari 圧力試験 (uji tekanan). 破損 = rusak."},{id:859,category:"keselamatan",source:"lifeline4",furi:"ていか",jp:"低下",romaji:"teika",id_text:"Penurunan / penurun fungsi",desc:"シール性が低下する = kemampuan sealing menurun. Terjadi bila 冷媒管接続部 terkena 油."},{id:860,category:"karier",source:"lifeline4",furi:"いち",jp:"位置",romaji:"ichi",id_text:"Posisi / lokasi",desc:"埋設配管の位置を図面に記録する = catat posisi pipa terpendam di gambar teknik agar bisa dilacak kelak."},{id:861,category:"keselamatan",source:"lifeline4",furi:"はそん",jp:"破損",romaji:"hason",id_text:"Kerusakan / pecah",desc:"圧力計の破損 = manometer rusak. Muncul sebagai pengecoh penyebab 異音 saat katup dibuka."},{id:862,category:"keselamatan",source:"lifeline4",furi:"ぶりっじ",jp:"ブリッジ",romaji:"burijji",id_text:"Bridge (jembatan termal)",desc:"Istilah pengecoh di soal Q10. Fenomena bocornya panas melalui material yang menghubungkan sisi panas & dingin. Jawaban benar Q10 adalah ヒートロス."},{id:863,category:"keselamatan",source:"lifeline4",furi:"さーまるぎゃっぷ",jp:"サーマルギャップ",romaji:"saamaru gyappu",id_text:"Thermal gap (celah termal)",desc:"Istilah pengecoh di soal Q10. Bukan istilah standar konstruksi Jepang. Jawaban benar Q10 adalah ヒートロス bukan サーマルギャップ."},{id:864,category:"listrik",source:"lifeline4",furi:"でんせん",jp:"電線",romaji:"densen",id_text:"Kabel listrik / kawat",desc:"Kawat penghantar listrik. Berbeda dari 電線管（konduit pelindung）. 電線を複数束ねて通す = memasukkan banyak kabel sekaligus → panas terperangkap."},{id:865,category:"karier",source:"lifeline4",furi:"おくがい",jp:"屋外",romaji:"okugai",id_text:"Luar ruangan / outdoor",desc:"Di luar gedung. 屋外配線 = kabel luar ruangan（rentan UV）. 屋外で配管保温を行う場合 = saat insulasi pipa di luar ruangan → wajib tambah 防水カバー."},{id:866,category:"karier",source:"lifeline4",furi:"しゅるい",jp:"種類",romaji:"shurui",id_text:"Jenis / tipe",desc:"冷媒の種類 = jenis refrigeran. Muncul sebagai pengecoh di Q4. Penyebab 結露 多発 bukan jenis refrigeran, melainkan ketipisan 断熱材."},{id:867,category:"karier",source:"lifeline4",furi:"もくてき",jp:"目的",romaji:"mokuteki",id_text:"Tujuan / maksud",desc:"アースを取る主な目的 = tujuan utama pemasangan grounding. Jawaban: 感電防止 (mencegah sengatan listrik)."},{id:868,category:"keselamatan",source:"lifeline4",furi:"じょうしょう",jp:"上昇",romaji:"joushou",id_text:"Kenaikan / peningkatan",desc:"温度上昇防止 = mencegah kenaikan suhu. Muncul sebagai pengecoh di Q13 (tujuan アース). Tujuan アース bukan mencegah 温度上昇, melainkan 感電防止."},{id:869,category:"alat_umum",source:"lifeline4",furi:"そくてい",jp:"測定",romaji:"sokutei",id_text:"Pengukuran / pengujian",desc:"騒音測定 = pengukuran kebisingan. Muncul sebagai pengecoh di Q8 (安全確認 gas). Jawaban benar Q8 adalah ガス漏れ試験, bukan 騒音測定."},{id:870,category:"karier",source:"lifeline4",furi:"けっか",jp:"結果",romaji:"kekka",id_text:"Hasil / hasil akhir",desc:"圧力試験の結果が安定しない場合 = jika hasil uji tekanan tidak stabil → kemungkinan ada 漏れ (kebocoran)."},{id:871,category:"karier",source:"lifeline4",furi:"へんか",jp:"変化",romaji:"henka",id_text:"Perubahan",desc:"温度の変化 = perubahan suhu（pengecoh Q6）. 色の変化 = perubahan warna（pengecoh Q19）. Kedua-duanya bukan penyebab utama dalam soal terkait."},{id:872,category:"pipa",source:"lifeline4",furi:"ながれ",jp:"流れ",romaji:"nagare",id_text:"Aliran (fluida)",desc:"流れが悪くなる = aliran memburuk. Terjadi akibat 勾配不足（kemiringan pipa tidak cukup）→ fluida tidak mengalir lancar → bisa menggenang."},{id:873,category:"karier",source:"lifeline4",furi:"もんだい",jp:"問題",romaji:"mondai",id_text:"Masalah / persoalan",desc:"勾配不足が原因で起こる問題 = masalah yang timbul akibat kemiringan pipa kurang. Kunci: 流れが悪くなる (aliran memburuk)."},{id:874,category:"jenis_kerja",source:"lifeline4",furi:"ぺんきぬり",jp:"ペンキ塗り",romaji:"penki nuri",id_text:"Pengecatan dengan cat biasa",desc:"Pengecoh di Q11. Jika pipa berkarat, solusinya bukan hanya cat biasa (ペンキ塗り) — harus 洗浄＋防錆処理 (cuci + anti-karat) sebelum konstruksi."},{id:875,category:"karier",source:"lifeline4",furi:"いろ",jp:"色",romaji:"iro",id_text:"Warna",desc:"Pengecoh paling sering di soal — muncul 6x: バルブの色(Q4)、材料の色(Q6)、色を塗る(Q15)、色検査(Q16)、色をそろえる(Q18)、色が変わる(Q20). Warna tidak pernah jadi jawaban benar."},{id:876,category:"keselamatan",source:"lifeline4",furi:"ふえる",jp:"増える",romaji:"fueru",id_text:"Bertambah / meningkat",desc:"Pengecoh yang muncul 4x: 流量が増える(Q2,Q17)、重量が増える(Q14,Q20). Selalu jadi pengecoh — bukan jawaban benar di soal manapun."},{id:877,category:"karier",source:"lifeline4",furi:"いってい",jp:"一定",romaji:"ittei",id_text:"Tetap / konstan",desc:"温度が一定になる = suhu menjadi konstan. Pengecoh Q2 — bukan efek dari 真空引き yang tidak tuntas. Efek nyatanya: 水分が残り故障する."},{id:878,category:"jenis_kerja",source:"lifeline4",furi:"とりつけ",jp:"取り付け",romaji:"toritsuke",id_text:"Pemasangan / instalasi",desc:"防水カバー取り付け = pemasangan penutup anti-air. Jawaban benar Q12 — pekerjaan tambahan saat insulasi pipa di luar ruangan."},{id:879,category:"jenis_kerja",source:"lifeline4",furi:"こうかん",jp:"交換",romaji:"koukan",id_text:"Penggantian / tukar",desc:"圧力計交換 = mengganti manometer. Pengecoh Q12 — bukan pekerjaan tambahan yang dibutuhkan saat insulasi pipa luar ruangan."},{id:880,category:"jenis_kerja",source:"lifeline4",furi:"とそう",jp:"塗装",romaji:"tosou",id_text:"Pengecatan / pelapisan",desc:"色塗装 = pengecatan warna. Pengecoh Q12 — bukan tindakan tambahan standar untuk insulasi pipa di luar ruangan."},{id:881,category:"keselamatan",source:"lifeline4",furi:"あがる",jp:"上がる",romaji:"agaru",id_text:"Naik / meningkat",desc:"流量が上がる = debit aliran naik. Pengecoh Q14 — minyak pada sambungan 冷媒管 tidak menyebabkan debit naik, melainkan シール性が低下する."},{id:882,category:"karier",source:"lifeline4",furi:"おと",jp:"音",romaji:"oto",id_text:"Suara / bunyi",desc:"音検査 = inspeksi suara. Pengecoh Q16 — inspeksi wajib setelah pengelasan bukan 音検査 melainkan 漏れ検査 (inspeksi kebocoran)."},{id:883,category:"keselamatan",source:"lifeline4",furi:"へる",jp:"減る",romaji:"heru",id_text:"Berkurang / menurun",desc:"騒音が減る = kebisingan berkurang. Pengecoh Q17 — jarak saddle terlalu lebar tidak mengurangi kebisingan, melainkan menyebabkan たわみ (lendutan)."},{id:884,category:"karier",source:"lifeline4",furi:"ながさ",jp:"長さ",romaji:"nagasa",id_text:"Panjang / panjangnya",desc:"長さをそろえる = menyamakan panjang kabel. Pengecoh Q18 — saat memasukkan banyak kabel dalam konduit, yang penting bukan panjang tapi agar 熱がこもらない (panas tidak terperangkap)."},{id:885,category:"keselamatan",source:"lifeline4",furi:"かわる",jp:"変わる",romaji:"kawaru",id_text:"Berubah",desc:"色が変わる = warna berubah. Pengecoh Q20 — kemiringan pipa kurang (勾配不足) tidak menyebabkan warna berubah, melainkan 流れが悪くなる (aliran memburuk)."},{id:886,category:"karier",source:"lifeline4",furi:"あさい",jp:"浅い",romaji:"asai",id_text:"Dangkal",desc:"配管を浅く埋める = kubur pipa dangkal-dangkal. Pengecoh Q1 — pipa bawah tanah yang dangkal justru lebih rentan membeku. Harus pakai 保温材＋電熱線."},{id:887,category:"karier",source:"lifeline4",furi:"はだか",jp:"裸",romaji:"hadaka",id_text:"Tanpa pelindung / telanjang",desc:"裸のまま埋める = kubur pipa tanpa pelindung apapun. Pengecoh Q1 — cara terburuk untuk pipa bawah tanah di cuaca dingin. Wajib pakai 保温材＋電熱線."},{id:888,category:"keselamatan",source:"lifeline4",furi:"ちゅうい",jp:"注意",romaji:"chuui",id_text:"Perhatian / kewaspadaan",desc:"特に注意するべき危険 = bahaya yang perlu diwaspadai khususnya. Muncul di Q5 (高所溶接). 注意する = memperhatikan / waspada."},{id:889,category:"karier",source:"lifeline4",furi:"こくしょく",jp:"黒色",romaji:"kokushoku",id_text:"Warna hitam",desc:"黒色テープで覆う = tutup dengan selotip hitam. Pengecoh Q7 — selotip hitam bukan pelindung UV yang tepat. Yang benar: 耐候性カバーを使用する."},{id:890,category:"karier",source:"lifeline4",furi:"けいさん",jp:"計算",romaji:"keisan",id_text:"Perhitungan / kalkulasi",desc:"流量計算 = menghitung debit aliran. Pengecoh Q8 — sebelum mengoperasikan pipa gas bukan saatnya hitung debit, yang wajib adalah ガス漏れ試験 dulu."},{id:891,category:"jenis_kerja",source:"lifeline4",furi:"ひやす",jp:"冷やす",romaji:"hiyasu",id_text:"Mendinginkan / mengompres",desc:"コードを水で冷やす = dinginkan kabel dengan air. Pengecoh Q9 — JANGAN lakukan ini! Kabel panas → segera 使用を中止する. Air bisa menyebabkan korsleting."},{id:892,category:"karier",source:"lifeline4",furi:"つよい",jp:"強い",romaji:"tsuyoi",id_text:"Kuat / keras",desc:"電源を強くする = perkuat/naikkan daya listrik. Pengecoh Q9 — JANGAN dilakukan saat kabel panas. Justru memperburuk kondisi → kebakaran. Solusi: 使用中止."},{id:893,category:"karier",source:"lifeline4",furi:"しょうらい",jp:"将来",romaji:"shourai",id_text:"Masa depan / kelak",desc:"将来確認するために = agar bisa diketahui di masa depan. Konteks Q15: posisi pipa bawah tanah dicatat di 図面 agar bisa dilacak kelak."},{id:894,category:"pipa",source:"lifeline4",furi:"ひろい",jp:"広い",romaji:"hiroi",id_text:"Lebar / luas",desc:"サドル間隔が広すぎる = jarak saddle terlalu lebar. Konteks Q17 — penyebab たわみが発生する (lendutan terjadi). Interval saddle harus sesuai spesifikasi pipa."},{id:895,category:"jenis_kerja",source:"lifeline4",furi:"そろえる",jp:"そろえる",romaji:"soroeru",id_text:"Menyamakan / menyelaraskan",desc:"色をそろえる = samakan warna (Q18 pengecoh). 長さをそろえる = samakan panjang (Q18 pengecoh). Kedua-duanya bukan hal yang diutamakan saat banyak kabel masuk konduit."},{id:896,category:"karier",source:"lifeline4",furi:"さい",jp:"際",romaji:"sai",id_text:"Pada saat / ketika",desc:"〜する際（さい）= pada saat melakukan〜. 配管を埋設する際 = pada saat pemasangan pipa. Mirip 時（とき）tapi lebih formal. Sering muncul di teks soal."},{id:897,category:"karier",source:"lifeline4",furi:"ばあい",jp:"場合",romaji:"baai",id_text:"Dalam kasus / apabila",desc:"〜の場合（ばあい）= dalam kasus〜 / apabila〜. Muncul di hampir semua soal sebagai frasa syarat: 結露が多発する場合、コードが熱くなる場合, dll."},{id:898,category:"jenis_kerja",source:"lifeline4",furi:"まく",jp:"巻く",romaji:"maku",id_text:"Membelit / melilit",desc:"絶縁テープで巻く = balut dengan selotip insulasi. Pengecoh Q3 — selotip insulasi (絶縁テープ) bukan untuk waterproofing. Yang benar: シーリング材を充填する."},{id:899,category:"karier",source:"lifeline4",furi:"ふとい",jp:"太い",romaji:"futoi",id_text:"Tebal / gemuk (kabel)",desc:"電線を太くする = ganti kabel lebih tebal. Pengecoh Q3 — ketebalan kabel tidak mencegah air masuk ke konduit. Yang benar: 管端にシーリング材を充填する."},{id:900,category:"jenis_kerja",source:"lifeline4",furi:"おおう",jp:"覆う",romaji:"oou",id_text:"Menutup / menyelimuti",desc:"黒色テープで覆う = tutup dengan selotip hitam. Pengecoh Q7. 耐候性カバーで覆う = tutup dengan pelindung tahan cuaca → metode benar pencegahan UV."},{id:901,category:"karier",source:"lifeline4",furi:"みじかい",jp:"短い",romaji:"mijikai",id_text:"Pendek",desc:"電線を短く切る = potong kabel lebih pendek. Pengecoh Q7 — memotong kabel tidak ada hubungannya dengan pencegahan degradasi UV. Yang benar: 耐候性カバー."},{id:902,category:"jenis_kerja",source:"lifeline4",furi:"きる",jp:"切る",romaji:"kiru",id_text:"Memotong",desc:"電線を短く切る = potong kabel lebih pendek. Pengecoh Q7. Juga terkait 使用を中止する (hentikan, bukan potong) pada Q9."},{id:903,category:"karier",source:"lifeline4",furi:"よぶ",jp:"呼ぶ",romaji:"yobu",id_text:"Menyebut / memanggil",desc:"何と呼びますか = disebut apa? Pola pertanyaan nama/istilah. Muncul di Q10: 断熱材の隙間から熱が漏れる現象は何と呼びますか → ヒートロス."},{id:904,category:"karier",source:"lifeline4",furi:"おもな",jp:"主な",romaji:"omona",id_text:"Utama / terutama",desc:"主な目的（おもなもくてき）= tujuan utama. Muncul di Q13: アースを取る主な目的は何ですか → 感電防止. 主に = terutama, 主な = yang utama."},{id:905,category:"jenis_kerja",source:"lifeline4",furi:"せこうじ",jp:"施工時",romaji:"sekou ji",id_text:"Saat konstruksi / waktu pengerjaan",desc:"施工時（せこうじ）に行うこと = yang dilakukan saat konstruksi. Konteks Q15: posisi pipa bawah tanah dicatat di 図面 saat施工時."},{id:906,category:"jenis_kerja",source:"lifeline4",furi:"さぎょうご",jp:"作業後",romaji:"sagyou go",id_text:"Setelah pekerjaan",desc:"溶接作業後（さぎょうご）= setelah pekerjaan pengelasan. Konteks Q16: 溶接作業後に必ず行うべき検査 = inspeksi wajib setelah las → 漏れ検査."},{id:907,category:"jenis_kerja",source:"lifeline4",furi:"ぬる",jp:"塗る",romaji:"nuru",id_text:"Mengecat / melapisi",desc:"色を塗る = mengecat dengan warna. Pengecoh Q15 — mengecat pipa bukan cara untuk menandai posisi pipa bawah tanah. Yang benar: 図面に記録する."},{id:908,category:"jenis_kerja",source:"lifeline4",furi:"つける",jp:"付ける",romaji:"tsukeru",id_text:"Memasang / menempelkan",desc:"圧力計を付ける = pasang manometer. Pengecoh Q15 — memasang manometer bukan cara untuk menandai posisi pipa bawah tanah. Yang benar: 図面に記録する."},{id:909,category:"jenis_kerja",source:"lifeline4",furi:"たばねる",jp:"束ねる",romaji:"tabaneru",id_text:"Mengikat / membundel",desc:"電線を複数束ねて配管に通す = memasukkan banyak kabel yang dibundel ke dalam konduit. Konteks Q18: bahaya 熱がこもる (panas terperangkap) bila terlalu banyak."},{id:910,category:"pipa",source:"lifeline4",furi:"とおす",jp:"通す",romaji:"toosu",id_text:"Melewatkan / meneruskan",desc:"配管に通す = melewatkan melalui konduit/pipa. Konteks Q18: 電線を配管に通す場合の注意点 = hal yang diperhatikan saat kabel dimasukkan ke konduit."},{id:911,category:"pipa",source:"lifeline4",furi:"ひらく",jp:"開く",romaji:"hiraku",id_text:"Membuka",desc:"バルブを開いた直後 = segera setelah katup dibuka. Konteks Q19: membuka katup terlalu cepat → 流量が急変 → 異音が発生する. バルブはゆっくり開くべき."},{id:912,category:"jenis_kerja",source:"lifeline4",furi:"せこうまえ",jp:"施工前",romaji:"sekou mae",id_text:"Sebelum konstruksi",desc:"施工前に何を行いますか = apa yang dilakukan sebelum konstruksi? Konteks Q11: jika pipa berkarat → 施工前に洗浄と防錆処理を行う. 施工前 = sebelum mulai pengerjaan konstruksi."},{id:913,category:"karier",source:"lifeline4",furi:"ちゅういてん",jp:"注意点",romaji:"chuuiten",id_text:"Poin perhatian / hal yang perlu diperhatikan",desc:"注意点は何ですか = apa yang perlu diperhatikan? Konteks Q18: 電線を複数束ねて配管に通す場合の注意点 → 熱がこもらないようにする. Beda dari 注意（ちゅうい）= peringatan umum."},{id:914,category:"karier",source:"lifeline4",furi:"かならず",jp:"必ず",romaji:"kanarazu",id_text:"Wajib / pasti / selalu",desc:"必ず行うべき = yang wajib dilakukan. Kata kunci soal prosedur wajib. Muncul di Q8 (ガス配管接続→ガス漏れ試験必ず) dan Q16 (溶接作業後→漏れ検査必ず). 必ず = tidak boleh dilewati."},{id:915,category:"karier",source:"lifeline4",furi:"まず",jp:"まず",romaji:"mazu",id_text:"Pertama-tama / langkah pertama",desc:"まず行うべきことは何ですか = apa yang pertama harus dilakukan? Muncul di Q4 (まず確認すべき点 → 断熱材の厚さ) dan Q9 (まず行うべきこと → 使用を中止する). まず = urutan prioritas utama."},{id:916,category:"karier",source:"lifeline4",furi:"とくに",jp:"特に",romaji:"tokuni",id_text:"Khususnya / terutama",desc:"特に注意するべき危険は何ですか = bahaya apa yang khususnya perlu diwaspadai? Muncul di Q5 (高所溶接 → 特に注意 = 落下). 特に = kata penekanan untuk hal paling penting/prioritas."},{id:917,category:"jenis_kerja",source:"lifeline4",furi:"うめる",jp:"埋める",romaji:"umeru",id_text:"Mengubur / menanam (pipa)",desc:"配管を埋める = mengubur pipa (di bawah tanah). Muncul sebagai opsi Q1: 浅く埋める (kubur dangkal — pengecoh), 裸のまま埋める (kubur tanpa pelindung — pengecoh). Yang benar: 保温材＋電熱線を併用して埋める."},{id:918,category:"karier",source:"lifeline4",furi:"ふせぐ",jp:"防ぐ",romaji:"fusegu",id_text:"Mencegah / melindungi dari",desc:"〜を防ぐ = mencegah〜. Muncul di Q3: 電線管に水が侵入するのを防ぐための処置, dan Q7: 紫外線劣化を防ぐ方法. 防止（ぼうし）= pencegahan (kata benda); 防ぐ = mencegah (kata kerja)."},{id:919,category:"karier",source:"lifeline4",furi:"おこなう",jp:"行う",romaji:"okonau",id_text:"Melakukan / melaksanakan",desc:"〜を行う = melaksanakan〜. Kata kerja paling sering di soal ujian. 施工を行う = melaksanakan konstruksi, 検査を行う = melakukan inspeksi, 処置を行う = mengambil tindakan. Formal version of する."},{id:920,category:"karier",source:"lifeline4",furi:"かんがえられる",jp:"考えられる",romaji:"kangaerareru",id_text:"Yang dapat diperkirakan / kemungkinan",desc:"考えられる原因 = penyebab yang mungkin / dapat diperkirakan. Muncul di Q6: 圧力試験の結果が安定しない場合、考えられる原因はどれですか → 漏れの有無. Bentuk potensial pasif dari 考える（かんがえる）."},{id:921,category:"karier",source:"lifeline4",furi:"しようちゅう",jp:"使用中",romaji:"shiyouchuu",id_text:"Saat digunakan / sedang digunakan",desc:"使用中（しようちゅう）= sedang dipakai / dalam penggunaan. Konteks Q9: 電動工具使用中にコードが熱くなる場合 = saat power tool sedang digunakan dan kabelnya panas. 〜中 = sedang berlangsung."},{id:922,category:"karier",source:"lifeline4",furi:"べき",jp:"べき",romaji:"beki",id_text:"Seharusnya / harus dilakukan",desc:"動詞 + べき = seharusnya melakukan〜 / wajib〜. Muncul di banyak soal: 必ず行うべき検査, まず行うべきこと, 注意するべき危険. 〜すべき = 〜するべき (harus/seharusnya). Kata kunci soal prosedur wajib."},{id:923,category:"karier",source:"lifeline4",furi:"おこる",jp:"起こる",romaji:"okoru",id_text:"Terjadi / timbul",desc:"Kata kerja PALING SERING di soal — muncul di Q2,Q14,Q17,Q19,Q20 sebagai '何が起こりますか'. 起こる = terjadi (intransitif); 起こす = menyebabkan (transitif). Hafal polanya: 〜すると何が起こりますか = jika〜, apa yang terjadi?"},{id:924,category:"karier",source:"lifeline4",furi:"のこる",jp:"残る",romaji:"nokoru",id_text:"Tersisa / tertinggal",desc:"水分が残り故障する = kelembapan tersisa → menyebabkan kerusakan. Konteks Q2: pemvakuman tidak tuntas → 水分が残る (kelembapan tertinggal di dalam pipa refrigeran). 残る = tersisa; 残す = menyisakan (transitif)."},{id:925,category:"alat_umum",source:"lifeline4",furi:"しけん",jp:"試験",romaji:"shiken",id_text:"Uji / pengujian (tekanan/teknis)",desc:"圧力試験（Q6）= uji tekanan. ガス漏れ試験（Q8）= uji kebocoran gas. 試験 = pengujian terhadap batas/standar teknis. Berbeda dari 検査（けんさ）= inspeksi kondisi visual/kebocoran pasca-konstruksi."},{id:926,category:"alat_umum",source:"lifeline4",furi:"けんさ",jp:"検査",romaji:"kensa",id_text:"Inspeksi / pemeriksaan",desc:"漏れ検査（Q16）= inspeksi kebocoran — WAJIB setelah pengelasan. 色検査 & 音検査 = pengecoh Q16. 検査 = pemeriksaan kondisi pasca-pekerjaan. Berbeda dari 試験（しけん）= pengujian teknis terhadap standar/tekanan."},{id:927,category:"jenis_kerja",source:"lifeline4",furi:"さぎょう",jp:"作業",romaji:"sagyou",id_text:"Pekerjaan / operasi kerja",desc:"高所作業（Q5）= pekerjaan di ketinggian. 溶接作業後（Q16）= setelah pekerjaan pengelasan. 作業中 = sedang bekerja. 作業員（さぎょういん）= pekerja/operator. Lebih spesifik dari 工事（pekerjaan konstruksi besar）."},{id:928,category:"karier",source:"lifeline4",furi:"ほうほう",jp:"方法",romaji:"houhou",id_text:"Cara / metode",desc:"施工方法（Q1）= metode konstruksi. 防ぐ方法（Q7）= cara mencegah. 〜のための方法/〜する方法 = cara untuk〜. Sering menjadi kata kunci pertanyaan 'bagaimana caranya'. Beda dari 施工方法（metode khusus konstruksi）."},{id:929,category:"jenis_kerja",source:"lifeline4",furi:"こうじ",jp:"工事",romaji:"kouji",id_text:"Pekerjaan konstruksi",desc:"保冷工事（Q4）= pekerjaan insulasi dingin. 工事 = pekerjaan konstruksi secara umum (berskala proyek). Lebih besar dari 作業（さぎょう）= operasi kerja harian. 工事中 = sedang dalam konstruksi."},{id:930,category:"keselamatan",source:"lifeline4",furi:"あんぜん",jp:"安全",romaji:"anzen",id_text:"Aman / keselamatan",desc:"安全確認（Q8）= pemeriksaan keamanan. 安全管理 = manajemen K3. 安全第一 = safety first. 安全 = kondisi aman/safety. Kata dasar yang sering kombinasi: 安全確認、安全管理、安全帯（ハーネス）."},{id:931,category:"jenis_kerja",source:"lifeline4",furi:"せこう",jp:"施工",romaji:"sekou",id_text:"Pelaksanaan konstruksi",desc:"Kata dasar dari: 施工方法（cara konstruksi）, 施工前（sebelum konstruksi）, 施工時（saat konstruksi）, 追加施工（konstruksi tambahan）, 施工後（setelah konstruksi）. 施工する = melaksanakan konstruksi."},{id:932,category:"jenis_kerja",source:"lifeline4",furi:"とる",jp:"取る",romaji:"toru",id_text:"Mengambil / memasang / mendapatkan",desc:"アースを取る（Q13）= memasang grounding. 取り付け（とりつけ）= pemasangan（Q12）. 取る banyak makna kontekstual: mengambil, memasang, mendapatkan. Perhatikan bentuk: 取り付ける = memasang (lebih spesifik)."},// ── VOCAB v48: +108 vocab_jac + vocab_core (IDs 933-1040, furi+contoh kalimat) ──
{id:933,category:"karier",source:"vocab_jac",furi:"せいり",jp:"整理",romaji:"seiri",id_text:"Pilah / sortir",desc:"例: 不要なものを整理する。→ Pisahkan barang yang tidak perlu."},{id:934,category:"karier",source:"vocab_jac",furi:"せいとん",jp:"整頓",romaji:"seiton",id_text:"Tata / rapikan",desc:"例: 工具を決めた場所に整頓する。→ Taruh alat di tempat yang sudah ditentukan."},{id:935,category:"karier",source:"vocab_jac",furi:"せいそう",jp:"清掃",romaji:"seisou",id_text:"Bersihkan / sapu",desc:"例: 毎日作業後に清掃する。→ Bersihkan area kerja setelah selesai setiap hari."},{id:936,category:"karier",source:"vocab_jac",furi:"せいけつ",jp:"清潔",romaji:"seiketsu",id_text:"Jaga kebersihan / higienis",desc:"例: 作業員詰め所を清潔に保つ。→ Jaga ruang pekerja tetap bersih dan sehat."},{id:937,category:"karier",source:"vocab_jac",furi:"しつけ",jp:"しつけ",romaji:"shitsuke",id_text:"Disiplin / kebiasaan baik",desc:"例: 5Sの5つ目はしつけ。→ Elemen ke-5 dari 5S = disiplin menjaga aturan."},{id:938,category:"karier",source:"vocab_jac",furi:"ちーむわーく",jp:"チームワーク",romaji:"chiimu waaku",id_text:"Kerja tim",desc:"例: 専門業者間のチームワークが大切。→ Kunci lancarnya konstruksi multi-kontraktor."},{id:939,category:"karier",source:"vocab_jac",furi:"ゆういせい",jp:"優位性",romaji:"yuuisei",id_text:"Keunggulan / superioritas posisi",desc:"例: 職場の優位性を利用したいじめ＝パワハラ。→ Memanfaatkan jabatan untuk menekan orang lain."},{id:940,category:"karier",source:"vocab_jac",furi:"くつう",jp:"苦痛",romaji:"kutsuu",id_text:"Penderitaan / tekanan",desc:"例: 精神的な苦痛を与える行為はパワハラ。→ Tindakan yang menyebabkan penderitaan mental = pelecehan."},{id:941,category:"karier",source:"vocab_jac",furi:"ろうどうしゃ",jp:"労働者",romaji:"roudousha",id_text:"Pekerja / tenaga kerja",desc:"例: 労働者の安全を守る法律＝労働安全衛生法。→ UU yang melindungi keselamatan pekerja."},{id:942,category:"karier",source:"vocab_jac",furi:"じぎょうぬし",jp:"事業主",romaji:"jigyounushi",id_text:"Pemberi kerja / majikan",desc:"例: 労災保険の保険料は事業主が払う。→ Premi asuransi kecelakaan kerja ditanggung majikan."},{id:943,category:"karier",source:"vocab_jac",furi:"ししつ",jp:"資質",romaji:"shishitsu",id_text:"Kualitas / kompetensi / mutu SDM",desc:"例: 建設業法の目的は業者の資質の向上。→ Tujuan UU Konstruksi = tingkatkan mutu pelaku usaha."},{id:944,category:"karier",source:"vocab_jac",furi:"はいざい",jp:"廃材",romaji:"haizai",id_text:"Material limbah / sisa bongkaran",desc:"例: 廃材の適切な処理は建設リサイクル法で定める。→ Penanganan limbah material diatur UU Daur Ulang Konstruksi."},{id:945,category:"karier",source:"vocab_jac",furi:"さいていげん",jp:"最低限",romaji:"saiteigen",id_text:"Minimum / batas paling rendah",desc:"例: 建築基準法は最低限のルールを定める。→ UU Standar Bangunan menetapkan aturan minimum."},{id:946,category:"karier",source:"vocab_jac",furi:"けいげん",jp:"軽減",romaji:"keigen",id_text:"Pengurangan / mitigasi",desc:"例: 消防法は火災の被害を軽減する目的。→ UU Pemadam bertujuan memitigasi kerugian kebakaran."},{id:947,category:"karier",source:"vocab_jac",furi:"あんか",jp:"安価",romaji:"anka",id_text:"Murah / terjangkau",desc:"例: 水道法は安価な水の供給を目指す。→ UU Air Bersih bertujuan menyediakan air dengan harga terjangkau."},{id:948,category:"karier",source:"vocab_jac",furi:"ぎのうこうしゅう",jp:"技能講習",romaji:"ginou koushu",id_text:"Pelatihan keterampilan (wajib sebelum operasikan mesin)",desc:"例: 車両系建設機械3t以上は技能講習が必要。→ Alat berat ≥3t wajib ikut pelatihan keterampilan."},{id:949,category:"karier",source:"vocab_jac",furi:"とくべつきょういく",jp:"特別教育",romaji:"tokubetsu kyouiku",id_text:"Pendidikan khusus (wajib K3)",desc:"例: アーク溶接は特別教育が必要。→ Las busur wajib ikut pendidikan khusus K3."},{id:950,category:"karier",source:"vocab_jac",furi:"めんきょ",jp:"免許",romaji:"menkyo",id_text:"Lisensi / SIM / izin resmi negara",desc:"例: ガス溶接は免許が必要。→ Las gas membutuhkan lisensi dari negara."},{id:951,category:"jenis_kerja",source:"vocab_jac",furi:"じゅんびこうじ",jp:"準備工事",romaji:"junbi kouji",id_text:"Pekerjaan persiapan",desc:"例: 着工前に準備工事を行う。→ Sebelum mulai konstruksi, lakukan pekerjaan persiapan terlebih dahulu."},{id:952,category:"jenis_kerja",source:"vocab_jac",furi:"やりかた",jp:"遣り方",romaji:"yarikata",id_text:"Batter board / rangka referensi",desc:"例: 遣り方で建物の位置・水平を確認する。→ Batter board dipakai untuk menentukan posisi & level bangunan."},{id:953,category:"jenis_kerja",source:"vocab_jac",furi:"ねきり",jp:"根切り",romaji:"nekiri",id_text:"Penggalian fondasi",desc:"例: 基礎のために根切りを行う。→ Gali tanah untuk pemasangan fondasi bangunan."},{id:954,category:"jenis_kerja",source:"vocab_jac",furi:"うめもどし",jp:"埋戻し",romaji:"umemodoshi",id_text:"Urugan kembali / backfill",desc:"例: 配管設置後に埋戻しを行う。→ Setelah pipa terpasang, uruk kembali tanah di atasnya."},{id:955,category:"jenis_kerja",source:"vocab_jac",furi:"やまどめ",jp:"山留め",romaji:"yamadome",id_text:"Penahan tanah / earth retaining",desc:"例: 深い掘削では山留めが必要。→ Untuk galian dalam, wajib pasang sistem penahan tanah."},{id:956,category:"jenis_kerja",source:"vocab_jac",furi:"しゅんこう",jp:"竣工",romaji:"shunkou",id_text:"Selesai konstruksi / serah terima",desc:"例: 竣工検査に合格したら引き渡し。→ Setelah lulus inspeksi akhir, bangunan diserahkan ke pemilik."},{id:957,category:"jenis_kerja",source:"vocab_jac",furi:"ちゃっこう",jp:"着工",romaji:"chakkou",id_text:"Mulai konstruksi / groundbreaking",desc:"例: 着工から竣工まで18ヶ月かかった。→ Dari mulai konstruksi sampai selesai butuh 18 bulan."},{id:958,category:"jenis_kerja",source:"vocab_jac",furi:"こうき",jp:"工期",romaji:"kouki",id_text:"Periode konstruksi / durasi proyek",desc:"例: 工期を守るには工程管理が重要。→ Untuk tepat waktu, manajemen jadwal konstruksi itu krusial."},{id:959,category:"jenis_kerja",source:"vocab_jac",furi:"しめがため",jp:"締固め",romaji:"shime gatame",id_text:"Pemadatan tanah / compaction",desc:"例: 盛り土は転圧機で締固める。→ Tanah urukan dipadatkan menggunakan mesin pemadat."},{id:960,category:"jenis_kerja",source:"vocab_jac",furi:"だんきり",jp:"段切り",romaji:"dankiri",id_text:"Pemotongan bertangga di lereng",desc:"例: 急な斜面に盛り土するとき段切りを行う。→ Saat mengurug lereng curam, potong bertangga agar tidak longsor."},{id:961,category:"jenis_kerja",source:"vocab_jac",furi:"ろしょう",jp:"路床",romaji:"roshou",id_text:"Subgrade / lapisan tanah dasar jalan",desc:"例: 路床の上に路盤材を敷く。→ Di atas subgrade, hampar material lapis pondasi jalan."},{id:962,category:"jenis_kerja",source:"vocab_jac",furi:"おしど",jp:"押土",romaji:"oshido",id_text:"Mendorong tanah (bulldozer)",desc:"例: ブルドーザで土砂を押土する。→ Bulldozer dipakai untuk mendorong timbunan tanah."},{id:963,category:"jenis_kerja",source:"vocab_jac",furi:"うんぱん",jp:"運搬",romaji:"unpan",id_text:"Pengangkutan / transport material",desc:"例: ダンプカーで土砂を運搬する。→ Truk dump dipakai untuk mengangkut tanah galian."},{id:964,category:"jenis_kerja",source:"vocab_jac",furi:"しきならし",jp:"敷き均し",romaji:"shiki narashi",id_text:"Penghamparan & perataan",desc:"例: アスファルトをフィニッシャーで敷き均す。→ Aspal dihampar dan diratakan menggunakan mesin finisher."},{id:965,category:"jenis_kerja",source:"vocab_jac",furi:"くったい",jp:"躯体",romaji:"kutai",id_text:"Struktur utama bangunan",desc:"例: 躯体＝基礎・柱・梁・壁・床。→ Kutai = pondasi + kolom + balok + dinding + lantai."},{id:966,category:"jenis_kerja",source:"vocab_jac",furi:"ないそう",jp:"内装",romaji:"naisou",id_text:"Finishing interior",desc:"例: 躯体工事の後に内装仕上げを行う。→ Setelah struktur selesai, baru pekerjaan finishing interior."},{id:967,category:"jenis_kerja",source:"vocab_jac",furi:"かたわく",jp:"型枠",romaji:"katawaku",id_text:"Bekisting / formwork",desc:"例: 型枠にコンクリートを打設する。→ Tuang beton ke dalam bekisting untuk membentuk struktur."},{id:968,category:"jenis_kerja",source:"vocab_jac",furi:"しほこう",jp:"支保工",romaji:"shihokou",id_text:"Perancah penyangga / shoring",desc:"例: 型枠を鉄パイプで支保工する。→ Perkuat bekisting menggunakan perancah dari pipa baja."},{id:969,category:"jenis_kerja",source:"vocab_jac",furi:"ようじょう",jp:"養生",romaji:"youjou",id_text:"Perawatan beton / curing",desc:"例: コンクリート打設後は養生が必要。→ Setelah pengecoran, beton perlu dirawat agar mengeras sempurna."},{id:970,category:"jenis_kerja",source:"vocab_jac",furi:"てっきん",jp:"鉄筋",romaji:"tekkin",id_text:"Tulangan baja / rebar",desc:"例: 鉄筋はコンクリートの引張力を補う。→ Tulangan baja menambah kekuatan tarik pada beton."},{id:971,category:"jenis_kerja",source:"vocab_jac",furi:"くぎじまい",jp:"釘仕舞",romaji:"kugi jimai",id_text:"Mencabut paku (daur ulang bekisting)",desc:"例: 型枠解体後に釘仕舞をして再利用する。→ Setelah bekisting dibongkar, cabut paku agar bisa dipakai ulang."},{id:972,category:"jenis_kerja",source:"vocab_jac",furi:"てんよう",jp:"転用",romaji:"tenyou",id_text:"Penggunaan ulang / reuse bekisting",desc:"例: 型枠の転用回数を記録する。→ Catat berapa kali bekisting sudah dipakai ulang."},{id:973,category:"alat_umum",source:"vocab_jac",furi:"つぼ",jp:"坪",romaji:"tsubo",id_text:"Tsubo — satuan luas (≈3.3 m²)",desc:"例: 1坪＝約3.3m²。→ Satuan luas tradisional Jepang, masih dipakai di properti."},{id:974,category:"alat_umum",source:"vocab_jac",furi:"しゃく",jp:"尺",romaji:"shaku",id_text:"Shaku — satuan panjang (≈30.3 cm)",desc:"例: 1尺＝約30.3cm。→ 10寸＝1尺、10尺＝1丈。"},{id:975,category:"alat_umum",source:"vocab_jac",furi:"すん",jp:"寸",romaji:"sun",id_text:"Sun — satuan panjang (≈3.03 cm)",desc:"例: 1寸＝約3.03cm＝1尺の1/10。→ Sering muncul di gambar teknik bangunan tradisional Jepang."},{id:976,category:"alat_umum",source:"vocab_jac",furi:"いっけん",jp:"一間",romaji:"ikken",id_text:"1 Ken — satuan panjang (≈1.818 m)",desc:"例: 柱の間隔は一間（約1.82m）が基本。→ Jarak antar kolom standar bangunan Jepang = 1 ken."},{id:977,category:"pipa",source:"vocab_jac",furi:"かんろ",jp:"管路",romaji:"kanro",id_text:"Jalur pipa / conduit path",desc:"例: マンホール間を結ぶのが管路。→ Jalur pipa yang menghubungkan antar manhole."},{id:978,category:"pipa",source:"vocab_jac",furi:"まいせつぶつ",jp:"埋設物",romaji:"maisetsu butsu",id_text:"Utilitas bawah tanah / buried utilities",desc:"例: 穴を掘る前に埋設物を確認する。→ Sebelum menggali, periksa dulu ada tidaknya pipa/kabel bawah tanah."},{id:979,category:"pipa",source:"vocab_jac",furi:"たてこう",jp:"立坑",romaji:"tatekou",id_text:"Shaft vertikal / sumur akses",desc:"例: 推進工事の発進立坑をジャッキで掘る。→ Shaft vertikal dipakai sebagai titik start konstruksi jacking."},{id:980,category:"pipa",source:"vocab_jac",furi:"きょうどうこう",jp:"共同溝",romaji:"kyoudoukou",id_text:"Saluran utilitas bersama",desc:"例: 電気・ガス・水道を共同溝にまとめる。→ Listrik, gas, air bersih dikumpulkan dalam 1 saluran bawah tanah."},{id:981,category:"pipa",source:"vocab_jac",furi:"どかぶり",jp:"土被り",romaji:"dokaburi",id_text:"Kedalaman penimbunan / cover tanah",desc:"例: 車道の管路の土被りは0.8m以上。→ Pipa di bawah jalan harus tertanam minimal 0.8m."},{id:982,category:"pipa",source:"vocab_jac",furi:"ぼうせい",jp:"防錆",romaji:"bousei",id_text:"Anti-karat / rust prevention",desc:"例: 配管施工前に洗浄と防錆処理を行う。→ Sebelum pasang pipa berkarat, bersihkan dan beri lapisan anti-karat."},{id:992,category:"listrik",source:"vocab_jac",furi:"ぜつえん",jp:"絶縁",romaji:"zetsuen",id_text:"Insulasi listrik",desc:"例: 電気が他の部分に流れないよう絶縁する。→ Cegah arus mengalir ke bagian lain dengan insulasi."},{id:993,category:"listrik",source:"vocab_jac",furi:"せっち",jp:"接地",romaji:"secchi",id_text:"Pentanahan / grounding",desc:"例: 感電防止のため電気設備にアース(接地)を取る。→ Pasang grounding di peralatan listrik untuk cegah sengatan."},{id:994,category:"listrik",source:"vocab_jac",furi:"ろうでん",jp:"漏電",romaji:"rouden",id_text:"Kebocoran listrik",desc:"例: 漏電は感電・火災の原因になる。→ Kebocoran listrik bisa menyebabkan sengatan dan kebakaran."},{id:995,category:"listrik",source:"vocab_jac",furi:"たんらく",jp:"短絡",romaji:"tanraku",id_text:"Korsleting / short circuit",desc:"例: 2本以上の電線が負荷なしに接触すると短絡。→ Dua kabel bersentuhan tanpa beban = korsleting."},{id:1000,category:"keselamatan",source:"vocab_jac",furi:"ついらく",jp:"墜落",romaji:"tsuiraku",id_text:"Jatuh dari ketinggian (orang)",desc:"例: 建設業の三大災害の1位は墜落・転落。→ Jatuh dari ketinggian = penyebab kecelakaan terbesar di konstruksi."},{id:1002,category:"keselamatan",source:"vocab_jac",furi:"さんそけつぼう",jp:"酸素欠乏",romaji:"sanso ketsubou",id_text:"Kekurangan oksigen",desc:"例: マンホール内は酸素欠乏に注意が必要。→ Di dalam manhole, waspadai kondisi kekurangan oksigen."},{id:1003,category:"keselamatan",source:"vocab_jac",furi:"どどめ",jp:"土留め",romaji:"dodo me",id_text:"Penahan tanah / soil retaining",desc:"例: 掘削深さ1.5m以上では土留めが必要。→ Galian lebih dari 1.5m wajib pasang penahan tanah."},{id:1004,category:"keselamatan",source:"vocab_jac",furi:"かんき",jp:"換気",romaji:"kanki",id_text:"Ventilasi / sirkulasi udara",desc:"例: マンホール作業前に換気を行う。→ Sebelum masuk manhole, pastikan ada ventilasi yang cukup."},{id:1007,category:"jenis_kerja",source:"vocab_jac",furi:"せこうかんり",jp:"施工管理",romaji:"sekou kanri",id_text:"Manajemen pelaksanaan konstruksi",desc:"例: 施工管理＝品質・工程・原価・安全・環境の管理。→ Construction management = kelola kualitas, jadwal, biaya, K3, lingkungan."},{id:1008,category:"jenis_kerja",source:"vocab_jac",furi:"ひんしつ",jp:"品質",romaji:"hinshitsu",id_text:"Kualitas / mutu",desc:"例: 施工管理の4大管理のひとつが品質管理。→ Salah satu dari 4 manajemen konstruksi = quality control."},{id:1009,category:"jenis_kerja",source:"vocab_jac",furi:"こうてい",jp:"工程",romaji:"koutei",id_text:"Jadwal / tahapan proses",desc:"例: 工程表で工事の進捗を管理する。→ Gunakan bagan jadwal untuk pantau kemajuan konstruksi."},{id:1011,category:"salam",source:"vocab_jac",furi:"ごあんぜんに",jp:"ご安全に",romaji:"go anzen ni",id_text:"Semoga selamat / stay safe",desc:"例: 工事現場での挨拶は「ご安全に」。→ Sapaan khas di lokasi konstruksi = semoga selamat bekerja."},{id:1012,category:"salam",source:"vocab_jac",furi:"おつかれさまです",jp:"お疲れ様です",romaji:"otsukaresama desu",id_text:"Terima kasih sudah bekerja keras",desc:"例: 現場でも事務所でもすれ違ったときに使える。→ Bisa dipakai di mana saja — di lapangan, kantor, atau lorong."},{id:1013,category:"salam",source:"vocab_jac",furi:"あぶない",jp:"危ない",romaji:"abunai",id_text:"Bahaya! / Awas!",desc:"例: まわりの人が「危ない！」と叫んだらすぐ反応。→ Jika orang sekitar berteriak 'bahaya!', segera bereaksi."},{id:1018,category:"jenis_kerja",source:"vocab_core",furi:"しようしょ",jp:"仕様書",romaji:"shiyousho",id_text:"Dokumen spesifikasi teknis",desc:"例: 施工は仕様書に従って行う。→ Pelaksanaan konstruksi harus sesuai spesifikasi teknis."},{id:1019,category:"jenis_kerja",source:"vocab_core",furi:"けんちく",jp:"建築",romaji:"kenchiku",id_text:"Bangunan / konstruksi gedung",desc:"例: 建築工事＝住宅・ビルなどの建物を作る工事。→ Pekerjaan membangun rumah, gedung, dll."},{id:1020,category:"jenis_kerja",source:"vocab_core",furi:"どぼく",jp:"土木",romaji:"doboku",id_text:"Teknik sipil / infrastruktur",desc:"例: 土木工事＝道路・ダム・橋など。→ Pekerjaan jalan, bendungan, jembatan, dll."},{id:1021,category:"jenis_kerja",source:"vocab_core",furi:"かいたい",jp:"解体",romaji:"kaitai",id_text:"Pembongkaran / demolition",desc:"例: 解体工事ではアスベストに注意する。→ Dalam pekerjaan bongkar, waspadai material asbes."},{id:1022,category:"jenis_kerja",source:"vocab_core",furi:"きそ",jp:"基礎",romaji:"kiso",id_text:"Fondasi / pondasi",desc:"例: 建物の基礎は躯体の一部。→ Fondasi adalah bagian dari struktur utama bangunan."},{id:1023,category:"jenis_kerja",source:"vocab_core",furi:"はしら",jp:"柱",romaji:"hashira",id_text:"Kolom / pilar",desc:"例: 柱は建物の垂直荷重を支える。→ Kolom menahan beban vertikal bangunan."},{id:1024,category:"jenis_kerja",source:"vocab_core",furi:"はり",jp:"梁",romaji:"hari",id_text:"Balok struktural",desc:"例: 梁は柱と柱をつなぐ水平部材。→ Balok = elemen horizontal yang menghubungkan kolom ke kolom."},{id:1025,category:"jenis_kerja",source:"vocab_core",furi:"ゆか",jp:"床",romaji:"yuka",id_text:"Lantai",desc:"例: 地墨は床など水平面に直接つける墨。→ Garis lantai (jizumi) ditarik langsung di permukaan horizontal."},{id:1026,category:"alat_umum",source:"vocab_core",furi:"すみだし",jp:"墨出し",romaji:"sumidashi",id_text:"Penarikan garis referensi / layout marking",desc:"例: 壁の位置を墨出しで確認する。→ Posisi dinding ditentukan dengan menarik garis referensi."},{id:1027,category:"alat_umum",source:"vocab_core",furi:"にげずみ",jp:"逃げ墨",romaji:"nigezumi",id_text:"Garis referensi offset",desc:"例: 仕上げ面から500mm逃げた位置に逃げ墨を引く。→ Garis offset dari permukaan finishing, biasanya 500mm."},{id:1028,category:"alat_umum",source:"vocab_core",furi:"じずみ",jp:"地墨",romaji:"jizumi",id_text:"Garis lantai / floor marking",desc:"例: 床に直接つける墨を地墨という。→ Garis yang ditarik langsung di lantai = garis lantai."},{id:1029,category:"alat_umum",source:"vocab_core",furi:"みずもり",jp:"水盛り",romaji:"mizumori",id_text:"Penentuan level air / water leveling",desc:"例: 水盛りで水平基準を出す。→ Tentukan level horizontal menggunakan metode air."},{id:1031,category:"pipa",source:"vocab_core",furi:"せつごう",jp:"接合",romaji:"setsugou",id_text:"Penyambungan / joint",desc:"例: 鉄管はねじ接合、ポリエチレン管はEF接合。→ Pipa baja = sambungan ulir; pipa PE = sambungan EF."},{id:1032,category:"listrik",source:"vocab_core",furi:"でんちゅう",jp:"電柱",romaji:"denchuu",id_text:"Tiang listrik / utility pole",desc:"例: 電柱を建てる前に埋設物を確認する。→ Sebelum pasang tiang listrik, cek utilitas bawah tanah."},{id:1033,category:"listrik",source:"vocab_core",furi:"まんほーる",jp:"マンホール",romaji:"manhoooru",id_text:"Manhole",desc:"例: マンホール内は酸素欠乏と有害ガスに注意。→ Di dalam manhole, waspadai kekurangan oksigen dan gas berbahaya."},{id:1034,category:"keselamatan",source:"vocab_core",furi:"あんぜんたい",jp:"安全帯",romaji:"anzentai",id_text:"Harness / sabuk keselamatan",desc:"例: 高所作業では安全帯（フルハーネス型）を着用。→ Wajib pakai harness tipe full-body untuk kerja di ketinggian."},{id:1035,category:"keselamatan",source:"vocab_core",furi:"ほごぐ",jp:"保護具",romaji:"hogogu",id_text:"Alat pelindung diri / APD",desc:"例: ヘルメット・安全帯・安全靴は基本の保護具。→ Helm, harness, sepatu safety = APD dasar di konstruksi."},{id:1036,category:"keselamatan",source:"vocab_core",furi:"さいがい",jp:"災害",romaji:"saigai",id_text:"Kecelakaan / bencana kerja",desc:"例: 建設業の三大災害＝墜落・機械・温度接触。→ 3 kecelakaan terbesar di konstruksi = jatuh, mesin, suhu ekstrem."},{id:1037,category:"keselamatan",source:"vocab_core",furi:"きけんよちかつどう",jp:"危険予知活動",romaji:"kiken yochi katsudou",id_text:"Kegiatan prediksi bahaya / KY",desc:"例: 作業前にKYで危険を予測し対策を立てる。→ Sebelum kerja, prediksi bahaya (KY) dan tentukan tindakan pencegahan."},{id:1038,category:"karier",source:"vocab_core",furi:"げんばかんとく",jp:"現場監督",romaji:"genba kantoku",id_text:"Pengawas lapangan / site supervisor",desc:"例: 現場監督は品質・安全・工程を管理する。→ Site supervisor mengelola kualitas, K3, dan jadwal di lapangan."},{id:1039,category:"karier",source:"vocab_core",furi:"はっちゅうしゃ",jp:"発注者",romaji:"hacchuusha",id_text:"Pemilik proyek / klien",desc:"例: 発注者から受注してゼネコンが工事を行う。→ Klien memesan → general contractor melaksanakan konstruksi."},{id:1040,category:"karier",source:"vocab_core",furi:"したうけ",jp:"下請け",romaji:"shitauke",id_text:"Sub-kontraktor",desc:"例: ゼネコンは専門工事業者に下請けに出す。→ GC menyub-kontrakkan pekerjaan spesialis ke sub-kontraktor."},// ── LIFELINE4 VOCAB v65: +55 cards from Wayground quiz PDFs (IDs 1291-1345, source: lifeline4) ──
{id:1291,category:"pipa",source:"lifeline4",furi:"おんすいかん",jp:"温水管",romaji:"onsui kan",id_text:"Pipa air panas",desc:"Pipa untuk mengalirkan air panas dari boiler/water heater ke titik penggunaan."},{id:1292,category:"pipa",source:"lifeline4",furi:"かいへいべん",jp:"開閉弁",romaji:"kaihei ben",id_text:"Katup buka-tutup (gate valve)",desc:"Katup untuk membuka dan menutup aliran fluida sepenuhnya. 機能: 流れを開閉する."},{id:1293,category:"pipa",source:"lifeline4",furi:"はいすいろ",jp:"排水路",romaji:"haisui ro",id_text:"Saluran pembuangan air",desc:"Saluran untuk mengalirkan air limbah/buangan keluar dari area kerja atau bangunan."},{id:1294,category:"pipa",source:"lifeline4",furi:"きゅうすいこう",jp:"給水口",romaji:"kyuusui kou",id_text:"Lubang suplai air / water inlet",desc:"Titik masuk air bersih ke dalam sistem perpipaan gedung."},{id:1295,category:"pipa",source:"lifeline4",furi:"つぎて",jp:"継手",romaji:"tsugite",id_text:"Fitting / sambungan pipa",desc:"Komponen penghubung dua pipa. Contoh: elbow, tee, reducer, coupling."},{id:1296,category:"pipa",source:"lifeline4",furi:"ちちゅうかん",jp:"地中管",romaji:"chichuu kan",id_text:"Pipa bawah tanah",desc:"Pipa yang ditanam di bawah permukaan tanah. Perlu perhatian kedalaman untuk cegah 凍結."},{id:1297,category:"pipa",source:"lifeline4",furi:"てんじょうかん",jp:"天井管",romaji:"tenjou kan",id_text:"Pipa langit-langit / ceiling pipe",desc:"Pipa yang dipasang di atas plafon/langit-langit ruangan."},{id:1298,category:"pipa",source:"lifeline4",furi:"しすいせん",jp:"止水栓",romaji:"shisui sen",id_text:"Keran penutup air / stopcock",desc:"Keran untuk menghentikan aliran air. 役割: 水の流れを止める."},{id:1299,category:"alat_umum",source:"lifeline4",furi:"すいへいき",jp:"水平器",romaji:"suihei ki",id_text:"Waterpass / spirit level",desc:"Alat pengukur kerataan/kelurusan horizontal. Digunakan saat memasang pipa dan peralatan."},{id:1300,category:"pipa",source:"lifeline4",furi:"きゅうとうかん",jp:"給湯管",romaji:"kyuutou kan",id_text:"Pipa air panas (suplai)",desc:"Pipa yang menyalurkan air panas ke keran, shower, dll. Berbeda dari 温水管 (lebih umum)."},{id:1301,category:"pipa",source:"lifeline4",furi:"かんきせん",jp:"換気扇",romaji:"kanki sen",id_text:"Kipas ventilasi / exhaust fan",desc:"Kipas untuk mengeluarkan udara kotor dari ruangan. 目的: 汚れた空気を排出する."},{id:1302,category:"pipa",source:"lifeline4",furi:"はいきこう",jp:"排気口",romaji:"haiki kou",id_text:"Lubang pembuangan udara",desc:"Lubang tempat udara kotor keluar dari sistem ventilasi."},{id:1303,category:"alat_umum",source:"lifeline4",furi:"きゃたつ",jp:"脚立",romaji:"kyatatsu",id_text:"Tangga lipat (stepladder)",desc:"Tangga yang bisa berdiri sendiri, dilipat saat tidak digunakan. Untuk pekerjaan di ketinggian sedang."},{id:1304,category:"alat_umum",source:"lifeline4",furi:"はしご",jp:"梯子",romaji:"hashigo",id_text:"Tangga (ladder)",desc:"Tangga panjang yang disandarkan ke dinding. Untuk akses ke tempat tinggi."},{id:1305,category:"alat_umum",source:"lifeline4",furi:"ぱいぷれんち",jp:"パイプレンチ",romaji:"paipu renchi",id_text:"Kunci pipa (pipe wrench)",desc:"Kunci khusus bergigi untuk memutar dan mengencangkan pipa besi/baja."},{id:1306,category:"alat_umum",source:"lifeline4",furi:"もんきーれんち",jp:"モンキーレンチ",romaji:"monkii renchi",id_text:"Kunci inggris (adjustable wrench)",desc:"Kunci yang bisa disesuaikan bukaannya untuk berbagai ukuran baut dan mur."},{id:1307,category:"pipa",source:"lifeline4",furi:"うすいかん",jp:"雨水管",romaji:"usui kan",id_text:"Pipa pembuangan air hujan",desc:"Pipa untuk mengalirkan air hujan dari atap ke saluran drainase. 役割: 雨水を排水する."},{id:1308,category:"pipa",source:"lifeline4",furi:"れいきゃくとう",jp:"冷却塔",romaji:"reikyaku tou",id_text:"Menara pendingin (cooling tower)",desc:"Peralatan untuk mendinginkan air sirkulasi sistem AC. 役割: 循環水を冷やす."},{id:1309,category:"pipa",source:"lifeline4",furi:"かんきこう",jp:"換気口",romaji:"kanki kou",id_text:"Lubang ventilasi",desc:"Lubang pada dinding/langit-langit untuk sirkulasi udara segar."},{id:1310,category:"alat_umum",source:"lifeline4",furi:"ほーす",jp:"ホース",romaji:"hoosu",id_text:"Selang (hose)",desc:"Pipa fleksibel untuk mengalirkan air atau fluida. Terbuat dari karet atau PVC."},{id:1311,category:"pipa",source:"lifeline4",furi:"れいふうかん",jp:"冷風管",romaji:"reifuu kan",id_text:"Pipa udara dingin / cold air duct",desc:"Saluran yang mengalirkan udara dingin dari AC ke ruangan."},{id:1312,category:"pipa",source:"lifeline4",furi:"おんぷうかん",jp:"温風管",romaji:"onpuu kan",id_text:"Pipa udara panas / hot air duct",desc:"Saluran yang mengalirkan udara panas dari pemanas ke ruangan."},{id:1313,category:"listrik",source:"lifeline4",furi:"ちちゅうけーぶる",jp:"地中ケーブル",romaji:"chichuu keeburu",id_text:"Kabel bawah tanah",desc:"Kabel listrik yang ditanam di bawah tanah, biasanya dalam konduit pelindung."},{id:1314,category:"listrik",source:"lifeline4",furi:"ちじょうけーぶる",jp:"地上ケーブル",romaji:"chijou keeburu",id_text:"Kabel di atas tanah",desc:"Kabel listrik yang dipasang di permukaan tanah atau di atas permukaan."},{id:1315,category:"listrik",source:"lifeline4",furi:"かくうけーぶる",jp:"架空ケーブル",romaji:"kakuu keeburu",id_text:"Kabel udara / overhead cable",desc:"Kabel listrik yang dibentangkan di atas tiang (電柱). Paling umum di jalanan Jepang."},{id:1316,category:"pipa",source:"lifeline4",furi:"ぐりる",jp:"グリル",romaji:"guriru",id_text:"Grill (penutup ventilasi)",desc:"Penutup berlubang pada saluran udara/ventilasi untuk mengatur arah aliran udara."},{id:1317,category:"jenis_kerja",source:"lifeline4",furi:"てんじょうない",jp:"天井内",romaji:"tenjou nai",id_text:"Bagian dalam plafon / ceiling space",desc:"Ruang tersembunyi di atas plafon tempat pipa, kabel, dan duct dipasang."},{id:1318,category:"jenis_kerja",source:"lifeline4",furi:"しゃこ",jp:"車庫",romaji:"shako",id_text:"Garasi",desc:"Tempat parkir kendaraan dalam bangunan. Perlu ventilasi khusus (換気) karena gas buang."},{id:1319,category:"jenis_kerja",source:"lifeline4",furi:"おくがいろしゅつぶぶん",jp:"屋外露出部分",romaji:"okugai roshutsu bubun",id_text:"Bagian terbuka di luar ruangan",desc:"Area di mana pipa/kabel terekspos langsung ke cuaca luar. Perlu perlindungan anti-UV dan anti-air."},{id:1320,category:"jenis_kerja",source:"lifeline4",furi:"おくないろしゅつぶぶん",jp:"屋内露出部分",romaji:"okunai roshutsu bubun",id_text:"Bagian terbuka di dalam ruangan",desc:"Area di mana pipa/kabel terlihat langsung di dalam ruangan (tidak tersembunyi di plafon/dinding)."},{id:1321,category:"pipa",source:"lifeline4",furi:"かつざいのとふ",jp:"滑剤の塗布",romaji:"katsuzai no tofu",id_text:"Pengolesan pelumas",desc:"Melumasi bagian sambungan pipa agar mudah dimasukkan. Langkah penting dalam pemasangan pipa ductile."},{id:1322,category:"pipa",source:"lifeline4",furi:"さしくちのそうにゅう",jp:"挿し口の挿入",romaji:"sashikuchi no sounyuu",id_text:"Memasukkan spigot",desc:"Proses memasukkan ujung spigot pipa ke dalam socket pipa lain. Bagian dari penyambungan pipa DIP."},{id:1323,category:"pipa",source:"lifeline4",furi:"ごむわのせっと",jp:"ゴム輪のセット",romaji:"gomu wa no setto",id_text:"Pemasangan cincin karet",desc:"Memasang o-ring/gasket karet pada alur pipa sebelum penyambungan. Fungsi: mencegah kebocoran."},{id:1324,category:"pipa",source:"lifeline4",furi:"ごむわのいち",jp:"ゴム輪の位置",romaji:"gomu wa no ichi",id_text:"Posisi cincin karet",desc:"Memastikan cincin karet berada pada posisi yang benar di alur pipa. Posisi salah = kebocoran."},{id:1325,category:"pipa",source:"lifeline4",furi:"ゆうちゃくじゅんび",jp:"融着準備",romaji:"yuuchaku junbi",id_text:"Persiapan fusi (EF welding)",desc:"Langkah-langkah persiapan sebelum proses electrofusion welding pada pipa polietilen."},{id:1326,category:"pipa",source:"lifeline4",furi:"ゆうちゃくめんのせいそう",jp:"融着面の清掃",romaji:"yuuchaku men no seisou",id_text:"Membersihkan permukaan fusi",desc:"Membersihkan area yang akan difusi dari kotoran/minyak agar sambungan sempurna."},{id:1327,category:"pipa",source:"lifeline4",furi:"いーえふそけっと",jp:"EFソケット",romaji:"EF soketto",id_text:"Soket EF (electrofusion socket)",desc:"Fitting elektrofusi yang memiliki kawat pemanas internal. Digunakan untuk menyambung pipa polietilen."},{id:1328,category:"listrik",source:"lifeline4",furi:"こんとろーら",jp:"コントローラ",romaji:"kontroora",id_text:"Pengontrol (controller)",desc:"Alat pengontrol yang mengatur proses fusi, suhu, atau operasi mesin."},{id:1329,category:"listrik",source:"lifeline4",furi:"いんじけーた",jp:"インジケータ",romaji:"injikeeta",id_text:"Indikator",desc:"Alat penunjuk status atau kondisi. Contoh: indikator tekanan, suhu, atau daya."},{id:1330,category:"pipa",source:"lifeline4",furi:"すいどうはいすいようぽりえちれんかん",jp:"水道配水用ポリエチレン管",romaji:"suidou haisui you poriechiren kan",id_text:"Pipa polietilen distribusi air",desc:"Pipa PE khusus untuk jaringan distribusi air bersih. Disambung dengan metode EF (electrofusion)."},{id:1331,category:"jenis_kerja",source:"lifeline4",furi:"ばんきんのかこう",jp:"板金の加工",romaji:"bankin no kakou",id_text:"Pengolahan pelat logam",desc:"Proses memotong, menekuk, dan membentuk lembaran logam untuk ducting atau cladding."},{id:1332,category:"alat_umum",source:"lifeline4",furi:"けがき",jp:"ケガキ",romaji:"kegaki",id_text:"Kegaki (marking layout lines)",desc:"Teknik menggaris pada permukaan logam untuk panduan pemotongan/penekukan. Alat: スクライバー."},{id:1333,category:"pipa",source:"lifeline4",furi:"かくだくとのせつぞく",jp:"角ダクトの接続",romaji:"kaku dakuto no setsuzoku",id_text:"Sambungan duct bersudut",desc:"Cara menyambung saluran udara berbentuk kotak/persegi. Metode: アングルフランジ工法 atau 共板フランジ工法."},{id:1334,category:"pipa",source:"lifeline4",furi:"だくとのせつぞくほうほう",jp:"ダクト接続方法",romaji:"dakuto no setsuzoku houhou",id_text:"Metode sambungan duct/saluran",desc:"Cara-cara menyambung saluran udara (ducting). Termasuk metode flange dan metode tanpa flange."},{id:1335,category:"pipa",source:"lifeline4",furi:"あんぐるふらんじ",jp:"アングルフランジ",romaji:"anguru furanji",id_text:"Flensa bersudut (angle flange)",desc:"Tipe flange dari besi siku yang dipasang di tepi duct untuk penyambungan dengan baut."},{id:1336,category:"alat_umum",source:"lifeline4",furi:"わっしゃー",jp:"ワッシャー",romaji:"wasshaa",id_text:"Ring / washer",desc:"Cincin logam tipis yang dipasang di bawah mur/baut untuk mendistribusikan tekanan."},{id:1337,category:"alat_umum",source:"lifeline4",furi:"なっと",jp:"ナット",romaji:"natto",id_text:"Mur (nut)",desc:"Komponen baut berkepala segi enam dengan ulir dalam. Dipasangkan dengan ボルト."},{id:1338,category:"jenis_kerja",source:"lifeline4",furi:"くっさく",jp:"掘削",romaji:"kussaku",id_text:"Penggalian / excavation",desc:"Proses menggali tanah untuk pemasangan pipa atau kabel bawah tanah."},{id:1339,category:"jenis_kerja",source:"lifeline4",furi:"かんのまいせつこうじ",jp:"管の埋設工事",romaji:"kan no maisetsu kouji",id_text:"Pekerjaan menanam pipa",desc:"Pekerjaan membenamkan pipa ke dalam tanah, termasuk penggalian, pemasangan, dan penimbunan kembali."},{id:1340,category:"listrik",source:"lifeline4",furi:"こうあつ・ていあつ",jp:"高圧・低圧",romaji:"kouatsu / teiatsu",id_text:"Tegangan tinggi dan rendah",desc:"Klasifikasi tegangan listrik. 高圧: di atas 600V. 低圧: 600V ke bawah. Penting untuk keselamatan."},{id:1342,category:"alat_umum",source:"lifeline4",furi:"かばー",jp:"カバー",romaji:"kabaa",id_text:"Cover / penutup",desc:"Penutup pelindung untuk pipa, kabel, atau peralatan. Contoh: cable cover, duct cover."},// ── LIFELINE4 VOCAB v66: +19 cards from remaining Wayground PDFs (IDs 1346-1364) ──
{id:1346,category:"pipa",source:"lifeline4",furi:"おんすいき",jp:"温水器",romaji:"onsui ki",id_text:"Pemanas air / water heater",desc:"Alat untuk memanaskan air. Bahasa Indonesia: pemanas air."},{id:1347,category:"pipa",source:"lifeline4",furi:"ふうかん",jp:"風管",romaji:"fuu kan",id_text:"Duct / saluran udara",desc:"Saluran untuk mengalirkan udara dalam sistem HVAC. Terbuat dari logam atau fiberglass."},{id:1348,category:"jenis_kerja",source:"lifeline4",furi:"そうこ",jp:"倉庫",romaji:"souko",id_text:"Gudang",desc:"Tempat menyimpan barang/material. Perlu ventilasi dan penerangan yang memadai."},{id:1349,category:"jenis_kerja",source:"lifeline4",furi:"きかいしつ",jp:"機械室",romaji:"kikai shitsu",id_text:"Ruang mesin / mechanical room",desc:"Ruang khusus tempat mesin-mesin besar (boiler, chiller, pompa) dipasang."},{id:1350,category:"pipa",source:"lifeline4",furi:"きゃっぷ",jp:"キャップ",romaji:"kyappu",id_text:"Cap / penutup ujung pipa",desc:"Tutup yang dipasang di ujung pipa untuk menutup aliran."},{id:1351,category:"pipa",source:"lifeline4",furi:"こっく",jp:"コック",romaji:"kokku",id_text:"Keran kecil / cock valve",desc:"Katup kecil untuk mengatur aliran. Lebih kecil dari バルブ."},{id:1352,category:"alat_umum",source:"lifeline4",furi:"ばりとり",jp:"バリ取り",romaji:"bari tori",id_text:"Deburring / hilangkan gerinda",desc:"Proses menghilangkan sisa potongan tajam (gerinda) pada logam setelah dipotong."},{id:1353,category:"alat_umum",source:"lifeline4",furi:"めんをとる",jp:"面を取る",romaji:"men wo toru",id_text:"Chamfering / buat chamfer",desc:"Proses menghaluskan tepi tajam pipa/logam dengan sudut 45°."},{id:1354,category:"pipa",source:"lifeline4",furi:"しんえんしゅうせい",jp:"真円修正",romaji:"shin'en shuusei",id_text:"Koreksi kebulatan pipa",desc:"Proses mengembalikan bentuk pipa yang oval/penyok menjadi bulat sempurna."},{id:1355,category:"pipa",source:"lifeline4",furi:"かんかこう",jp:"管加工",romaji:"kan kakou",id_text:"Pengolahan/pemrosesan pipa",desc:"Semua proses pengerjaan pipa: potong, tekuk, chamfer, deburring, dll."},{id:1356,category:"pipa",source:"lifeline4",furi:"かりつけようせつ",jp:"仮付溶接",romaji:"karitsuke yousetsu",id_text:"Tack welding / las titik sementara",desc:"Pengelasan titik sementara untuk menahan posisi pipa sebelum las penuh."},{id:1357,category:"pipa",source:"lifeline4",furi:"かいさきかこう",jp:"開先加工",romaji:"kaisaki kakou",id_text:"Bevel preparation / pengolahan ujung las",desc:"Membuat sudut bevel pada ujung pipa agar hasil las penetrasi sempurna."},{id:1358,category:"pipa",source:"lifeline4",furi:"てまげかこう",jp:"手曲げ加工",romaji:"te mage kakou",id_text:"Hand bending / tekuk manual",desc:"Menekuk pipa dengan tangan tanpa mesin. Untuk pipa kecil dan tipis."},{id:1359,category:"pipa",source:"lifeline4",furi:"べんだーまげかこう",jp:"ベンダー曲げ加工",romaji:"bendaa mage kakou",id_text:"Bender bending / tekuk mesin",desc:"Menekuk pipa menggunakan mesin bender. Untuk pipa besar atau tebal."},{id:1360,category:"keselamatan",source:"lifeline4",furi:"てんけん",jp:"点検",romaji:"tenken",id_text:"Pengecekan rutin / routine inspection",desc:"Pemeriksaan rutin berkala pada peralatan dan instalasi."},{id:1361,category:"pipa",source:"lifeline4",furi:"かんとつぎてのそうにゅう・こてい",jp:"管と継手の挿入・固定",romaji:"kan to tsugite no sounyuu kotei",id_text:"Memasukkan & mengencangkan pipa-fitting",desc:"Proses memasukkan pipa ke fitting lalu mengencangkan/memfiksasi sambungan."},{id:1362,category:"pipa",source:"lifeline4",furi:"ちじょうかん",jp:"地上管",romaji:"chijou kan",id_text:"Pipa di atas tanah",desc:"Pipa yang dipasang di permukaan tanah, bukan dikubur."},{id:1363,category:"pipa",source:"lifeline4",furi:"れいきゃくき",jp:"冷却器",romaji:"reikyaku ki",id_text:"Cooler / alat pendingin",desc:"Alat atau perangkat untuk mendinginkan fluida atau udara."},// ── LIFELINE 5-6 NEW VOCAB (v72: +29 cards, IDs 1364-1392, source: lifeline5-6) ──
{id:1364,category:"listrik",source:"lifeline4",jp:"手工具",romaji:"tekoogu",furi:"てこうぐ",id_text:"Perkakas tangan (hand tools)",desc:"Alat kerja yang dioperasikan dengan tangan tanpa motor/listrik. Contoh: obeng, palu, tang."},{id:1365,category:"listrik",source:"lifeline4",jp:"3路スイッチ",romaji:"sanro suicchi",furi:"さんろスイッチ",id_text:"Saklar dua arah (two-way switch)",desc:"Saklar yang bisa mengontrol satu lampu dari 2 lokasi berbeda. Sering dipasang di tangga atau koridor panjang."},{id:1366,category:"listrik",source:"lifeline4",jp:"4路スイッチ",romaji:"yonro suicchi",furi:"よんろスイッチ",id_text:"Saklar empat arah (four-way switch)",desc:"Saklar tambahan yang dipasang di antara 2 buah 3路スイッチ. Memungkinkan kontrol dari 3+ lokasi."},{id:1367,category:"listrik",source:"lifeline4",jp:"単極スイッチ",romaji:"tankyoku suicchi",furi:"たんきょくスイッチ",id_text:"Saklar tunggal (single-pole switch)",desc:"Saklar paling sederhana — nyala/mati dari 1 lokasi saja."},{id:1368,category:"listrik",source:"lifeline4",jp:"テープ巻き",romaji:"teepu maki",furi:"テープまき",id_text:"Gulungan isolasi (tape winding)",desc:"Proses membalut sambungan kabel dengan selotip isolasi."},{id:1369,category:"listrik",source:"lifeline4",jp:"保護テープ",romaji:"hogo teepu",furi:"ほごテープ",id_text:"Pita pelindung (protective tape)",desc:"Pita untuk melindungi kabel/pipa dari gesekan atau kerusakan fisik. Berbeda dari 絶縁テープ."},{id:1370,category:"listrik",source:"lifeline4",jp:"結束バンド",romaji:"kessoku bando",furi:"けっそくバンド",id_text:"Cable tie / pengikat kabel",desc:"Tali plastik untuk mengikat dan merapikan kumpulan kabel listrik."},{id:1371,category:"listrik",source:"lifeline4",jp:"支線",romaji:"shisen",furi:"しせん",id_text:"Jalur percabangan (branch line)",desc:"Kabel cabang yang menyalurkan listrik dari 幹線 ke peralatan individual."},{id:1372,category:"listrik",source:"lifeline4",jp:"吸気ファン",romaji:"kyuuki fan",furi:"きゅうきファン",id_text:"Kipas isap (intake fan)",desc:"Kipas yang menghisap udara dari luar ke dalam ruangan. Berbeda dari 排気ファン (exhaust fan)."},{id:1373,category:"listrik",source:"lifeline4",jp:"防振ゴム",romaji:"boushin gomu",furi:"ぼうしんゴム",id_text:"Karet anti-getar (vibration damper)",desc:"Karet yang dipasang di bawah mesin AC/kompresor untuk menyerap getaran."},{id:1374,category:"listrik",source:"lifeline4",jp:"吸音材",romaji:"kyuuon zai",furi:"きゅうおんざい",id_text:"Material penyerap suara",desc:"Bahan yang menyerap gelombang suara untuk mengurangi kebisingan di dalam ruangan."},{id:1375,category:"listrik",source:"lifeline4",jp:"空気清浄機",romaji:"kuuki seijouki",furi:"くうきせいじょうき",id_text:"Pembersih udara (air purifier)",desc:"Alat untuk memurnikan udara di ruangan dengan menyaring debu & partikel."},{id:1376,category:"listrik",source:"lifeline4",jp:"作業灯",romaji:"sagyoutou",furi:"さぎょうとう",id_text:"Lampu kerja (work light)",desc:"Lampu portabel untuk menerangi area kerja gelap di lokasi konstruksi."},{id:1377,category:"pipa",source:"lifeline4",jp:"送水ポンプ",romaji:"sousui ponpu",furi:"そうすいポンプ",id_text:"Pompa air bersih (water supply pump)",desc:"Pompa untuk mengalirkan air bersih ke sistem distribusi gedung."},{id:1378,category:"pipa",source:"lifeline4",jp:"排水ポンプ",romaji:"haisui ponpu",furi:"はいすいポンプ",id_text:"Pompa air limbah (drainage pump)",desc:"Pompa untuk mengalirkan air limbah/kotor dari gedung ke saluran pembuangan."},{id:1379,category:"pipa",source:"lifeline4",jp:"冷却ポンプ",romaji:"reikyaku ponpu",furi:"れいきゃくポンプ",id_text:"Pompa pendingin (cooling pump)",desc:"Pompa untuk mengalirkan air pendingin di sistem AC sentral."},{id:1380,category:"pipa",source:"lifeline4",jp:"温水循環ポンプ",romaji:"onsui junkan ponpu",furi:"おんすいじゅんかんポンプ",id_text:"Pompa sirkulasi air panas",desc:"Pompa untuk mensirkulasikan air panas di sistem pemanas gedung."},{id:1381,category:"pipa",source:"lifeline4",jp:"ポリブテン管",romaji:"poributen kan",furi:"ポリブテンかん",id_text:"Pipa polibuten (polybutene pipe)",desc:"Pipa plastik fleksibel, tahan korosi, dipakai untuk suplai air panas & dingin."},{id:1382,category:"pipa",source:"lifeline4",jp:"鉛管",romaji:"namari kan",furi:"なまりかん",id_text:"Pipa timah (lead pipe)",desc:"Pipa dari timah, dulu dipakai untuk suplai air. Sekarang jarang dipakai karena bahaya kesehatan."},{id:1383,category:"pipa",source:"lifeline4",jp:"給水タンク",romaji:"kyuusui tanku",furi:"きゅうすいたんく",id_text:"Tangki air bersih (water supply tank)",desc:"Tangki penampung air bersih di gedung, biasanya di atap atau ruang bawah tanah."},{id:1384,category:"pipa",source:"lifeline4",jp:"パイプバンド",romaji:"paipu bando",furi:"パイプバンド",id_text:"Pipe band / pengikat pipa",desc:"Pengikat logam untuk memfiksasi pipa ke dinding atau langit-langit."},{id:1385,category:"alat_umum",source:"lifeline4",jp:"モップ",romaji:"moppu",furi:"モップ",id_text:"Mop / alat pel",desc:"Alat pembersih lantai, digunakan untuk membersihkan lokasi kerja."},{id:1386,category:"alat_umum",source:"lifeline4",jp:"たらい",romaji:"tarai",furi:"たらい",id_text:"Baskom (basin)",desc:"Wadah besar untuk mencuci atau menampung air."},{id:1387,category:"alat_umum",source:"lifeline4",jp:"梯子脚立",romaji:"hashigo kyatatsu",furi:"はしごきゃたつ",id_text:"Tangga lipat (folding ladder)",desc:"Tangga yang bisa dilipat, digunakan untuk pekerjaan di ketinggian rendah."},{id:1388,category:"alat_umum",source:"lifeline4",jp:"ゴムパッド",romaji:"gomu paddo",furi:"ゴムパッド",id_text:"Bantalan karet (rubber pad)",desc:"Bantalan karet untuk peredam atau alas anti-selip pada peralatan."},{id:1389,category:"alat_umum",source:"lifeline4",jp:"シートガスケット",romaji:"shiito gasuketto",furi:"シートガスケット",id_text:"Gasket lembaran (sheet gasket)",desc:"Gasket berbentuk lembaran untuk mencegah kebocoran pada sambungan flensa."},{id:1390,category:"alat_umum",source:"lifeline4",jp:"緩衝材",romaji:"kanshouzai",furi:"かんしょうざい",id_text:"Material peredam benturan (cushioning material)",desc:"Bahan untuk melindungi peralatan atau pipa dari benturan fisik."},{id:1391,category:"alat_umum",source:"lifeline4",jp:"段差台",romaji:"dansadai",furi:"だんさだい",id_text:"Platform bertingkat (step platform)",desc:"Platform kecil bertingkat sebagai pijakan untuk pekerjaan di ketinggian rendah."},{id:1392,category:"telekomunikasi",source:"lifeline4",jp:"光ケーブル地中配線",romaji:"hikari keepuru chichuu haisen",furi:"ひかりケーブルちちゅうはいせん",id_text:"Pengabelan kabel optik bawah tanah",desc:"Pemasangan kabel serat optik di dalam tanah melalui 管路 atau 共同溝."},{id:1343,category:"pipa",source:"lifeline4",furi:"かしつき",jp:"加湿器",romaji:"kashitsuki",id_text:"Humidifier / pelembab udara",desc:"Alat untuk menambah kelembaban udara ruangan. Bagian dari sistem HVAC."},// ── VOCAB EXAM: +250 cards from 10-agent generation (IDs 1041-1290, source: vocab_exam) ──
{id:1041,category:"pemadam",source:"vocab_exam",furi:"すぷりんくらーへっど",jp:"スプリンクラーヘッド",romaji:"supurinkuraa heddo",id_text:"Kepala sprinkler pemadam api",desc:"例: スプリンクラーヘッドは火災時に熱で溶栓が溶けて自動放水する。→ Kepala sprinkler meleleh saat suhu tinggi dan memancarkan air secara otomatis. Ada dua jenis: 開放型 (terbuka) dan 閉鎖型 (tertutup)."},{id:1042,category:"pemadam",source:"vocab_exam",furi:"かいほうがたすぷりんくらー",jp:"開放型スプリンクラー",romaji:"kaihou gata supurinkuraa",id_text:"Sprinkler jenis terbuka (open)",desc:"例: 開放型スプリンクラーは舞台や劇場など広い空間に使われる。→ Sprinkler terbuka digunakan di panggung atau ruang besar; semua kepala menyembur serentak saat katup utama dibuka."},{id:1043,category:"pemadam",source:"vocab_exam",furi:"へいさがたすぷりんくらー",jp:"閉鎖型スプリンクラー",romaji:"heisa gata supurinkuraa",id_text:"Sprinkler jenis tertutup (closed)",desc:"例: 閉鎖型スプリンクラーは感熱部が溶けた箇所だけ放水する。→ Sprinkler tertutup hanya menyembur di kepala yang terkena panas; paling umum digunakan di gedung bertingkat."},{id:1044,category:"pemadam",source:"vocab_exam",furi:"さどうしきかんちき",jp:"差動式感知器",romaji:"sadou shiki kanchi ki",id_text:"Detektor panas diferensial",desc:"例: 差動式感知器は温度が急激に上昇したときに作動する。→ Detektor diferensial aktif ketika suhu naik dengan cepat; cocok untuk ruangan yang suhunya normal stabil."},{id:1045,category:"pemadam",source:"vocab_exam",furi:"ていおんしきかんちき",jp:"定温式感知器",romaji:"teion shiki kanchi ki",id_text:"Detektor suhu tetap (fixed-temperature)",desc:"例: 定温式感知器は設定温度（例：60℃）に達すると作動する。→ Detektor suhu tetap aktif saat mencapai suhu yang sudah ditentukan; cocok untuk dapur atau ruang boiler."},{id:1046,category:"pemadam",source:"vocab_exam",furi:"こうでんしきかんちき",jp:"光電式感知器",romaji:"kouden shiki kanchi ki",id_text:"Detektor asap fotoelektrik",desc:"例: 光電式感知器は煙が光の通路を遮ることで作動する。→ Detektor fotoelektrik mendeteksi asap yang menghalangi sinar cahaya; efektif untuk asap pekat dari api membara lambat."},{id:1047,category:"pemadam",source:"vocab_exam",furi:"いおんかしきかんちき",jp:"イオン化式感知器",romaji:"ionka shiki kanchi ki",id_text:"Detektor asap ionisasi",desc:"例: イオン化式感知器は微小な煙粒子でも早期に感知できる。→ Detektor ionisasi mendeteksi partikel asap halus sejak dini; sensitif terhadap api nyala terbuka yang cepat menyebar."},{id:1048,category:"pemadam",source:"vocab_exam",furi:"じどうかさいほうちせつび",jp:"自動火災報知設備",romaji:"jidou kasai houchi setsubi",id_text:"Sistem alarm kebakaran otomatis",desc:"例: 自動火災報知設備は感知器・発信機・受信機・ベルで構成される。→ Sistem ini terdiri dari detektor, tombol manual, panel penerima, dan bel; wajib dipasang di gedung tertentu sesuai 消防法."},{id:1049,category:"pemadam",source:"vocab_exam",furi:"かんこうき",jp:"緩降機",romaji:"kankou ki",id_text:"Alat turun perlahan / slow descender",desc:"例: 緩降機はロープを体に巻いて窓から安全に降下する避難器具だ。→ Alat evakuasi yang memungkinkan pengguna turun dari jendela secara perlahan dengan tali; digunakan satu orang per waktu."},{id:1050,category:"pemadam",source:"vocab_exam",furi:"ひなんはしご",jp:"避難はしご",romaji:"hinan hashigo",id_text:"Tangga evakuasi darurat",desc:"例: 避難はしごは窓に取り付けて外壁を伝って降りる避難器具だ。→ Tangga evakuasi dipasang di jendela untuk turun menyusuri dinding luar gedung saat lift tidak bisa digunakan."},{id:1051,category:"pemadam",source:"vocab_exam",furi:"きゅうじょぶくろ",jp:"救助袋",romaji:"kyuujo bukuro",id_text:"Kantong/seluncur evakuasi darurat",desc:"例: 救助袋は布製の袋状トンネルに入って建物外に脱出する器具だ。→ Berbentuk terowongan kain; penghuni masuk ke dalam dan meluncur turun ke titik aman di luar gedung."},{id:1052,category:"pemadam",source:"vocab_exam",furi:"ぼうかど",jp:"防火戸",romaji:"bouka do",id_text:"Pintu tahan api (fire door)",desc:"例: 防火戸は火災時に自動閉鎖して延焼を防ぐ構造を持つ。→ Pintu tahan api menutup otomatis saat kebakaran untuk menghambat penyebaran api dan asap antar zona; bagian dari 防火区画."},{id:1053,category:"pemadam",source:"vocab_exam",furi:"ぼうかだんぱー",jp:"防火ダンパー",romaji:"bouka danpaa",id_text:"Fire damper (katup pemadam di ducting)",desc:"例: 防火ダンパーはダクトが防火区画を貫通する部分に設置する。→ Dipasang di titik duct yang menembus dinding tahan api; menutup otomatis saat sensor meleleh akibat panas untuk mencegah api merambat lewat ducting."},{id:1054,category:"pemadam",source:"vocab_exam",furi:"れんけつさんすいせつび",jp:"連結散水設備",romaji:"renketsu sansui setsubi",id_text:"Sistem sprinkler terhubung (siamese)",desc:"例: 連結散水設備は地下街などで消防隊が外部から送水する設備だ。→ Digunakan di area bawah tanah; unit pemadam memompakan air dari luar ke jaringan pipa dalam gedung melalui sambungan siamese."},{id:1055,category:"pemadam",source:"vocab_exam",furi:"れんけつそうすいかん",jp:"連結送水管",romaji:"renketsu sousui kan",id_text:"Pipa suplai air terhubung (standpipe)",desc:"例: 連結送水管は11階以上の高層建築に設置義務がある。→ Standpipe yang memungkinkan petugas pemadam menyambungkan selang di setiap lantai; wajib di gedung tinggi sesuai peraturan 消防法."},{id:1056,category:"pemadam",source:"vocab_exam",furi:"しょうかぽんぷ",jp:"消火ポンプ",romaji:"shouka ponpu",id_text:"Pompa pemadam kebakaran",desc:"例: 消火ポンプは加圧送水装置として屋内消火栓やスプリンクラーに水を供給する。→ Pompa pemadam menyuplai air bertekanan ke sistem hidran dan sprinkler; dilengkapi 性能試験装置 untuk pengujian berkala."},{id:1057,category:"pemadam",source:"vocab_exam",furi:"ひじょうとう",jp:"非常灯",romaji:"hijou tou",id_text:"Lampu darurat (emergency light)",desc:"例: 非常灯は停電時でも自動点灯して室内を照らす照明設備だ。→ Lampu yang menyala otomatis saat listrik padam; wajib dipasang di koridor dan tangga darurat agar penghuni bisa bergerak aman."},{id:1058,category:"pemadam",source:"vocab_exam",furi:"ゆうどうとう",jp:"誘導灯",romaji:"yuudou tou",id_text:"Lampu penunjuk jalur evakuasi",desc:"例: 誘導灯は「EXIT」や矢印マークで避難方向を示す緑色の照明だ。→ Lampu hijau bertanda panah atau EXIT yang memandu penghuni menuju pintu darurat; berbeda dari 非常灯 yang berfungsi sebagai penerangan umum."},{id:1059,category:"pemadam",source:"vocab_exam",furi:"はっしんき",jp:"発信機",romaji:"hasshin ki",id_text:"Tombol alarm kebakaran manual",desc:"例: 発信機は人が火災を発見した際に手動で押して警報を鳴らす装置だ。→ Manual call point; ditekan oleh orang yang melihat api untuk mengaktifkan alarm; biasanya berwarna merah dan dipasang di koridor tiap lantai."},{id:1060,category:"pemadam",source:"vocab_exam",furi:"じゅしんき",jp:"受信機",romaji:"jushin ki",id_text:"Panel penerima alarm kebakaran",desc:"例: 受信機は感知器や発信機からの信号を受けて警報を表示・発報する中枢装置だ。→ Panel utama sistem alarm kebakaran yang menampilkan lokasi kebakaran dan mengaktifkan bel; biasanya di ruang penjaga gedung."},{id:1061,category:"pemadam",source:"vocab_exam",furi:"はいえんせつび",jp:"排煙設備",romaji:"haien setsubi",id_text:"Sistem pembuangan asap kebakaran",desc:"例: 排煙設備は火災時に煙を屋外に排出して避難経路を確保する設備だ。→ Sistem exhaust asap yang menjaga koridor tetap bersih dari asap selama evakuasi; terdiri dari damper, kipas, dan shaft khusus asap."},{id:1062,category:"pemadam",source:"vocab_exam",furi:"ふんまつしょうかき",jp:"粉末消火器",romaji:"funmatsu shouka ki",id_text:"Tabung pemadam bubuk kering (portable)",desc:"例: 粉末消火器はABC火災すべてに対応できる万能型の携帯消火器だ。→ Tabung pemadam portabel berisi bubuk kering; efektif untuk kebakaran kelas A (padat), B (cair/gas), dan C (listrik)."},{id:1063,category:"pemadam",source:"vocab_exam",furi:"しょうぼうようすい",jp:"消防用水",romaji:"shoubouyousui",id_text:"Cadangan air untuk pemadam kebakaran",desc:"例: 消防用水は敷地内に一定量の水を貯留しておく消防設備の一種だ。→ Tangki atau kolam cadangan air yang wajib tersedia di lokasi tertentu; digunakan sebagai sumber air alternatif saat pasokan PDAM tidak cukup."},{id:1064,category:"pemadam",source:"vocab_exam",furi:"ぼうかくかく",jp:"防火区画",romaji:"bouka kukaku",id_text:"Zona tahan api / fire compartment",desc:"例: 防火区画は耐火構造の壁・床・防火戸で建物を区切った区域だ。→ Gedung dibagi menjadi zona-zona tahan api untuk membatasi penyebaran api; diatur dalam 建築基準法 berdasarkan luas lantai dan fungsi bangunan."},{id:1065,category:"pemadam",source:"vocab_exam",furi:"たいかこうぞう",jp:"耐火構造",romaji:"taika kouzou",id_text:"Struktur / konstruksi tahan api",desc:"例: 耐火構造は一定時間火熱に耐えられる壁・柱・床などの建築構造だ。→ Konstruksi yang mampu menahan panas api selama waktu tertentu tanpa runtuh; standar ditetapkan dalam 建築基準法 untuk gedung bertingkat dan fasilitas publik."},{id:1066,category:"isolasi",source:"vocab_exam",furi:"ろっくうーる",jp:"ロックウール",romaji:"rokku uuru",id_text:"Rock wool / wol batu",desc:"例: ロックウールはグラスウールより耐熱温度が高く、約600℃まで使用できる。→ Rock wool tahan panas lebih tinggi dari glass wool, bisa digunakan hingga ±600°C. Terbuat dari basalt/batu terak, lebih berat tapi lebih tahan api."},{id:1067,category:"isolasi",source:"vocab_exam",furi:"びーずほうぽりすちれんふぉーむ",jp:"ビーズ法ポリスチレンフォーム",romaji:"biizu hou porisuchiren foomu",id_text:"EPS / styrofoam bead method",desc:"例: ビーズ法ポリスチレンフォーム（EPS）は発泡ビーズを型に入れて成形した断熱材だ。→ EPS dibentuk dari butiran polistirena yang dipanaskan dalam cetakan. Ringan dan murah, tapi daya serap air lebih tinggi dibanding XPS."},{id:1068,category:"isolasi",source:"vocab_exam",furi:"おしだしほうぽりすちれんふぉーむ",jp:"押出法ポリスチレンフォーム",romaji:"oshidashi hou porisuchiren foomu",id_text:"XPS / extruded polystyrene foam",desc:"例: 押出法ポリスチレンフォーム（XPS）は連続押出成形のため、吸水率が低く床断熱に多用される。→ XPS diproduksi dengan ekstrusi kontinu sehingga berstruktur sel tertutup rapat, tahan air, dan kuat tekan tinggi. Cocok untuk isolasi lantai dan fondasi."},{id:1069,category:"isolasi",source:"vocab_exam",furi:"こうしつうれたんふぉーむ",jp:"硬質ウレタンフォーム",romaji:"koushitsu uretan foomu",id_text:"Rigid urethane foam (board/panel)",desc:"例: 硬質ウレタンフォームボードは熱伝導率が非常に低く、薄くても高い断熱性能を発揮する。→ Papan busa uretan keras memiliki nilai λ sangat rendah (~0.022 W/mK), efisien untuk ruang sempit. Beda dengan吹付けウレタン yang disemprotkan di tempat."},{id:1070,category:"isolasi",source:"vocab_exam",furi:"ふぇのーるふぉーむ",jp:"フェノールフォーム",romaji:"fenooru foomu",id_text:"Phenolic foam / busa fenolik",desc:"例: フェノールフォームは断熱材の中で最も熱伝導率が低い部類に入り、難燃性も高い。→ Busa fenolik termasuk insulasi dengan λ terendah (~0.020 W/mK) dan sangat tahan api. Digunakan pada bangunan berperforma tinggi dan pipa suhu tinggi."},{id:1071,category:"isolasi",source:"vocab_exam",furi:"ぱーらいとほおんざい",jp:"パーライト保温材",romaji:"paaraito hoon zai",id_text:"Perlite insulation material",desc:"例: パーライト保温材は膨張させた真珠岩を原料とし、高温配管や機器の保温に使われる。→ Insulasi perlit terbuat dari obsidian/batu vulkanik yang dipanaskan hingga mengembang. Tahan suhu sangat tinggi (hingga 800°C+), cocok untuk boiler dan pipa steam."},{id:1072,category:"isolasi",source:"vocab_exam",furi:"がいそうざい",jp:"外装材",romaji:"gaisou zai",id_text:"Jacketing material / material pelapis luar",desc:"例: 保温材の外装材には、アルミ・亜鉛鉄板・ステンレスなどが使われる。→ Material penutup luar lapisan insulasi pipa/duct untuk melindungi dari cuaca dan benturan fisik. Pemilihan tergantung lokasi (dalam/luar ruangan) dan kondisi lingkungan."},{id:1073,category:"isolasi",source:"vocab_exam",furi:"あるみがいそう",jp:"アルミ外装",romaji:"arumi gaisou",id_text:"Aluminum jacketing (outer cladding)",desc:"例: 屋外露出配管の保温仕上げには、軽量で耐候性のあるアルミ外装が多く採用される。→ Jacketing aluminium ringan dan tahan karat, umum dipakai pada pipa outdoor. Tersedia dalam bentuk lembaran (sheet) atau coil yang dibentuk sesuai diameter pipa."},{id:1074,category:"isolasi",source:"vocab_exam",furi:"ぼうしつそう",jp:"防湿層",romaji:"boushitsu sou",id_text:"Vapor barrier layer",desc:"例: 冷水管の保冷工事では、外部からの湿気侵入を防ぐため防湿層を設ける。→ Lapisan penghalang uap dipasang pada sistem insulasi pipa dingin untuk mencegah uap air masuk ke dalam insulasi yang menyebabkan kondensasi dan korosi."},{id:1075,category:"isolasi",source:"vocab_exam",furi:"ぼうろこうじ",jp:"防露工事",romaji:"bouro kouji",id_text:"Anti-condensation insulation work",desc:"例: 冷房ダクトや冷水配管には結露防止のために防露工事が必要だ。→ Pekerjaan insulasi khusus yang bertujuan mencegah pembentukan embun (kondensasi) pada permukaan pipa/duct dingin. Berbeda dengan 保温工事 yang fokus pada retensi panas."},{id:1076,category:"isolasi",source:"vocab_exam",furi:"しんしゅくつぎてかばー",jp:"伸縮継手カバー",romaji:"shinshuku tsugite kabaa",id_text:"Expansion joint cover",desc:"例: 配管の伸縮継手部分には、熱膨張に対応できる伸縮継手カバーを取り付ける。→ Cover khusus yang dipasang pada sambungan ekspansi pipa, dirancang untuk mengikuti gerakan termal. Biasanya terbuat dari material fleksibel atau berbentuk bellow."},{id:1077,category:"isolasi",source:"vocab_exam",furi:"ほおんとう",jp:"保温筒",romaji:"hoontou",id_text:"Pre-formed pipe insulation section",desc:"例: 保温筒は配管の外径に合わせて半円形に成形された保温材で、2枚合わせて取り付ける。→ Insulasi pipa berbentuk silinder yang sudah dicetak setengah lingkaran, dipasang memeluk pipa. Tersedia dalam berbagai diameter dan bahan (glass wool, rock wool, dll)."},{id:1078,category:"isolasi",source:"vocab_exam",furi:"ほおんたい",jp:"保温帯",romaji:"hoontai",id_text:"Insulation band / blanket strip",desc:"例: バルブやフランジなど複雑な形状の箇所には保温筒の代わりに保温帯を巻き付けて施工する。→ Strip insulasi fleksibel (blanket) yang dililitkan pada bagian pipa tidak beraturan seperti valve, fitting, dan flensa yang tidak bisa memakai 保温筒 standar."},{id:1079,category:"isolasi",source:"vocab_exam",furi:"あえんてっせん",jp:"亜鉛鉄線",romaji:"aentessen",id_text:"Galvanized binding wire",desc:"例: 保温筒を固定するために亜鉛鉄線で一定間隔に巻き縛りを行う。→ Kawat besi berlapis seng digunakan untuk mengikat lapisan insulasi pipa agar tidak bergeser sebelum dipasang jacketing. Interval pengikatan biasanya setiap 300mm atau sesuai spesifikasi."},{id:1080,category:"isolasi",source:"vocab_exam",furi:"ねつでんどうりつ",jp:"熱伝導率",romaji:"netsu dendou ritsu",id_text:"Thermal conductivity (λ value)",desc:"例: 熱伝導率（λ値）が低いほど断熱性能が高く、フェノールフォームはλ≈0.020 W/mKと非常に低い。→ Nilai λ (lambda) menunjukkan seberapa mudah panas berpindah melalui material. Makin kecil λ, makin baik insulasinya. Satuan: W/(m·K)."},{id:1081,category:"isolasi",source:"vocab_exam",furi:"ねつていこう",jp:"熱抵抗",romaji:"netsu teikou",id_text:"Thermal resistance (R-value)",desc:"例: 熱抵抗（R値）は保温材の厚さを熱伝導率で割った値で、大きいほど断熱性能が高い。→ Nilai R = tebal material ÷ λ. Makin besar R, makin baik kemampuan menghambat aliran panas. Digunakan untuk menghitung kebutuhan ketebalan insulasi."},{id:1082,category:"isolasi",source:"vocab_exam",furi:"ねつかんりゅうりつ",jp:"熱貫流率",romaji:"netsu kanryuu ritsu",id_text:"Overall heat transfer coefficient (U-value)",desc:"例: 熱貫流率（U値）は壁や床全体の断熱性能を示す値で、省エネ設計の基準に使われる。→ Nilai U menunjukkan total perpindahan panas melalui seluruh lapisan dinding/lantai/atap (termasuk insulasi). Makin kecil U, makin hemat energi. Satuan: W/(m²·K)."},{id:1083,category:"isolasi",source:"vocab_exam",furi:"ほおんあつさけいさん",jp:"保温厚さ計算",romaji:"hoon atsusa keisan",id_text:"Insulation thickness calculation",desc:"例: 保温厚さ計算では、流体温度・外気温度・熱伝導率・許容熱損失を考慮して必要な保温厚さを求める。→ Perhitungan ketebalan insulasi yang diperlukan berdasarkan suhu fluida, suhu ambient, nilai λ material, dan batas kehilangan panas yang diizinkan."},{id:1084,category:"isolasi",source:"vocab_exam",furi:"けつろぼうし",jp:"結露防止",romaji:"ketsuro boushi",id_text:"Condensation prevention (measures)",desc:"例: 冷水管では表面温度が露点を下回らないよう、十分な厚さの保冷材で結露防止を行う。→ Upaya mencegah terbentuknya embun pada permukaan pipa/duct dingin dengan memastikan suhu permukaan insulasi tetap di atas titik embun (dew point) ruangan."},{id:1085,category:"isolasi",source:"vocab_exam",furi:"たいねつおんど",jp:"耐熱温度",romaji:"tainetsu ondo",id_text:"Heat resistance temperature (max service temp)",desc:"例: 保温材を選定する際は、配管流体の温度が保温材の耐熱温度を超えないことを確認する。→ Suhu maksimum yang dapat ditahan material insulasi tanpa mengalami degradasi. Contoh: GW ±350°C, RW ±600°C, EPS ±80°C. Harus disesuaikan dengan suhu fluida pipa."},{id:1086,category:"isolasi",source:"vocab_exam",furi:"きゅうすいりつ",jp:"吸水率",romaji:"kyuusui ritsu",id_text:"Water absorption rate",desc:"例: 保温材の吸水率が高いと断熱性能が著しく低下するため、屋外や多湿環境では低吸水率の材料を選ぶ。→ Persentase air yang dapat diserap material insulasi. Insulasi basah kehilangan performa drastis karena air menghantar panas jauh lebih baik. XPS dan busa uretan memiliki吸水率 rendah."},{id:1087,category:"isolasi",source:"vocab_exam",furi:"ほかんつうかんすいしょり",jp:"防火区画貫通処理",romaji:"bouka kukaku kantsuu shori",id_text:"Fire compartment penetration sealing",desc:"例: 保温した配管が防火区画を貫通する場合、貫通部に耐火充填材や耐火カバーを設けなければならない。→ Penyegelan wajib pada titik pipa berinsulasi yang menembus dinding/lantai tahan api (防火区画). Insulasi standar mudah terbakar, sehingga perlu material khusus tahan api di area penetrasi."},{id:1088,category:"isolasi",source:"vocab_exam",furi:"ほおんせこうてじゅん",jp:"保温施工手順",romaji:"hoon sekou tejun",id_text:"Insulation installation procedure",desc:"例: 保温施工手順は一般に①下地確認→②保温材取付→③結束線固定→④防湿層施工→⑤外装仕上げの順で行う。→ Prosedur pemasangan insulasi: (1) cek permukaan pipa bersih & bebas karat, (2) pasang保温筒/保温帯, (3) ikat dengan亜鉛鉄線, (4) pasang防湿層 jika perlu, (5) finish dengan外装材."},{id:1089,category:"isolasi",source:"vocab_exam",furi:"ぽりえちれんふぉーむ",jp:"ポリエチレンフォーム",romaji:"poriechiren foomu",id_text:"Polyethylene foam insulation",desc:"例: ポリエチレンフォームは軽くて柔軟性が高く、冷媒配管や給水管の防露・保冷に広く使われる。→ Busa polietilena (PE foam) fleksibel dan ringan, cocok untuk pipa AC (冷媒管) dan pipa air dingin. Struktur sel tertutup memberikan resistensi kelembaban yang baik."},{id:1090,category:"isolasi",source:"vocab_exam",furi:"ほれいこうじ",jp:"保冷工事",romaji:"horei kouji",id_text:"Cold insulation work / refrigeration insulation",desc:"例: 保冷工事では、外部からの熱侵入を防ぐとともに、結露による腐食も防止しなければならない。→ Pekerjaan insulasi khusus untuk pipa/peralatan bersuhu rendah (pipa chiller, AC, freezer). Tujuan ganda: cegah masuknya panas dari luar + cegah kondensasi pada permukaan luar insulasi."},{id:1091,category:"listrik",source:"vocab_exam",furi:"ぶんでんばん",jp:"分電盤",romaji:"bunden ban",id_text:"Panel distribusi / breaker box",desc:"例: 分電盤には主幹ブレーカーと複数の分岐ブレーカーが設置されている。→ Panel distribusi berisi breaker utama dan breaker-breaker cabang untuk tiap sirkuit."},{id:1092,category:"listrik",source:"vocab_exam",furi:"へんあつき",jp:"変圧器",romaji:"henatsuki",id_text:"Transformator / trafo",desc:"例: 変圧器は高圧の電力を低圧に変換して建物内の機器に供給する。→ Transformator mengubah tegangan tinggi ke rendah untuk menyuplai daya ke peralatan dalam gedung."},{id:1093,category:"listrik",source:"vocab_exam",furi:"じゃんくしょんぼっくす",jp:"ジャンクションボックス",romaji:"jankushon bokkusu",id_text:"Kotak sambungan / junction box",desc:"例: 電線の分岐・接続はジャンクションボックス内で行い、蓋をして保護する。→ Percabangan dan sambungan kabel dilakukan di dalam junction box, lalu ditutup untuk perlindungan."},{id:1094,category:"listrik",source:"vocab_exam",furi:"せっちていこう",jp:"接地抵抗",romaji:"secchi teikou",id_text:"Resistansi grounding / tahanan pembumian",desc:"例: D種接地工事では接地抵抗値が100Ω以下でなければならない。→ Untuk grounding jenis D, nilai resistansi pembumian tidak boleh melebihi 100Ω."},{id:1095,category:"listrik",source:"vocab_exam",furi:"ぶっしんぐ",jp:"ブッシング",romaji:"busshingu",id_text:"Bushing / pelindung ujung konduit",desc:"例: 電線管の管端にブッシングを取り付け、通線時に電線の被覆が傷つかないようにする。→ Bushing dipasang di ujung konduit untuk melindungi isolasi kabel saat penarikan."},{id:1096,category:"listrik",source:"vocab_exam",furi:"でんりょくりょうけい",jp:"電力量計",romaji:"denryoku ryou kei",id_text:"KWh meter / meteran listrik",desc:"例: 電力量計は消費電力量（kWh）を積算計測する機器で、電気料金の算定に使われる。→ KWh meter mengakumulasi total konsumsi listrik dan digunakan sebagai dasar perhitungan tagihan."},{id:1097,category:"listrik",source:"vocab_exam",furi:"かんせん",jp:"幹線",romaji:"kansen",id_text:"Kabel feeder utama",desc:"例: 幹線は引込口から主分電盤までを結ぶ主電力供給ラインである。→ Feeder utama adalah jalur suplai daya primer yang menghubungkan titik masukan hingga panel utama."},{id:1098,category:"listrik",source:"vocab_exam",furi:"ぶんきかいろ",jp:"分岐回路",romaji:"bunki kairo",id_text:"Sirkuit cabang / branch circuit",desc:"例: 分岐回路は分電盤から各コンセントや照明器具へ電力を分配する個別の回路である。→ Branch circuit adalah sirkuit individual yang mendistribusikan daya dari panel ke stop kontak atau lampu."},{id:1099,category:"listrik",source:"vocab_exam",furi:"たんそう",jp:"単相",romaji:"tansou",id_text:"Fase tunggal / single phase",desc:"例: 家庭用電源は単相2線式（100V）または単相3線式（100V/200V）が標準である。→ Listrik rumah tangga umumnya menggunakan single phase 2 kawat (100V) atau 3 kawat (100V/200V)."},{id:1100,category:"listrik",source:"vocab_exam",furi:"さんそう",jp:"三相",romaji:"sansou",id_text:"Tiga fase / three phase",desc:"例: 大型モーターや工場設備には三相3線式200Vまたは400Vが使用される。→ Motor besar dan peralatan industri menggunakan listrik tiga fase 200V atau 400V."},{id:1101,category:"listrik",source:"vocab_exam",furi:"きょようでんりゅう",jp:"許容電流",romaji:"kyoyou denryuu",id_text:"Ampasitas / arus maksimum yang diizinkan",desc:"例: 電線の許容電流を超えると絶縁被覆が過熱し、火災の原因となる。→ Jika arus melebihi ampasitas kabel, isolasi akan kepanasan dan dapat menyebabkan kebakaran."},{id:1102,category:"listrik",source:"vocab_exam",furi:"ぜつえんていこうそくてい",jp:"絶縁抵抗測定",romaji:"zetsuen teikou sokutei",id_text:"Pengukuran resistansi isolasi (tes megger)",desc:"例: 竣工検査では絶縁抵抗測定を行い、電路の絶縁状態に異常がないことを確認する。→ Saat inspeksi akhir, tes megger dilakukan untuk memverifikasi bahwa isolasi sirkuit dalam kondisi baik."},{id:1103,category:"listrik",source:"vocab_exam",furi:"がいし",jp:"碍子",romaji:"gaishi",id_text:"Insulator listrik (porselen/keramik)",desc:"例: 碍子は電線を構造物に固定しながら電気的に絶縁するための部品である。→ Insulator berfungsi menjaga kabel tetap pada posisinya sekaligus memisahkannya secara elektrik dari struktur."},{id:1104,category:"listrik",source:"vocab_exam",furi:"はいせんようしゃだんき",jp:"配線用遮断器",romaji:"haisen you shadanki",id_text:"MCB / pemutus sirkuit kabel",desc:"例: 配線用遮断器は過電流・短絡時に回路を遮断するが、漏電には反応しない点に注意する。→ MCB memutus sirkuit saat arus lebih atau korsleting, namun tidak bereaksi terhadap kebocoran arus (butuh ELCB)."},{id:1105,category:"listrik",source:"vocab_exam",furi:"けーぶるとれい",jp:"ケーブルトレイ",romaji:"keeburu torei",id_text:"Cable tray (jalur kabel dasar tertutup)",desc:"例: ケーブルトレイは底が閉じた形状で、ケーブルラックより防塵・防水性に優れる。→ Cable tray memiliki dasar tertutup sehingga lebih tahan debu dan cipratan air dibanding cable ladder."},{id:1106,category:"listrik",source:"vocab_exam",furi:"ていあつ",jp:"低圧",romaji:"teiatsu",id_text:"Tegangan rendah (AC ≤600V / DC ≤750V)",desc:"例: 電気設備技術基準では交流600V以下・直流750V以下を低圧と定義している。→ Standar teknis instalasi listrik mendefinisikan tegangan rendah sebagai AC ≤600V atau DC ≤750V."},{id:1107,category:"listrik",source:"vocab_exam",furi:"こうあつ",jp:"高圧",romaji:"kouatsu",id_text:"Tegangan tinggi (AC 600V–7000V)",desc:"例: 交流600Vを超え7000V以下の電圧を高圧といい、工場やビルの受電設備に使われる。→ Tegangan AC di atas 600V hingga 7000V disebut tegangan tinggi, digunakan di panel penerimaan pabrik dan gedung."},{id:1108,category:"listrik",source:"vocab_exam",furi:"りんぐすりーぶ",jp:"リングスリーブ",romaji:"ringu suriibuu",id_text:"Ring sleeve / selongsong sambungan kabel",desc:"例: リングスリーブを使って複数の電線を圧着接続する。サイズは電線断面積の合計で決まる。→ Ring sleeve dikrimping untuk menyambung beberapa kabel. Ukurannya ditentukan oleh total luas penampang kabel."},{id:1109,category:"listrik",source:"vocab_exam",furi:"せっちこうじのしゅるい",jp:"接地工事の種類",romaji:"secchi kouji no shurui",id_text:"Jenis-jenis pekerjaan grounding (A/B/C/D種)",desc:"例: A種（10Ω以下）・C種（10Ω以下）・D種（100Ω以下）の接地抵抗値が試験頻出。→ Nilai resistansi grounding jenis A (≤10Ω), C (≤10Ω), dan D (≤100Ω) sering muncul dalam soal ujian."},{id:1110,category:"listrik",source:"vocab_exam",furi:"せいぎょけーぶる",jp:"制御ケーブル",romaji:"seigyo keeburu",id_text:"Kabel kontrol / sinyal",desc:"例: 制御ケーブルは動力ケーブルと分離して配線し、電磁ノイズによる誤作動を防ぐ。→ Kabel kontrol harus dipisah dari kabel daya untuk mencegah gangguan sinyal akibat interferensi elektromagnetik."},{id:1111,category:"listrik",source:"vocab_exam",furi:"あーすくらんぷ",jp:"アースクランプ",romaji:"aasu kuranpu",id_text:"Klem grounding / penjepit kabel bumi",desc:"例: アースクランプで接地線を接地棒にしっかりと固定し、良好な接地接続を確保する。→ Klem grounding menghubungkan kabel bumi ke batang grounding secara kuat dan andal."},{id:1112,category:"listrik",source:"vocab_exam",furi:"のっくあうと",jp:"ノックアウト",romaji:"nokuauto",id_text:"Knockout / bukaan pre-cetak pada panel listrik",desc:"例: 配電盤や金属ボックスのノックアウト部分を打ち抜いて、電線管引き込み口を設ける。→ Bagian knockout pada panel dilepas untuk membuat lubang masuknya konduit kabel."},{id:1113,category:"listrik",source:"vocab_exam",furi:"でんせんのしきべつしょく",jp:"電線の識別色",romaji:"densen no shikibetsu shoku",id_text:"Kode warna identifikasi kabel listrik",desc:"例: 単相3線式では黒・赤（非接地側）と白（接地側中性線）が識別色の基本となる。→ Pada sistem single phase 3 kawat, hitam & merah untuk fasa aktif dan putih untuk netral (grounded)."},{id:1114,category:"listrik",source:"vocab_exam",furi:"ひきこみせん",jp:"引込線",romaji:"hikikomi sen",id_text:"Kabel masukan dari tiang ke gedung (service drop)",desc:"例: 引込線は電力会社の電柱から建物の引込口まで引き渡される電線で、電力会社の管轄である。→ Kabel masukan ditarik dari tiang listrik ke gedung dan menjadi tanggung jawab perusahaan listrik."},{id:1115,category:"listrik",source:"vocab_exam",furi:"でんきこうじし",jp:"電気工事士",romaji:"denki kouji shi",id_text:"Teknisi listrik berlisensi (第一種 / 第二種)",desc:"例: 第二種電気工事士は一般用電気工作物（交流600V以下）の電気工事を行える国家資格である。→ Lisensi teknisi listrik tingkat 2 memungkinkan pengerjaan instalasi listrik tegangan rendah (AC ≤600V)."},{id:1116,category:"pipa",source:"vocab_exam",furi:"しきりべん",jp:"仕切弁",romaji:"shikiri ben",id_text:"Gate valve / katup pintu geser",desc:"例: 仕切弁は全開か全閉で使用し、流量調節には適さない。→ Gate valve dipakai posisi buka penuh atau tutup penuh; tidak cocok untuk mengatur debit aliran."},{id:1117,category:"pipa",source:"vocab_exam",furi:"たまがたべん",jp:"玉形弁",romaji:"tama gata ben",id_text:"Globe valve / katup bola bulat",desc:"例: 玉形弁は流量調節に適しているが、圧力損失が大きい。→ Globe valve cocok untuk mengatur aliran, namun kerugian tekanannya besar dibanding gate valve."},{id:1118,category:"pipa",source:"vocab_exam",furi:"ボールバルブ",jp:"ボールバルブ",romaji:"booru barubu",id_text:"Ball valve / katup bola putar",desc:"例: ボールバルブはレバー1回転で全開・全閉でき、操作が簡単だ。→ Ball valve dapat dibuka/ditutup penuh hanya dengan memutar tuas 90°; mudah dioperasikan."},{id:1119,category:"pipa",source:"vocab_exam",furi:"バタフライバルブ",jp:"バタフライバルブ",romaji:"batafurai barubu",id_text:"Butterfly valve / katup kupu-kupu",desc:"例: バタフライバルブは大口径ダクトや冷水配管の流量制御によく使われる。→ Butterfly valve sering dipakai pada pipa berdiameter besar untuk pengendalian debit air dingin."},{id:1120,category:"pipa",source:"vocab_exam",furi:"ぎゃくしべん",jp:"逆止弁",romaji:"gyakushi ben",id_text:"Check valve / katup non-balik",desc:"例: 逆止弁はポンプ出口に設置し、逆流を防止する。→ Check valve dipasang di sisi keluar pompa untuk mencegah aliran balik saat pompa berhenti."},{id:1121,category:"pipa",source:"vocab_exam",furi:"あんぜんべん",jp:"安全弁",romaji:"anzen ben",id_text:"Safety / relief valve — katup pengaman tekanan",desc:"例: 安全弁は設定圧力を超えると自動的に開き、圧力を逃がす。→ Safety valve terbuka otomatis saat tekanan melebihi nilai seting, membuang kelebihan tekanan."},{id:1122,category:"pipa",source:"vocab_exam",furi:"フランジせつごう",jp:"フランジ接合",romaji:"furangi setsugou",id_text:"Sambungan flange / flange joint",desc:"例: フランジ接合はボルト・ナットで締め付け、ガスケットで気密を保つ。→ Sambungan flange diikat baut-mur dan disekat gasket; mudah dibongkar pasang untuk perawatan."},{id:1123,category:"pipa",source:"vocab_exam",furi:"ソケットせつごう",jp:"ソケット接合",romaji:"soketto setsugou",id_text:"Sambungan soket / socket joint",desc:"例: 塩ビ管のソケット接合では、接着剤を均一に塗布してから素早く挿入する。→ Pada sambungan soket pipa PVC, oleskan lem merata lalu masukkan pipa dengan cepat sebelum lem mengering."},{id:1124,category:"pipa",source:"vocab_exam",furi:"グルーブドせつごう",jp:"グルーブド接合",romaji:"guruubudo setsugou",id_text:"Sambungan grooved / Victaulic joint",desc:"例: グルーブド接合はパイプ端に溝を加工し、カップリングとガスケットで接合するため、工期が短い。→ Sambungan grooved menggunakan alur di ujung pipa dan coupling; pengerjaan lebih cepat dibanding las."},{id:1125,category:"pipa",source:"vocab_exam",furi:"ストレーナー",jp:"ストレーナー",romaji:"sutoreinaa",id_text:"Strainer / saringan kotoran pipa",desc:"例: ストレーナーはポンプや機器の前に設置し、異物を取り除いて機器を保護する。→ Strainer dipasang sebelum pompa atau peralatan untuk menyaring kotoran dan melindungi komponen."},{id:1126,category:"pipa",source:"vocab_exam",furi:"レデューサー",jp:"レデューサー",romaji:"redyuusaa",id_text:"Reducer / reduser perbedaan diameter pipa",desc:"例: 異径管をつなぐときはレデューサー（径違い継手）を使用する。→ Saat menyambung pipa berbeda diameter, gunakan reducer; tersedia tipe konsentrik dan eksentrik."},{id:1127,category:"pipa",source:"vocab_exam",furi:"ユニオン",jp:"ユニオン",romaji:"yunion",id_text:"Union / sambungan pipa yang dapat dilepas",desc:"例: ユニオンはバルブや機器の前後に設け、取り外しを容易にする継手だ。→ Union dipasang di sisi masuk/keluar katup agar peralatan mudah dibongkar saat pemeliharaan."},{id:1128,category:"pipa",source:"vocab_exam",furi:"ゆーボルト",jp:"Uボルト",romaji:"yuu boruto",id_text:"U-bolt / penjepit pipa berbentuk U",desc:"例: Uボルトは配管を支持するために使われ、適切な締め付けトルクで固定する。→ U-bolt digunakan sebagai penjepit pipa pada dudukan; kencangkan sesuai torsi yang ditentukan agar tidak merusak pipa."},{id:1129,category:"pipa",source:"vocab_exam",furi:"つりバンド",jp:"吊りバンド",romaji:"tsuri bando",id_text:"Pipe hanger band / penggantung pipa",desc:"例: 吊りバンドは天井スラブから吊りボルトで下げ、水平配管を支持する。→ Hanger band digantung dari pelat beton lewat baut gantung untuk menopang pipa horizontal di langit-langit."},{id:1130,category:"pipa",source:"vocab_exam",furi:"ぼうしんつぎて",jp:"防振継手",romaji:"boushin tsugite",id_text:"Anti-vibration joint / sambungan peredam getaran",desc:"例: ポンプ出口には防振継手を設け、振動が配管に伝わるのを防ぐ。→ Pasang anti-vibration joint di sambungan keluar pompa untuk mencegah getaran merambat ke jaringan pipa."},{id:1131,category:"pipa",source:"vocab_exam",furi:"かとうつぎて",jp:"可とう継手",romaji:"katou tsugite",id_text:"Flexible joint / sambungan pipa fleksibel",desc:"例: 可とう継手は地震時の変位や温度変化による伸縮を吸収する。→ Flexible joint menyerap perpindahan saat gempa dan ekspansi-kontraksi akibat perubahan suhu pada sistem perpipaan."},{id:1132,category:"pipa",source:"vocab_exam",furi:"つうきかん",jp:"通気管",romaji:"tsuuki kan",id_text:"Vent pipe / pipa ventilasi saluran air",desc:"例: 通気管は排水管内の空気圧を調整し、トラップの封水が破れないようにする。→ Pipa vent menstabilkan tekanan udara dalam pipa drainase agar air di dalam trap tidak tersedot habis."},{id:1133,category:"pipa",source:"vocab_exam",furi:"よびけい",jp:"呼び径",romaji:"yobi kei",id_text:"Nominal diameter / ukuran nominal pipa",desc:"例: 呼び径25Aの鋼管は外径34mm、実際の内径は25mmより若干異なる。→ Pipa baja 25A berarti ukuran nominal 25 mm; diameter sebenarnya sedikit berbeda tergantung standar A atau B."},{id:1134,category:"pipa",source:"vocab_exam",furi:"きみつしけん",jp:"気密試験",romaji:"kimitsu shiken",id_text:"Air tightness test / uji kebocoran udara",desc:"例: ガス配管の気密試験では、設定圧力で所定時間保持し、圧力降下がないか確認する。→ Pada pipa gas, lakukan uji tekanan udara pada tekanan yang ditentukan dan pantau apakah ada penurunan tekanan."},{id:1135,category:"pipa",source:"vocab_exam",furi:"きゅうすいかん",jp:"給水管",romaji:"kyuusui kan",id_text:"Pipa suplai air bersih",desc:"例: 給水管は水道本管から分岐し、各器具へ水を供給する。→ Pipa suplai air bersih bercabang dari jaringan utama PDAM dan mendistribusikan air ke setiap fixture bangunan."},{id:1136,category:"pipa",source:"vocab_exam",furi:"はいすいかん",jp:"排水管",romaji:"haisui kan",id_text:"Pipa drainase / buangan air limbah",desc:"例: 排水管は適切な勾配（一般的に1/100）を確保して詰まりを防ぐ。→ Pipa drainase harus dipasang dengan kemiringan memadai (umumnya 1/100) agar aliran lancar dan tidak mampet."},{id:1137,category:"pipa",source:"vocab_exam",furi:"ニップル",jp:"ニップル",romaji:"nippuru",id_text:"Nipple / sambungan pendek berulir dua sisi",desc:"例: ニップルは両端に雄ねじが切ってあり、ソケットや機器との短距離接続に使う。→ Nipple memiliki ulir jantan di kedua ujungnya; dipakai untuk menyambung dua fitting yang berdekatan."},{id:1138,category:"pipa",source:"vocab_exam",furi:"はいかんず",jp:"配管図",romaji:"haikan zu",id_text:"Gambar diagram perpipaan / piping diagram",desc:"例: 配管図を正しく読むことで、バルブの位置や流れの方向を把握できる。→ Dengan membaca gambar perpipaan dengan benar, kita bisa memahami posisi katup dan arah aliran dalam sistem."},{id:1139,category:"pipa",source:"vocab_exam",furi:"かんしじかなぐ",jp:"管支持金具",romaji:"kan shiji kanagu",id_text:"Pipe support bracket / dudukan penopang pipa",desc:"例: 管支持金具の間隔は管径と材質によって異なり、施工基準で定められている。→ Jarak antara dudukan pipa ditentukan berdasarkan diameter dan material pipa sesuai standar pemasangan."},{id:1140,category:"pipa",source:"vocab_exam",furi:"すいげきさよう",jp:"水撃作用",romaji:"suigeki sayou",id_text:"Water hammer / hentakan air (pukulan palu air)",desc:"例: ポンプの急停止でバルブを急閉すると水撃作用が発生し、配管を損傷させることがある。→ Water hammer terjadi saat pompa mendadak berhenti atau katup ditutup tiba-tiba, menimbulkan lonjakan tekanan yang bisa merusak pipa."},{id:1141,category:"telekomunikasi",source:"vocab_exam",furi:"おーえぬゆー（ひかりかいせんしゅうたんそうち）",jp:"ONU（光回線終端装置）",romaji:"oo enu yuu (hikari kaisen shuutan souchi)",id_text:"Perangkat terminasi jaringan fiber optik (sisi pelanggan)",desc:"例: ONUはFTTHで光信号を電気信号に変換する装置だ。→ ONU adalah perangkat FTTH yang mengubah sinyal cahaya menjadi sinyal listrik di sisi pelanggan."},{id:1142,category:"telekomunikasi",source:"vocab_exam",furi:"おーえるてぃー（ひかりかにゅうしゃせんしゅうたんそうち）",jp:"OLT（光加入者線終端装置）",romaji:"oo eru tii (hikari kanyuusha sen shuutan souchi)",id_text:"Perangkat terminasi optik sisi penyedia (ISP/sentral)",desc:"例: OLTは局舎側に設置され、スプリッターを介して複数のONUを管理する。→ OLT dipasang di sisi sentral dan mengelola banyak ONU melalui splitter."},{id:1143,category:"telekomunikasi",source:"vocab_exam",furi:"しんぐるもーどふぁいばー",jp:"シングルモードファイバー",romaji:"shinguru moodo faibaa",id_text:"Fiber optik mode tunggal, untuk jarak jauh",desc:"例: シングルモードファイバーは芯径約9μmで、長距離幹線通信に使われる。→ SMF berdiameter inti sekitar 9μm, digunakan untuk komunikasi trunk jarak jauh."},{id:1144,category:"telekomunikasi",source:"vocab_exam",furi:"まるちもーどふぁいばー",jp:"マルチモードファイバー",romaji:"maruchi moodo faibaa",id_text:"Fiber optik multi-mode, untuk jarak dekat",desc:"例: マルチモードファイバーは芯径50または62.5μmで、構内LAN配線に用いられる。→ MMF berdiameter inti 50 atau 62.5μm, umum dipakai untuk kabel LAN dalam gedung."},{id:1145,category:"telekomunikasi",source:"vocab_exam",furi:"えすしーこねくた",jp:"SCコネクタ",romaji:"esu shii konekuta",id_text:"Konektor fiber optik tipe SC (push-pull)",desc:"例: SCコネクタはプッシュプル式でワンタッチ着脱でき、ONU接続によく使われる。→ Konektor SC bertipe push-pull, mudah dipasang dan dilepas, sering dipakai pada sambungan ONU."},{id:1146,category:"telekomunikasi",source:"vocab_exam",furi:"えるしーこねくた",jp:"LCコネクタ",romaji:"eru shii konekuta",id_text:"Konektor fiber optik tipe LC, lebih kecil dari SC",desc:"例: LCコネクタはSCより小型で高密度実装が可能なため、データセンターのスイッチに多用される。→ LC lebih kecil dari SC dan memungkinkan kepadatan tinggi, banyak dipakai di switch data center."},{id:1147,category:"telekomunikasi",source:"vocab_exam",furi:"えすてぃーこねくた",jp:"STコネクタ",romaji:"esu tii konekuta",id_text:"Konektor fiber optik tipe ST (bayonet/putar)",desc:"例: STコネクタはバヨネット式で回して固定するタイプで、配線盤への接続に古くから使われてきた。→ Konektor ST dikunci dengan memutar seperti bayonet, dahulu banyak digunakan untuk panel distribusi fiber."},{id:1148,category:"telekomunikasi",source:"vocab_exam",furi:"はんしゃそんしつ",jp:"反射損失",romaji:"hansha sonshitsu",id_text:"Rugi daya akibat pantulan sinyal optik",desc:"例: OTDRで測定すると、コネクタ接続部では反射損失が大きく現れ、波形にスパイクが出る。→ Saat diukur dengan OTDR, sambungan konektor menunjukkan nilai refleksi tinggi berupa lonjakan pada grafik."},{id:1149,category:"telekomunikasi",source:"vocab_exam",furi:"そうにゅうそんしつ",jp:"挿入損失",romaji:"sounyuu sonshitsu",id_text:"Rugi sisip akibat penyambungan komponen optik",desc:"例: コネクタや融着部の挿入損失が規定値を超えると、伝送距離が短くなり通信品質が低下する。→ Jika rugi sisip pada konektor atau sambungan fusion melebihi batas, jarak transmisi berkurang dan kualitas komunikasi menurun."},{id:1150,category:"telekomunikasi",source:"vocab_exam",furi:"でっどぞーん",jp:"デッドゾーン",romaji:"deddo zoon",id_text:"Zona buta OTDR (area tak terukur setelah refleksi)",desc:"例: OTDRのデッドゾーン内は測定不能なため、光コネクタ直後の損失は正確に読み取れない。→ Area dalam dead zone OTDR tidak dapat diukur, sehingga rugi tepat setelah konektor optik tidak terbaca dengan akurat."},{id:1151,category:"telekomunikasi",source:"vocab_exam",furi:"ぱっちぱねる",jp:"パッチパネル",romaji:"pacchi paneru",id_text:"Panel distribusi dan penghubung kabel jaringan",desc:"例: パッチパネルにLANケーブルを接続し、スイッチとの配線を一か所にまとめて整理する。→ Kabel LAN dari berbagai titik disambungkan ke patch panel untuk merapikan kabel menuju switch dalam satu lokasi."},{id:1152,category:"telekomunikasi",source:"vocab_exam",furi:"えすてぃーぴーけーぶる",jp:"STPケーブル",romaji:"esu tii pii keepuru",id_text:"Kabel twisted pair berpelindung (shielded)",desc:"例: STPケーブルはシールドが電磁ノイズを遮断するため、工場などノイズの多い環境で使われる。→ STP memiliki pelindung EMI yang memblokir gangguan elektromagnetik, cocok untuk lingkungan pabrik yang banyak noise."},{id:1153,category:"telekomunikasi",source:"vocab_exam",furi:"つうしんらっく",jp:"通信ラック",romaji:"tsuushin rakku",id_text:"Rak perangkat telekomunikasi standar 19 inci",desc:"例: 通信ラックは19インチ規格が主流で、スイッチ・パッチパネル・サーバーを搭載できる。→ Rak telekomunikasi umumnya berstandar 19 inci, mampu menampung switch, patch panel, dan server."},{id:1154,category:"telekomunikasi",source:"vocab_exam",furi:"つうしんきゃびねっと",jp:"通信キャビネット",romaji:"tsuushin kyabinetto",id_text:"Kabinet/lemari tertutup untuk perangkat telekomunikasi",desc:"例: 屋外設置の通信キャビネットは防水・防塵（IP55以上）構造が必要だ。→ Kabinet telekomunikasi untuk pemasangan luar ruangan harus memiliki konstruksi tahan air dan debu (IP55 ke atas)."},{id:1155,category:"telekomunikasi",source:"vocab_exam",furi:"あいでぃーえふ（ちゅうかんはいせんばん）",jp:"IDF（中間配線盤）",romaji:"ai dii efu (chuukan haisen ban)",id_text:"Panel distribusi kabel tingkat lantai/zona",desc:"例: 大型ビルではMDFから引き出した幹線をIDFで各フロアの端末へ分岐させる。→ Di gedung besar, kabel trunk dari MDF didistribusikan via IDF ke setiap terminal di masing-masing lantai."},{id:1156,category:"telekomunikasi",source:"vocab_exam",furi:"せっちたんしばん",jp:"接地端子盤",romaji:"secchi tanshi ban",id_text:"Panel terminal grounding untuk perangkat komunikasi",desc:"例: 通信機器室の接地端子盤に各機器のアース線を集結させ、一点接地を確保する。→ Kabel grounding semua perangkat komunikasi dikumpulkan di panel terminal grounding guna memastikan single-point earthing."},{id:1157,category:"telekomunikasi",source:"vocab_exam",furi:"ほあんき",jp:"保安器",romaji:"hoaan ki",id_text:"Pelindung jalur masuk telepon (arrester/protector)",desc:"例: 保安器は雷サージや過電流から屋内の通信機器を保護するために引き込み口に設置される。→ Hoaan-ki dipasang di titik masuk kabel untuk melindungi peralatan komunikasi dalam gedung dari lonjakan petir dan arus lebih."},{id:1158,category:"telekomunikasi",source:"vocab_exam",furi:"たんしだい",jp:"端子台",romaji:"tanshi dai",id_text:"Terminal block / blok penghubung kabel",desc:"例: 端子台に複数の電線をねじで固定し、通信回路を分岐・接続する。→ Beberapa kabel diikat dengan sekrup pada terminal block untuk membagi dan menyambungkan rangkaian komunikasi."},{id:1159,category:"telekomunikasi",source:"vocab_exam",furi:"せいたん",jp:"成端",romaji:"seitan",id_text:"Terminasi ujung kabel (pengakhiran / penyelesaian ujung)",desc:"例: 光ケーブルの成端作業では、コネクタ取り付けと端面研磨を丁寧に行う必要がある。→ Dalam pekerjaan terminasi kabel fiber, pemasangan konektor dan pemolesan permukaan ujung serat harus dilakukan dengan teliti."},{id:1160,category:"telekomunikasi",source:"vocab_exam",furi:"しんせんたいしょう",jp:"心線対照",romaji:"shinsen taishou",id_text:"Identifikasi / pelacakan pasangan inti kabel",desc:"例: 心線対照器を使って、多心ケーブルのどの心線がどの端末に対応しているかを確認する。→ Alat pelacak inti kabel digunakan untuk memastikan inti mana di dalam kabel multi-core yang terhubung ke terminal mana."},{id:1161,category:"telekomunikasi",source:"vocab_exam",furi:"ひかりけーぶるのまげはんけい",jp:"光ケーブルの曲げ半径",romaji:"hikari keepuru no mage hankei",id_text:"Radius tikungan minimum kabel fiber optik",desc:"例: 光ケーブルの曲げ半径を規定値以下にすると光損失が急増し、最悪断線する恐れがある。→ Jika radius tikungan kabel fiber lebih kecil dari nilai minimum, rugi cahaya melonjak dan serat berisiko putus."},{id:1162,category:"telekomunikasi",source:"vocab_exam",furi:"かてごりーごいーけーぶる",jp:"Cat5eケーブル",romaji:"kategoori go ii keepuru",id_text:"Kabel UTP Cat5e, mendukung hingga 1 Gbps",desc:"例: Cat5eケーブルはギガビットイーサネット（1000BASE-T）に対応し、一般オフィスLANに広く使われる。→ Kabel Cat5e mendukung Gigabit Ethernet (1000BASE-T) dan banyak digunakan untuk LAN kantor umum."},{id:1163,category:"telekomunikasi",source:"vocab_exam",furi:"かてごりーろくけーぶる",jp:"Cat6ケーブル",romaji:"kategoori roku keepuru",id_text:"Kabel UTP Cat6, mendukung 10 Gbps jarak dekat",desc:"例: Cat6ケーブルはCat5eより高周波ノイズに強く、短距離なら10ギガビットイーサネットにも対応できる。→ Kabel Cat6 lebih tahan noise frekuensi tinggi dari Cat5e dan mampu mendukung 10GbE pada jarak pendek."},{id:1164,category:"telekomunikasi",source:"vocab_exam",furi:"ひかりすぷりったー",jp:"光スプリッター",romaji:"hikari supuritta",id_text:"Pembagi sinyal optik pasif untuk jaringan PON",desc:"例: PONシステムでは光スプリッターで1本の光ファイバーを複数の加入者向けに分岐させる。→ Dalam sistem PON, splitter optik membagi satu fiber menjadi jalur untuk banyak pelanggan sekaligus."},{id:1165,category:"telekomunikasi",source:"vocab_exam",furi:"ぽん（じゅどうひかりねっとわーく）",jp:"PON（受動光ネットワーク）",romaji:"pon (judou hikari nettowa-ku)",id_text:"Passive Optical Network, jaringan fiber pasif",desc:"例: FTTHサービスの多くはOLTとONUを光スプリッターで接続するPON方式を採用している。→ Sebagian besar layanan FTTH menggunakan sistem PON yang menghubungkan OLT dan ONU melalui splitter optik."},{id:1166,category:"keselamatan",source:"vocab_exam",furi:"わくぐみあしば",jp:"枠組足場",romaji:"wakugumi ashiba",id_text:"Scaffolding rangka (perancah pabrikasi)",desc:"例: 枠組足場は、建設工事で最も一般的に使われる仮設足場の一種です。→ Scaffolding rangka adalah jenis perancah sementara yang paling umum di proyek konstruksi. Terbuat dari panel baja pabrikasi yang dipasang vertikal dan horizontal."},{id:1167,category:"keselamatan",source:"vocab_exam",furi:"たんかんあしば",jp:"単管足場",romaji:"tankan ashiba",id_text:"Scaffolding pipa tunggal",desc:"例: 単管足場は鋼管とクランプを組み合わせて組み立てる足場です。→ Scaffolding pipa tunggal dirakit dari pipa baja yang disambung dengan klem. Fleksibel untuk berbagai bentuk bangunan."},{id:1168,category:"keselamatan",source:"vocab_exam",furi:"くさびきんけつしきあしば",jp:"くさび緊結式足場",romaji:"kusabi kinketsushiki ashiba",id_text:"Scaffolding sistem baji / wedge-lock",desc:"例: くさび緊結式足場は、ハンマー一本で組み立て・解体ができる足場です。→ Scaffolding sistem baji dapat dipasang dan dibongkar hanya dengan satu palu. Lebih cepat dari scaffolding pipa tunggal."},{id:1169,category:"keselamatan",source:"vocab_exam",furi:"あんぜんねっと",jp:"安全ネット",romaji:"anzen netto",id_text:"Jaring pengaman (safety net)",desc:"例: 高所作業では、安全ネットを設置して作業員の墜落を防ぎます。→ Saat kerja di ketinggian, safety net dipasang untuk mencegah pekerja jatuh. Wajib dipasang di bawah area kerja yang berisiko."},{id:1170,category:"keselamatan",source:"vocab_exam",furi:"てすり",jp:"手すり",romaji:"tesuri",id_text:"Pegangan tangan / guardrail",desc:"例: 作業床の端には、高さ85cm以上の手すりを設けなければなりません。→ Di tepi platform kerja, guardrail setinggi minimal 85 cm wajib dipasang. Berfungsi mencegah pekerja jatuh dari tepi."},{id:1171,category:"keselamatan",source:"vocab_exam",furi:"なかさん",jp:"中さん",romaji:"nakasan",id_text:"Mid-rail / rel tengah scaffolding",desc:"例: 手すりと幅木の間に中さんを取り付けて、作業員の転落を防ぎます。→ Mid-rail dipasang di antara guardrail atas dan toe board untuk mencegah pekerja tergelincir jatuh. Posisi sekitar 35–50 cm dari platform."},{id:1172,category:"keselamatan",source:"vocab_exam",furi:"はばき",jp:"巾木",romaji:"habaki",id_text:"Toe board / papan pengaman bawah",desc:"例: 巾木を足場の端に設置することで、工具や資材の落下を防げます。→ Toe board dipasang di bagian bawah tepi scaffolding untuk mencegah alat dan material jatuh ke bawah. Tinggi minimal 10 cm."},{id:1173,category:"keselamatan",source:"vocab_exam",furi:"しょうこうせつび",jp:"昇降設備",romaji:"shouko setsubi",id_text:"Fasilitas naik-turun (tangga/stairway)",desc:"例: 足場には、作業員が安全に昇降できる昇降設備を設けることが義務です。→ Scaffolding wajib dilengkapi fasilitas naik-turun agar pekerja dapat mengakses ketinggian dengan aman. Termasuk tangga tetap dan tangga portable."},{id:1174,category:"keselamatan",source:"vocab_exam",furi:"さんそのうどけい",jp:"酸素濃度計",romaji:"sanso noudokei",id_text:"Alat ukur kadar oksigen",desc:"例: 密閉空間に入る前に、酸素濃度計で酸素濃度が18%以上あることを確認します。→ Sebelum memasuki ruang tertutup, konfirmasi kadar oksigen minimal 18% dengan oksimeter. Kadar di bawah 18% = bahaya kekurangan oksigen."},{id:1175,category:"keselamatan",source:"vocab_exam",furi:"りゅうかすいそ",jp:"硫化水素",romaji:"ryuuka suiso",id_text:"Hidrogen sulfida (H₂S)",desc:"例: 硫化水素は腐卵臭のある無色の有毒ガスで、下水道や地下工事で発生しやすいです。→ Hidrogen sulfida adalah gas beracun tak berwarna berbau telur busuk, mudah muncul di pekerjaan saluran dan bawah tanah. Batas aman: di bawah 10 ppm."},{id:1176,category:"keselamatan",source:"vocab_exam",furi:"ゆうがいがすけんちき",jp:"有害ガス検知器",romaji:"yuugai gasu kenchiki",id_text:"Detektor gas berbahaya",desc:"例: 密閉空間作業前に有害ガス検知器を使って、一酸化炭素や硫化水素の濃度を測ります。→ Sebelum kerja di ruang tertutup, ukur konsentrasi CO dan H₂S menggunakan detektor gas berbahaya. Wajib dilakukan sebelum pekerja masuk."},{id:1177,category:"keselamatan",source:"vocab_exam",furi:"そうきますく",jp:"送気マスク",romaji:"souki masuku",id_text:"Respirator suplai udara / airline mask",desc:"例: 酸素欠乏や有毒ガスが発生する環境では、送気マスクを着用して作業します。→ Di lingkungan kekurangan oksigen atau bergas beracun, gunakan respirator suplai udara. Berbeda dengan masker filter biasa karena mengalirkan udara bersih dari luar."},{id:1178,category:"keselamatan",source:"vocab_exam",furi:"ろっくあうとたぐあうと",jp:"ロックアウト・タグアウト",romaji:"rokkuauto taguauto",id_text:"Lockout-Tagout (LOTO) — prosedur pengamanan energi",desc:"例: 設備のメンテナンス中は、ロックアウト・タグアウトを実施して誤作動を防ぎます。→ Saat perawatan alat, terapkan prosedur LOTO untuk mencegah mesin menyala tidak sengaja. Energi dikunci (lock) dan diberi tanda peringatan (tag)."},{id:1179,category:"keselamatan",source:"vocab_exam",furi:"さぎょうしゅにんしゃ",jp:"作業主任者",romaji:"sagyou shuninsha",id_text:"Pengawas kerja (mandated supervisor)",desc:"例: 足場組立や酸欠危険作業など、特定の危険作業には作業主任者の選任が法律で義務付けられています。→ Untuk pekerjaan berbahaya tertentu seperti pemasangan scaffolding atau ruang oksigen rendah, penunjukan pengawas kerja bersertifikat diwajibkan oleh undang-undang."},{id:1180,category:"keselamatan",source:"vocab_exam",furi:"つーるぼっくすみーてぃんぐ",jp:"ツールボックスミーティング",romaji:"tsuuru bokkusu miitingu",id_text:"Toolbox meeting (TBM) / rapat singkat keselamatan",desc:"例: 毎朝の作業開始前にツールボックスミーティングで当日の危険ポイントを確認します。→ Setiap pagi sebelum kerja dimulai, bahaya hari itu dikonfirmasi bersama dalam toolbox meeting. Biasanya berlangsung 5–15 menit di lokasi kerja."},{id:1181,category:"keselamatan",source:"vocab_exam",furi:"あんぜんとうばん",jp:"安全当番",romaji:"anzen touban",id_text:"Petugas keselamatan harian (giliran)",desc:"例: 安全当番は、当日の現場の安全状態を巡回して確認し、記録する役割を担います。→ Petugas keselamatan harian bertugas berkeliling mengecek dan mencatat kondisi keamanan lapangan. Dilakukan secara bergilir oleh anggota tim."},{id:1182,category:"keselamatan",source:"vocab_exam",furi:"あんぜんぱとろーる",jp:"安全パトロール",romaji:"anzen patorooru",id_text:"Patroli inspeksi keselamatan",desc:"例: 安全パトロールでは、ヘルメット未着用や足場の異常など危険箇所を点検します。→ Dalam patroli keselamatan, dicek hal-hal seperti helm tidak dipakai atau scaffolding tidak normal. Dilakukan oleh pengawas atau tim K3 secara berkala."},{id:1183,category:"keselamatan",source:"vocab_exam",furi:"さぎょうてじゅんしょ",jp:"作業手順書",romaji:"sagyou tejunsho",id_text:"Manual prosedur kerja (SOP)",desc:"例: 作業手順書には、作業の流れ・使用機材・注意事項・緊急時の対応が記載されています。→ Manual prosedur kerja memuat alur pekerjaan, peralatan yang digunakan, peringatan keselamatan, dan langkah darurat. Wajib dibuat sebelum pekerjaan berisiko dimulai."},{id:1184,category:"keselamatan",source:"vocab_exam",furi:"ついらくせいしようきぐ",jp:"墜落制止用器具",romaji:"tsuiraku seishi youkigu",id_text:"Alat pencegah jatuh / harness",desc:"例: 高さ2m以上の作業では、墜落制止用器具（フルハーネス型）の使用が義務化されています。→ Penggunaan alat pencegah jatuh tipe full-harness diwajibkan saat bekerja di ketinggian 2 meter atau lebih. Regulasi diperketat sejak 2019."},{id:1185,category:"keselamatan",source:"vocab_exam",furi:"ひらいらっか",jp:"飛来・落下",romaji:"hirai rakka",id_text:"Bahaya benda terbang / jatuh dari atas",desc:"例: 飛来・落下による事故を防ぐため、上部作業中は下の立入を禁止します。→ Untuk mencegah kecelakaan akibat benda terbang atau jatuh, masuk ke area bawah pekerjaan atas dilarang. Helm dan safety shoes wajib di seluruh area konstruksi."},{id:1186,category:"keselamatan",source:"vocab_exam",furi:"ねっちゅうしょう",jp:"熱中症",romaji:"netchuu shou",id_text:"Heat stroke / serangan panas",desc:"例: 夏の屋外作業では、こまめな水分・塩分補給で熱中症を予防します。→ Saat kerja luar ruangan di musim panas, minum air dan suplemen garam secara rutin mencegah heat stroke. WBGT (indeks panas) digunakan untuk menentukan tingkat risiko."},{id:1187,category:"keselamatan",source:"vocab_exam",furi:"ふんじん",jp:"粉じん",romaji:"funjin",id_text:"Debu / partikel berbahaya (dust)",desc:"例: 粉じんが多い現場では、防じんマスクを着用して作業します。→ Di lokasi dengan debu tinggi, gunakan masker anti-debu saat bekerja. Paparan debu jangka panjang dapat menyebabkan pneumokoniosis (penyakit paru akibat debu)."},{id:1188,category:"keselamatan",source:"vocab_exam",furi:"りすくあせすめんと",jp:"リスクアセスメント",romaji:"risuku asesuménto",id_text:"Penilaian risiko (risk assessment)",desc:"例: 作業前にリスクアセスメントを行い、危険を特定・評価・対策して記録します。→ Sebelum kerja, lakukan penilaian risiko: identifikasi bahaya, evaluasi tingkat risiko, tetapkan tindakan pencegahan, dan dokumentasikan. Diwajibkan oleh UU Keselamatan Kerja Jepang."},{id:1189,category:"keselamatan",source:"vocab_exam",furi:"ひやりはっと",jp:"ヒヤリハット",romaji:"hiyari hatto",id_text:"Near miss / hampir celaka",desc:"例: ヒヤリハット報告書を提出・共有することで、重大事故の予防につながります。→ Melaporkan dan berbagi near miss membantu mencegah kecelakaan serius. Berdasarkan Hukum Heinrich, 1 kecelakaan besar didahului oleh 29 insiden kecil dan 300 near miss."},{id:1190,category:"keselamatan",source:"vocab_exam",furi:"きけんよちくんれん",jp:"KYT（危険予知訓練）",romaji:"kiken yochi kunren",id_text:"Pelatihan prediksi bahaya (KYT)",desc:"例: KYTでは、作業前にチーム全員で現場の危険箇所を指摘し合い、対策を決めます。→ Dalam KYT, seluruh tim saling menunjukkan titik berbahaya di lokasi sebelum kerja dimulai dan menetapkan tindakan pencegahan. KY = Kiken Yochi (prediksi bahaya)."},{id:1191,category:"jenis_kerja",source:"vocab_exam",furi:"こうかんくい",jp:"鋼管杭",romaji:"koukan kui",id_text:"Tiang pancang pipa baja",desc:"例: 軟弱地盤では鋼管杭を支持層まで打ち込む。→ Pada tanah lunak, tiang pipa baja dipancang hingga lapisan pendukung. Jenis tiang pracetak berbahan baja, kuat menahan beban lateral."},{id:1192,category:"jenis_kerja",source:"vocab_exam",furi:"ピーシーぐい",jp:"PC杭",romaji:"pii shii kui",id_text:"Tiang pancang beton prategang",desc:"例: PC杭はプレストレストコンクリート製の既製杭である。→ PC杭 adalah tiang pracetak dari beton prategang (prestressed concrete). Digunakan sebagai pondasi dalam di tanah berbatu."},{id:1193,category:"jenis_kerja",source:"vocab_exam",furi:"ピーエイチシーぐい",jp:"PHC杭",romaji:"pii eichi shii kui",id_text:"Tiang beton prategang tegangan tinggi",desc:"例: PHC杭はPC杭より強度が高く、大型建築物の基礎に使われる。→ PHC杭 memiliki kekuatan lebih tinggi dari PC杭, dipakai untuk pondasi bangunan besar. PHC = Pretensioned spun High strength Concrete."},{id:1194,category:"jenis_kerja",source:"vocab_exam",furi:"しーとぱいる",jp:"シートパイル",romaji:"shiito pairu",id_text:"Sheet pile / turap baja",desc:"例: シートパイルを連続して打ち込み、土砂の崩壊を防ぐ。→ Sheet pile dipancang berurutan untuk mencegah longsornya tanah. Sama dengan 鋼矢板; istilah katakana lebih umum di lapangan."},{id:1195,category:"jenis_kerja",source:"vocab_exam",furi:"あーすあんかー",jp:"アースアンカー",romaji:"aasuankaa",id_text:"Angkur tanah / ground anchor",desc:"例: 急傾斜地の擁壁にはアースアンカーを使って引張力を確保する。→ Pada dinding penahan di lereng curam, earth anchor digunakan untuk menahan gaya tarik. Kabel atau batang baja ditanam ke tanah keras."},{id:1196,category:"jenis_kerja",source:"vocab_exam",furi:"あすふぁるとぼうすい",jp:"アスファルト防水",romaji:"asufuruto bousui",id_text:"Waterproofing aspal",desc:"例: 屋上の防水にはアスファルト防水が多く使われる。→ Waterproofing aspal banyak digunakan pada atap beton. Metode ini melapis permukaan dengan lembaran aspal yang dipanaskan atau dilekatkan (トーチ工法)."},{id:1197,category:"jenis_kerja",source:"vocab_exam",furi:"しーとぼうすい",jp:"シート防水",romaji:"shiito bousui",id_text:"Waterproofing lembaran (sheet)",desc:"例: シート防水は合成ゴムや塩化ビニルのシートを貼り付ける工法である。→ Sheet waterproofing menggunakan lembaran karet sintetis atau PVC yang ditempelkan ke permukaan. Lebih cepat pasang dibanding aspal."},{id:1198,category:"jenis_kerja",source:"vocab_exam",furi:"とまくぼうすい",jp:"塗膜防水",romaji:"tomaku bousui",id_text:"Waterproofing lapisan coating",desc:"例: 塗膜防水はウレタン系材料をローラーで塗布して防水層を形成する。→ Coating waterproofing membentuk lapisan kedap air dengan cara mengoleskan material uretan menggunakan roller. Cocok untuk bentuk permukaan tidak beraturan."},{id:1199,category:"jenis_kerja",source:"vocab_exam",furi:"しつじゅんようじょう",jp:"湿潤養生",romaji:"shitsujun youjou",id_text:"Perawatan beton dengan pembasahan",desc:"例: 打設後のコンクリートは湿潤養生を行い、乾燥によるクラックを防ぐ。→ Setelah pengecoran, beton dirawat dengan menjaga kelembaban (湿潤養生) untuk mencegah retak akibat pengeringan terlalu cepat."},{id:1200,category:"jenis_kerja",source:"vocab_exam",furi:"じょうきようじょう",jp:"蒸気養生",romaji:"jouki youjou",id_text:"Perawatan beton dengan uap panas",desc:"例: プレキャスト製品は蒸気養生で短期間に強度を出す。→ Produk precast (pracetak) menggunakan steam curing (蒸気養生) untuk mencapai kekuatan awal dalam waktu singkat. Suhu dijaga sekitar 60–80°C."},{id:1201,category:"jenis_kerja",source:"vocab_exam",furi:"ひまくようじょう",jp:"被膜養生",romaji:"himaku youjou",id_text:"Perawatan beton dengan lapisan membran",desc:"例: 被膜養生剤を散布して、コンクリート表面から水分が蒸発するのを防ぐ。→ Agen membran disemprotkan ke permukaan beton untuk mencegah penguapan air. Metode ini tidak memerlukan penyiraman berkala."},{id:1202,category:"jenis_kerja",source:"vocab_exam",furi:"すぺーさー",jp:"スペーサー",romaji:"supeeसाaa",id_text:"Penyangga tulangan / beton tahu",desc:"例: スペーサーはかぶり厚さを一定に保つために鉄筋の下に置く。→ Spacer (beton tahu) diletakkan di bawah tulangan untuk menjaga ketebalan selimut beton tetap sesuai standar. Terbuat dari mortar atau plastik."},{id:1203,category:"jenis_kerja",source:"vocab_exam",furi:"うちつぎめ",jp:"打ち継ぎ目",romaji:"uchitsugi me",id_text:"Sambungan pengecoran beton",desc:"例: 打ち継ぎ目は構造的弱点になりやすいため、位置を適切に設けること。→ Construction joint (打ち継ぎ目) adalah batas antara pengecoran lama dan baru, yang rawan menjadi titik lemah struktural jika tidak dikerjakan dengan benar."},{id:1204,category:"jenis_kerja",source:"vocab_exam",furi:"せぱれーたー",jp:"セパレーター",romaji:"separeetaa",id_text:"Pengikat jarak bekisting (form tie)",desc:"例: セパレーターは両側の型枠を一定間隔に保持する金属製スペーサーである。→ Separator adalah pengikat logam yang menjaga jarak antar dua sisi bekisting agar tetap konsisten saat pengecoran beton."},{id:1205,category:"jenis_kerja",source:"vocab_exam",furi:"かたわくりけいざい",jp:"型枠離型剤",romaji:"katawaku rikei zai",id_text:"Minyak/agen pelepas bekisting",desc:"例: 型枠離型剤を塗布することで、脱型時にコンクリートが型枠に張り付くのを防ぐ。→ Release agent (離型剤) dioleskan ke permukaan bekisting sebelum pengecoran agar mudah dilepas setelah beton mengeras."},{id:1206,category:"jenis_kerja",source:"vocab_exam",furi:"すらんぷしけん",jp:"スランプ試験",romaji:"suranpu shiken",id_text:"Uji slump (kekentalan beton segar)",desc:"例: 生コンの品質確認のためにスランプ試験を現場で実施する。→ Slump test dilakukan di lapangan untuk mengecek konsistensi (kekentalan) beton segar sebelum pengecoran. Nilai slump yang lebih tinggi berarti beton lebih encer."},{id:1207,category:"jenis_kerja",source:"vocab_exam",furi:"ぶりーでぃんぐ",jp:"ブリーディング",romaji:"buriidingu",id_text:"Bleeding (naiknya air ke permukaan beton)",desc:"例: ブリーディングが過剰だと表面強度が低下し、クラックの原因となる。→ Bleeding adalah fenomena air naik ke permukaan beton segar akibat gravitasi. Jika berlebihan, permukaan beton menjadi lemah dan mudah retak."},{id:1208,category:"jenis_kerja",source:"vocab_exam",furi:"じゃんか",jp:"ジャンカ",romaji:"janka",id_text:"Sarang lebah / cacat beton keropos",desc:"例: 締固め不足や生コンの分離によってジャンカが発生する。→ Janka (honeycomb) adalah cacat pada beton dimana terdapat rongga-rongga yang terlihat di permukaan, akibat pemadatan yang kurang atau beton terlalu encer."},{id:1209,category:"jenis_kerja",source:"vocab_exam",furi:"くらっく",jp:"クラック",romaji:"kurakku",id_text:"Retak / retakan pada beton",desc:"例: 乾燥収縮や過大な応力によってコンクリートにクラックが生じる。→ Retakan (クラック) pada beton bisa disebabkan oleh penyusutan pengeringan, pembebanan berlebih, atau perawatan yang tidak tepat. Dibedakan antara retak struktural dan retak non-struktural."},{id:1210,category:"jenis_kerja",source:"vocab_exam",furi:"てっきんたんさき",jp:"鉄筋探査機",romaji:"tekkin tansa ki",id_text:"Alat deteksi/pencari tulangan beton",desc:"例: 鉄筋探査機（電磁波レーダー）でコンクリート内部の鉄筋位置を確認する。→ Rebar detector menggunakan gelombang elektromagnetik untuk mendeteksi posisi dan kedalaman tulangan di dalam beton tanpa merusaknya. Penting saat renovasi atau coring."},{id:1211,category:"jenis_kerja",source:"vocab_exam",furi:"べーすぷれーと",jp:"ベースプレート",romaji:"beesu pureeto",id_text:"Pelat dasar kolom baja",desc:"例: 鉄骨柱の下部にベースプレートを設け、アンカーボルトで基礎と固定する。→ Base plate adalah pelat baja yang dipasang di bawah kolom baja, disambungkan ke pondasi beton menggunakan anchor bolt untuk menyalurkan beban."},{id:1212,category:"jenis_kerja",source:"vocab_exam",furi:"くいうちき",jp:"杭打ち機",romaji:"kui uchi ki",id_text:"Mesin pemancang tiang",desc:"例: 杭打ち機（パイルドライバー）で鋼管杭を所定深さまで打ち込む。→ Mesin pemancang (pile driver) digunakan untuk memancang tiang ke dalam tanah hingga kedalaman yang ditentukan. Ada tipe diesel hammer, hydraulic hammer, dan vibratory hammer."},{id:1213,category:"jenis_kerja",source:"vocab_exam",furi:"えきじょうか",jp:"液状化",romaji:"ekijou ka",id_text:"Likuefaksi / pencairan tanah",desc:"例: 地震時に砂質地盤が液状化すると、構造物が沈下・傾斜する恐れがある。→ Likuefaksi (液状化) terjadi saat gempa bumi menyebabkan tanah berpasir jenuh air kehilangan kekuatan dan berperilaku seperti cairan. Sangat berbahaya bagi pondasi bangunan."},{id:1214,category:"jenis_kerja",source:"vocab_exam",furi:"じたいりょく",jp:"地耐力",romaji:"ji tairyoku",id_text:"Daya dukung tanah",desc:"例: 建物を建てる前に地耐力を確認し、必要に応じて地盤改良を行う。→ Daya dukung tanah (地耐力) adalah kemampuan tanah menahan beban dari struktur di atasnya. Diukur melalui uji N-value (ボーリング調査) atau uji plat beban."},{id:1215,category:"jenis_kerja",source:"vocab_exam",furi:"あんかーぼると",jp:"アンカーボルト",romaji:"ankaa boruto",id_text:"Baut angkur / anchor bolt",desc:"例: アンカーボルトはベースプレートと基礎コンクリートを緊結する締結部材である。→ Anchor bolt adalah baut yang ditanam di pondasi beton untuk mengikat base plate kolom baja. Posisinya harus presisi sesuai shop drawing sebelum pengecoran pondasi."},{id:1216,category:"jenis_kerja",source:"vocab_exam",furi:"せっこうボード",jp:"石膏ボード",romaji:"sekkoo boodo",id_text:"Papan gipsum / gypsum board",desc:"例: 石膏ボードは内壁や天井の仕上げに広く使われる。→ Papan gipsum banyak dipakai untuk finishing dinding dalam dan plafon. Material ringan, mudah dipotong, dan memiliki sifat tahan api (準不燃). Disebut juga プラスターボード."},{id:1217,category:"jenis_kerja",source:"vocab_exam",furi:"けいりょうてっこつしたじ",jp:"軽量鉄骨下地",romaji:"keiryoo tekkotsu shitaji",id_text:"Rangka baja ringan (LGS) untuk dinding/plafon",desc:"例: 軽量鉄骨下地にビスで石膏ボードを留めて壁を仕上げる。→ Papan gipsum disekrup ke rangka baja ringan untuk membentuk dinding finishing. Rangka ini disusun dari ランナー (runner) dan スタッド (stud)."},{id:1218,category:"jenis_kerja",source:"vocab_exam",furi:"てんじょうしたじ",jp:"天井下地",romaji:"tenjoo shitaji",id_text:"Rangka substrat plafon",desc:"例: 天井下地は野縁受けと野縁で構成され、その上に石膏ボードを張る。→ Rangka plafon terdiri dari penggantung (野縁受け) dan besi furring (野縁), lalu papan gipsum dipasang di atasnya sebagai penutup plafon."},{id:1219,category:"jenis_kerja",source:"vocab_exam",furi:"システムてんじょう",jp:"システム天井",romaji:"shisutemu tenjoo",id_text:"Plafon sistem / suspended ceiling modular",desc:"例: オフィスビルのシステム天井は照明・空調・防災設備を一体で収める。→ Plafon sistem pada gedung perkantoran mengintegrasikan pencahayaan, AC, dan peralatan kebakaran dalam satu modul yang dapat dibongkar-pasang untuk perawatan."},{id:1220,category:"jenis_kerja",source:"vocab_exam",furi:"フリーアクセスフロア",jp:"フリーアクセスフロア",romaji:"furii akusesu furoa",id_text:"Lantai akses bebas / raised access floor",desc:"例: OAフロアは床下空間に電気・LANケーブルを自由に配線できる二重床構造だ。→ Raised floor (OAフロア) adalah struktur lantai ganda yang memungkinkan kabel listrik dan LAN diatur bebas di ruang bawah lantai gedung perkantoran."},{id:1221,category:"jenis_kerja",source:"vocab_exam",furi:"ALCパネル",jp:"ALCパネル",romaji:"ALC paneru",id_text:"Panel beton ringan otoklaf (ALC)",desc:"例: ALCパネルは軽量で断熱性・耐火性に優れ、外壁や床・屋根に使用される。→ Panel ALC (Autoclaved Lightweight Concrete) sangat ringan, memiliki sifat insulasi panas dan tahan api yang baik, digunakan untuk dinding luar, lantai, dan atap."},{id:1222,category:"jenis_kerja",source:"vocab_exam",furi:"カーテンウォール",jp:"カーテンウォール",romaji:"kaaten wōru",id_text:"Dinding tirai / curtain wall",desc:"例: 高層ビルのカーテンウォールは建物の荷重を負担しない外壁で、アルミや金属パネルで構成される。→ Curtain wall pada gedung tinggi adalah dinding luar non-struktural yang tidak menanggung beban, biasanya terbuat dari aluminium atau panel logam."},{id:1223,category:"jenis_kerja",source:"vocab_exam",furi:"サイディング",jp:"サイディング",romaji:"saijingu",id_text:"Siding / pelapis dinding eksterior",desc:"例: 窯業系サイディングは戸建て住宅の外壁仕上げとして広く使われている。→ Siding berbahan keramik (窯業系) adalah penutup dinding luar yang paling umum untuk rumah tinggal di Jepang. Tersedia juga jenis metal dan kayu."},{id:1224,category:"jenis_kerja",source:"vocab_exam",furi:"コーキング",jp:"コーキング",romaji:"kookingu",id_text:"Caulking / pengisian celah sambungan",desc:"例: サイディングのパネル継ぎ目にコーキング材を充填して防水性を確保する。→ Material caulking diisikan pada celah sambungan antar panel siding untuk memastikan ketahanan air. Berbeda dari シーリング材, istilah コーキング lebih sering dipakai untuk pekerjaan kecil dan celah sempit."},{id:1225,category:"jenis_kerja",source:"vocab_exam",furi:"プライマー",jp:"プライマー",romaji:"puraimaa",id_text:"Primer / lapisan dasar perekat",desc:"例: シーリング材を充填する前に、目地面にプライマーを塗布して接着力を高める。→ Primer dioleskan ke permukaan celah sebelum aplikasi sealant untuk meningkatkan daya rekat. Tanpa primer, sealant dapat mudah terlepas dari substrat."},{id:1226,category:"jenis_kerja",source:"vocab_exam",furi:"バックアップざい",jp:"バックアップ材",romaji:"bakkuappu zai",id_text:"Backer rod / pengisi belakang sealant",desc:"例: 目地が深い場合はバックアップ材を入れてシーリングの厚みを適切に調整する。→ Jika celah terlalu dalam, backer rod (biasanya busa polyethylene bulat) dimasukkan terlebih dahulu untuk mengatur ketebalan sealant agar efektif dan tidak retak."},{id:1227,category:"jenis_kerja",source:"vocab_exam",furi:"ぼうすいシート",jp:"防水シート",romaji:"bousui shiito",id_text:"Membran / lembaran waterproof",desc:"例: 屋根の仕上げ材の下に防水シートを敷いて雨水の浸入を防ぐ。→ Membran waterproof dipasang di bawah penutup atap untuk mencegah rembesan air hujan masuk ke struktur bangunan. Termasuk jenis アスファルトルーフィング."},{id:1228,category:"jenis_kerja",source:"vocab_exam",furi:"みずきり",jp:"水切り",romaji:"mizukiri",id_text:"Flashing / talang pengarah air hujan",desc:"例: 外壁の最下部に水切りを取り付けて、雨水が壁内部へ回り込まないようにする。→ Flashing dipasang di bagian bawah dinding luar untuk mengalirkan air hujan menjauhi struktur bangunan. Disebut juga フラッシング pada detail sambungan atap dan dinding."},{id:1229,category:"jenis_kerja",source:"vocab_exam",furi:"めじ",jp:"目地",romaji:"meji",id_text:"Nat / celah sambungan antar tile",desc:"例: タイル貼り完了後、目地材（セメント系）を充填して目地を仕上げる。→ Setelah pemasangan tile selesai, material nat (umumnya berbasis semen) diisikan untuk mengisi celah antar tile. Lebar目地 biasanya 3〜10mm tergantung jenis tile."},{id:1230,category:"jenis_kerja",source:"vocab_exam",furi:"モルタル",jp:"モルタル",romaji:"morutaru",id_text:"Mortar / adukan semen dan pasir",desc:"例: 外壁タイルの下地にモルタルを塗り付け、平滑に均してからタイルを張る。→ Mortar dioleskan sebagai dasar sebelum tile dipasang, kemudian diratakan. Komposisi umum: semen : pasir = 1 : 3 (volumetrik). Berbeda dari beton yang menggunakan tambahan kerikil."},{id:1231,category:"jenis_kerja",source:"vocab_exam",furi:"ふきつけとそう",jp:"吹付け塗装",romaji:"fukitsuke tosou",id_text:"Pengecatan semprot / spray painting",desc:"例: 吹付け塗装はエアスプレーで塗料を霧状に吹き付け、広い面積を均一に仕上げる工法だ。→ Pengecatan semprot menggunakan semprotan udara bertekanan untuk menghasilkan lapisan cat yang merata di area luas seperti dinding beton dan fasad bangunan."},{id:1232,category:"jenis_kerja",source:"vocab_exam",furi:"ビニルゆかシート",jp:"ビニル床シート",romaji:"biniru yuka shiito",id_text:"Lembaran lantai vinil",desc:"例: トイレや厨房などの水まわりにはビニル床シートが多く使用される。→ Lembaran lantai vinil banyak dipakai di toilet dan dapur karena tahan air, mudah dibersihkan, dan relatif mudah dipasang. Dipotong sesuai ukuran ruangan dan direkatkan ke lantai."},{id:1233,category:"jenis_kerja",source:"vocab_exam",furi:"ちょうじゃくシート",jp:"長尺シート",romaji:"choojaku shiito",id_text:"Long sheet / lembaran lantai panjang sambungan minim",desc:"例: 廊下や通路に長尺シートを施工すると継ぎ目が少なく衛生的に管理できる。→ Long sheet banyak dipakai di koridor dan area publik karena sambungan sedikit sehingga mudah dijaga kebersihannya. Dipasang dengan cara digelar dan direkatkan, lalu tepi-tepinya di-welding."},{id:1234,category:"jenis_kerja",source:"vocab_exam",furi:"したじしょり",jp:"下地処理",romaji:"shitaji shori",id_text:"Persiapan substrat / surface preparation",desc:"例: 塗装工事の前に下地処理として汚れ・旧塗膜・錆を除去して素地を整える。→ Sebelum pengecatan atau pemasangan finishing, substrat dibersihkan dari kotoran, cat lama, dan karat. Kualitas下地処理 menentukan daya tahan lapisan finishing."},{id:1235,category:"jenis_kerja",source:"vocab_exam",furi:"かべクロス",jp:"壁クロス",romaji:"kabe kurosu",id_text:"Wallcovering vinil / wallpaper dinding",desc:"例: 壁クロスは下地ボードにのりで貼り付ける内装仕上げの最終工程だ。→ Wallpaper vinil (壁クロス) ditempel pada papan gipsum menggunakan lem sebagai tahap akhir finishing interior. Jenis paling umum adalah ビニルクロス (vinyl cloth)."},{id:1236,category:"jenis_kerja",source:"vocab_exam",furi:"スタッド",jp:"スタッド",romaji:"sutaddo",id_text:"Stud / tiang vertikal baja ringan LGS",desc:"例: LGS工事でスタッドをランナーに差し込んで間仕切り壁の骨組みを組む。→ Stud adalah profil baja ringan berbentuk C yang dimasukkan secara vertikal ke dalam runner untuk membentuk rangka dinding partisi. Jarak antar stud biasanya 303mm atau 455mm."},{id:1237,category:"jenis_kerja",source:"vocab_exam",furi:"ランナー",jp:"ランナー",romaji:"rannaa",id_text:"Runner / rel horizontal LGS di lantai dan plafon",desc:"例: ランナーは床と天井にアンカーで固定され、スタッドを保持するU形の鋼材だ。→ Runner adalah profil baja berbentuk U yang dipasang di lantai dan plafon menggunakan anchor, berfungsi sebagai landasan dan penahan untuk stud pada sistem rangka LGS."},{id:1238,category:"jenis_kerja",source:"vocab_exam",furi:"ロックウールきゅうおんばん",jp:"ロックウール吸音板",romaji:"rokkuuuru kyuuon ban",id_text:"Panel akustik rockwool / ceiling tile penyerap suara",desc:"例: ロックウール吸音板はシステム天井に多く使われ、吸音性と防火性を兼ね備える。→ Panel akustik rockwool banyak dipakai pada sistem plafon karena dapat menyerap suara sekaligus memiliki sifat tahan api. Berbeda dari ロックウール断熱材 yang digunakan untuk insulasi panas."},{id:1239,category:"jenis_kerja",source:"vocab_exam",furi:"ふねんざいりょう",jp:"不燃材料",romaji:"funen zairyou",id_text:"Material tidak dapat terbakar (non-combustible)",desc:"例: 石膏ボードやALCパネルは建築基準法で不燃材料として認定されている。→ Papan gipsum dan panel ALC diakui sebagai材料 tidak dapat terbakar (不燃材料) berdasarkan Undang-Undang Standar Bangunan Jepang. Digunakan pada area yang mensyaratkan ketahanan api."},{id:1240,category:"jenis_kerja",source:"vocab_exam",furi:"せっちゃくこうほう",jp:"接着工法",romaji:"setchaku kouhoo",id_text:"Metode pemasangan adhesif (tile/board)",desc:"例: 内装タイルの接着工法では有機系接着剤を下地に塗布してタイルを張り付ける。→ Pada metode adhesif untuk tile interior, lem organik dioleskan ke substrat kemudian tile ditempel langsung. Metode ini lebih cepat dari mortar bed, namun memerlukan下地処理 yang baik."},{id:1241,category:"alat_umum",source:"vocab_exam",furi:"はんまーどりる",jp:"ハンマードリル",romaji:"hanmaa doriru",id_text:"Bor rotary / hammer drill",desc:"例: ハンマードリルはコンクリートへの穴あけや斫り作業に使う。→ Hammer drill digunakan untuk mengebor beton dan pekerjaan bongkaran (斫り). Wajib pakai pelindung telinga saat operasi."},{id:1242,category:"alat_umum",source:"vocab_exam",furi:"いんぱくとどらいばー",jp:"インパクトドライバー",romaji:"inpakuto doraibaa",id_text:"Impact driver / bor sekrup bertenaga",desc:"例: インパクトドライバーはビスやボルトを素早く締め付ける電動工具だ。→ Impact driver adalah alat listrik untuk mengencangkan baut dan sekrup dengan cepat. Berbeda dari drill driver biasa karena memberikan pukulan rotasi."},{id:1243,category:"alat_umum",source:"vocab_exam",furi:"ういんち",jp:"ウインチ",romaji:"uinchi",id_text:"Winch / derek penarik bermotor",desc:"例: ウインチで重い資材を引き上げる作業では、ロープの点検が欠かせない。→ Saat menarik material berat dengan winch, pemeriksaan tali/rantai dan kapasitas beban wajib dilakukan sebelum operasi."},{id:1244,category:"alat_umum",source:"vocab_exam",furi:"ぱいぷばいす",jp:"パイプバイス",romaji:"paipu baisu",id_text:"Ragum pipa / pipe vise",desc:"例: パイプバイスで鋼管を固定してからねじ切り加工を行う。→ Kencangkan pipa baja di ragum pipa (pipe vise) sebelum melakukan threading/penyayatan ulir dengan ねじ切り機. Cegah pipa bergeser saat dikerjakan."},{id:1245,category:"alat_umum",source:"vocab_exam",furi:"ぱいぷべんだー",jp:"パイプベンダー",romaji:"paipu bendaa",id_text:"Pembengkok pipa / pipe bender",desc:"例: パイプベンダーで鋼管を所定の角度に曲げる。最小曲げ半径に注意すること。→ Gunakan pipe bender untuk menekuk pipa baja ke sudut yang ditentukan. Perhatikan radius tekukan minimum agar pipa tidak penyok atau retak."},{id:1246,category:"alat_umum",source:"vocab_exam",furi:"ゆあつじゃっき",jp:"油圧ジャッキ",romaji:"yuatsu jakki",id_text:"Dongkrak hidrolik / hydraulic jack",desc:"例: 油圧ジャッキで重量物を持ち上げて位置を調整する。→ Dongkrak hidrolik digunakan untuk mengangkat beban berat atau menyesuaikan posisi material konstruksi. Pastikan landasan stabil sebelum mengoperasikan."},{id:1247,category:"alat_umum",source:"vocab_exam",furi:"あっちゃくこうぐ",jp:"圧着工具",romaji:"acchaku kougu",id_text:"Alat crimping / tang krimping kabel",desc:"例: 圧着工具で電線端子を確実に圧着し、接触不良を防ぐ。→ Gunakan alat crimping untuk menjepitkan terminal kabel dengan benar guna mencegah kontak yang buruk. Warna gagang: merah=端子用, kuning=リングスリーブ用."},{id:1248,category:"alat_umum",source:"vocab_exam",furi:"とるくれんち",jp:"トルクレンチ",romaji:"toruku renchi",id_text:"Kunci torsi / torque wrench",desc:"例: フランジボルトの締め付けはトルクレンチで規定トルク値を守る。→ Saat mengencangkan baut flens, gunakan kunci torsi sesuai nilai torsi yang ditentukan dalam spesifikasi. Mencegah over-torque yang bisa merusak ulir atau sambungan."},{id:1249,category:"alat_umum",source:"vocab_exam",furi:"しゃこまんりき",jp:"シャコ万力",romaji:"shako manriki",id_text:"Klem-C / C-clamp / ragum penjepit",desc:"例: 溶接作業中、シャコ万力で部材を固定して位置ずれを防ぐ。→ Saat pengelasan, gunakan C-clamp untuk memfix material agar tidak bergeser. Juga disebut Cクランプ. Digunakan saat menjepit papan, profil baja, atau pipa selama pengerjaan."},{id:1250,category:"alat_umum",source:"vocab_exam",furi:"たっぷ・だいす",jp:"タップ・ダイス",romaji:"tappu daisu",id_text:"Tap & dies / alat pembuat ulir",desc:"例: タップで金属に雌ねじを切り、ダイスで丸棒に雄ねじを切る。→ Tap digunakan untuk membuat ulir dalam (mur/雌ねじ), sedangkan dies untuk membuat ulir luar (baut/雄ねじ) pada batang logam. Keduanya adalah alat threading manual."},{id:1251,category:"alat_umum",source:"vocab_exam",furi:"かなきりのこ",jp:"金切りのこ",romaji:"kanakiri noko",id_text:"Gergaji besi / hacksaw",desc:"例: 金切りのこは鋼管や鉄棒の手動切断に使う。刃は消耗したら交換する。→ Gergaji besi digunakan untuk memotong pipa baja, besi batang, atau profil logam secara manual. Bilah gergaji (刃) dapat diganti saat sudah aus."},{id:1252,category:"alat_umum",source:"vocab_exam",furi:"ほーるそー",jp:"ホールソー",romaji:"hoorusoo",id_text:"Hole saw / mata bor pemotong lubang bulat",desc:"例: ホールソーで壁や天井に配管用の円形穴を開ける。→ Hole saw digunakan untuk membuat lubang bulat besar di dinding atau plafon untuk jalur pipa (配管) atau kabel listrik. Dipasang pada electric drill."},{id:1253,category:"alat_umum",source:"vocab_exam",furi:"がすばーなー",jp:"ガスバーナー",romaji:"gasu baanaa",id_text:"Pembakar gas / gas torch / burner",desc:"例: ガスバーナーは銅管のろう付けや防水材の炙り加工に使用する。→ Gas torch digunakan untuk penyolderan pipa tembaga (ろう付け/brazing) atau pemanasan material waterproofing. Pastikan ventilasi cukup dan jauh dari bahan mudah terbakar."},{id:1254,category:"alat_umum",source:"vocab_exam",furi:"ぜつえんていこうけい",jp:"絶縁抵抗計",romaji:"zetsuen teikou kei",id_text:"Megger / alat ukur tahanan isolasi kabel",desc:"例: 絶縁抵抗計（メガー）で電線の絶縁状態を確認し、漏電がないかを検査する。→ Megger digunakan untuk mengukur resistansi isolasi kabel listrik. Memastikan tidak ada kebocoran arus (漏電) ke ground sebelum sistem dinyalakan."},{id:1255,category:"alat_umum",source:"vocab_exam",furi:"せっちていこうけい",jp:"接地抵抗計",romaji:"secchi teikou kei",id_text:"Earth tester / alat ukur tahanan grounding",desc:"例: 接地抵抗計でアース極の接地抵抗値が規定値以下かを確認する。→ Earth tester digunakan untuk mengukur nilai tahanan grounding (接地/アース) dan memastikan instalasi pembumian memenuhi standar keamanan listrik."},{id:1256,category:"alat_umum",source:"vocab_exam",furi:"でんどうどりる",jp:"電動ドリル",romaji:"dendou doriru",id_text:"Bor listrik / electric drill",desc:"例: 電動ドリルは木材・金属・コンクリートへの穴あけに使う汎用工具だ。→ Bor listrik adalah alat serbaguna untuk mengebor kayu, logam, dan beton. Berbeda dengan ハンマードリル yang memberikan pukulan tambahan untuk material keras seperti beton."},{id:1257,category:"alat_umum",source:"vocab_exam",furi:"えあこんぷれっさー",jp:"エアコンプレッサー",romaji:"ea konpuressaa",id_text:"Kompresor udara / air compressor",desc:"例: エアコンプレッサーは釘打ち機やエアブロー清掃など幅広い作業に使用される。→ Kompresor udara digunakan untuk berbagai pekerjaan: alat tembak paku (釘打ち機), pembersihan debu dengan udara bertekanan, dan pengecatan semprot."},{id:1258,category:"alat_umum",source:"vocab_exam",furi:"こんくりーとかったー",jp:"コンクリートカッター",romaji:"konkuriito kattaa",id_text:"Gergaji beton / concrete cutter / floor saw",desc:"例: コンクリートカッターで床スラブに配管用の溝を切る。粉塵対策と給水が必須。→ Concrete cutter digunakan untuk memotong alur jalur pipa di lantai beton. Wajib menggunakan proteksi debu (防塵マスク) dan pendingin air saat operasi."},{id:1259,category:"alat_umum",source:"vocab_exam",furi:"ちっぱー",jp:"チッパー",romaji:"chippaa",id_text:"Pahat pneumatik / chipping hammer",desc:"例: チッパーはコンクリートのはつり作業や古い仕上げ材の除去に使う。→ Chipping hammer (chipper) digunakan untuk membongkar beton (斫り/はつり) atau mengupas material finishing lama. Gunakan goggles dan pelindung telinga saat operasi."},{id:1260,category:"alat_umum",source:"vocab_exam",furi:"じぐそー",jp:"ジグソー",romaji:"jigusoo",id_text:"Jigsaw / gergaji listrik serabut",desc:"例: ジグソーは曲線や複雑な形状の切断に適した電動のこぎりだ。→ Jigsaw adalah gergaji listrik yang cocok untuk memotong bentuk melengkung atau pola kompleks pada kayu, lembaran logam, atau papan gipsum di lokasi konstruksi."},{id:1261,category:"alat_umum",source:"vocab_exam",furi:"ぼーるばん",jp:"ボール盤",romaji:"booruban",id_text:"Mesin bor duduk / drill press",desc:"例: ボール盤は精密な穴あけ作業に使う据え置き型の電動ドリルだ。→ Drill press adalah mesin bor stasioner yang digunakan untuk pengeboran presisi di bengkel atau area persiapan material. Lebih akurat dari electric drill genggam."},{id:1262,category:"alat_umum",source:"vocab_exam",furi:"ぼうばくこうぐ",jp:"防爆工具",romaji:"boubaku kougu",id_text:"Alat anti-percikan / explosion-proof tools",desc:"例: ガス管周辺での作業には防爆工具を使用し、火花による爆発を防ぐ。→ Alat anti-percikan (防爆工具) wajib digunakan saat bekerja di sekitar pipa gas atau ruang dengan gas mudah terbakar, untuk mencegah ledakan akibat percikan api."},{id:1263,category:"alat_umum",source:"vocab_exam",furi:"すこや",jp:"スコヤ",romaji:"sukoya",id_text:"Siku presisi / try square / engineer's square",desc:"例: スコヤで部材の直角を確認してから溶接や加工を行う。→ Try square (スコヤ) digunakan untuk memeriksa sudut siku-siku (90°) pada material sebelum pengelasan atau pengerjaan lebih lanjut. Penting untuk akurasi pekerjaan logam dan kayu."},{id:1264,category:"alat_umum",source:"vocab_exam",furi:"ぷらいやー",jp:"プライヤー",romaji:"puraiyaa",id_text:"Tang jepit / pliers",desc:"例: プライヤーはナットや配管継手など円筒物をつかんで回す作業に使う。→ Pliers digunakan untuk mencengkeram dan memutar mur, fitting pipa, atau benda silindris lainnya. Berbeda dari ペンチ (kombinasi) — プライヤー memiliki rahang yang dapat disesuaikan lebarnya."},{id:1265,category:"alat_umum",source:"vocab_exam",furi:"しんくうぽんぷ",jp:"真空ポンプ",romaji:"shinkuu ponpu",id_text:"Pompa vakum / vacuum pump",desc:"例: 真空ポンプは冷媒配管の施工後、真空引きして水分・空気を除去するために使う。→ Pompa vakum digunakan setelah pemasangan pipa refrigerant (冷媒管) untuk mengosongkan udara dan kelembaban melalui proses vakumisasi (真空引き) sebelum pengisian refrigerant."},{id:1266,category:"karier",source:"vocab_exam",furi:"せこうけいかくしょ",jp:"施工計画書",romaji:"sekou keikaku sho",id_text:"Dokumen rencana pelaksanaan konstruksi",desc:"例: 施工計画書は着工前に作成し、監理者に提出する。→ Dokumen rencana pelaksanaan dibuat sebelum mulai kerja dan diserahkan ke pengawas. Mencakup metode kerja, jadwal, keselamatan, dan pengelolaan kualitas."},{id:1268,category:"karier",source:"vocab_exam",furi:"ケーワイシート",jp:"KYシート",romaji:"ke wai shi to",id_text:"Lembar prediksi bahaya (KY)",desc:"例: 朝礼でKYシートを記入し、今日の危険ポイントを共有した。→ Saat apel pagi, lembar KY diisi dan titik bahaya hari itu dibagikan ke semua pekerja. Berbeda dengan KYボード — シート adalah formulir tertulis per sesi."},{id:1269,category:"karier",source:"vocab_exam",furi:"しんきにゅうじょうしゃカード",jp:"新規入場者カード",romaji:"shinki nyuujoushya ka do",id_text:"Kartu pendataan pekerja baru",desc:"例: 新規入場者カードには、氏名・緊急連絡先・保有資格などを記入する。→ Kartu pekerja baru diisi dengan nama, kontak darurat, dan sertifikasi yang dimiliki. Wajib diserahkan sebelum pertama kali masuk lokasi."},{id:1270,category:"karier",source:"vocab_exam",furi:"グリーンファイル",jp:"グリーンファイル",romaji:"guriin fairu",id_text:"Green file — kumpulan dokumen keselamatan",desc:"例: グリーンファイルには、安全衛生計画書・KY記録・作業員名簿などが綴られる。→ Green file memuat rencana K3, catatan KY, daftar tenaga kerja, dll. Disimpan di lokasi dan diperiksa oleh pengawas proyek."},{id:1271,category:"karier",source:"vocab_exam",furi:"こうていひょう",jp:"工程表",romaji:"koutei hyou",id_text:"Tabel jadwal pekerjaan konstruksi",desc:"例: 工程表をもとに、各工種の開始日と終了日を管理する。→ Berdasarkan jadwal, tanggal mulai dan selesai setiap jenis pekerjaan dikelola. Ada dua jenis utama: バーチャート dan ネットワーク工程表."},{id:1272,category:"karier",source:"vocab_exam",furi:"バーチャート",jp:"バーチャート",romaji:"baachaato",id_text:"Jadwal balok (Gantt chart konstruksi)",desc:"例: バーチャートは見やすいが、作業の関連性が分かりにくい。→ Jadwal balok mudah dibaca tapi tidak menunjukkan ketergantungan antar pekerjaan. Cocok untuk proyek sederhana atau laporan kemajuan ke klien."},{id:1273,category:"karier",source:"vocab_exam",furi:"ネットワークこうていひょう",jp:"ネットワーク工程表",romaji:"nettowa ku koutei hyou",id_text:"Jadwal jaringan / CPM schedule",desc:"例: ネットワーク工程表でクリティカルパスを特定し、遅延リスクを管理した。→ Dengan jadwal jaringan, jalur kritis diidentifikasi untuk mengelola risiko keterlambatan. Menunjukkan urutan dan ketergantungan antar pekerjaan."},{id:1274,category:"karier",source:"vocab_exam",furi:"できだか",jp:"出来高",romaji:"dekidaka",id_text:"Nilai pekerjaan yang telah selesai (progres)",desc:"例: 今月の出来高は契約金額の40%に達した。→ Progres bulan ini mencapai 40% dari nilai kontrak. Digunakan untuk penagihan bertahap (partial billing) dan laporan kemajuan proyek."},{id:1275,category:"karier",source:"vocab_exam",furi:"ぶがかり",jp:"歩掛り",romaji:"bugakari",id_text:"Koefisien produktivitas tenaga kerja",desc:"例: 配管工事の歩掛りは、1mあたり何人工かかるかを示す。→ Koefisien kerja pipa menunjukkan berapa orang-hari yang dibutuhkan per meter. Digunakan untuk estimasi biaya tenaga kerja dalam RAB."},{id:1276,category:"karier",source:"vocab_exam",furi:"ちょくせつかせつ",jp:"直接仮設",romaji:"chokusetsu kasetsu",id_text:"Pekerjaan sementara langsung (per lokasi)",desc:"例: 直接仮設には、各工事専用の足場・型枠支保工などが含まれる。→ Pekerjaan sementara langsung mencakup perancah dan bekisting yang khusus untuk satu area pekerjaan tertentu. Berbeda dari 共通仮設."},{id:1277,category:"karier",source:"vocab_exam",furi:"きょうつうかせつ",jp:"共通仮設",romaji:"kyoutsuu kasetsu",id_text:"Pekerjaan sementara bersama (seluruh proyek)",desc:"例: 共通仮設には、現場事務所・トイレ・電力引込などが含まれる。→ Pekerjaan sementara bersama mencakup kantor lapangan, toilet, dan sambungan listrik yang dipakai semua pihak di proyek."},{id:1278,category:"karier",source:"vocab_exam",furi:"げんかかんり",jp:"原価管理",romaji:"genka kanri",id_text:"Manajemen biaya / pengendalian harga pokok",desc:"例: 原価管理では、実際原価と計画原価を比較して差異を分析する。→ Dalam manajemen biaya, biaya aktual dibandingkan dengan biaya rencana untuk menganalisis selisih. Termasuk dalam 4 pilar施工管理 (Q, C, D, S)."},{id:1279,category:"karier",source:"vocab_exam",furi:"せっけいとしょ",jp:"設計図書",romaji:"sekkei tosho",id_text:"Dokumen desain (gambar + spesifikasi)",desc:"例: 設計図書には、設計図・仕様書・現場説明書などが含まれる。→ Dokumen desain mencakup gambar kerja, spesifikasi teknis, dan penjelasan lapangan. Menjadi dasar kontrak dan pelaksanaan."},{id:1280,category:"karier",source:"vocab_exam",furi:"しゅんこうず",jp:"竣工図",romaji:"shunkou zu",id_text:"Gambar as-built (setelah selesai dibangun)",desc:"例: 竣工図は、実際に施工した内容を反映した最終図面で、引渡し時に提出する。→ Gambar as-built mencerminkan kondisi yang benar-benar dibangun, diserahkan saat serah terima ke klien. Berbeda dari gambar desain awal."},{id:1281,category:"karier",source:"vocab_exam",furi:"せこうず",jp:"施工図",romaji:"sekouzu",id_text:"Gambar kerja lapangan (shop drawing)",desc:"例: 施工図は設計図書をもとに現場で作業できるよう詳細化した図面である。→ Gambar kerja adalah gambar detail yang dibuat dari dokumen desain agar bisa langsung digunakan di lapangan. Dibuat oleh kontraktor, disetujui pengawas."},{id:1282,category:"karier",source:"vocab_exam",furi:"うちあわせきろく",jp:"打合せ記録",romaji:"uchiawasekiroku",id_text:"Notulen / catatan rapat koordinasi",desc:"例: 打合せ記録には、日時・参加者・決定事項・担当者を明記する。→ Notulen rapat mencantumkan tanggal, peserta, keputusan, dan penanggung jawab. Dokumen penting sebagai bukti kesepakatan di lapangan."},{id:1283,category:"karier",source:"vocab_exam",furi:"こうじにっぽう",jp:"工事日報",romaji:"kouji nippou",id_text:"Laporan harian pekerjaan konstruksi",desc:"例: 工事日報には、当日の作業内容・人員数・天気・問題点を記録する。→ Laporan harian mencatat jenis pekerjaan, jumlah tenaga kerja, cuaca, dan kendala hari itu. Diisi oleh pengawas lapangan setiap hari."},{id:1284,category:"karier",source:"vocab_exam",furi:"ざいりょうはんにゅう",jp:"材料搬入",romaji:"zairyou hanyuu",id_text:"Pengiriman / penerimaan material ke lokasi",desc:"例: 材料搬入時は、納品書と照合して数量・品番を確認する。→ Saat material tiba, jumlah dan nomor produk dicocokkan dengan surat jalan. Proses ini mendahului 検収 (penerimaan resmi setelah inspeksi)."},{id:1285,category:"karier",source:"vocab_exam",furi:"けんしゅう",jp:"検収",romaji:"kenshuu",id_text:"Inspeksi & penerimaan material resmi",desc:"例: 検収では、材料の品質・数量・規格が仕様書と一致するか確認する。→ Dalam inspeksi penerimaan, kualitas, jumlah, dan spesifikasi material dikonfirmasi sesuai dokumen. Setelah 検収 dinyatakan lulus, material sah digunakan."},{id:1286,category:"karier",source:"vocab_exam",furi:"ぜせい",jp:"是正",romaji:"zesei",id_text:"Tindakan koreksi / perbaikan ketidaksesuaian",desc:"例: 検査で不適合が見つかり、是正処置を施工者に指示した。→ Ketidaksesuaian ditemukan saat inspeksi, dan tindakan koreksi diperintahkan ke kontraktor. Dalam sistem ISO 9001, 是正処置は根本原因の除去を含む."},{id:1287,category:"karier",source:"vocab_exam",furi:"ひきわたし",jp:"引渡し",romaji:"hikiwatashi",id_text:"Serah terima bangunan / fasilitas ke klien",desc:"例: 引渡し前に竣工検査を行い、合格後に鍵と竣工図書を施主に渡す。→ Sebelum serah terima, inspeksi akhir dilakukan; lulus → kunci dan dokumen diserahkan ke pemilik. Menandai berakhirnya tanggung jawab kontraktor."},{id:1288,category:"karier",source:"vocab_exam",furi:"せこうたいせいだいちょう",jp:"施工体制台帳",romaji:"sekou taisei daichou",id_text:"Buku besar struktur pelaksana proyek",desc:"例: 施工体制台帳には、元請け・下請け・専門業者の情報を記載する。→ Buku besar ini memuat informasi kontraktor utama, sub-kontraktor, dan spesialis. Wajib dibuat pada proyek dengan nilai tertentu ke atas."},{id:1289,category:"karier",source:"vocab_exam",furi:"そうごうせこうけいかくしょ",jp:"総合施工計画書",romaji:"sougou sekou keikaku sho",id_text:"Rencana pelaksanaan konstruksi menyeluruh",desc:"例: 総合施工計画書は工事全体を俯瞰した計画書で、着工前に作成される。→ Dokumen ini merangkum rencana keseluruhan proyek dan dibuat sebelum pekerjaan dimulai. Menjadi acuan bagi semua 施工計画書 per bidang pekerjaan."},{id:1290,category:"karier",source:"vocab_exam",furi:"ひんしつかんりけいかくしょ",jp:"品質管理計画書",romaji:"hinshitsu kanri keikaku sho",id_text:"Dokumen rencana manajemen kualitas",desc:"例: 品質管理計画書には、検査項目・頻度・担当者・合否基準を定める。→ Dokumen ini menetapkan item inspeksi, frekuensi, penanggung jawab, dan kriteria lulus/gagal. Bagian dari sistem ISO 9001 yang diterapkan di proyek konstruksi."},// ── VOCAB TEORI v84: +35 kartu vocab 学科 (IDs 1393-1427) ─────────────────
// Cluster A: 法規 (Regulasi & Hukum)
{id:1393,category:"hukum",source:"vocab_teori",furi:"きょか",jp:"許可",romaji:"kyoka",id_text:"Izin / lisensi usaha konstruksi",desc:"例: 建設業を営むには知事または大臣の許可が必要だ。→ Menjalankan usaha konstruksi wajib mendapat izin dari gubernur atau menteri. 許可なしで工事受注 = 違法（いほう）."},{id:1394,category:"hukum",source:"vocab_teori",furi:"うけおいけいやく",jp:"請負契約",romaji:"ukeoi keiyaku",id_text:"Kontrak borongan / construction contract",desc:"例: 建設工事は発注者と元請けの請負契約に基づいて行われる。→ Pekerjaan konstruksi dilakukan berdasarkan kontrak borongan antara pemilik proyek dan kontraktor utama."},{id:1395,category:"hukum",source:"vocab_teori",furi:"もとうけ",jp:"元請け",romaji:"motouke",id_text:"Kontraktor utama / prime contractor",desc:"例: 元請けは発注者から直接工事を受注し、下請け全体を管理する。→ Pihak yang menerima proyek langsung dari pemilik; bertanggung jawab atas seluruh sub-kontraktor."},{id:1396,category:"hukum",source:"vocab_teori",furi:"したうけ",jp:"下請け",romaji:"shitauke",id_text:"Sub-kontraktor / sub-contractor",desc:"例: 元請けから工事の一部を受注するのが下請け業者だ。→ Pihak yang menerima sebagian pekerjaan dari kontraktor utama. 二次下請け・三次下請けと連鎖する場合もある."},{id:1397,category:"hukum",source:"vocab_teori",furi:"ろうどうきじゅんかんとくしょ",jp:"労働基準監督署",romaji:"roudou kijun kantoku sho",id_text:"Kantor Inspeksi Standar Ketenagakerjaan",desc:"例: 労働災害が起きたら、労働基準監督署に速やかに報告する義務がある。→ Jika terjadi kecelakaan kerja, wajib segera melapor ke Kantor Inspeksi. 報告を怠ると労災かくし（犯罪）になる."},{id:1398,category:"hukum",source:"vocab_teori",furi:"ゆうきゅうきゅうか",jp:"有給休暇",romaji:"yuukyuu kyuuka",id_text:"Cuti berbayar / paid leave",desc:"例: 6ヶ月継続勤務かつ出勤率80%以上で、10日の有給休暇が付与される。→ Setelah bekerja 6 bulan dengan tingkat kehadiran ≥80%, berhak atas 10 hari cuti berbayar. Hak ini diatur dalam 労働基準法."},{id:1399,category:"hukum",source:"vocab_teori",furi:"わりましちんぎん",jp:"割増賃金",romaji:"warimashi chingin",id_text:"Upah premi / overtime premium pay",desc:"例: 時間外労働の割増賃金は、通常の25%増し以上と法律で定められている。→ Upah lembur minimal 1.25× gaji normal sesuai UU Standar Ketenagakerjaan. Lembur >60jam/bulan = 1.5×."},{id:1400,category:"hukum",source:"vocab_teori",furi:"ばっそく",jp:"罰則",romaji:"bassoku",id_text:"Sanksi / hukuman pidana pelanggaran UU",desc:"例: 建設業法違反には罰則があり、業許可の取消しや罰金が科せられる。→ Pelanggaran UU Konstruksi dikenai sanksi berupa pencabutan izin usaha atau denda. 罰則を知ることは法令遵守の基本."},// Cluster B: 安全管理 (Safety Management)
{id:1401,category:"keselamatan",source:"vocab_teori",furi:"あんぜんかんりしゃ",jp:"安全管理者",romaji:"anzen kanrisha",id_text:"Safety manager / manajer keselamatan kerja",desc:"例: 常時50人以上の事業場には安全管理者の選任が義務付けられている。→ Wajib ada safety manager di tempat kerja dengan ≥50 pekerja tetap. Berbeda dari 衛生管理者 yang fokus pada kesehatan."},{id:1402,category:"keselamatan",source:"vocab_teori",furi:"さぎょうしゅにんしゃ",jp:"作業主任者",romaji:"sagyou shunin sha",id_text:"Pengawas pekerjaan / work leader (ditunjuk resmi)",desc:"例: 足場組み立てや酸欠危険作業では作業主任者の選任が義務だ。→ Untuk pekerjaan perancah, galian dalam, dan area kekurangan oksigen WAJIB ada pengawas resmi yang ditunjuk. Memerlukan sertifikasi khusus."},{id:1403,category:"keselamatan",source:"vocab_teori",furi:"さんだいさいがい",jp:"三大災害",romaji:"sandai saigai",id_text:"Tiga besar kecelakaan konstruksi",desc:"例: 建設業の三大災害は①墜落・転落②建設機械③崩壊・倒壊だ。→ ①Jatuh dari ketinggian (墜落・転落) = terbanyak, ②Kecelakaan mesin konstruksi, ③Runtuh/kolaps. 安全教育では必ず覚える基礎知識."},{id:1404,category:"keselamatan",source:"vocab_teori",furi:"あんぜんたい",jp:"安全帯",romaji:"anzentai",id_text:"Sabuk/harness keselamatan (generic term)",desc:"例: 高所作業では安全帯（ハーネス型）の着用が義務付けられている。→ Pekerjaan ketinggian wajib memakai safety harness. 2022年以降、フルハーネス型が原則。胴ベルト型は限られた条件のみ."},{id:1405,category:"keselamatan",source:"vocab_teori",furi:"ふるはーねすがた",jp:"フルハーネス型",romaji:"furu haanesugata",id_text:"Full-body harness type (standar keselamatan ketinggian)",desc:"例: 高さ6.75m以上（建設業は5m以上）ではフルハーネス型安全帯が義務。→ Di ketinggian ≥5m (konstruksi), wajib pakai full harness (bukan sabuk biasa). Mengurangi risiko cedera dalam saat jatuh."},{id:1406,category:"keselamatan",source:"vocab_teori",furi:"たちいりきんし",jp:"立入禁止",romaji:"tachiiri kinshi",id_text:"Dilarang masuk / no-entry zone",desc:"例: 重機の旋回範囲内は立入禁止区域として必ずロープで囲う。→ Area ayunan alat berat wajib dipasang tali dan tanda 'Dilarang Masuk'. 看板や標識の設置義務あり."},{id:1407,category:"keselamatan",source:"vocab_teori",furi:"ほごぐ",jp:"保護具",romaji:"hogogu",id_text:"APD / alat pelindung diri (general term)",desc:"例: 建設現場ではヘルメット・安全靴・安全帯が基本的な保護具だ。→ Helm, sepatu safety, dan harness adalah APD dasar di site konstruksi. 作業内容に応じた適切な保護具の選定が重要."},{id:1408,category:"keselamatan",source:"vocab_teori",furi:"かんでん",jp:"感電",romaji:"kanden",id_text:"Sengatan listrik / electric shock",desc:"例: 電気工事では感電事故を防ぐため、必ず電源を切ってから作業する。→ Dalam pekerjaan listrik, selalu matikan sumber daya sebelum bekerja untuk mencegah sengatan. 感電は最悪の場合死亡事故になる."},{id:1409,category:"keselamatan",source:"vocab_teori",furi:"ねっちゅうしょう",jp:"熱中症",romaji:"necchuushou",id_text:"Heat stroke / penyakit panas (kedaruratan kerja musim panas)",desc:"例: 夏の建設現場では熱中症対策として、こまめな水分補給と休憩が重要だ。→ Di musim panas, minum air rutin dan istirahat berkala sangat penting untuk cegah heat stroke. 症状: めまい・頭痛・意識消失. 緊急時は救急車を呼ぶ."},{id:1410,category:"keselamatan",source:"vocab_teori",furi:"ひやりはっと",jp:"ヒヤリハット",romaji:"hiyarihatto",id_text:"Near-miss / hampir celaka (tapi tidak terjadi)",desc:"例: ヒヤリハットを記録し報告することで、大事故を未然に防ぐことができる。→ Dengan mencatat dan melaporkan near-miss, kecelakaan besar bisa dicegah. ハインリッヒの法則: 1件の重大事故の背後に29のヒヤリハット."},// Cluster C: 施工管理 (Construction Management)
{id:1411,category:"jenis_kerja",source:"vocab_teori",furi:"せこうけいかく",jp:"施工計画",romaji:"sekou keikaku",id_text:"Rencana pelaksanaan konstruksi",desc:"例: 施工計画は工事着工前に作成し、工程・品質・安全の方針を定める。→ Dibuat sebelum pekerjaan dimulai, menetapkan kebijakan jadwal, kualitas, dan keselamatan."},{id:1412,category:"jenis_kerja",source:"vocab_teori",furi:"こうていひょう",jp:"工程表",romaji:"koutei hyou",id_text:"Bagan jadwal konstruksi (Gantt chart / network)",desc:"例: 工程表で各作業の開始・終了予定日と担当者を管理する。→ Jadwal menampilkan tanggal mulai/selesai setiap pekerjaan. バーチャート = mudah dibaca; ネットワーク工程表 = menampilkan ketergantungan antar pekerjaan."},{id:1413,category:"jenis_kerja",source:"vocab_teori",furi:"せこうず",jp:"施工図",romaji:"sekou zu",id_text:"Gambar kerja / shop drawing",desc:"例: 設計図を基に、実際の施工に使う詳細な施工図を作成する。→ Gambar detail yang dibuat dari gambar desain, digunakan langsung di lapangan. 施工図 ≠ 設計図; 施工図は実寸・取り付け詳細を含む."},{id:1414,category:"jenis_kerja",source:"vocab_teori",furi:"しゅんこうず",jp:"竣工図",romaji:"shunkou zu",id_text:"Gambar purna bangun / as-built drawing",desc:"例: 竣工後に実際の施工状況を反映した竣工図を作成し、発注者に引き渡す。→ Gambar yang diperbarui sesuai kondisi aktual setelah konstruksi selesai; diserahkan ke pemilik proyek untuk keperluan pemeliharaan."},{id:1415,category:"hukum",source:"vocab_teori",furi:"はっちゅうしゃ",jp:"発注者",romaji:"hacchuusha",id_text:"Pemilik proyek / project owner / client",desc:"例: 発注者は工事の内容・期間・金額を決め、元請けと請負契約を結ぶ。→ Pihak yang memesan proyek, menentukan isi/durasi/anggaran, dan menandatangani kontrak borongan."},{id:1416,category:"hukum",source:"vocab_teori",furi:"せんもんぎょうしゃ",jp:"専門業者",romaji:"senmon gyousha",id_text:"Kontraktor spesialis / specialty contractor",desc:"例: 電気・空調・配管などは各分野の専門業者が施工する。→ Listrik, AC, dan perpipaan dikerjakan oleh kontraktor spesialis masing-masing bidang. 元請けが全体調整し、各専門業者が実施工を担う."},// Cluster D: 設備・ライフライン teknis (High-yield for exam)
{id:1417,category:"pipa",source:"vocab_teori",furi:"れいばい",jp:"冷媒",romaji:"reibai",id_text:"Refrigeran / zat pendingin AC (HFC dll)",desc:"例: エアコンの冷媒管には冷媒が封入されており、接続時には漏れ試験が必須だ。→ Pipa refrigeran AC berisi zat pendingin; sambungan wajib diuji kebocoran setelah pemasangan. 冷媒管の接続後は必ず漏れ確認."},{id:1418,category:"pipa",source:"vocab_teori",furi:"こうばい",jp:"勾配",romaji:"koubai",id_text:"Kemiringan / gradient pipa drainase (agar aliran lancar)",desc:"例: 排水管は水が自然に流れるよう、必ず適切な勾配をつけて配管する。→ Pipa drainase harus dipasang dengan kemiringan yang cukup agar air mengalir secara gravitasi. 勾配不足 → 水が溜まり、流れが悪くなる."},{id:1419,category:"pipa",source:"vocab_teori",furi:"すいあつしけん",jp:"水圧試験",romaji:"suiatsu shiken",id_text:"Uji tekanan hidraulik / hydraulic pressure test",desc:"例: 配管工事完了後、接続部の漏れを確認するために水圧試験を実施する。→ Setelah pipa selesai dipasang, uji tekanan air dilakukan untuk memastikan tidak ada kebocoran. 試験圧力は仕様書の規定値で行う."},{id:1420,category:"pipa",source:"vocab_teori",furi:"もれしけん",jp:"漏れ試験",romaji:"more shiken",id_text:"Uji kebocoran (gas/refrigeran/pipa)",desc:"例: ガス管溶接後は必ず漏れ試験を行い、ガス漏れがないことを確認する。→ Setelah pengelasan pipa gas, wajib uji kebocoran sebelum dioperasikan. 冷媒管でも配線でも: 接続後の漏れ確認は鉄則."},{id:1421,category:"pipa",source:"vocab_teori",furi:"さどる",jp:"サドル",romaji:"sadoru",id_text:"Saddle / braket penopang pipa di dinding/langit-langit",desc:"例: サドルは配管を壁・天井・床に固定するための支持金具だ。→ Braket pelana untuk menempelkan pipa ke dinding, plafon, atau lantai. サドル間隔が広すぎると配管がたわむ（lendut）."},{id:1422,category:"pipa",source:"vocab_teori",furi:"つぎて",jp:"継手",romaji:"tsugite",id_text:"Fitting / komponen sambungan antar pipa",desc:"例: 継手には、エルボ（曲がり）・チーズ（T字）・ソケット（直線）などがある。→ Berbagai jenis fitting: elbow (belok), tee (T), socket (lurus). 材料・用途・接合方法によって選定が変わる."},{id:1423,category:"pipa",source:"vocab_teori",furi:"ふらんじ",jp:"フランジ",romaji:"furanji",id_text:"Flensa / sambungan pipa dengan baut (mudah dibuka)",desc:"例: バルブや機器との接続にはフランジ接合が使われ、メンテナンスが容易だ。→ Sambungan flensa menggunakan baut sehingga mudah dibuka untuk perawatan. 溶接・ねじに比べて着脱が簡単."},{id:1424,category:"pipa",source:"vocab_teori",furi:"ばるぶ",jp:"バルブ",romaji:"barubu",id_text:"Katup / valve (mengatur aliran dalam pipa)",desc:"例: バルブは流体の開閉・流量調節に使う。ゲート・ボール・グローブ・逆止めなど種類が多い。→ Mengatur buka/tutup aliran. Jenis: gate valve (全開/全閉), ball valve (cepat), globe (kontrol aliran), check valve (searah)."},{id:1425,category:"listrik",source:"vocab_teori",furi:"はいせん",jp:"配線",romaji:"haisen",id_text:"Pengkabelan / wiring (instalasi kabel listrik)",desc:"例: 配線工事では、電線の太さ・種類・配線ルートを図面通りに施工する。→ Instalasi kabel listrik sesuai gambar: ukuran kabel, jenis, dan rute harus tepat. 誤配線 → 漏電・感電・火災のリスク."},{id:1426,category:"listrik",source:"vocab_teori",furi:"ぶんき",jp:"分岐",romaji:"bunki",id_text:"Percabangan / branch (listrik atau pipa)",desc:"例: 幹線から各フロアへの分岐は、分電盤を介して行われる。→ Dari feeder utama, percabangan ke tiap lantai melalui panel distribusi. 電気でも配管でも: 幹線から分岐して各末端へ."},{id:1427,category:"listrik",source:"vocab_teori",furi:"でんねつせん",jp:"電熱線",romaji:"dennetsusen",id_text:"Kabel pemanas elektrik / heat trace (anti-beku pipa luar)",desc:"例: 寒冷地の屋外配管には、凍結防止のために電熱線を巻き付けて保温する。→ Di daerah dingin, kawat pemanas dililitkan pada pipa luar ruangan untuk mencegah pembekuan. 保温材と組み合わせて使用することが多い."},// ── VOCAB AISATSU v85: +18 kartu挨拶 (IDs 1428-1445, source: vocab_jac, category: salam) ──
// Workplace Japanese greetings — wajib hafal untuk komunikasi di lapangan
{id:1428,category:"salam",source:"vocab_jac",furi:"おはようございます",jp:"おはようございます",romaji:"ohayou gozaimasu",id_text:"Selamat pagi (formal)",desc:"例: 現場に到着したら「おはようございます」と挨拶する。→ Saat tiba di site, ucapkan selamat pagi kepada semua orang. ⚠️ Di konstruksi, sering dipakai sepanjang hari bukan hanya pagi hari."},{id:1429,category:"salam",source:"vocab_jac",furi:"よろしくおねがいします",jp:"よろしくお願いします",romaji:"yoroshiku onegai shimasu",id_text:"Mohon bimbingannya / salam kenal (serba guna)",desc:"例: 初日の挨拶「よろしくお願いします」／作業依頼の最後にも使う。→ Dipakai saat: pertama kali bertemu, menitipkan tugas ke orang lain, memohon bantuan. Frasa yang paling sering dibutuhkan di lapangan."},{id:1430,category:"salam",source:"vocab_jac",furi:"ありがとうございます",jp:"ありがとうございます",romaji:"arigatou gozaimasu",id_text:"Terima kasih (formal)",desc:"例: 仕事を手伝ってもらったら「ありがとうございます」。→ Ucapkan setelah dibantu atau menerima sesuatu. Versi kasual ke sesama pekerja: ありがとう (tanpa ございます)."},{id:1431,category:"salam",source:"vocab_jac",furi:"すみません",jp:"すみません",romaji:"sumimasen",id_text:"Permisi / maaf / excuse me (serbaguna)",desc:"例: 通路をふさいでいるとき「すみません」／何か頼むときにも使う。→ Dipakai untuk: meminta izin lewat, minta tolong, meminta perhatian seseorang, atau minta maaf ringan. Frasa paling serbaguna di tempat kerja Jepang."},{id:1432,category:"salam",source:"vocab_jac",furi:"わかりました",jp:"わかりました",romaji:"wakarimashita",id_text:"Sudah mengerti / paham (merespons instruksi)",desc:"例: 監督から指示を受けたら「わかりました」と返事する。→ Respons standar saat menerima instruksi dari atasan. Lebih formal dari 分かった (wakata). Wajib biasakan ini agar tidak dianggap tidak mendengarkan."},{id:1433,category:"salam",source:"vocab_jac",furi:"わかりません",jp:"わかりません",romaji:"wakarimasen",id_text:"Tidak mengerti / tidak tahu",desc:"例: 指示が聞き取れなかったら「わかりません。もう一度お願いします」と言う。→ Jika tidak mengerti, selalu bilang dengan jelas — jangan pura-pura mengerti! Tambahkan もう一度お願いします untuk minta diulang."},{id:1434,category:"salam",source:"vocab_jac",furi:"もういちどいってください",jp:"もう一度言ってください",romaji:"mou ichido itte kudasai",id_text:"Tolong ulangi sekali lagi",desc:"例: 聞き取れなかったとき「すみません、もう一度言ってください」。→ Kalimat wajib untuk meminta pengulangan. Tidak perlu malu menggunakannya — lebih baik bertanya daripada melakukan pekerjaan yang salah."},{id:1435,category:"salam",source:"vocab_jac",furi:"てつだってください",jp:"手伝ってください",romaji:"tetsudatte kudasai",id_text:"Tolong bantu saya",desc:"例: 重い材料を運ぶとき「手伝ってください」と頼む。→ Minta bantuan saat mengangkat beban berat, kesulitan teknis, dsb. Versi lebih sopan: お手伝いいただけますか？"},{id:1436,category:"salam",source:"vocab_jac",furi:"ちょっとまってください",jp:"ちょっと待ってください",romaji:"chotto matte kudasai",id_text:"Tolong tunggu sebentar",desc:"例: 準備が終わっていないとき「ちょっと待ってください」と言う。→ Minta waktu sebentar sebelum mulai atau menjawab. Sopan dan alami di lapangan. ちょっと = sedikit/sebentar."},{id:1437,category:"salam",source:"vocab_jac",furi:"おさきにしつれいします",jp:"お先に失礼します",romaji:"osaki ni shitsurei shimasu",id_text:"Permisi, saya pulang duluan / pamit sebelum orang lain",desc:"例: 仕事が終わって先に帰るとき「お先に失礼します」と言う。→ Ucapkan saat pulang/pergi sebelum rekan kerja lain. Wajib di budaya kerja Jepang — tidak bilang ini dianggap tidak sopan."},{id:1438,category:"salam",source:"vocab_jac",furi:"おつかれさまでした",jp:"お疲れ様でした",romaji:"otsukaresama deshita",id_text:"Terima kasih atas kerja kerasnya (akhir hari / selesai pekerjaan)",desc:"例: 一日の作業が終わったとき「お疲れ様でした」と言い合う。→ Ucapkan di akhir shift kepada semua orang. Berbeda dari お疲れ様です (sedang berlangsung) vs です (formal ongoing). Respon yang sama: お疲れ様でした."},{id:1439,category:"salam",source:"vocab_jac",furi:"りょうかいしました",jp:"了解しました",romaji:"ryoukai shimashita",id_text:"Siap / roger / mengerti dan akan dilaksanakan",desc:"例: 作業指示を受けて「了解しました、すぐ取りかかります」。→ Lebih aktif dari わかりました — menyiratkan kesiapan untuk bertindak. Di lapangan sering dipersingkat menjadi 了解（りょうかい）. ⚠️ Ke atasan: 承知しました (shouchiشimashita) lebih formal."},{id:1440,category:"salam",source:"vocab_jac",furi:"おわりました",jp:"終わりました",romaji:"owarimashita",id_text:"Sudah selesai (laporan penyelesaian tugas)",desc:"例: 作業が完了したら監督に「○○の作業が終わりました」と報告する。→ Laporan setelah menyelesaikan tugas. Selalu laporkan ke pengawas saat pekerjaan selesai — jangan diam saja. Bisa ditambahkan: 確認をお願いします (mohon diperiksa)."},{id:1441,category:"salam",source:"vocab_jac",furi:"きをつけて",jp:"気をつけて",romaji:"ki wo tsukete",id_text:"Hati-hati! / Be careful! (kepada orang lain)",desc:"例: 危険な場所を通る仲間に「気をつけて」と声をかける。→ Ucapkan kepada rekan yang sedang melewati area berbahaya atau pulang kerja. Versi lebih kuat: 気をつけてください (formal) atau 危ない！ (darurat)."},{id:1442,category:"salam",source:"vocab_jac",furi:"おねがいします",jp:"お願いします",romaji:"onegai shimasu",id_text:"Mohon / tolong (saat meminta sesuatu)",desc:"例: 資材を運んでほしいとき「○○をお願いします」と頼む。→ Tambahkan setelah permintaan apapun: 確認をお願いします (tolong cek), 手伝いをお願いします (tolong bantu), dll. Lebih sopan dari ください saja."},{id:1443,category:"salam",source:"vocab_jac",furi:"かくにんします",jp:"確認します",romaji:"kakunin shimasu",id_text:"Saya akan memastikan / mengecek",desc:"例: 指示の内容が不明なとき「確認してから報告します」。→ Ungkapkan saat perlu memverifikasi sesuatu sebelum menjawab. 確認 = konfirmasi/verifikasi. Jangan asal bilang OK kalau belum yakin — bilang 確認します!"},{id:1444,category:"salam",source:"vocab_jac",furi:"いってきます／いってらっしゃい",jp:"行ってきます／行ってらっしゃい",romaji:"ittekimasu / itterasshai",id_text:"Saya berangkat / Hati-hati di jalan (pasangan sapaan pergi)",desc:"例: 現場に向かう前「行ってきます」→ 残る人「行ってらっしゃい」。→ Pasangan sapaan saat seseorang berangkat meninggalkan tempat. Juga dipakai antar rekan kerja di site besar."},{id:1445,category:"salam",source:"vocab_jac",furi:"おせわになっております",jp:"お世話になっております",romaji:"osewa ni natte orimasu",id_text:"Terima kasih atas dukungan / bimbingan selama ini (formal)",desc:"例: 電話や会議の冒頭「お世話になっております、○○の田中です」。→ Kalimat pembuka formal dalam telepon atau rapat. Setara dengan 'thank you for your continued support'. Wajib di lingkungan kerja profesional Jepang."},// ── VOCAB GAP WAVE v86 — JAC Modul Resmi (IDs 1446-1485, 40 kartu) ──────────
// ─ Cluster A: ほうれんそう & 指示 (JAC 章7 コミュニケーション) ─
{id:1446,category:"karier",source:"vocab_jac",furi:"ほうこく",jp:"報告",romaji:"houkoku",id_text:"Laporan kepada atasan",desc:"例: 作業が完了したら上司に「○○が終わりました」と報告する。→ Setelah menyelesaikan tugas, langsung laporkan ke atasan. ほうれんそうの「ほう」。問題が起きたときも迷わず報告すること。報告なしは信頼を失う。"},{id:1447,category:"karier",source:"vocab_jac",furi:"れんらく",jp:"連絡",romaji:"renraku",id_text:"Komunikasi / pemberitahuan antar tim",desc:"例: 材料が足りなくなったら現場監督に連絡する。→ Jika material habis, segera hubungi supervisor. ほうれんそうの「れん」。こまめな連絡が現場の混乱を防ぐ。情報は抱え込まず共有する。"},{id:1448,category:"karier",source:"vocab_jac",furi:"そうだん",jp:"相談",romaji:"soudan",id_text:"Konsultasi / diskusi dengan atasan/senior",desc:"例: やり方が分からないときは一人で悩まず先輩に相談する。→ Kalau tidak tahu caranya, konsultasikan dengan senior — jangan coba-coba sendiri. ほうれんそうの「そう」。迷ったら必ず相談。"},{id:1449,category:"karier",source:"vocab_jac",furi:"ほうれんそう",jp:"ほう・れん・そう",romaji:"hourenso",id_text:"Lapor–Hubungi–Konsultasi = 3 pilar komunikasi kerja Jepang",desc:"例: 建設現場では「ほう・れん・そう」が基本中の基本。ほう=報告、れん=連絡、そう=相談。→ Konsep fundamental komunikasi di tempat kerja Jepang. Tanpa ほうれんそう, koordinasi lapangan gagal. JAC テキストで必出。"},{id:1450,category:"karier",source:"vocab_jac",furi:"しじ",jp:"指示",romaji:"shiji",id_text:"Instruksi / perintah kerja dari atasan",desc:"例: 監督から指示を受けたら、内容をメモして「わかりました」と返事する。→ Saat menerima instruksi, catat isinya dan respons dengan jelas. 指示に従って作業する = bekerja sesuai arahan. 指示なしで勝手に動かない。"},// ─ Cluster B: 職場マナー (JAC 章7 職業倫理・態度) ─
{id:1451,category:"karier",source:"vocab_jac",furi:"けいご",jp:"敬語",romaji:"keigo",id_text:"Bahasa hormat Jepang (kepada atasan/klien)",desc:"例: 上司や発注者には敬語を使う。「食べる」→「いただく」、「言う」→「おっしゃる」。→ Bahasa hormat digunakan kepada atasan, senior, dan klien. Keigo dasar: ～ます/～ます form = sudah cukup di lapangan."},{id:1452,category:"karier",source:"vocab_jac",furi:"みだしなみ",jp:"身だしなみ",romaji:"midashinami",id_text:"Penampilan / kerapian diri di tempat kerja",desc:"例: 現場では清潔な作業着・正しくかぶったヘルメット・安全靴が身だしなみの基本。→ Penampilan di site: seragam bersih, helm benar, sepatu safety. 身だしなみが良い = kesan profesional, kepercayaan atasan meningkat."},{id:1453,category:"karier",source:"vocab_jac",furi:"ちこく",jp:"遅刻",romaji:"chikoku",id_text:"Terlambat / keterlambatan masuk kerja",desc:"例: 遅刻しそうなときは、必ず事前に上司に連絡する。無断遅刻は厳禁。→ Jika akan terlambat, WAJIB hubungi atasan lebih dulu. Terlambat tanpa kabar (無断遅刻) = pelanggaran serius. 朝礼の時間に間に合うよう余裕を持って出勤する。"},{id:1454,category:"karier",source:"vocab_jac",furi:"けっきん",jp:"欠勤",romaji:"kekkin",id_text:"Tidak masuk kerja / absen",desc:"例: 体調不良で欠勤する場合は、始業時間前に会社へ電話連絡する。→ Kalau sakit dan tidak bisa masuk, telepon perusahaan SEBELUM jam kerja dimulai. 無断欠勤 = 最悪の場合、解雇の原因になる。欠勤の際は診断書が必要な場合もある。"},{id:1455,category:"karier",source:"vocab_jac",furi:"とどけで",jp:"届け出",romaji:"todokede",id_text:"Notifikasi / pelaporan resmi (izin/cuti/absen)",desc:"例: 遅刻・欠勤・早退の場合は届け出（とどけで）が必要。→ Terlambat, absen, atau pulang lebih awal semua memerlukan pemberitahuan resmi. 事前の届け出 = izin sebelumnya. 事後報告より事前届けが原則。"},// ─ Cluster C: 体調管理・休憩 (JAC 章2 安全衛生) ─
{id:1456,category:"keselamatan",source:"vocab_jac",furi:"たいちょうかんり",jp:"体調管理",romaji:"taichoukanri",id_text:"Manajemen kondisi fisik / menjaga kesehatan diri",desc:"例: プロとして毎日の体調管理は自分の責任だ。睡眠・食事・水分補給の3つが基本。→ Sebagai profesional, menjaga kondisi tubuh adalah tanggung jawab pribadi. 体調不良で作業すると事故・ミスの原因になる。JAC テキスト必出トピック。"},{id:1457,category:"keselamatan",source:"vocab_jac",furi:"たいちょうふりょう",jp:"体調不良",romaji:"taichoufuryou",id_text:"Kondisi badan tidak fit / merasa tidak enak badan",desc:"例: 体調不良を感じたら無理せず、すぐに上司に「体調が悪いです」と報告する。→ Kalau tidak enak badan, jangan dipaksakan — langsung lapor ke atasan. 高所作業・機械操作中の体調不良は重大事故の原因になる。"},{id:1458,category:"keselamatan",source:"vocab_jac",furi:"すいぶんほきゅう",jp:"水分補給",romaji:"suibunhokyuu",id_text:"Minum air / rehidrasi (cegah heat stroke)",desc:"例: 夏の現場では、1時間ごとに水分補給して熱中症を予防する。→ Di musim panas, minum air setiap jam untuk cegah heat stroke. のどが渇く前に飲む = minum sebelum merasa haus. スポーツドリンクで電解質も補充する。"},{id:1459,category:"karier",source:"vocab_jac",furi:"きゅうけい",jp:"休憩",romaji:"kyuukei",id_text:"Istirahat / break kerja (hak berdasarkan UU)",desc:"例: 労働基準法で6時間超は45分、8時間超は60分の休憩が義務づけられている。→ UU mewajibkan istirahat: kerja >6 jam = 45 menit, >8 jam = 60 menit. 休憩時間は賃金が発生しない。Tetapi tidak bisa dipotong oleh perusahaan."},{id:1460,category:"karier",source:"vocab_jac",furi:"ざんぎょう",jp:"残業",romaji:"zangyou",id_text:"Lembur / kerja lebih dari jam normal",desc:"例: 残業は36協定の範囲内で行い、残業代（割増賃金）が支払われる。→ Lembur dilakukan dalam batas 36 perjanjian dan dibayar upah premi. 36協定なしの残業 = 違法。残業時間の上限: 原則45時間/月。"},{id:1461,category:"karier",source:"vocab_jac",furi:"じかんげんしゅ",jp:"時間厳守",romaji:"jikangennshu",id_text:"Tepat waktu / kepatuhan terhadap jadwal",desc:"例: 朝礼・作業開始・材料搬入など、すべての時間を厳守することが信頼の基本。→ Semua jadwal — apel, mulai kerja, pengiriman material — harus tepat waktu. 「5分前行動」= siap 5 menit sebelum waktu yang ditetapkan. Kebiasaan di Jepang."},{id:1462,category:"karier",source:"vocab_jac",furi:"きゅうよめいさい",jp:"給与明細",romaji:"kyuuyomeisai",id_text:"Slip gaji / rincian pembayaran upah bulanan",desc:"例: 毎月の給与明細を確認し、残業代・各種控除が正しいか確認する。→ Cek slip gaji setiap bulan: pastikan upah lembur dan potongan sudah benar. 不明な点は会社の担当者に相談する権利がある。給与明細の交付は法律上の義務。"},// ─ Cluster D: 特定技能・在留 (JAC 章1 在留資格) ─
{id:1463,category:"hukum",source:"vocab_teori",furi:"とくていぎのう",jp:"特定技能",romaji:"tokutei ginou",id_text:"SSW / Specified Skilled Worker — status tinggal kerja Jepang",desc:"例: 特定技能は2019年創設の在留資格で、人手不足の14分野（建設・製造・介護など）で就労できる。→ Status tinggal baru 2019 untuk bekerja di 14 bidang kekurangan tenaga kerja. 特定技能1号: max 5年, 家族帯同不可 / 2号: 更新可能, 家族帯同可。"},{id:1464,category:"hukum",source:"vocab_teori",furi:"ざいりゅうかーど",jp:"在留カード",romaji:"zairyuu kaado",id_text:"Kartu izin tinggal / residence card",desc:"例: 在留カードは常に携帯義務。警察・入管に求められたら提示する。住所変更後14日以内に届け出が必要。→ Wajib dibawa setiap saat. Jika diminta polisi/imigrasi, wajib tunjukkan. Masa berlaku tertera di kartu — jangan sampai kedaluwarsa."},{id:1465,category:"hukum",source:"vocab_teori",furi:"ざいりゅうしかく",jp:"在留資格",romaji:"zairyuu shikaku",id_text:"Status tinggal / jenis izin untuk tinggal & bekerja di Jepang",desc:"例: 在留資格の種類によって、働ける仕事の範囲が決まる。資格外の仕事をすると不法就労になる。→ Jenis status tinggal menentukan pekerjaan yang boleh dilakukan. 特定技能・技能実習・留学など種類が多い。"},{id:1466,category:"hukum",source:"vocab_teori",furi:"ざいりゅうきかん",jp:"在留期間",romaji:"zairyuu kikan",id_text:"Masa berlaku izin tinggal",desc:"例: 特定技能1号の在留期間は最長5年。期限が切れる前に更新の手続きが必要。→ Max 5 tahun untuk SSW 1. Wajib proses perpanjangan sebelum kedaluwarsa. 在留期間を過ぎると不法滞在（オーバーステイ）となり強制退去の対象。"},{id:1467,category:"hukum",source:"vocab_teori",furi:"しゅうろう",jp:"就労",romaji:"shuurou",id_text:"Bekerja / kegiatan kerja berdasarkan izin tinggal",desc:"例: 在留資格の範囲外での就労は「不法就労」として処罰される。雇用主も罰則の対象。→ Kerja di luar izin tinggal = kerja ilegal, bisa dipenjara/dideportasi. Majikan juga kena sanksi. 特定技能では指定分野のみ就労可。"},{id:1468,category:"hukum",source:"vocab_teori",furi:"こうしん",jp:"更新",romaji:"koushin",id_text:"Perpanjangan (visa / izin tinggal / kontrak)",desc:"例: 在留期間の更新は期限の3ヶ月前から申請できる。忘れずに早めに手続きをする。→ Perpanjangan masa tinggal bisa diajukan mulai 3 bulan sebelum kedaluwarsa. 契約の更新, 免許の更新にも使う同じ単語。"},// ─ Cluster E: 社会保険 (JAC 章6 法令) ─
{id:1469,category:"hukum",source:"vocab_teori",furi:"しゃかいほけん",jp:"社会保険",romaji:"shakai hoken",id_text:"Asuransi sosial — umbrella term (健康保険+厚生年金+雇用保険)",desc:"例: 社会保険とは健康保険・厚生年金・雇用保険などの総称で、一定規模の会社では加入義務がある。→ Istilah umum untuk semua asuransi wajib. 保険料は会社と従業員が折半。外国人も加入対象で、一定条件で給付を受けられる。"},{id:1470,category:"hukum",source:"vocab_teori",furi:"けんこうほけん",jp:"健康保険",romaji:"kenkou hoken",id_text:"Asuransi kesehatan (医療費の7割をカバー)",desc:"例: 健康保険に加入すると、病院の医療費が原則3割負担になる。→ Dengan asuransi kesehatan, biaya medis jadi 30% tanggungan sendiri (70% ditanggung). 保険証（ほけんしょう）が交付され、病院で提示する。"},{id:1471,category:"hukum",source:"vocab_teori",furi:"こうせいねんきん",jp:"厚生年金",romaji:"kousei nenkin",id_text:"Pensiun perusahaan / employees' pension insurance",desc:"例: 厚生年金保険料は会社と従業員で折半し、将来の年金受給権が積み上がる。→ Premi pensiun ditanggung bersama (50%:50%). Setelah pensiun, berhak menerima uang pensiun. 外国人は帰国時に「脱退一時金」を受け取れる場合あり。"},{id:1472,category:"hukum",source:"vocab_teori",furi:"こようほけん",jp:"雇用保険",romaji:"koyou hoken",id_text:"Asuransi ketenagakerjaan (tunjangan pengangguran)",desc:"例: 雇用保険に加入していれば、失業時に失業給付（失業手当）が支給される。→ Jika kehilangan pekerjaan, dapat tunjangan pengangguran dari asuransi ini. 保険料は会社と従業員の両方が負担。育児・介護休業給付もここから。"},{id:1473,category:"hukum",source:"vocab_teori",furi:"ほけんしょう",jp:"保険証",romaji:"hokenshou",id_text:"Kartu asuransi kesehatan / health insurance card",desc:"例: 病院に行くときは保険証を持参する。提示することで3割負担になる。紛失したらすぐ会社に連絡。→ Bawa kartu asuransi setiap kali ke dokter. 忘れた場合は一旦全額負担になるが後で差額が戻る場合あり。"},// ─ Cluster F: APD詳細 (JAC 章2 安全衛生) ─
{id:1474,category:"keselamatan",source:"vocab_teori",furi:"へるめっと",jp:"ヘルメット",romaji:"herumetto",id_text:"Helm keselamatan / hard hat (飛来・落下物から頭を守る)",desc:"例: 建設現場ではヘルメット（保護帽）の着用が義務。あご紐を必ず締める。→ Helm WAJIB di semua site konstruksi — tidak hanya di area kerja aktif. Melindungi kepala dari benda jatuh. JIS T8131規格品を使用。約2年で定期交換。"},{id:1475,category:"keselamatan",source:"vocab_teori",furi:"あんぜんぐつ",jp:"安全靴",romaji:"anzengutsu",id_text:"Sepatu safety / steel-toe boots (足先を保護)",desc:"例: 安全靴は先芯（つまさき保護）入りで、重量物が落下しても足先を守る。→ Sepatu safety punya pelindung baja di ujung kaki. JIS T8101規格品を選ぶ。現場では必ず着用。スニーカーや普通の靴は不可。"},{id:1476,category:"keselamatan",source:"vocab_teori",furi:"ぼうじんますく",jp:"防じんマスク",romaji:"boujin masuku",id_text:"Masker anti-debu / dust respirator (粉じんから肺を守る)",desc:"例: コンクリート切断・はつり作業では防じんマスク（DS2以上）を着用する。→ Saat memotong beton/keramik, wajib pakai masker anti-debu. 通常のマスク（布・サージカル）では粉じん・シリカを防げない。塵肺（じんぱい）予防のために必須。"},{id:1477,category:"keselamatan",source:"vocab_teori",furi:"みみせん",jp:"耳栓",romaji:"mimisen",id_text:"Penyumbat telinga / earplugs (騒音から聴力を守る)",desc:"例: 85dB以上の騒音環境（グラインダー・チッパー使用時）では耳栓または耳覆いを着用する義務がある。→ Lingkungan >85 dB wajib pakai pelindung telinga. Paparan bising berkepanjangan → 騒音性難聴 (tuli akibat kebisingan) yang tidak bisa sembuh."},{id:1478,category:"keselamatan",source:"vocab_teori",furi:"ほごめがね",jp:"保護めがね",romaji:"hogo megane",id_text:"Kacamata pelindung / safety goggles (飛散物から目を守る)",desc:"例: 金属を切断・研磨するとき、飛散する破片から目を守るため保護めがねを着用する。→ Wajib pakai saat menggerinda/memotong logam atau beton. コンタクトレンズ使用者は特に注意 — 粒子が目の中に入ると取り出せない。"},{id:1479,category:"keselamatan",source:"vocab_teori",furi:"ついらくせいしようきぐ",jp:"墜落制止用器具",romaji:"tsuiraku seishi you kigu",id_text:"Alat penahan jatuh — nama resmi baru (2022～) pengganti 安全帯",desc:"例: 2022年から「安全帯」の正式名称は「墜落制止用器具」に変更。建設業では高さ5m以上でフルハーネス型が原則義務。→ Perubahan nama resmi 2022. Full-harness type = standar wajib. 旧名称「安全帯」もまだ現場で使われる。"},// ─ Cluster G: CCUS & キャリア (JAC 章1 建設キャリアアップ) ─
{id:1480,category:"karier",source:"vocab_teori",furi:"けんせつきゃりああっぷしすてむ",jp:"CCUS（建設キャリアアップシステム）",romaji:"kensetsu kyaria appu shisutemu",id_text:"Construction Career Up System — sistem kartu IC rekam riwayat kerja",desc:"例: CCUSカードを現場で毎日打刻すると、就業実績・資格・経験がデジタル管理される。→ Swipe kartu CCUS tiap hari merekam riwayat kerja secara digital. 外国人SSW労働者も登録が推奨（義務化進行中）。レベル評価で処遇改善につながる。"},{id:1481,category:"karier",source:"vocab_teori",furi:"ぎのうれべる",jp:"技能レベル",romaji:"ginou reberu",id_text:"Level keahlian kerja (CCUS評価 レベル1〜4)",desc:"例: CCUSでは技能レベルが4段階で評価：レベル1=見習い → レベル4=職長・班長クラス。→ Level makin tinggi, upah yang wajar makin tinggi dan kesempatan kerja makin luas. SSWは経験を積みながらレベルアップを目指す。"},// ─ Cluster H: 空調工事 (JAC 章4 設備工事) ─
{id:1482,category:"jenis_kerja",source:"vocab_jac",furi:"しつがいき",jp:"室外機",romaji:"shitsugaiki",id_text:"Unit luar AC / outdoor unit (compressor & condenser)",desc:"例: 室外機は建物の外に設置し、冷媒を圧縮して熱を外に放出する。室外機と室内機は冷媒管で接続する。→ Unit luar berisi kompresor dan kondenser. 設置場所は通気性確保が必須 — 囲ったり日光が強すぎると効率低下。"},{id:1483,category:"jenis_kerja",source:"vocab_jac",furi:"しつないき",jp:"室内機",romaji:"shitsunaiki",id_text:"Unit dalam AC / indoor unit (evaporator & fan)",desc:"例: 室内機は壁や天井に取り付け、蒸発器で冷媒が蒸発するときの吸熱作用で室内を冷やす。→ Unit dalam dipasang di dinding/plafon, mendinginkan ruangan melalui evaporasi refrigeran. ドレン配管で結露水を外部に排水する。"},{id:1484,category:"pipa",source:"vocab_jac",furi:"ふれあかこう",jp:"フレア加工",romaji:"furea kakou",id_text:"Flare processing — mengembangkan ujung pipa tembaga untuk sambungan refrigeran AC",desc:"例: 冷媒管の接続はフレア加工で行い、フレアツールで銅管の端を拡張してからフレアナットで締め付ける。→ Ujung pipa tembaga dikembangkan dengan flare tool sebelum disambung. フレア不完全 → 冷媒漏れの原因。正確な加工が品質を左右する重要工程。"},{id:1485,category:"pipa",source:"vocab_jac",furi:"どれんはいかん",jp:"ドレン配管",romaji:"doren haikan",id_text:"Pipa drain AC — mengalirkan air kondensasi dari unit dalam ke luar",desc:"例: 室内機で発生した結露水（ドレン水）はドレン配管を通じて屋外または排水管へ排水する。→ Air kondensasi dari unit dalam dialirkan ke luar lewat pipa drain. 勾配不足 → 水が逆流・水漏れ。ドレン配管は必ず下り勾配（1/100以上）で施工。"}];// ─── DATA: 30 SOAL RESMI JAC ────────────────────────────────────────────────
var JAC_OFFICIAL=[// ── SET 1: st_sample_l.pdf ─────────────────────────────────────────────
{id:"st1_q01",set:"st1",setLabel:"実技 Set 1",jp:"過大電流が流れた時に、自動的に電気の供給を止める安全装置を、何というか。",hiragana:"かだい でんりゅう が ながれた とき に、 じどうてき に でんき の きょうきゅう を とめる あんぜん そうち を、 なんと いうか。",id_text:"Ketika arus berlebih mengalir, alat keselamatan yang secara otomatis menghentikan pasokan listrik disebut apa?",options:["リレー (Relay)","コンセント (Stop kontak)","ブレーカー (Breaker / NFB)","ストリップゲージ (Strip gauge)"],answer:3,hasPhoto:false,explanation:"ブレーカー (NFB = No-Fuse Breaker) secara otomatis memutus pasokan listrik saat arus berlebih. Kartu #41.",related_card_id:41},{id:"st1_q02",set:"st1",setLabel:"実技 Set 1",jp:"写真の道具の名前はどれか。",hiragana:"しゃしん の どうぐ の なまえ は どれか。",id_text:"Apa nama alat dalam foto?",options:["ドライバー (Obeng)","ポンチ (Punch/penanda)","ファイバカッター (Pemotong serat)","電工ナイフ（でんこうナイフ）(Pisau listrik)"],answer:4,hasPhoto:true,photoDesc:"📷 Foto: Pisau lipat dengan bilah melengkung, ujung TUMPUL (bukan lancip). Ciri khas: bilah agak lebar, ujung membulat tumpul untuk melindungi konduktor.",explanation:"電工ナイフ (Pisau listrik) — bilah melengkung dengan ujung TUMPUL, khusus untuk mengupas isolasi kabel. Kartu #104.",related_card_id:104},{id:"st1_q03",set:"st1",setLabel:"実技 Set 1",jp:"写真の道具の名前はどれか。",hiragana:"しゃしん の どうぐ の なまえ は どれか。",id_text:"Apa nama alat dalam foto?",options:["パイプ万力（パイプまんりき）(Ragum pipa)","パイプカッター (Pemotong pipa)","パイプねじ切機（パイプねじきりき）(Mesin ulir pipa)","パイプレンチ (Kunci pipa)"],answer:2,hasPhoto:true,photoDesc:"📷 Foto: Alat berbentuk C/U kecil dengan roda pemotong di ujung dan pegangan hitam. Berbeda dari kunci pipa yang seperti tang besar.",explanation:"パイプカッター — memotong pipa dengan cara roda pemotong mengencang melingkar pipa. Kartu #60.",related_card_id:60},{id:"st1_q04",set:"st1",setLabel:"実技 Set 1",jp:"写真の設備の名前はどれか。",hiragana:"しゃしん の せつび の なまえ は どれか。",id_text:"Apa nama peralatan dalam foto?",options:["消火器（しょうかき）(APAR)","屋内消火栓設備（おくないしょうかせんせつび）(Hidran dalam gedung)","スプリンクラー設備（スプリンクラーせつび）(Sprinkler)","屋外消火栓設備（おくがいしょうかせんせつび）(Hidran luar gedung)"],answer:4,hasPhoto:true,photoDesc:"📷 Foto: Beberapa tiang hidran berwarna silver/perak berdiri di area luar gedung, di antara semak-semak. Terletak di LUAR ruangan.",explanation:"屋外消火栓設備 — hidran di LUAR gedung, untuk pemadaman awal & mencegah api menyebar (jangkauan lantai 1-2). Kartu #74.",related_card_id:74},{id:"st1_q05",set:"st1",setLabel:"実技 Set 1",jp:"写真の道具の名前はどれか。",hiragana:"しゃしん の どうぐ の なまえ は どれか。",id_text:"Apa nama alat dalam foto?",options:["墨さし（すみさし）(Kuas tinta)","チョーク (Kapur)","墨つぼ（すみつぼ）(Wadah tinta/chalk line reel)","レーザー墨出し器（レーザーすみだしき）(Laser marker)"],answer:3,hasPhoto:true,photoDesc:"📷 Foto: Alat kecil berbentuk drum/gulungan dengan cangkang logam gelap dan pengait benang. Ada tombol/roda di badan untuk menggulung benang.",explanation:"墨つぼ — membuat garis lurus panjang dengan benang bercelup tinta. Kartu #106.",related_card_id:106},{id:"st1_q06",set:"st1",setLabel:"実技 Set 1",jp:"写真の道具の名前はどれか。",hiragana:"しゃしん の どうぐ の なまえ は どれか。",id_text:"Apa nama alat dalam foto?",options:["三脚（さんきゃく）(Tripod)","気泡管（きほうかん）(Tabung gelembung)","望遠鏡（ぼうえんきょう）(Teleskop)","レベル (Level/waterpas survei)"],answer:4,hasPhoto:true,photoDesc:"📷 Foto: Instrumen survei putih/abu dengan teleskop horizontal, dipasang di atas tripod kayu di lingkungan hutan/outdoor. Bukan transit (yang mengukur sudut vertikal).",explanation:"レベル (水準器) — instrumen survei untuk mengukur ketinggian/elevasi, dipasang di tripod. Kartu #94.",related_card_id:94},{id:"st1_q07",set:"st1",setLabel:"実技 Set 1",jp:"施工管理とは、施工計画に基づいて、施工者が、所定の（　）の工事目的物を完成させるために必要な管理のことである。",hiragana:"いかの ぶんしょうの （ ）に はいる ことばを えらびなさい。せこう かんり とは、 せこう けいかく に もとづいて、 せこうしゃが、 しょてい の （ ）の こうじ もくてきぶつ を かんせい させる ために ひつよう な かんり の ことで ある。",id_text:"Manajemen konstruksi adalah manajemen yang diperlukan untuk menyelesaikan objek pekerjaan dengan ( ) yang telah ditentukan berdasarkan rencana konstruksi.",options:["環境（かんきょう）(Lingkungan)","品質（ひんしつ）(Kualitas)"],answer:2,hasPhoto:false,explanation:"施工管理 bertujuan menyelesaikan pekerjaan dengan KUALITAS (品質) yang ditentukan — bukan 'lingkungan'. Kartu #153.",related_card_id:153},{id:"st1_q08",set:"st1",setLabel:"実技 Set 1",jp:"配管用炭素鋼鋼管の代表的な接合方法である、ねじ接合方法は、主に（　）に採用されている。",hiragana:"いかの ぶんしょうの （ ）に はいる ことばを えらびなさい。はいかんよう たんそこう こうかんの だいひょう てきな せつごう ほうほう である ねじ せつごう ほうほう は、おもに（ ）に さいよう されている。",id_text:"Metode sambungan ulir (ねじ接合) pada pipa baja karbon untuk pemipaan (SGP) terutama digunakan pada ( ).",options:["100A以上（100Aいじょう）(100A ke atas)","15A～100A","15A以下（15Aいか）(15A ke bawah)"],answer:2,hasPhoto:false,explanation:"SGP ねじ接合 digunakan untuk ukuran 15A～100A. Di atas 100A → flensa/las. Kartu #114.",related_card_id:114},{id:"st1_q09",set:"st1",setLabel:"実技 Set 1",jp:"2本以上の電線が、負荷を通さないで接触してしまうことを、何というか。",hiragana:"2ほん いじょう の でんせん が、 ふか を とおさない で せっしょく して しまう こと を、 なんと いうか。",id_text:"Kondisi di mana 2 kabel atau lebih bersentuhan TANPA melalui beban (load) disebut apa?",options:["短絡（たんらく）(Short circuit)","漏電（ろうでん）(Arus bocor)","感電（かんでん）(Sengatan listrik)"],answer:1,hasPhoto:false,explanation:"短絡 (tanraku) = short circuit. Berbeda: 漏電 = kebocoran arus ke ground, 感電 = listrik mengalir ke tubuh manusia. Kartu #103.",related_card_id:103},{id:"st1_q10",set:"st1",setLabel:"実技 Set 1",jp:"青い矢印が指し示す設備の名前はどれか。",hiragana:"あおい やじるし が さし しめす せつび の なまえ は どれか。",id_text:"Apa nama peralatan yang ditunjukkan oleh panah biru? [Diagram jaringan telekomunikasi: gedung komunikasi → tiang → kabel bawah tanah → rumah]",options:["通信ケーブル（つうしんケーブル）(Kabel komunikasi)","管路（かんろ）(Jalur kabel bawah tanah)","電柱（でんちゅう）(Tiang listrik/telepon)","マンホール (Manhole)"],answer:3,hasPhoto:true,photoDesc:"📷 Diagram: Jaringan telekomunikasi dari gedung komunikasi ke rumah. Panah biru menunjuk ke TIANG yang berdiri di atas tanah, di antara gedung dan rumah.",explanation:"電柱 (denchu) = tiang listrik/telepon. Berbeda dari 管路 (jalur bawah tanah) dan マンホール. Kartu #113.",related_card_id:113},{id:"st1_q11",set:"st1",setLabel:"実技 Set 1",jp:"築炉とは、電気炉など、高温になる内側を、（　）で構築する工事のことである。",hiragana:"いかの ぶんしょうの （ ）に はいる ことばを えらびなさい。ちくろ とは、でんき ろ など、こうおん になる うちがわを、（ ）で こうちく する こうじ の こと である。",id_text:"築炉 adalah pekerjaan membangun bagian dalam yang menjadi suhu tinggi (seperti tungku listrik) menggunakan ( ).",options:["保温材（ほおんざい）(Bahan isolasi panas)","保冷材（ほれいざい）(Bahan isolasi dingin)","耐火物（たいかぶつ）(Bahan tahan api)","断熱材（だんねつざい）(Bahan insulasi)"],answer:3,hasPhoto:false,explanation:"築炉 = konstruksi tungku menggunakan BAHAN TAHAN API (耐火物). BUKAN 保温材 atau 断熱材 biasa. Perekat: 耐熱断熱煉瓦用モルタル. Kartu #124.",related_card_id:124},{id:"st1_q12",set:"st1",setLabel:"実技 Set 1",jp:"建設業における三大災害のなかで、最も多いのは、どれか。",hiragana:"けんせつぎょう における さん だいさいがい の なか で、 もっとも おおい の は、 どれか。",id_text:"Di antara tiga bencana besar konstruksi (三大災害), mana yang paling banyak terjadi?",options:["墜落・転落（ついらく・てんらく）(Jatuh dari ketinggian / bergulir)","建設機械・クレーンなど災害（けんせつきかい・クレーンなどさいがい）(Kecelakaan mesin/crane)","高温・低温の物との接触（こうおん・ていおんのものとのせっしょく）(Kontak benda suhu ekstrem)"],answer:1,hasPhoto:false,explanation:"墜落・転落 (jatuh) adalah penyebab kematian TERBANYAK. 2021: 110 dari 288 total kematian. Opsi 3 BUKAN bagian dari 三大災害 (③ sebenarnya adalah 崩壊・倒壊). Kartu #127.",related_card_id:127},{id:"st1_q13",set:"st1",setLabel:"実技 Set 1",jp:"人の体の中を電気が通って、強いショックを受けることを、何というか。",hiragana:"ひと の からだ の なか を でんき が かよって、 つよい しょっく を うける こと を、 なんと いうか。",id_text:"Kondisi di mana listrik mengalir melalui tubuh manusia dan menerima kejutan kuat disebut apa?",options:["停電（ていでん）(Pemadaman listrik)","火傷（やけど）(Luka bakar)","感電（かんでん）(Sengatan listrik)"],answer:3,hasPhoto:false,explanation:"感電 (kanden) = sengatan listrik. Listrik mengalir melalui tubuh → kejutan kuat. Kecelakaan khas pekerjaan listrik. Kartu #81.",related_card_id:81},{id:"st1_q14",set:"st1",setLabel:"実技 Set 1",jp:"酸素欠乏に注意するべき作業は、どれか。",hiragana:"さんそ けつぼう に ちゅうい するべき さぎょう は、 どれか。",id_text:"Pekerjaan apa yang perlu memperhatikan kekurangan oksigen (酸素欠乏)?",options:["マンホール内での作業（マンホールないでのさぎょう）(Di dalam manhole)","電柱の上での作業（でんちゅうのうえでのさぎょう）(Di atas tiang listrik)","建物屋上での作業（たてものおくじょうでのさぎょう）(Di atap gedung)"],answer:1,hasPhoto:false,explanation:"酸素欠乏 terjadi di ruang TERTUTUP seperti MANHOLE. Kerja di atas tiang atau atap gedung = tidak ada risiko kekurangan oksigen. Kartu #107.",related_card_id:107},{id:"st1_q15",set:"st1",setLabel:"実技 Set 1",jp:"掘削の深さが1.5ｍ以上になる場合、土砂崩れを防ぐため行うことは、どれか。",hiragana:"くっさく の ふかさ が 1.5ｍ いじょう に なる ばあい、 どしゃくずれ を ふせぐ ため おこなう こと は、 どれか。",id_text:"Jika kedalaman galian mencapai 1.5m atau lebih, apa yang dilakukan untuk mencegah longsor tanah?",options:["換気（かんき）(Ventilasi)","排水（はいすい）(Drainase)","土留め（どどめ）(Penahan tanah)"],answer:3,hasPhoto:false,explanation:"土留め (dodome) WAJIB jika kedalaman galian ≥1.5m. Angka 1.5m harus dihafalkan. Kartu #108.",related_card_id:108},// ── SET 2: st_sample2_l.pdf ────────────────────────────────────────────
{id:"st2_q01",set:"st2",setLabel:"実技 Set 2",jp:"光ファイバーの特徴を選べ。",hiragana:"ひかりふぁいばー の とくちょう を えらべ。",id_text:"Pilih ciri-ciri serat optik.",options:["損失が小さい（そんしつがちいさい）(Rugi-rugi kecil)","重い（おもい）(Berat)","傷に強い（きずにつよい）(Tahan goresan)","伝送容量が小さい（でんそうようりょうがちいさい）(Kapasitas transmisi kecil)"],answer:1,hasPhoto:false,explanation:"Serat optik: 損失が小さい (rugi kecil) ✓, ringan ✓, kapasitas BESAR ✓. Kelemahannya: rentan goresan & tekukan. Kartu #45.",related_card_id:45},{id:"st2_q02",set:"st2",setLabel:"実技 Set 2",jp:"光ファイバー芯線の線路長や、接続による損失、反射などの異常箇所を測定することができる装置を何というか。",hiragana:"ひかりふぁいばー しんせん の せんろちょう や、 せつぞく による そんしつ、 はんしゃ など の いじょう かしょ を そくてい する こと が できる そうち を なんと いうか。",id_text:"Alat yang dapat mengukur panjang jalur serat optik, kerugian akibat sambungan, dan mendeteksi titik abnormal seperti pantulan disebut apa?",options:["ファイバーカッター (Pemotong serat)","OTDR","光パワーメーター（ひかりパワーメーター）(Pengukur daya optik)","クランプメーター (Clamp meter)"],answer:2,hasPhoto:false,explanation:"OTDR (Optical Time Domain Reflectometer) = mengukur panjang jalur & titik abnormal serat optik. 光パワーメーター hanya mengukur daya/kekuatan sinyal. Kartu #51.",related_card_id:51},{id:"st2_q03",set:"st2",setLabel:"実技 Set 2",jp:"光ファイバーの先端部を溶かして、接続する方法を何というか。",hiragana:"ひかりふぁいばー の せんたんぶ を とかして、 せつぞく する ほうほう を なんと いうか。",id_text:"Metode penyambungan serat optik dengan cara MELELEHKAN ujung serat disebut apa?",options:["コネクタ接続（コネクタせつぞく）(Sambungan konektor)","はんだあげ (Soldering)","融着接続（ゆうちゃくせつぞく）(Fusion splicing)","メカニカルスプライス接続（メカニカルスプライスせつぞく）(Mechanical splice)"],answer:3,hasPhoto:false,explanation:"融着接続 = melelehkan/memfusikan ujung serat → sambungan permanen, rugi terkecil. Kata kunci: 'MELELEHKAN ujung serat'. Kartu #109.",related_card_id:109},{id:"st2_q04",set:"st2",setLabel:"実技 Set 2",jp:"主に冷凍空気調和機器工事で使う乾いた空気に水分を加える機器は、次のどれか。",hiragana:"おも に れいとう くうき ちょうわ きき こうじ で つかう かわいた くうき に すいぶん を くわえる きき は、 つぎ の どれか。",id_text:"Alat yang digunakan terutama dalam pekerjaan mesin pendingin AC, yang MENAMBAHKAN kelembapan ke udara kering, adalah yang mana?",options:["除湿器（じょしつき）(Penyerap kelembapan)","冷却コイル（れいきゃくコイル）(Koil pendingin)","けい酸カルシウム保温材（けいさんカルシウムほおんざい）(Isolasi kalsium silikat)","加湿器（かしつき）(Pelembap udara)"],answer:4,hasPhoto:false,explanation:"加湿器 = MENAMBAH kelembapan ke udara kering. 除湿器 = mengurangi kelembapan. Kata kunci: 'menambah air ke udara kering'. Kartu #115.",related_card_id:115},{id:"st2_q05",set:"st2",setLabel:"実技 Set 2",jp:"主に保温保冷工事で使うガラスを溶かし、繊維状にした保温材は、次のどれか。",hiragana:"おも に ほおんほれいこうじ で つかう がらす を とかし、 せんいじょう に した ほおんざい は、 つぎ の どれか。",id_text:"Bahan isolasi yang digunakan terutama dalam pekerjaan isolasi termal, dibuat dengan MELELEHKAN KACA menjadi bentuk serat, adalah yang mana?",options:["グラスウール保温材（グラスウールほおんざい）(Wol kaca)","ロックウール保温材（ロックウールほおんざい）(Wol batu)","ポリスチレンフォーム保温材（ポリスチレンフォームほおんざい）(Busa polistiren)","けい酸カルシウム保温材（けいさんカルシウムほおんざい）(Kalsium silikat)"],answer:1,hasPhoto:false,explanation:"グラスウール = dari KACA dilebur menjadi serat. ロックウール = dari BATU BASALT. Kata kunci: 'kaca dilelehkan jadi serat'. Kartu #111.",related_card_id:111},{id:"st2_q06",set:"st2",setLabel:"実技 Set 2",jp:"写真の道具の名前は、次のどれか。",hiragana:"しゃしん の どうぐ の なまえ は、 つぎ の どれか。",id_text:"Apa nama alat dalam foto?",options:["一輪車（いちりんしゃ）(Gerobak satu roda)","台車（だいしゃ）(Kereta dorong datar)","そり (Sledge)","ころ (Roller)"],answer:2,hasPhoto:true,photoDesc:"📷 Foto: Kereta dorong datar berbentuk platform persegi panjang rendah dengan 4 roda kecil dan pegangan lipat/condong. Dilihat dari atas/sudut.",explanation:"台車 (daisha) = kereta dorong datar 4 roda untuk mengangkut material berat. Berbeda dari 一輪車 (gerobak satu roda). Kartu #342 (id di alat_umum).",related_card_id:342},{id:"st2_q07",set:"st2",setLabel:"実技 Set 2",jp:"配管の保温保冷の屋外露出箇所では、保温筒を（　）で覆い仕上げます。",hiragana:"いか の ぶんしょう の （ ） に はいる ことば を えらびなさい。はいかん の ほおんほれい の おくがい ろしゅつ かしょ では、 ほおん とう を （ ） で おおい しあげます。",id_text:"Pada bagian pipa isolasi yang terekspos di LUAR RUANGAN, tabung insulasi (保温筒) ditutup menggunakan ( ).",options:["ラッキングカバー (Lagging cover)","マグパイプカバー (Mag pipe cover)"],answer:1,hasPhoto:false,explanation:"ラッキングカバー = penutup finishing untuk isolasi pipa LUAR RUANGAN (屋外露出). Untuk dalam ruangan tidak wajib. Kartu #112.",related_card_id:112},{id:"st2_q08",set:"st2",setLabel:"実技 Set 2",jp:"上水道やガス配管で使うポリエチレン管の接合は、次のどれか。",hiragana:"じょうすいどう や がすはいかん で つかう ぽりえちれんかん の せつごう は、 つぎ の どれか。",id_text:"Sambungan pipa polietilen yang digunakan untuk pipa air bersih dan pipa gas adalah yang mana?",options:["ねじ接合（ねじせつごう）(Sambungan ulir)","ＥＦ接合（ＥＦせつごう）(EF / Electro Fusion)"],answer:2,hasPhoto:false,explanation:"Pipa polietilen (polyethylene) → EF接合 (Electro Fusion). SGP (baja) → ねじ接合 (sambungan ulir). Kartu #110.",related_card_id:110},{id:"st2_q09",set:"st2",setLabel:"実技 Set 2",jp:"建築板金の丸ダクトの接続方法は、次のどれか。",hiragana:"けんちくばんきん の まるだくと の せつぞくほうほう は、 つぎ の どれか。",id_text:"Metode sambungan saluran udara bulat (丸ダクト) dalam pekerjaan pelat bangunan adalah yang mana?",options:["差し込み継手工法（さしこみつぎてこうほう）(Insert joint method)","共板フランジ工法（きょうばんフランジこうほう）(Common plate flange method)"],answer:1,hasPhoto:false,explanation:"丸ダクト (round duct) → 差し込み継手工法 (selip/insert). 角ダクト (square duct) → 共板フランジ工法. Kartu #126.",related_card_id:126},{id:"st2_q10",set:"st2",setLabel:"実技 Set 2",jp:"電柱を建てる穴を掘る前に、（　）や探針棒をつかって埋設物を確認します。",hiragana:"いか の ぶんしょう の （ ） に はいる ことば を えらびなさい。でんちゅう を たてる あな を ほる まえ に、 （ ） や たんしん ぼう を つかって まいせつぶつ を かくにん します。",id_text:"Sebelum menggali lubang untuk mendirikan tiang listrik, ( ) dan batang probe (探針棒) digunakan untuk mengkonfirmasi benda terpendam (埋設物).",options:["穴掘建柱車（あなほりけんちゅうしゃ）(Kendaraan penggali & pendiri tiang)","手掘り（てぼり）(Penggalian manual)"],answer:2,hasPhoto:false,explanation:"手掘り (gali manual) + 探針棒 (batang probe) digunakan BERSAMA untuk memeriksa benda terpendam secara hati-hati sebelum menggali dengan mesin. 穴掘建柱車 = kendaraan untuk menggali & mendirikan tiang. Kartu #154.",related_card_id:154},{id:"st2_q11",set:"st2",setLabel:"実技 Set 2",jp:"マンホール、ハンドホール、とう道、引上柱の間を結ぶ設備を何というか。",hiragana:"まんほーる、 はんど ほーる、 とうどう、 ひきあげちゅう の あいだ を むすぶ せつび を なんと いうか。",id_text:"Peralatan yang menghubungkan antara manhole, handhole, terowongan (とう道), dan tiang pengangkat (引上柱) disebut apa?",options:["管路（かんろ）(Jalur kabel bawah tanah)","共同溝（きょうどうこう）(Terowongan utilitas bersama)"],answer:1,hasPhoto:false,explanation:"管路 (kanro) = infrastruktur yang menghubungkan manhole - handhole - とう道 - 引上柱. Berbeda dari 共同溝 yang merupakan terowongan utilitas besar. Kartu #113.",related_card_id:113},{id:"st2_q12",set:"st2",setLabel:"実技 Set 2",jp:"管路の土被りは、車道では何メートルを超えなければならないか。",hiragana:"かんろ の どかぶり は、 しゃどう で は なんめーとる を こえなければ ならないか。",id_text:"Kedalaman tanah (土被り) jalur kabel (管路) di jalan raya harus melebihi berapa meter?",options:["0.6ｍ","0.8ｍ"],answer:2,hasPhoto:false,explanation:"管路 di jalan raya (車道) → kedalaman tanah harus >0.8m. Angka ini wajib dihafalkan. Kartu #113.",related_card_id:113},{id:"st2_q13",set:"st2",setLabel:"実技 Set 2",jp:"築炉工事での耐火煉瓦の接着に使うものは、次のどれか。",hiragana:"ちくろこうじ での たいかれんが の せっちゃく に つかう もの は、 つぎ の どれか。",id_text:"Bahan yang digunakan untuk merekatkan bata tahan api dalam pekerjaan築炉 adalah yang mana?",options:["耐熱断熱煉瓦用モルタル（たいねつだんねつれんがようモルタル）(Mortar khusus bata tahan api)","樹脂モルタル（じゅしモルタル）(Mortar resin)"],answer:1,hasPhoto:false,explanation:"Perekat bata tahan api di konstruksi tungku = 耐熱断熱煉瓦用モルタル (mortar khusus tahan panas untuk bata tahan api). BUKAN mortar resin biasa. Kartu #124.",related_card_id:124},{id:"st2_q14",set:"st2",setLabel:"実技 Set 2",jp:"事業者が新しく労働者を雇い入れた時に行う安全教育を何というか。",hiragana:"じぎょうしゃ が あたらしく ろうどうしゃ を やといいれた とき に おこなう あんぜん きょういく を なんと いうか。",id_text:"Pendidikan keselamatan yang dilakukan ketika pengusaha MEREKRUT PEKERJA BARU disebut apa?",options:["新規入場者教育（しんきにゅうじょうしゃきょういく）(Pendidikan pekerja baru lokasi kerja)","安全パトロール（あんぜんパトロール）(Patroli keselamatan)","新入者安全衛生教育（しんにゅうしゃあんぜんえいせいきょういく）(Pendidikan K3 pekerja baru perusahaan)"],answer:3,hasPhoto:false,explanation:"新入者安全衛生教育 = untuk PEREKRUTAN BARU oleh perusahaan. 新規入場者教育 = untuk PENDATANG BARU ke lokasi kerja (bisa sudah lama bekerja di perusahaan). Kartu #119.",related_card_id:119},{id:"st2_q15",set:"st2",setLabel:"実技 Set 2",jp:"疲労がたまると事故につながるので、（　）を心がける。",hiragana:"いか の ぶんしょう の （ ） に はいる ことば を えらびなさい。ひろう が たまると じこ に つながるので、 （ ） を こころがける。",id_text:"Karena kelelahan yang menumpuk bisa menyebabkan kecelakaan, yang perlu diperhatikan adalah ( ).",options:["適切な睡眠と食事をとること（てきせつなすいみんとしょくじをとること）(Tidur & makan yang cukup)","お酒を飲んで作業すること（おさけをのんでさぎょうすること）(Bekerja sambil minum alkohol)","前日に徹夜すること（ぜんじつにてつやすること）(Begadang sehari sebelumnya)"],answer:1,hasPhoto:false,explanation:"Pencegahan kelelahan → 適切な睡眠と食事 (tidur & makan yang cukup). Kelelahan = penyebab kecelakaan. Kartu #155.",related_card_id:155},// ── SET tt1: tt_sample.pdf — 学科 Set 1 (29 soal) ─────────────────────────
{id:"tt1_q01",set:"tt1",setLabel:"学科 Set 1",jp:"流れよく工事を進めるには、専門工事業者間の（　）が大切である。",hiragana:"ながれよく こうじ を すすめる には、 せんもん こうじ ぎょうしゃ かん の （ ） が たいせつ である。",id_text:"Untuk memajukan pekerjaan dengan lancar, ( ) antar kontraktor spesialis sangat penting.",options:["興味を持たないこと（きょうみをもたないこと）(Tidak peduli)","チームワーク (Kerja tim / Teamwork)"],answer:2,hasPhoto:false,explanation:"Kerjasama antar kontraktor spesialis = チームワーク. Tanpa teamwork, alur konstruksi kacau.",related_card_id:764},{id:"tt1_q02",set:"tt1",setLabel:"学科 Set 1",jp:"一般的には、朝礼の最後に、２人１組となって、声を出しながら、（　）を行う。",hiragana:"いっぱんてき には、 ちょうれい の さいご に、 ふたりひとくみ と なって、 こえ を だしながら、 （ ） を おこなう。",id_text:"Pada umumnya, di akhir apel pagi, berpasangan dua orang, sambil bersuara, melakukan ( ).",options:["あいさつ (Salam)","体操（たいそう）(Senam)","安全確認（あんぜんかくにん）(Konfirmasi keselamatan)"],answer:3,hasPhoto:false,explanation:"Di akhir apel pagi, berpasangan → 安全確認 (konfirmasi keselamatan) sambil bersuara keras. Ini adalah 指差し呼称.",related_card_id:7},{id:"tt1_q03",set:"tt1",setLabel:"学科 Set 1",jp:"職場内での優位性を利用して、業務の適正な範囲を超えて、精神・肉体に苦痛を与える、または職場環境を悪化させる行為は、何と呼ばれるか。",hiragana:"しょくばない で の ゆういせい を りよう して、 ぎょうむ の てきせい な はんい を こえて、 せいしん・にくたい に くつう を あたえる、 または しょくば かんきょう を あっか させる こうい は、 なに と よばれる か。",id_text:"Tindakan yang menggunakan superioritas di tempat kerja untuk menyebabkan penderitaan fisik/mental melebihi batas wajar disebut apa?",options:["パワー・ハラスメント (Power Harassment)","セクシャル・ハラスメント (Sexual Harassment)","アルコール・ハラスメント (Alcohol Harassment)"],answer:1,hasPhoto:false,explanation:"パワハラ = pelecehan berbasis kekuasaan jabatan. セクハラ = pelecehan seksual. Kata kunci: 'superioritas jabatan + penderitaan fisik/mental'.",related_card_id:102},{id:"tt1_q04",set:"tt1",setLabel:"学科 Set 1",jp:"法定労働時間では、働く時間は1日何時間までか。",hiragana:"ほうてい ろうどう じかん で は、 はたらく じかん は 1 にち なんじかん まで か。",id_text:"Berdasarkan jam kerja yang ditetapkan undang-undang, batas jam kerja per hari adalah berapa jam?",options:["6時間（6じかん）(6 jam)","8時間（8じかん）(8 jam)","12時間（12じかん）(12 jam)"],answer:2,hasPhoto:false,explanation:"Batas jam kerja legal = 8 jam/hari & 40 jam/minggu (UU Standar Ketenagakerjaan). Kartu #9.",related_card_id:9},{id:"tt1_q05",set:"tt1",setLabel:"学科 Set 1",jp:"建築基準法では、安全で安心な生活を送れるようにするため、建物の建築や利用についての（　）ルールを定めています。",hiragana:"けんちく きじゅんほう で は、 あんぜん で あんしん な せいかつ を おくれる よう に する ため、 たてもの の けんちく や りよう について の （ ） るーる を さだめて います。",id_text:"UU Standar Bangunan menetapkan aturan ( ) untuk konstruksi dan penggunaan bangunan demi kehidupan yang aman.",options:["安全が保証される（あんぜんがほしょうされる）(Yang menjamin keamanan)","最低限の（さいていげんの）(Minimum)","必要以上の（ひつよういじょうの）(Lebih dari yang diperlukan)"],answer:2,hasPhoto:false,explanation:"建築基準法 = menetapkan standar MINIMUM (最低限の) untuk bangunan. Bukan jaminan mutlak, bukan berlebihan. Kartu #13.",related_card_id:13},{id:"tt1_q06",set:"tt1",setLabel:"学科 Set 1",jp:"消防法の目的には、火災または地震等の災害による被害を（　）することがあります。",hiragana:"しょうぼうほう の もくてき には、 かさい または じしん とう の さいがい による ひがい を （ ） する ことが あります。",id_text:"Salah satu tujuan UU Pemadam Kebakaran adalah ( ) kerugian akibat kebakaran atau bencana seperti gempa.",options:["増加（ぞうか）(Meningkatkan)","軽減（けいげん）(Mengurangi / Meringankan)"],answer:2,hasPhoto:false,explanation:"Tujuan 消防法 = MENGURANGI (軽減) kerugian bencana. Bukan meningkatkan! Kartu #14.",related_card_id:14},{id:"tt1_q07",set:"tt1",setLabel:"学科 Set 1",jp:"水道法が目指すものはどれか。",hiragana:"すいどうほうが めざすものは どれか。",id_text:"Apa yang menjadi tujuan UU Air Bersih (水道法)?",options:["安価な水を供給する（あんかなみずをきょうきゅうする）(Menyuplai air yang terjangkau)","高価な水を供給する（こうかなみずをきょうきゅうする）(Menyuplai air yang mahal)","不浄な水を供給する（ふじょうなみずをきょうきゅうする）(Menyuplai air yang kotor)"],answer:1,hasPhoto:false,explanation:"水道法 = bertujuan menyuplai air bersih yang terjangkau (安価). Bukan air mahal, bukan air kotor. Kartu #15.",related_card_id:15},{id:"tt1_q08",set:"tt1",setLabel:"学科 Set 1",jp:"電気設備の工事や保安について定めている法律は何か。",hiragana:"でんき せつび の こうじ や ほあん について さだめて いる ほうりつ は なに か。",id_text:"UU apa yang mengatur konstruksi dan keamanan fasilitas kelistrikan?",options:["ガス事業法（ガスじぎょうほう）(UU Usaha Gas)","電気通信事業法（でんきつうしんじぎょうほう）(UU Usaha Telekomunikasi)","電波法（でんぱほう）(UU Gelombang Radio)","電気事業法（でんきじぎょうほう）(UU Usaha Kelistrikan)"],answer:4,hasPhoto:false,explanation:"電気事業法 = mengatur konstruksi, pemeliharaan, & keamanan fasilitas listrik. Jangan bingung dengan 電気工事業法 (UU kontraktor listrik). Kartu #16.",related_card_id:16},{id:"tt1_q09",set:"tt1",setLabel:"学科 Set 1",jp:"建築工事はどれか。",hiragana:"けんちくこうじは どれか。",id_text:"Yang mana yang termasuk pekerjaan bangunan (建築工事)?",options:["住宅を作る工事（じゅうたくをつくるこうじ）(Membangun rumah)","道路を作る工事（どうろをつくるこうじ）(Membangun jalan)","ダムを作る工事（ダムをつくるこうじ）(Membangun bendungan)"],answer:1,hasPhoto:false,explanation:"建築工事 = membangun gedung/rumah. Jalan & bendungan = 土木工事 (sipil). Perbedaan kunci: 建築 = struktur bangunan, 土木 = infrastruktur.",related_card_id:641},{id:"tt1_q10",set:"tt1",setLabel:"学科 Set 1",jp:"写真の装置は、次のうちどれか。",hiragana:"しゃしんの そうちは、 つぎのうち どれか。",id_text:"Perangkat dalam foto adalah yang mana?",options:["防水装置（ぼうすいそうち）(Alat kedap air)","免振装置（めんしんそうち）(Alat isolasi seismik)","空調装置（くうちょうそうち）(Alat AC)"],answer:2,hasPhoto:true,photoDesc:"📸 FOTO: Perangkat berbentuk silinder/bantalan karet tebal di bawah struktur bangunan — ini adalah 免振装置 (seismic isolator), sistem isolasi gempa yang memisahkan bangunan dari gerakan tanah.",explanation:"免振装置 = seismic isolator — bantalan karet + baja berlapis di fondasi bangunan untuk meredam getaran gempa. Berbeda dari 制振 (damper) dan 耐震 (tahan gempa kaku).",related_card_id:200},{id:"tt1_q11",set:"tt1",setLabel:"学科 Set 1",jp:"電気・ガス・水道・電話・インターネットなどに関わる工事を何というか。",hiragana:"でんき・がす・すいどう・でんわ・いんたーねっと など に かかわる こうじ を なに と いう か。",id_text:"Pekerjaan yang berkaitan dengan listrik, gas, air, telepon, internet disebut apa?",options:["ライフライン工事（ライフラインこうじ）(Pekerjaan lifeline)","建築工事（けんちくこうじ）(Pekerjaan bangunan)","土木工事（どぼくこうじ）(Pekerjaan sipil)"],answer:1,hasPhoto:false,explanation:"ライフライン工事 = pekerjaan jaringan utilitas vital: listrik, gas kota, air, telekomunikasi. Kartu #21.",related_card_id:21},{id:"tt1_q12",set:"tt1",setLabel:"学科 Set 1",jp:"地面を掘って、井戸を作る工事を（　）と言います。",hiragana:"じめん を ほって、 いど を つくる こうじ を （ ） と いいます。",id_text:"Pekerjaan menggali tanah untuk membuat sumur disebut ( ).",options:["掘削工事（くっさくこうじ）(Pekerjaan penggalian)","トンネル工事（トンネルこうじ）(Pekerjaan terowongan)","さく井工事（さくいこうじ）(Pekerjaan pengeboran sumur)","穴掘工事（あなほりこうじ）(Pekerjaan gali lubang)"],answer:3,hasPhoto:false,explanation:"さく井工事 = pengeboran sumur air secara vertikal. Bukan 掘削 (galian umum) atau 穴掘 (galian biasa). Kata kunci: 'menggali SUMUR' (井戸).",related_card_id:205},{id:"tt1_q13",set:"tt1",setLabel:"学科 Set 1",jp:"既成杭工法とは、次のうちどれか。",hiragana:"きせいくいこうほう とは、 つぎ の うち どれか。",id_text:"Metode tiang pancang precast (既成杭工法) adalah yang mana?",options:["工場で製作した杭を、現場に運んで打ち込む工法（こうじょうでせいさくしたくいを、げんばにはこんでうちこむこうほう）(Tiang dibuat di pabrik, dibawa & dipancang di lapangan)","工事現場で杭を作る工法（こうじげんばでくいをつくるこうほう）(Tiang dibuat di lokasi proyek)","既に使用された杭を再利用する工法（すでにしようされたくいをさいりようするこうほう）(Tiang bekas digunakan kembali)","穴の中に生コンクリートを入れて杭を造る工法（あなのなかになまコンクリートをいれてくいをつくるこうほう）(Beton segar dituang ke lubang untuk membuat tiang)"],answer:1,hasPhoto:false,explanation:"既成杭 = precast pile: dibuat di pabrik → dibawa ke lapangan → dipancang. Lawannya: 場所打ち杭 = beton cor di tempat (opsi 4). Pasangan jebakan klasik!",related_card_id:332},{id:"tt1_q14",set:"tt1",setLabel:"学科 Set 1",jp:"柱や梁などの建物の骨組みを、鉄骨を使って組み立てる工事を、何というか。",hiragana:"はしら や はり など の たてもの の ほねぐみ を、 てっこつ を つかって くみたてる こうじ を、 なんと いうか。",id_text:"Pekerjaan memasang rangka bangunan (kolom, balok, dll) menggunakan baja struktural disebut apa?",options:["鉄筋工事（てっきんこうじ）(Pekerjaan pembesian)","型枠工事（かたわくこうじ）(Pekerjaan bekisting)","鉄筋継手工事（てっきんつぎてこうじ）(Pekerjaan sambungan tulangan)","鉄骨工事（てっこつこうじ）(Pekerjaan struktur baja)"],answer:4,hasPhoto:false,explanation:"鉄骨工事 = pekerjaan struktur baja (kolom+balok baja). 鉄筋工事 = pekerjaan tulangan beton. Jangan tukar: 骨 (kerangka/baja) vs 筋 (tulangan/rebar).",related_card_id:765},{id:"tt1_q15",set:"tt1",setLabel:"学科 Set 1",jp:"鉄筋の周りにコンクリートを流しこむための枠を作る工事は次のうちどれか。",hiragana:"てっきんの まわりに こんくりーとを ながしこむための わくを つくる こうじは つぎのうちどれか。",id_text:"Pekerjaan membuat cetakan/bekisting untuk mengecor beton di sekitar tulangan adalah yang mana?",options:["鉄筋工事（てっきんこうじ）(Pembesian)","鉄筋継手工事（てっきんつぎてこうじ）(Sambungan tulangan)","型枠工事（かたわくこうじ）(Bekisting/formwork)","窓枠工事（まどわくこうじ）(Pemasangan kusen jendela)"],answer:3,hasPhoto:false,explanation:"型枠工事 = membuat cetakan (formwork/bekisting) agar beton mengeras dalam bentuk yang diinginkan. 鉄筋工事 = pasang tulangan baja saja.",related_card_id:210},{id:"tt1_q16",set:"tt1",setLabel:"学科 Set 1",jp:"写真はどのような工事を行っているか。",hiragana:"しゃしんは どのような こうじを おこなっているか。",id_text:"Foto menunjukkan pekerjaan apa yang sedang dilakukan?",options:["コンクリート打設工事（コンクリートだせつこうじ）(Pengecoran beton)","機械土工事（きかいどこうじ）(Pekerjaan tanah mekanis)","サッシ工事（サッシこうじ）(Pemasangan kusen aluminium)","屋根工事（やねこうじ）(Pekerjaan atap)"],answer:1,hasPhoto:true,photoDesc:"📸 FOTO: Beberapa pekerja berhelm merah & putih di atap bangunan mendatar, menggunakan selang besar & alat perata — ini adalah コンクリート打設工事 (pengecoran beton). Terlihat beton segar dituang & diratakan.",explanation:"コンクリート打設工事 = pengecoran beton. Ciri: selang pompa beton, alat pemadat (vibrator), permukaan datar yang sedang diisi beton.",related_card_id:766},{id:"tt1_q17",set:"tt1",setLabel:"学科 Set 1",jp:"電気工事を行うために必要な資格を選びなさい。",hiragana:"でんき こうじ を おこなう ため に ひつよう な しかく を えらびなさい。",id_text:"Pilih kualifikasi yang diperlukan untuk melakukan pekerjaan listrik.",options:["電気工事士（でんきこうじし）(Teknisi pekerjaan listrik)","工事担任者（こうじたんにんしゃ）(Penanggung jawab pekerjaan telekomunikasi)","電気通信主任技術者（でんきつうしんしゅにんぎじゅつしゃ）(Insinyur kepala telekomunikasi)","消防設備士（しょうぼうせつびし）(Teknisi peralatan pemadam)"],answer:1,hasPhoto:false,explanation:"電気工事士 = kualifikasi WAJIB untuk pekerjaan listrik. 工事担任者 = untuk telekomunikasi. 消防設備士 = untuk pemadam. Jangan tertukar!",related_card_id:252},{id:"tt1_q18",set:"tt1",setLabel:"学科 Set 1",jp:"消防設備工事で設置される設備を選びなさい。",hiragana:"しょうぼう せつび こうじ で せっち される せつび を えらびなさい。",id_text:"Pilih peralatan yang dipasang dalam pekerjaan peralatan pemadam kebakaran.",options:["洗面器（せんめんき）(Wastafel)","焼却炉（しょうきゃくろ）(Incinerator/tungku pembakaran)","スプリンクラー (Sprinkler)","エアコン (AC)"],answer:3,hasPhoto:false,explanation:"スプリンクラー (sprinkler) = peralatan pemadam otomatis → dipasang dalam 消防設備工事. Wastafel = sanitasi, AC = AC, tungku = bukan pemadam. Kartu #28.",related_card_id:28},{id:"tt1_q19",set:"tt1",setLabel:"学科 Set 1",jp:"建物や建造物を（　）作業を解体工事という。",hiragana:"たてもの や けんぞうぶつ を（ ）さぎょう を かいたい こうじ と いう。",id_text:"Pekerjaan yang ( ) bangunan atau konstruksi disebut pekerjaan pembongkaran (解体工事).",options:["作る（つくる）(Membuat)","直す（なおす）(Memperbaiki)","組み立てる（くみたてる）(Merakit)","壊す（こわす）(Menghancurkan/membongkar)"],answer:4,hasPhoto:false,explanation:"解体工事 = pekerjaan pembongkaran → kata kuncinya 壊す (menghancurkan). Bukan membuat, memperbaiki, atau merakit.",related_card_id:222},{id:"tt1_q20",set:"tt1",setLabel:"学科 Set 1",jp:"建設工事には、（　）が必要な作業がある。",hiragana:"けんせつこうじには （ ）が ひつようなさぎょうがある。",id_text:"Dalam pekerjaan konstruksi, ada pekerjaan yang memerlukan ( ).",options:["免許（めんきょ）(Lisensi/izin resmi)","パスポート (Paspor)","在留カード（ざいりゅうカード）(Kartu izin tinggal)"],answer:1,hasPhoto:false,explanation:"Ada pekerjaan konstruksi yang memerlukan 免許 (lisensi/sertifikasi resmi), seperti pekerjaan listrik, crane, dll. Paspor & kartu tinggal bukan untuk pekerjaan teknis.",related_card_id:220},{id:"tt1_q21",set:"tt1",setLabel:"学科 Set 1",jp:"特別教育は、社外で受講する方法と、（　）で実施する方法がある。",hiragana:"とくべつきょういくは、しゃがいで じゅこうする ほうほうと、（ ）で じっしする ほうほうが ある。",id_text:"Pelatihan khusus (特別教育) bisa dilaksanakan secara eksternal dan secara ( ).",options:["海外（かいがい）(Di luar negeri)","社内（しゃない）(Di dalam perusahaan)","労働局（ろうどうきょく）(Di kantor tenaga kerja)"],answer:2,hasPhoto:false,explanation:"特別教育 = 2 cara: ①社外 (eksternal, lembaga luar) dan ②社内 (internal, di dalam perusahaan sendiri). Keduanya sah secara hukum.",related_card_id:220},{id:"tt1_q22",set:"tt1",setLabel:"学科 Set 1",jp:"事故やケガが無く、無事に１日の作業が進められることを願う気持ちを表すために、（　）というあいさつが使われる。",hiragana:"じこ や けが が なく、 ぶじ に １にち の さぎょう が すすめられる こと を ねがう きもち を あらわす ため に、（ ） という あいさつ が つかわれる。",id_text:"Sapaan yang digunakan untuk mengungkapkan harapan agar pekerjaan sehari berjalan tanpa kecelakaan adalah ( ).",options:["お大事に（おだいじに）(Jaga kesehatan ya)","ご安全（あんぜん）に (Semoga selamat)","ご注意（ちゅうい）を (Harap berhati-hati)"],answer:2,hasPhoto:false,explanation:"ご安全に = sapaan keselamatan khas konstruksi, bermakna 'semoga selamat bekerja'. Diucapkan di awal/akhir kerja. Kartu #678.",related_card_id:678},{id:"tt1_q23",set:"tt1",setLabel:"学科 Set 1",jp:"（　）という言葉は、建設現場だけではなく、事務所や休憩場所などですれ違ったときにも使える。",hiragana:"（ ） という ことば は、 けんせつげんば だけ ではなく、 じむしょ や きゅうけいばしょ など で すれちがった とき にも つかえる。",id_text:"Kata ( ) bisa digunakan tidak hanya di lokasi konstruksi, tapi juga saat berpapasan di kantor atau ruang istirahat.",options:["さようなら (Selamat tinggal)","どういたしまして (Sama-sama)","おつかれさまです (Terima kasih atas kerja kerasnya)"],answer:3,hasPhoto:false,explanation:"お疲れ様です = bisa dipakai kapan saja & di mana saja di lingkungan kerja. ご安全に = khas lokasi konstruksi/berbahaya saja. Kartu #679.",related_card_id:679},{id:"tt1_q24",set:"tt1",setLabel:"学科 Set 1",jp:"床など水平面に直接付ける墨を何というか。",hiragana:"ゆか など すいへいめん に ちょくせつ つける すみ を なんと いうか。",id_text:"Garis tinta yang dibuat langsung di permukaan horizontal seperti lantai disebut apa?",options:["立て墨（たてずみ）(Garis vertikal)","逃げ墨（にげずみ）(Garis referensi offset)","仕上げ墨（しあげずみ）(Garis finishing)","地墨（じずみ）(Garis lantai)"],answer:4,hasPhoto:false,explanation:"地墨 (じずみ) = garis tinta di permukaan HORIZONTAL (lantai). 立て墨 = garis vertikal (kolom/dinding). 逃げ墨 = garis offset/referensi.",related_card_id:684},{id:"tt1_q25",set:"tt1",setLabel:"学科 Set 1",jp:"斜面や平坦でない土地、低い土地に土砂を盛り上げて、平らな地表を作ることを何というか。",hiragana:"しゃめん や へいたん でない とち、 ひくい とち に どしゃ を もりあげて、 たいら な ちひょう を つくる こと を なんと いうか。",id_text:"Menimbun tanah/pasir di lereng atau tanah rendah untuk membuat permukaan yang rata disebut apa?",options:["根切り（ねぎり）(Penggalian fondasi)","盛り土（もりど）(Urugan/timbunan tanah)","埋戻し（うめもどし）(Pengurugan kembali)","素掘り（すぼり）(Galian mentah tanpa perkuatan)"],answer:2,hasPhoto:false,explanation:"盛り土 = menambah/menumpuk tanah untuk meratakan permukaan. 根切り = menggali untuk fondasi. 埋戻し = menutup kembali galian setelah selesai.",related_card_id:203},{id:"tt1_q26",set:"tt1",setLabel:"学科 Set 1",jp:"鉄筋とこれを覆うコンクリート表面までの距離のことを何というか。",hiragana:"てっきんと これをおおう こんくりーと ひょうめんまでの きょりのことを なんと いうか。",id_text:"Jarak antara tulangan baja dengan permukaan beton yang menutupinya disebut apa?",options:["あき (Jarak bebas antar tulangan)","あそび (Kelonggaran)","かぶり厚さ（かぶりあつさ）(Selimut beton / concrete cover)","間隔（かんかく）(Jarak/spasi)"],answer:3,hasPhoto:false,explanation:"かぶり厚さ = selimut beton (concrete cover) — jarak dari tulangan ke permukaan beton. Fungsi: melindungi tulangan dari korosi & api.",related_card_id:279},{id:"tt1_q27",set:"tt1",setLabel:"学科 Set 1",jp:"ライフライン・設備工事で使われる用語で、部屋の温度、湿度などを調整するという意味の言葉はどれか。",hiragana:"らいふらいん・せつびこうじ で つかわれる ようご で、へや の おんど、しつど など を ちょうせいする という いみ の ことば は どれか。",id_text:"Istilah dalam pekerjaan lifeline/instalasi yang berarti mengatur suhu dan kelembapan ruangan adalah?",options:["空調（くうちょう）(AC / pengkondisian udara)","換気（かんき）(Ventilasi)","排煙（はいえん）(Pembuangan asap)","衛生（えいせい）(Sanitasi)"],answer:1,hasPhoto:false,explanation:"空調 (くうちょう) = Air Conditioning → mengatur suhu & kelembapan. 換気 = hanya sirkulasi udara. 排煙 = pembuangan asap darurat. Kartu #27.",related_card_id:27},{id:"tt1_q28",set:"tt1",setLabel:"学科 Set 1",jp:"安全で過ごしやすく働きやすい環境を作るための5Sは、整理・整頓・清掃・清潔ともう一つは何か。",hiragana:"あんぜん で すごしやすく はたらきやすい かんきょう を つくる ため の 5S は、せいり・せいとん・せいそう・せいけつ と もうひとつは なにか。",id_text:"5S untuk menciptakan lingkungan kerja yang aman adalah 整理・整頓・清掃・清潔 dan satu lagi adalah?",options:["修理（しゅうり）(Perbaikan)","相談（そうだん）(Konsultasi)","しつけ (Disiplin/Shitsuke)"],answer:3,hasPhoto:false,explanation:"5S = 整理(Seiri) + 整頓(Seiton) + 清掃(Seisou) + 清潔(Seiketsu) + しつけ(Shitsuke/Disiplin). Semua diawali 'S'. Hafal 5 kata ini!",related_card_id:101},{id:"tt1_q29",set:"tt1",setLabel:"学科 Set 1",jp:"作業員詰め所のルールとして、正しいものは、次のうちどれか。",hiragana:"さぎょういんつめしょ の るーる として、 ただしい もの は、 つぎ の うち どれか。",id_text:"Manakah yang merupakan aturan yang benar untuk ruang istirahat pekerja?",options:["喫煙は、まわりから見えない場所で隠れてする（きつえんは、まわりからみえないばしょでかくれてする）(Merokok di tempat tersembunyi dari pandangan orang)","ごみが落（お）ちているのを見（み）つけたら、そのままにしておく (Biarkan sampah yang ditemukan)","ヘルメットや安全帯は決められた場所に置く（ヘルメットやあんぜんたいはきめられたばしょにおく）(Simpan helm & harness di tempat yang ditentukan)"],answer:3,hasPhoto:false,explanation:"Helm & harness disimpan di tempat yang SUDAH DITENTUKAN → mudah ditemukan & tidak rusak. Merokok sembarangan & membiarkan sampah = SALAH.",related_card_id:304},// ── SET tt2: tt_sample2.pdf — 学科 Set 2 (36 soal) ────────────────────────
{id:"tt2_q01",set:"tt2",setLabel:"学科 Set 2",jp:"作業開始前に毎日行われる、すべての作業員が集まるミーティングを何というか。",hiragana:"さぎょう かいし まえ に まいにち おこなわれる、 すべて の さぎょう いん が あつまる みーてぃんぐ を なん と いう か。",id_text:"Pertemuan harian sebelum mulai kerja yang dihadiri semua pekerja disebut apa?",options:["朝礼（ちょうれい）(Apel pagi)","ラジオ体操（ラジオたいそう）(Senam radio)","安全唱和（あんぜんしょうわ）(Nyanyian keselamatan)"],answer:1,hasPhoto:false,explanation:"朝礼 = apel pagi wajib setiap hari sebelum kerja, dihadiri SEMUA pekerja. Ada 2 jenis: apel umum & apel per jenis kerja. Kartu #4.",related_card_id:4},{id:"tt2_q02",set:"tt2",setLabel:"学科 Set 2",jp:"写真は何の活動を行っているところか。",hiragana:"しゃしん は なん の かつどう を おこなっている ところ か。",id_text:"Foto menunjukkan kegiatan apa yang sedang dilakukan?",options:["KY活動（KYかつどう）(Kegiatan KY/identifikasi bahaya)","タッチアンドコール (Touch-and-call)","ラジオ体操（ラジオたいそう）(Senam radio)"],answer:2,hasPhoto:true,photoDesc:"📸 FOTO: Beberapa pekerja berhelm menumpuk tangan di tengah (seperti yel-yel tim olahraga) — ini adalah タッチアンドコール (touch-and-call), konfirmasi komitmen keselamatan kelompok.",explanation:"タッチアンドコール = semua anggota tumpuk tangan → teriak bersama → konfirmasi komitmen keselamatan. Berbeda dari KY活動 (identifikasi bahaya per titik).",related_card_id:599},{id:"tt2_q03",set:"tt2",setLabel:"学科 Set 2",jp:"労災保険の保険料を支払うのは誰か。",hiragana:"ろうさい ほけん の ほけんりょう を しはらう の は だれか。",id_text:"Siapa yang membayar premi asuransi kecelakaan kerja (労災保険)?",options:["事業主（じぎょうぬし）(Pengusaha/pemberi kerja)","労働者（ろうどうしゃ）(Pekerja/karyawan)"],answer:1,hasPhoto:false,explanation:"労災保険 = premi 100% ditanggung 事業主 (pengusaha). Pekerja tidak bayar sama sekali. BERBEDA dari 雇用保険 yang dibayar bersama. Kartu #19.",related_card_id:19},{id:"tt2_q04",set:"tt2",setLabel:"学科 Set 2",jp:"職場における労働者の安全と健康を確保することを目的とした法律は何か。",hiragana:"しょくば に おける ろうどうしゃ の あんぜん と けんこう を かくほ する こと を もくてき と した ほうりつ は なにか。",id_text:"UU apa yang bertujuan memastikan keselamatan dan kesehatan pekerja di tempat kerja?",options:["雇用保険法（こようほけんほう）(UU Asuransi Ketenagakerjaan)","労働安全衛生法（ろうどうあんぜんえいせいほう）(UU Keselamatan & Kesehatan Kerja)"],answer:2,hasPhoto:false,explanation:"労働安全衛生法 = UU K3 → keselamatan & kesehatan pekerja di tempat kerja. 雇用保険法 = asuransi saat kehilangan pekerjaan. Kartu #10.",related_card_id:10},{id:"tt2_q05",set:"tt2",setLabel:"学科 Set 2",jp:"建設業法の目的はどれか。",hiragana:"けんせつぎょうほう の もくてき は どれか。",id_text:"Apa tujuan dari UU Industri Konstruksi (建設業法)?",options:["建設業を営む者の資質の向上（けんせつぎょうをいとなむもののししつのこうじょう）(Peningkatan KUALITAS SDM pelaku konstruksi)","建設業を営む者の技能の向上（けんせつぎょうをいとなむもののぎのうのこうじょう）(Peningkatan KETERAMPILAN pelaku konstruksi)"],answer:1,hasPhoto:false,explanation:"建設業法の目的 = meningkatkan 資質 (kualitas/kompetensi menyeluruh). Bukan hanya 技能 (skill teknis). 資質 mencakup etika, manajemen, dll. Kartu #12.",related_card_id:12},{id:"tt2_q06",set:"tt2",setLabel:"学科 Set 2",jp:"建設リサイクル法とは、（　）の適切な処理や再資源化を促すための法律です。",hiragana:"けんせつ りさいくるほう とは、（ ） の てきせつ な しょり や さいしげんか を うながす ため の ほうりつ です。",id_text:"UU Daur Ulang Konstruksi adalah UU yang mendorong pengelolaan & daur ulang ( ) secara tepat.",options:["大気汚染物質（たいきおせんぶっしつ）(Polutan udara)","廃材（はいざい）(Material sisa/limbah konstruksi)"],answer:2,hasPhoto:false,explanation:"建設リサイクル法 = mengatur daur ulang 廃材 (material sisa konstruksi: beton, kayu, aspal). Bukan polutan udara. Kartu #116.",related_card_id:116},{id:"tt2_q07",set:"tt2",setLabel:"学科 Set 2",jp:"ガス事業法は、導管によりガスを供給する（　）ガス事業に関して、保安の確保や、ガスの使用者の保護を目的とした法律です。",hiragana:"がすじぎょうほう は、 どうかん に より がす を きょうきゅう する （ ）がすじぎょう に かんして、 ほあん の かくほ や、 がす の しよう しゃ の ほご を もくてき と した ほうりつ です。",id_text:"UU Usaha Gas mengatur usaha gas ( ) yang memasok gas melalui pipa, bertujuan memastikan keamanan & melindungi pengguna gas.",options:["都市（とし）(Gas kota/city gas)","LP (Gas LPG)"],answer:1,hasPhoto:false,explanation:"ガス事業法 = untuk 都市ガス (gas kota, distribusi lewat pipa/導管). LPガス diatur UU berbeda. Kata kunci: 導管 (pipa) = gas kota. Kartu #118.",related_card_id:118},{id:"tt2_q08",set:"tt2",setLabel:"学科 Set 2",jp:"電気通信工事を実施したり、監督するのに必要な資格は何か。",hiragana:"でんき つうしん こうじ を じっし したり、 かんとく する の に ひつよう な しかく は なにか。",id_text:"Kualifikasi apa yang diperlukan untuk melaksanakan atau mengawasi pekerjaan telekomunikasi?",options:["電気工事士（でんきこうじし）(Teknisi pekerjaan listrik)","工事担任者（こうじたんにんしゃ）(Penanggung jawab pekerjaan telekomunikasi)"],answer:2,hasPhoto:false,explanation:"工事担任者 = kualifikasi untuk pekerjaan TELEKOMUNIKASI. 電気工事士 = untuk pekerjaan LISTRIK. Pasangan jebakan klasik! Kartu #17.",related_card_id:17},{id:"tt2_q09",set:"tt2",setLabel:"学科 Set 2",jp:"電気は扱い方を間違えると、（　）につながる。",hiragana:"でんき は あつかいかた を まちがえると、 （ ） に つながる。",id_text:"Jika listrik ditangani dengan salah, akan menyebabkan ( ).",options:["火災や感電（かさいやかんでん）(Kebakaran dan sengatan listrik)","ガス漏れ（ガスもれ）(Kebocoran gas)"],answer:1,hasPhoto:false,explanation:"Listrik yang ditangani salah → kebakaran (火災) & sengatan listrik (感電). Bukan kebocoran gas. Kartu #81 (感電).",related_card_id:81},{id:"tt2_q10",set:"tt2",setLabel:"学科 Set 2",jp:"ダムの目的は、次のどれか。",hiragana:"だむ の もくてき は、 つぎ の どれか。",id_text:"Apa tujuan pembangunan bendungan (ダム)?",options:["治水（ちすい）(Pengendalian banjir)","汚水（おすい）(Air kotor/limbah)","排水（はいすい）(Drainase/pembuangan air)","治山（ちざん）(Konservasi lahan pegunungan)"],answer:1,hasPhoto:false,explanation:"Tujuan utama bendungan = 治水 (pengendalian banjir, penyediaan air). 治山 = reboisasi/konservasi gunung. Jangan tukar keduanya.",related_card_id:642},{id:"tt2_q11",set:"tt2",setLabel:"学科 Set 2",jp:"トンネルは、（　）、道路、水路、およびその他のインフラ設備の建設に使用されます。",hiragana:"とんねる は、 （ ）、 どうろ、 すいろ、 および そのた の いんふらせつび の けんせつ に しよう されます。",id_text:"Terowongan digunakan untuk pembangunan ( ), jalan raya, saluran air, dan infrastruktur lainnya.",options:["海路（かいろ）(Jalur laut)","鉄道（てつどう）(Jalur kereta api)","空路（くうろ）(Jalur udara)","橋（はし）(Jembatan)"],answer:2,hasPhoto:false,explanation:"Terowongan digunakan untuk 鉄道 (kereta api), jalan raya, saluran air. Bukan jalur laut/udara — itu di atas permukaan.",related_card_id:643},{id:"tt2_q12",set:"tt2",setLabel:"学科 Set 2",jp:"掘削工事によって土の壁が崩れないようにすることを（　）という。",hiragana:"くっさくこうじ に よって つち の かべ が くずれない よう に する こと を （ ） と いう。",id_text:"Tindakan mencegah dinding tanah runtuh akibat pekerjaan penggalian disebut ( ).",options:["仮設（かせつ）(Instalasi sementara)","排水（はいすい）(Drainase)","山留め（やまどめ）(Penahan tanah galian)","試掘（しくつ）(Galian uji coba)"],answer:3,hasPhoto:false,explanation:"山留め = mencegah tanah di sisi galian runtuh. Di bidang konstruksi sering disebut 土留め. Wajib jika kedalaman ≥1.5m. Kartu #108.",related_card_id:108},{id:"tt2_q13",set:"tt2",setLabel:"学科 Set 2",jp:"基礎、柱、梁、壁面、床などで構成される建物の構造部分を（　）と言う。",hiragana:"きそ、 はしら、 はり、 へきめん、 ゆか など で こうせい される たてもの の こうぞう ぶぶん を （ ） と いう。",id_text:"Bagian struktural bangunan yang terdiri dari fondasi, kolom, balok, dinding, lantai dsb disebut ( ).",options:["内装仕上げ（ないそうしあげ）(Finishing interior)","建具（たてぐ）(Kusen pintu/jendela)","屋根（やね）(Atap)","躯体（くたい）(Struktur utama/kutai)"],answer:4,hasPhoto:false,explanation:"躯体 (くたい) = struktur utama bangunan: fondasi + kolom + balok + dinding + lantai. 仕上げ = finishing, 建具 = kusen, 屋根 = atap.",related_card_id:767},{id:"tt2_q14",set:"tt2",setLabel:"学科 Set 2",jp:"都市ガス工事で行う工事はどれか。",hiragana:"とし がす こうじ で おこなう こうじ は どれか。",id_text:"Pekerjaan apa yang dilakukan dalam 都市ガス工事 (pekerjaan gas kota)?",options:["ケーブル工事（ケーブルこうじ）(Pekerjaan kabel)","管路の工事（かんろのこうじ）(Pekerjaan jalur pipa)","配電盤の工事（はいでんばんのこうじ）(Pekerjaan panel distribusi listrik)","電柱工事（でんちゅうこうじ）(Pekerjaan tiang listrik)"],answer:2,hasPhoto:false,explanation:"都市ガス工事 = pekerjaan jaringan PIPA (管路) untuk mendistribusikan gas kota. Kabel & panel = pekerjaan listrik. Kartu #24.",related_card_id:24},{id:"tt2_q15",set:"tt2",setLabel:"学科 Set 2",jp:"建物内で使用された水を集める施設を作る工事を何というか。",hiragana:"たてものない で しよう された みず を あつめる しせつ を つくる こうじ を なんと いうか。",id_text:"Pekerjaan membangun fasilitas yang mengumpulkan air yang sudah digunakan di dalam gedung disebut apa?",options:["電気通信工事（でんきつうしんこうじ）(Pekerjaan telekomunikasi)","上水道工事（じょうすいどうこうじ）(Pekerjaan air bersih)","下水道工事（げすいどうこうじ）(Pekerjaan saluran air limbah)","電気工事（でんきこうじ）(Pekerjaan listrik)"],answer:3,hasPhoto:false,explanation:"下水道工事 = membangun sistem pengumpulan air LIMBAH (bekas pakai). 上水道 = air BERSIH. Air yang sudah dipakai → 下水道. Kartu #25.",related_card_id:25},{id:"tt2_q16",set:"tt2",setLabel:"学科 Set 2",jp:"推進トンネル工事では、あらかじめ工場で製作した管を掘進機に連結し、発進立坑に設置した（　）で地中に押し込む。",hiragana:"すいしん とんねる こうじ では、 あらかじめ こうじょう で せいさく した かん を くっしんき に れんけつ し、 はっしん たてこう に せっち した （ ） で ちちゅう に おしこむ。",id_text:"Dalam pipe jacking tunnel, pipa yang dibuat di pabrik dihubungkan ke mesin bor dan didorong ke dalam tanah menggunakan ( ) yang dipasang di shaft awal.",options:["ジャッキ (Dongkrak hidrolik/jack)","クレーン (Crane)","押輪（おしわ）(Cincin pendorong)"],answer:1,hasPhoto:false,explanation:"推進トンネル工事 (pipe jacking) = pipa didorong dengan JACKS hidrolik (ジャッキ). Bukan crane (digunakan angkat, bukan dorong horizontal).",related_card_id:191},{id:"tt2_q17",set:"tt2",setLabel:"学科 Set 2",jp:"機械の運転・操作には、定められた（　）や特別教育を修了しなければならない。",hiragana:"きかい の うんてん・そうさ には、 さだめられた （ ） や とくべつ きょういく を しゅうりょう しなければ ならない。",id_text:"Untuk mengoperasikan mesin, harus menyelesaikan ( ) yang ditetapkan dan pelatihan khusus.",options:["マネジメント講習（マネジメントこうしゅう）(Pelatihan manajemen)","技能講習（ぎのうこうしゅう）(Pelatihan keterampilan)","基幹技能者講習（きかんぎのうしゃこうしゅう）(Pelatihan teknisi inti)"],answer:2,hasPhoto:false,explanation:"Operasi mesin berat = wajib 技能講習 (pelatihan keterampilan, misal: crane, forklift) + 特別教育. Bukan manajemen atau teknisi inti.",related_card_id:220},{id:"tt2_q18",set:"tt2",setLabel:"学科 Set 2",jp:"この写真は、どんな作業を行っているところか。",hiragana:"この しゃしん は、 どんな さぎょう を おこなっている ところ か。",id_text:"Foto ini menunjukkan pekerjaan apa yang sedang dilakukan?",options:["積み込み作業（つみこみさぎょう）(Pekerjaan pemuatan/loading)","盛り土作業（もりどさぎょう）(Pekerjaan urugan tanah)","敷き均し作業（しきならしさぎょう）(Pekerjaan penghamparan/grading)"],answer:3,hasPhoto:true,photoDesc:"📸 FOTO: Mesin paver aspal besar (asphalt finisher) berwarna hijau sedang bergerak di atas permukaan jalan, menghamparkan material aspal secara merata — ini adalah 敷き均し作業.",explanation:"敷き均し作業 = penghamparan material (aspal dll) secara merata menggunakan mesin finisher. Berbeda dari 盛り土 (timbunan tanah) atau 積み込み (pemuatan).",related_card_id:768},{id:"tt2_q19",set:"tt2",setLabel:"学科 Set 2",jp:"ブルドーザなどの機械を使って、土砂を押して運ぶことを（　）という。",hiragana:"ぶるどーざ など の きかい を つかって、 どしゃ を おして はこぶ こと を （ ） と いう。",id_text:"Mendorong dan memindahkan tanah/pasir menggunakan mesin seperti bulldozer disebut ( ).",options:["押土（おしど）(Mendorong tanah)","運搬（うんぱん）(Pengangkutan)","掘削（くっさく）(Penggalian)"],answer:1,hasPhoto:false,explanation:"押土 (おしど) = mendorong tanah dengan blade bulldozer. 掘削 = menggali. 運搬 = mengangkut. Kata kunci: 'mendorong' (押す) + bulldozer. Kartu #148 (転圧関連).",related_card_id:242},{id:"tt2_q20",set:"tt2",setLabel:"学科 Set 2",jp:"屋根工事に含まれる工事はどれか。",hiragana:"やねこうじ に ふくまれる こうじ は どれか。",id_text:"Mana yang termasuk dalam pekerjaan atap (屋根工事)?",options:["カーテン工事（カーテンこうじ）(Pemasangan tirai/curtain)","漆喰補修工事（しっくいほしゅうこうじ）(Perbaikan plester mortar)","吹付けウレタン断熱工事（ふきつけウレタンだんねつこうじ）(Semprot insulasi uretan)"],answer:2,hasPhoto:false,explanation:"漆喰補修工事 (perbaikan plester/mortar) = masuk 屋根工事 karena atap tradisional Jepang menggunakan plester. Tirai = interior. Semprot uretan = biasanya isolasi dinding/lantai.",related_card_id:674},{id:"tt2_q21",set:"tt2",setLabel:"学科 Set 2",jp:"型枠を鉄製のパイプで補強することを（　）という。",hiragana:"かたわく を てつせい の ぱいぷ で ほきょう することを （ ） と いう。",id_text:"Memperkuat bekisting dengan pipa besi disebut ( ).",options:["打設（だせつ）(Pengecoran)","保温（ほおん）(Isolasi termal)","支保工（しほこう）(Perancah penyangga/shoring)"],answer:3,hasPhoto:false,explanation:"支保工 = sistem perancah/shoring dengan pipa besi untuk menopang bekisting saat pengecoran. 打設 = menuang beton. 保温 = isolasi panas.",related_card_id:210},{id:"tt2_q22",set:"tt2",setLabel:"学科 Set 2",jp:"写真の鉄筋継手は何という工法か。",hiragana:"しゃしん の てっきん つぎて は なんという こうほう か。",id_text:"Metode sambungan tulangan dalam foto disebut apa?",options:["機械式継手（きかいしきつぎて）(Sambungan mekanis/coupler)","重ね継手（かさねつぎて）(Sambungan tumpang)","溶接継手（ようせつつぎて）(Sambungan las)"],answer:1,hasPhoto:true,photoDesc:"📸 FOTO: Batang baja berulir (rebar) dengan coupling sleeve logam di tengah — ini adalah 機械式継手 (mechanical coupler/sambungan mekanis), tulangan disambung lewat selongsong berulir.",explanation:"機械式継手 = coupler berulir menghubungkan 2 rebar. Ciri visual: ada selongsong/sleeve di tengah sambungan. 重ね継手 = tumpang, 溶接継手 = las.",related_card_id:208},{id:"tt2_q23",set:"tt2",setLabel:"学科 Set 2",jp:"（　）は、鉄筋と鉄筋のつなぐ部分を加熱して、軸方向に圧力をかけて接合する工法である。",hiragana:"（ ）は、 てっきん と てっきん の つなぐ ぶぶん を かねつ して、 じくほうこう に あつりょく を かけて せつごう する こうほう である。",id_text:"( ) adalah metode menyambung tulangan dengan memanaskan bagian sambungan lalu memberikan tekanan pada arah aksial.",options:["溶接継手（ようせつつぎて）(Las listrik)","ガス圧接継手（ガスあっせつつぎて）(Gas pressure welding)","重ね継手（かさねつぎて）(Tumpang)"],answer:2,hasPhoto:false,explanation:"ガス圧接継手 = pemanasan gas + tekanan aksial → sambungan permanen tanpa logam pengisi. 溶接継手 = las (ada logam pengisi). Kata kunci: 'dipanaskan + tekanan aksial'.",related_card_id:208},{id:"tt2_q24",set:"tt2",setLabel:"学科 Set 2",jp:"電気工事は、外線工事と（　）の大きく２つに分かれます。",hiragana:"でんき こうじ は、 がいせん こうじ と （ ） の おおきく ２ つ に わかれます。",id_text:"Pekerjaan listrik secara garis besar dibagi menjadi pekerjaan luar (外線工事) dan ( ).",options:["配線工事（はいせんこうじ）(Pekerjaan pengkabelan)","接地工事（せっちこうじ）(Pekerjaan pentanahan)","内線工事（ないせんこうじ）(Pekerjaan instalasi dalam gedung)"],answer:3,hasPhoto:false,explanation:"Listrik = 外線工事 (jaringan luar: tiang, kabel udara/bawah tanah) + 内線工事 (instalasi dalam gedung). Kartu #23.",related_card_id:23},{id:"tt2_q25",set:"tt2",setLabel:"学科 Set 2",jp:"電気通信には、ケーブルを用いた有線方式と、電波を用いた（　）がある。",hiragana:"でんき つうしん に は、 けーぶる を もちいた ゆうせん ほうしき と、 でんぱ を もちいた （ ） が ある。",id_text:"Telekomunikasi terbagi atas sistem berkabel (有線方式) dan ( ) yang menggunakan gelombang radio.",options:["無線方式（むせんほうしき）(Sistem nirkabel)","光ファイバー（ひかりファイバー）(Serat optik)","インターネット (Internet)"],answer:1,hasPhoto:false,explanation:"Telekomunikasi = 有線方式 (kabel, termasuk serat optik) + 無線方式 (nirkabel, gelombang radio). Serat optik masih 有線 (berkabel). Kartu #45, #26.",related_card_id:26},{id:"tt2_q26",set:"tt2",setLabel:"学科 Set 2",jp:"衛生器具設備工事で、設置する設備を選べ。",hiragana:"えいせい きぐ せつび こうじ で、 せっち する せつび を えらべ。",id_text:"Pilih peralatan yang dipasang dalam pekerjaan instalasi sanitasi (衛生器具設備工事).",options:["エアコン (AC)","トイレの便器（トイレのべんき）(Closet/toilet)","貯湯槽（ちょとうそう）(Tangki air panas)"],answer:2,hasPhoto:false,explanation:"衛生器具設備 = peralatan sanitasi: toilet/closet, wastafel, bath tub. AC = 空調. Tangki air panas = perlengkapan pemanas air, bukan sanitasi.",related_card_id:30},{id:"tt2_q27",set:"tt2",setLabel:"学科 Set 2",jp:"煙や熱を自動的に感知する装置や、非常ベル、非常放送などの設備を何というか。",hiragana:"けむり や ねつ を じどうてき に かんち する そうち や、 ひじょう べる、 ひじょう ほうそう など の せつび を なんと いうか。",id_text:"Perangkat yang secara otomatis mendeteksi asap/panas, bel darurat, dan siaran darurat disebut apa?",options:["消火設備（しょうかせつび）(Peralatan pemadam kebakaran)","避難設備（ひなんせつび）(Peralatan evakuasi)","警報設備（けいほうせつび）(Peralatan alarm/peringatan)"],answer:3,hasPhoto:false,explanation:"警報設備 = sistem alarm: detektor asap/panas, bel darurat, siaran darurat. 消火設備 = aktif memadamkan api (sprinkler, hidran). 避難設備 = tangga darurat, tanda evakuasi.",related_card_id:28},{id:"tt2_q28",set:"tt2",setLabel:"学科 Set 2",jp:"まわりにいる人が（　）と叫んだときは、自分に危険が迫っている可能性があるため、すぐに反応すること。",hiragana:"まわり に いる ひと が （ ） と さけんだ とき は、 じぶん に きけん が せまって いる かのうせい が ある ため、 すぐ に はんのう する こと。",id_text:"Saat orang di sekitar berteriak ( ), ada kemungkinan bahaya sedang mengancam dirimu, jadi segera bereaksi.",options:["危ない（あぶない）(Bahaya! / Awas!)","足元よし（あしもとよし）(Kondisi kaki/pijakan aman)","ご安全（あんぜん）に (Semoga selamat)","起立（きりつ）(Berdiri)"],answer:1,hasPhoto:false,explanation:"Teriakan 危ない！= bahaya mengancam SEGERA. Harus langsung bereaksi, minggir, atau hindari. Kartu #682.",related_card_id:682},{id:"tt2_q29",set:"tt2",setLabel:"学科 Set 2",jp:"土木工事では、「丁張り」ともいう建物を建てるための基準線、建物の位置、直角、水平が分かるように作る「仮の囲い」は、次のどれか。",hiragana:"どぼくこうじ では、「ちょうはり」 ともいう たてもの を たてるため の きじゅんせん、 たてもの の いち、 ちょっかく、 すいへい が わかるよう に つくる 「かりのかこい」 は、 つぎのどれか。",id_text:"Di konstruksi sipil, 'pagar sementara' yang disebut juga '丁張り' untuk menentukan garis referensi, posisi, sudut siku, dan ketinggian bangunan adalah?",options:["水盛り（みずもり）(Penyamaan ketinggian dengan air)","遣り方（やりかた）(Setting-out/tata letak referensi)","水貫（みずぬき）(Papan horizontal referensi)"],answer:2,hasPhoto:false,explanation:"遣り方 = rangka tiang kayu + papan (水貫) untuk menentukan posisi & ketinggian. Di sipil disebut 丁張り. 水盛り = hanya untuk cek kerataan. Kartu #152.",related_card_id:152},{id:"tt2_q30",set:"tt2",setLabel:"学科 Set 2",jp:"急な斜面に盛り土をするとき、盛り土が滑り落ちないようにするために、階段状に地盤を削ることは、次のどれか。",hiragana:"きゅうな しゃめん に もりど を するとき、 もりど が すべりおちないように するために、 かいだんじょう に じばん を けずることは、 つぎのどれか。",id_text:"Saat melakukan urugan di lereng terjal, apa yang dilakukan untuk mencegah urugan meluncur, yaitu memotong tanah dasar secara bertangga?",options:["路床（ろしょう）(Subgrade/lapisan sub-dasar jalan)","締固め（しめかため）(Pemadatan)","段切り（だんぎり）(Potongan bertangga/step cutting)"],answer:3,hasPhoto:false,explanation:"段切り = memotong lereng secara BERTANGGA (seperti tangga) sebelum menambah urugan → mencegah urugan meluncur. 締固め = memadatkan tanah (berbeda tahap).",related_card_id:267},{id:"tt2_q31",set:"tt2",setLabel:"学科 Set 2",jp:"日本で古くから使われている面積の単位は何か。",hiragana:"にほん で ふるく から つかわれている めんせき の たんい は なにか。",id_text:"Satuan luas yang sudah lama digunakan di Jepang adalah apa?",options:["坪（つぼ）(Tsubo — satuan luas tradisional)","寸（すん）(Sun — satuan panjang)","尺（しゃく）(Shaku — satuan panjang)"],answer:1,hasPhoto:false,explanation:"坪 (つぼ) = satuan luas tradisional Jepang ≈ 3.3 m². Masih digunakan dalam properti. 寸/尺 = satuan PANJANG (bukan luas).",related_card_id:288},{id:"tt2_q32",set:"tt2",setLabel:"学科 Set 2",jp:"型枠の再利用のために型枠から釘を抜き取ることを何というか。",hiragana:"かたわく の さいりよう の ために かたわく から くぎ を ぬきとる こと を なんというか。",id_text:"Mencabut paku dari bekisting agar bisa digunakan kembali disebut apa?",options:["打ち込み（うちこみ）(Pemakuan/menancapkan paku)","釘仕舞（くぎじまい）(Mencabut dan menyimpan paku)","釘止め（くぎどめ）(Pengikatan dengan paku)"],answer:2,hasPhoto:false,explanation:"釘仕舞 (くぎじまい) = mencabut paku dari bekisting yang sudah dibongkar, agar papan bisa dipakai ulang. 打ち込み = menancapkan. 釘止め = mengencangkan.",related_card_id:314},{id:"tt2_q33",set:"tt2",setLabel:"学科 Set 2",jp:"電気工事で、電気が流れる部分から、他の部分に電流が流れないようにすることは、次のどれか。",hiragana:"でんきこうじ で、 でんき が ながれる ぶぶん から、 た の ぶぶん に でんりゅう が ながれない よう に すること は、 つぎのどれか。",id_text:"Dalam pekerjaan listrik, tindakan mencegah arus mengalir dari bagian berlistrik ke bagian lain adalah?",options:["接続（せつぞく）(Penyambungan)","配線（はいせん）(Pengkabelan)","絶縁（ぜつえん）(Isolasi)"],answer:3,hasPhoto:false,explanation:"絶縁 (ぜつえん) = isolasi listrik — mencegah arus mengalir ke tempat yang tidak diinginkan. Dilakukan dengan karet, plastik, atau bahan dielektrik lainnya.",related_card_id:291},{id:"tt2_q34",set:"tt2",setLabel:"学科 Set 2",jp:"電気工事で、電気機器や回路と大地を電気的に接続することは、次のどれか。",hiragana:"でんきこうじ で、 でんききき や かいろ と だいち を でんきてき に せつぞく する こと は、 つぎのどれか。",id_text:"Dalam pekerjaan listrik, menghubungkan perangkat listrik atau rangkaian dengan tanah (bumi) secara elektrikal adalah?",options:["接地（せっち）(Pentanahan/grounding)","漏電（ろうでん）(Kebocoran arus)","通線（つうせん）(Penarikan kabel)"],answer:1,hasPhoto:false,explanation:"接地 (せっち) = grounding — menghubungkan ke tanah untuk keamanan (jika ada arus bocor, mengalir ke bumi bukan ke manusia). 漏電 = KEADAAN bocor, bukan tindakan.",related_card_id:42},{id:"tt2_q35",set:"tt2",setLabel:"学科 Set 2",jp:"（　）とは、必要なものを決められた場所に置くことである。",hiragana:"（ ） とは、 ひつよう な もの を きめられた ばしょ に おく こと で ある。",id_text:"( ) adalah meletakkan barang yang diperlukan di tempat yang sudah ditentukan.",options:["掃除（そうじ）(Membersihkan)","整頓（せいとん）(Menata/merapikan — Seiton)","清潔（せいけつ）(Bersih/higienis — Seiketsu)"],answer:2,hasPhoto:false,explanation:"整頓 (せいとん) = Seiton = meletakkan barang di TEMPAT YANG DITENTUKAN agar mudah ditemukan. 清潔 = menjaga kebersihan. 掃除 = aktif membersihkan.",related_card_id:338},{id:"tt2_q36",set:"tt2",setLabel:"学科 Set 2",jp:"服装に関する注意のうち、正しいものはどれか。",hiragana:"ふくそう に かんする ちゅうい の うち、 ただしい もの は どれか。",id_text:"Mana yang merupakan perhatian yang benar mengenai pakaian kerja?",options:["上着のボタンは外したままにする（うわぎのボタンははずしたままにする）(Biarkan kancing jaket terbuka)","暑い時は半袖を着用する（あついときははんそでをちゃくようする）(Saat panas, pakai baju lengan pendek)","袖は手首までおろして着用する（そではてくびまでおろしてちゃくようする）(Turunkan lengan baju hingga pergelangan tangan)"],answer:3,hasPhoto:false,explanation:"Di lokasi konstruksi: lengan HARUS diturunkan ke pergelangan tangan (melindungi dari luka/lecet). Kancing harus terkancing. Lengan pendek = DILARANG karena bahaya.",related_card_id:327}];// ─── CATEGORIES ──────────────────────────────────────────────────────────────
